/** Extract the resolved scoring metric from a job's result (top-level or nested in metrics). */
function getJobScoringMetric(job: { result?: Record<string, unknown> | null }): string | undefined {
  const r = job.result;
  if (r?.scoring_metric) return r.scoring_metric as string;
  const m = r?.metrics as Record<string, unknown> | undefined;
  if (m?.scoring_metric) return m.scoring_metric as string;
  return undefined;
}

/** Extract a short 8-char run ID from a pipeline_id, stripping the "preview_" prefix
 *  and any "__branch_N" suffix so all experiments from the same batch share the same ID. */
function shortRunId(job: { pipeline_id: string; parent_pipeline_id?: string | null }): string {
  const raw = job.parent_pipeline_id || job.pipeline_id;
  // Strip "preview_" prefix and any "__branch_*" suffix
  const clean = raw.replace(/^preview_/, '').replace(/__branch_.*$/, '');
  return clean.slice(0, 8);
}

interface EvaluationSplit {
  y_true: (string | number)[];
  y_pred: (string | number)[];
  y_proba?: {
    classes: (string | number)[];
        labels?: (string | number)[];
    values: number[][];
  };
  metrics?: Record<string, number>;
}

interface EvaluationData {
  problem_type: 'classification' | 'regression';
  splits: Record<string, EvaluationSplit>;
}

export const ExperimentsPage: React.FC = () => {
  const { jobs, fetchJobs, hasMore, loadMoreJobs, isLoading, promoteJob, unpromoteJob } = useJobStore();
  const [selectedJobIds, setSelectedJobIds] = useState<string[]>([]);
  const [filterType, setFilterType] = useState<'all' | 'basic_training' | 'advanced_tuning'>('all');
  const [datasets, setDatasets] = useState<{id: string, name: string}[]>([]);
  const [selectedDatasetId, setSelectedDatasetId] = useState<string>('all');
  
  const [selectedMetric, setSelectedMetric] = useState<string | null>(null);
  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
  
  // Metric visibility toggles
  const [showTrainMetrics, setShowTrainMetrics] = useState(true);
  const [showTestMetrics, setShowTestMetrics] = useState(true);
  const [showValMetrics, setShowValMetrics] = useState(true);
  const [showCvMetrics, setShowCvMetrics] = useState(true);

  // Table expansion states
  const [isMetricsExpanded, setIsMetricsExpanded] = useState(true);
  const [isParamsExpanded, setIsParamsExpanded] = useState(true);
  const [isTuningExpanded, setIsTuningExpanded] = useState(true);

  // View state
  const [activeView, setActiveView] = useState<'charts' | 'table' | 'evaluation' | 'importance'>('charts');
  const [evaluationData, setEvaluationData] = useState<EvaluationData | null>(null);
  const [isEvalLoading, setIsEvalLoading] = useState(false);
  const [evalError, setEvalError] = useState<string | null>(null);
  const [evalJobId, setEvalJobId] = useState<string | null>(null);
  const [downloadingChart, setDownloadingChart] = useState<string | null>(null);
  const [doneChart, setDoneChart] = useState<string | null>(null);
  const [selectedRocClass, setSelectedRocClass] = useState<string | null>(null);

  useEffect(() => {
    fetchJobs();
    void fetchDatasets();
  }, [fetchJobs]);

  useEffect(() => {
    if (evaluationData?.splits.train?.y_proba?.classes && evaluationData.splits.train.y_proba.classes.length > 0) {
                const proba = evaluationData.splits.train.y_proba;
                const first = proba.labels?.[0] ?? proba.classes[0];
                setSelectedRocClass(String(first));
    }
  }, [evaluationData]);

  const fetchDatasets = async () => {
    try {
      const response = await apiClient.get('/pipeline/datasets/list');
      setDatasets(response.data);
    } catch (e) {
      console.error("Failed to fetch datasets", e);
    }
  };

  const handleDeploy = async (e: React.MouseEvent, jobId: string) => {
    e.stopPropagation();
    if (!confirm('Are you sure you want to deploy this model to production?')) return;
    try {
      await deploymentApi.deployModel(jobId);
      alert('Model deployed successfully!');
    } catch (err) {
      alert('Failed to deploy model');
      console.error(err);
    }
  };

  const handlePromote = async (e: React.MouseEvent, job: typeof jobs[0]) => {
    e.stopPropagation();
    try {
      if (job.promoted_at) {
        await unpromoteJob(job.job_id);
      } else {
        await promoteJob(job.job_id);
      }
    } catch (err) {
      alert('Failed to update promotion status');
      console.error(err);
    }
  };

  const handleDownload = async (elementId: string, fileName: string) => {
    const element = document.getElementById(elementId);
    if (!element) return;
    
    setDownloadingChart(elementId);
    const isDarkMode = document.documentElement.classList.contains('dark');
    const backgroundColor = isDarkMode ? '#1f2937' : '#ffffff';

    try {
        const dataUrl = await toPng(element, {
            backgroundColor,
            pixelRatio: 2,
            filter: (node) => !(node instanceof HTMLElement && node.dataset.exportIgnore === 'true'),
        });
        const link = document.createElement('a');
        link.download = `${fileName}.png`;
        link.href = dataUrl;
        link.click();
    } catch (e) {
        console.error('Failed to download image', e);
    } finally {
        setDownloadingChart(null);
        setDoneChart(elementId);
        setTimeout(() => setDoneChart(null), 1200);
    }
  };

  const fetchEvaluationData = async (jobId: string) => {
      setIsEvalLoading(true);
      setEvaluationData(null);
      setEvalError(null);
      setEvalJobId(jobId);
      try {
          const res = await apiClient.get(`/pipeline/jobs/${jobId}/evaluation`);
          setEvaluationData(res.data);
      } catch (err: unknown) {
          console.error("Failed to fetch evaluation data", err);
          setEvalError((err as { response?: { data?: { detail?: string } } }).response?.data?.detail || "Failed to fetch evaluation data");
      } finally {
          setIsEvalLoading(false);
      }
  };

  const calculateConfusionMatrix = (
      y_true: (string | number)[],
      y_pred: (string | number)[],
      classOrder?: (string | number)[],
  ) => {
      const classes = (classOrder && classOrder.length > 0)
          ? [...classOrder]
          : Array.from(new Set([...y_true, ...y_pred])).sort((a, b) => String(a).localeCompare(String(b)));
      const matrix = classes.map(trueClass => {
          return classes.map(predClass => {
              return y_true.reduce((count: number, t, i) => {
                  const p = y_pred[i];
                  return (String(t) === String(trueClass) && String(p) === String(predClass)) ? count + 1 : count;
              }, 0);
          });
      });
      return { classes, matrix };
  };

    const calculateROC = (y_true: (string | number)[], y_proba: { classes: (string | number)[], labels?: (string | number)[], values: number[][] }, targetClass: string | number) => {
      // y_proba.values is typed as number[][], so it's always truthy if it exists on the type.
      // If the type definition allows undefined, then the check is valid. Assuming strict null checks.
      // Based on the error "Unnecessary conditional, value is always truthy", y_proba.values is not optional in the type definition above.
      
      const targetClassStr = String(targetClass);
      
      // Find index of target class (normalize types because <select> values are strings)
            const labelList = y_proba.labels && y_proba.labels.length === y_proba.classes.length
                ? y_proba.labels
                : undefined;
            const classIndex = (labelList ?? y_proba.classes).findIndex(c => String(c) === targetClassStr);
      if (classIndex === -1) return null;
      
      const scores = y_proba.values.map(v => v[classIndex]);
      
      const data = scores.map((score, i) => ({
          score,
          actual: String(y_true[i]) === targetClassStr ? 1 : 0
      }));
      
      // Sort by score descending
      data.sort((a, b) => b.score - a.score);
      
      const rocPoints = [];
      let tp = 0;
      let fp = 0;
      const totalPos = data.filter(d => d.actual === 1).length;
      const totalNeg = data.length - totalPos;
      
      if (totalPos === 0 || totalNeg === 0) return null; // Cannot calculate ROC if only one class present in split

      rocPoints.push({ fpr: 0, tpr: 0 });
      
      for (let i = 0; i < data.length; i++) {
          if (data[i].actual === 1) tp++;
          else fp++;
          
          rocPoints.push({
              fpr: fp / totalNeg,
              tpr: tp / totalPos
          });
      }
      
      return rocPoints;
  };

  // Effect to fetch evaluation data when view changes or selection changes
  useEffect(() => {
      if (activeView === 'evaluation') {
          // If we have a specific eval job selected, use it
          // Otherwise default to the first selected job
          if (!evalJobId && selectedJobIds.length > 0) {
              void fetchEvaluationData(selectedJobIds[0]);
          } else if (evalJobId && !selectedJobIds.includes(evalJobId) && selectedJobIds.length > 0) {
              // If current eval job is deselected, switch to another
              void fetchEvaluationData(selectedJobIds[0]);
          } else if (selectedJobIds.length === 0) {
              setEvaluationData(null);
              setEvalJobId(null);
          }
      }
  }, [activeView, selectedJobIds, evalJobId]);

  const filteredJobs = jobs.filter(job => {
    const typeMatch = filterType === 'all' || job.job_type === filterType;
    const datasetMatch = selectedDatasetId === 'all' || job.dataset_id === selectedDatasetId;
    const statusMatch = job.status === 'completed';
    return typeMatch && datasetMatch && statusMatch;
  }).sort((a, b) => {
    // Promoted jobs float to top
    if (a.promoted_at && !b.promoted_at) return -1;
    if (!a.promoted_at && b.promoted_at) return 1;
    return 0;
  });

  const selectedJobs = jobs.filter(job => selectedJobIds.includes(job.job_id));

  const toggleJobSelection = (jobId: string) => {
    setSelectedJobIds(prev => 
      prev.includes(jobId) 
        ? prev.filter(id => id !== jobId)
        : [...prev, jobId]
    );
  };

  // Prepare data for charts
  const metricsData = selectedJobs.map(job => {
    // Use top-level metrics field which is normalized for both types (training & tuning)
    const metrics = job.metrics || job.result?.metrics || {};
    return {
      name: shortRunId(job),
      ...metrics
    };
  });

  // Get all unique metric keys from selected jobs
  const metricKeys = Array.from(new Set(
    selectedJobs.flatMap(job => {
        const m = (job.metrics || job.result?.metrics || {}) as Record<string, unknown>;
        // Only include keys that have numeric values to prevent Recharts crashes
        return Object.keys(m).filter(k => {
            const val = m[k];
            return typeof val === 'number' && !isNaN(val);
        });
    })
  )).filter(key => {
      if (key.startsWith('train_') && !showTrainMetrics) return false;
      if (key.startsWith('test_') && !showTestMetrics) return false;
      if (key.startsWith('val_') && !showValMetrics) return false;
      if (key.startsWith('cv_') && !showCvMetrics) return false;
      return true;
  });

  const getDuration = (start: string | null, end: string | null) => {
      if (!start || !end) return '-';
      const diff = new Date(end).getTime() - new Date(start).getTime();
      const seconds = Math.floor(diff / 1000);
      if (seconds < 60) return `${seconds}s`;
      const minutes = Math.floor(seconds / 60);
      return `${minutes}m ${seconds % 60}s`;
  };

  // Helper to parse keys
  const parseMetricKey = (key: string) => {
      if (key === 'best_score') return { type: 'val', base: 'best_score' };
      if (key.startsWith('train_')) return { type: 'train', base: key.replace('train_', '') };
      if (key.startsWith('test_')) return { type: 'test', base: key.replace('test_', '') };
      if (key.startsWith('val_')) return { type: 'val', base: key.replace('val_', '') };
      return { type: 'other', base: key };
  };

  // Group keys by base metric name
  const metricGroups = new Map<string, string[]>();
  metricKeys.forEach(key => {
      const { base } = parseMetricKey(key);
      if (!metricGroups.has(base)) metricGroups.set(base, []);
      metricGroups.get(base)?.push(key);
  });

  metricGroups.forEach((keys, base) => {
      metricGroups.set(base, keys.sort());
  });

  const availableMetrics = Array.from(metricGroups.keys()).sort();
  const activeMetric = (selectedMetric && availableMetrics.includes(selectedMetric)) 
      ? selectedMetric 
      : availableMetrics[0] || null;

  // const colors = ['#8884d8', '#82ca9d', '#ffc658', '#ff7300', '#0088fe', '#00C49F'];

  // Feature Importances across selected jobs
  const featureImportancesByJob = selectedJobs.map(job => {
    const result = (job.result ?? {}) as Record<string, unknown>;
    const metrics = result.metrics as Record<string, unknown> | undefined;
    const raw = (metrics?.feature_importances ?? result.feature_importances) as Record<string, number> | undefined;
    return { jobId: job.job_id, modelType: job.model_type ?? 'unknown', importances: raw ?? null };
  });
  const hasFeatureImportances = featureImportancesByJob.some(j => j.importances !== null);

  return (
    <div className="h-full flex flex-col bg-gray-50 dark:bg-gray-900 overflow-hidden">
      {/* Header */}
      <div className="bg-white dark:bg-gray-800 border-b border-gray-200 dark:border-gray-700 p-4 flex justify-between items-center">
        <div>
          <h1 className="text-xl font-semibold text-gray-800 dark:text-gray-100">Experiments & Comparison</h1>
          <p className="text-sm text-gray-500 dark:text-gray-400">Compare metrics and parameters across multiple runs</p>
        </div>
        <div className="flex gap-2">
           <select 
             className="bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-gray-100 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-2.5"
             value={selectedDatasetId}
             onChange={(e) => { setSelectedDatasetId(e.target.value); }}
           >
             <option value="all">All Datasets</option>
             {datasets.map(ds => (
               <option key={ds.id} value={ds.id}>{ds.name}</option>
             ))}
           </select>
           <select 
             className="bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-gray-100 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-2.5"
             value={filterType}
             onChange={(e) => { setFilterType(e.target.value as 'all' | 'basic_training' | 'advanced_tuning'); }}
           >
             <option value="all">All Experiments</option>
             <option value="advanced_tuning">Advanced Training</option>
             <option value="basic_training">Standard Training</option>
           </select>
        </div>
      </div>

      <div className="flex-1 flex overflow-hidden">
        {/* Sidebar List */}
        <div className={`${isSidebarCollapsed ? 'w-12' : 'w-80'} border-r border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 flex flex-col relative`}>
          <div className="p-3 border-b border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-900/50 flex justify-between items-center h-[41px]">
            {!isSidebarCollapsed && (
              <span className="text-xs font-medium text-gray-500 uppercase truncate">
                Select Runs ({selectedJobIds.length})
              </span>
            )}
            <button 
              onClick={() => setIsSidebarCollapsed(!isSidebarCollapsed)}
              className={`p-1.5 rounded-lg transition-all duration-200 ${
                  isSidebarCollapsed 
                    ? 'mx-auto text-gray-500 hover:bg-gray-200 dark:hover:bg-gray-700 hover:text-gray-900 dark:hover:text-gray-100' 
                    : 'ml-auto text-gray-600 dark:text-gray-300 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600 shadow-sm hover:bg-gray-50 dark:hover:bg-gray-700'
              }`}
              title={isSidebarCollapsed ? "Expand Sidebar" : "Collapse Sidebar"}
            >
              {isSidebarCollapsed ? <ChevronRight className="w-4 h-4" /> : <ChevronLeft className="w-4 h-4" />}
            </button>
          </div>
          <div className="flex-1 overflow-y-auto overflow-x-hidden">
            {filteredJobs.map(job => (
              <div 
                key={job.job_id}
                onClick={() => { toggleJobSelection(job.job_id); }}
                className={`border-b border-gray-100 dark:border-gray-700 cursor-pointer transition-colors hover:bg-gray-50 dark:hover:bg-gray-700 ${
                  selectedJobIds.includes(job.job_id) ? 'bg-blue-50 dark:bg-blue-900/20 border-l-4 border-l-blue-500' : 'border-l-4 border-l-transparent'
                } ${isSidebarCollapsed ? 'p-2 flex justify-center' : 'p-3'}`}
                title={isSidebarCollapsed ? `${shortRunId(job)} · ${job.model_type}` : undefined}
              >
                {isSidebarCollapsed ? (
                    <div className={`w-2 h-2 rounded-full ${
                        job.status === 'completed' ? 'bg-green-500' :
                        job.status === 'failed' ? 'bg-red-500' : 'bg-gray-400'
                    }`} />
                ) : (
                  <>
                <div className="flex justify-between items-start mb-1">
                  <span className="font-mono text-xs font-semibold text-gray-700 dark:text-gray-300 break-all">
                    {shortRunId(job)}
                  </span>
                  <div className="flex items-center gap-2">
                    {job.status === 'completed' && (job.job_type === 'basic_training' || job.job_type === 'advanced_tuning') && (
                      <>
                        <button 
                            onClick={(e) => { void handlePromote(e, job); }}
                            className={`p-1 rounded transition-colors ${
                              job.promoted_at 
                                ? 'bg-amber-100 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400' 
                                : 'hover:bg-amber-100 dark:hover:bg-amber-900/20 text-gray-400 dark:text-gray-500'
                            }`}
                            title={job.promoted_at ? "Unpromote" : "Promote as Winner"}
                        >
                            <Trophy className="w-3 h-3" />
                        </button>
                        <button 
                            onClick={(e) => { void handleDeploy(e, job.job_id); }}
                            className="p-1 hover:bg-blue-100 dark:hover:bg-blue-900 rounded text-blue-600 dark:text-blue-400"
                            title="Deploy to Test"
                        >
                            <Rocket className="w-3 h-3" />
                        </button>
                      </>
                    )}
                  </div>
                </div>
                <div className="text-xs text-gray-500 dark:text-gray-400 mb-1">
                  {job.model_type} • {job.dataset_name || 'Unknown Dataset'}
                  {job.job_type === 'advanced_tuning' && (job.search_strategy || (job.config as { tuning?: { strategy?: string } }).tuning?.strategy) && (
                      <span className="ml-1 text-gray-400">
                          ({job.search_strategy || (job.config as { tuning?: { strategy?: string } }).tuning?.strategy})
                      </span>
                  )}
                  {job.branch_index != null && (
                    <span className="ml-1.5 inline-flex items-center gap-0.5 px-1.5 py-0.5 rounded-full bg-purple-100 dark:bg-purple-900/30 text-purple-700 dark:text-purple-400 text-[10px] font-semibold">
                      <GitBranch className="w-2.5 h-2.5" /> path {String.fromCharCode(65 + (job.branch_index ?? 0))}
                    </span>
                  )}
                  {job.promoted_at && (
                    <span className="ml-1.5 inline-flex items-center gap-0.5 px-1.5 py-0.5 rounded-full bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 text-[10px] font-semibold">
                      <Trophy className="w-2.5 h-2.5" /> Winner
                    </span>
                  )}
                </div>
                <div className="flex justify-between items-center text-[10px] text-gray-400">
                  <span>{new Date(job.start_time || job.created_at).toLocaleString()}</span>
                  <span className="font-mono bg-gray-100 dark:bg-gray-700 px-1.5 py-0.5 rounded text-gray-600 dark:text-gray-300">
                    {getDuration(job.start_time, job.end_time)}
                  </span>
                </div>
                </>
                )}
              </div>
            ))}
            
            {hasMore && (
                <div className="p-3 border-t border-gray-100 dark:border-gray-700 bg-gray-50/50 dark:bg-gray-900/30">
                    <button 
                        onClick={() => loadMoreJobs()}
                        disabled={isLoading}
                        className={`w-full py-2 text-xs font-medium rounded-lg border shadow-sm transition-all duration-200 flex items-center justify-center gap-2 ${
                            isSidebarCollapsed 
                                ? 'bg-transparent border-transparent text-blue-600 dark:text-blue-400 hover:bg-gray-100 dark:hover:bg-gray-800' 
                                : 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 text-gray-700 dark:text-gray-200 hover:border-blue-400 dark:hover:border-blue-500 hover:text-blue-600 dark:hover:text-blue-400'
                        } disabled:opacity-50 disabled:cursor-not-allowed`}
                        title="Load More Runs"
                    >
                        {isLoading ? <RefreshCw className="w-3.5 h-3.5 animate-spin" /> : <ChevronDown className="w-3.5 h-3.5" />}
                        {!isSidebarCollapsed && "Load More Runs"}
                    </button>
                </div>
            )}
          </div>
        </div>

        {/* Comparison Area */}
        <div className="flex-1 overflow-y-auto p-6">
          {selectedJobs.length === 0 ? (
            <div className="h-full flex flex-col items-center justify-center text-gray-400">
              <Filter className="w-12 h-12 mb-4 opacity-20" />
              <p>Select runs from the sidebar to compare them.</p>
            </div>
          ) : (
            <div className="space-y-6">
              
              {/* View Tabs */}
              <div className="flex border-b border-gray-200 dark:border-gray-700">
                  <button
                      className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
                          activeView === 'charts'
                              ? 'border-blue-500 text-blue-600 dark:text-blue-400'
                              : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700'
                      }`}
                      onClick={() => { setActiveView('charts'); }}
                  >
                      Visual Comparison
                  </button>
                  <button
                      className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
                          activeView === 'table'
                              ? 'border-blue-500 text-blue-600 dark:text-blue-400'
                              : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700'
                      }`}
                      onClick={() => { setActiveView('table'); }}
                  >
                      Detailed Metrics & Params
                  </button>
                  <button
                      className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
                          activeView === 'evaluation'
                              ? 'border-blue-500 text-blue-600 dark:text-blue-400'
                              : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700'
                      }`}
                      onClick={() => { setActiveView('evaluation'); }}
                  >
                      Model Evaluation
                  </button>
                  {hasFeatureImportances && (
                  <button
                      className={`px-4 py-2 text-sm font-medium border-b-2 transition-colors ${
                          activeView === 'importance'
                              ? 'border-blue-500 text-blue-600 dark:text-blue-400'
                              : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700'
                      }`}
                      onClick={() => { setActiveView('importance'); }}
                  >
                      Feature Importance
                  </button>
                  )}
              </div>

              {/* Branch Comparison Card — shown when selected jobs share a parallel run */}
              {(() => {
                const branchJobs = selectedJobs.filter(j => j.parent_pipeline_id != null);
                // Group by parent_pipeline_id
                const groups = new Map<string, typeof selectedJobs>();
                branchJobs.forEach(j => {
                  const key = j.parent_pipeline_id!;
                  if (!groups.has(key)) groups.set(key, []);
                  groups.get(key)!.push(j);
                });
                // Only show groups with 2+ branches
                const multiGroups = Array.from(groups.entries()).filter(([, jobs]) => jobs.length >= 2);
                if (multiGroups.length === 0) return null;

                // Collect all metric keys across branch jobs
                const allBranchMetricKeys = Array.from(new Set(
                  branchJobs.flatMap(j => {
                    const m = (j.metrics || j.result?.metrics || {}) as Record<string, unknown>;
                    return Object.keys(m).filter(k => typeof m[k] === 'number');
                  })
                )).filter(k => k.startsWith('test_') || k === 'best_score').sort();

                return multiGroups.map(([parentId, groupJobs]) => (
                  <div key={parentId} className="bg-gradient-to-r from-purple-50 to-blue-50 dark:from-purple-900/10 dark:to-blue-900/10 rounded-lg border border-purple-200 dark:border-purple-800 p-4">
                    <div className="flex items-center gap-2 mb-3">
                      <GitBranch className="w-4 h-4 text-purple-600 dark:text-purple-400" />
                      <h3 className="text-sm font-semibold text-purple-800 dark:text-purple-300">
                        Parallel Run Comparison
                      </h3>
                      <span className="text-xs text-purple-500 dark:text-purple-400 font-mono">
                        {groupJobs.length} paths · run {parentId.replace(/^preview_/, '').replace(/__branch_.*$/, '').slice(0, 8)}
                      </span>
                    </div>
                    <div className="overflow-x-auto">
                      <table className="w-full text-xs text-left">
                        <thead>
                          <tr className="border-b border-purple-200 dark:border-purple-700">
                            <th className="px-3 py-1.5 text-gray-600 dark:text-gray-400 font-medium">Metric</th>
                            {groupJobs.sort((a, b) => (a.branch_index ?? 0) - (b.branch_index ?? 0)).map(j => (
                              <th key={j.job_id} className="px-3 py-1.5 font-medium text-gray-700 dark:text-gray-300">
                                <div className="flex items-center gap-1">
                                  <span className="inline-block w-2 h-2 rounded-full" style={{ backgroundColor: `hsl(${(j.branch_index ?? 0) * 120}, 70%, 50%)` }} />
                                  Path {String.fromCharCode(65 + (j.branch_index ?? 0))} · {j.model_type}
                                  {j.promoted_at && <Trophy className="w-3 h-3 text-amber-500 ml-1" />}
                                </div>
                              </th>
                            ))}
                          </tr>
                        </thead>
                        <tbody>
                          {allBranchMetricKeys.map(key => {
                            // Find best value for highlighting
                            const values = groupJobs.map(j => {
                              const m = (j.metrics || j.result?.metrics || {}) as Record<string, number>;
                              return m[key];
                            });
                            const isLowerBetter = key.includes('loss') || key.includes('error') || key.includes('mse') || key.includes('mae');
                            const bestVal = isLowerBetter
                              ? Math.min(...values.filter(v => v != null))
                              : Math.max(...values.filter(v => v != null));

                            return (
                              <tr key={key} className="border-b border-purple-100 dark:border-purple-800/50">
                                <td className="px-3 py-1.5 text-gray-600 dark:text-gray-400">
                                  {key === 'best_score'
                                    ? `Best Score (${formatMetricName(getJobScoringMetric(groupJobs[0])) || 'CV'})`
                                    : key.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase())}
                                </td>
                                {groupJobs.map(j => {
                                  const m = (j.metrics || j.result?.metrics || {}) as Record<string, number>;
                                  const val = m[key];
                                  const isBest = val != null && val === bestVal;
                                  return (
                                    <td key={j.job_id} className={`px-3 py-1.5 font-mono ${isBest ? 'text-green-600 dark:text-green-400 font-bold' : 'text-gray-600 dark:text-gray-300'}`}>
                                      {val != null ? val.toFixed(4) : '-'}
                                      {isBest && ' ★'}
                                    </td>
                                  );
                                })}
                              </tr>
                            );
                          })}
                          <tr className="border-b border-purple-100 dark:border-purple-800/50">
                            <td className="px-3 py-1.5 text-gray-600 dark:text-gray-400">Duration</td>
                            {groupJobs.map(j => (
                              <td key={j.job_id} className="px-3 py-1.5 font-mono text-gray-600 dark:text-gray-300">
                                {getDuration(j.start_time, j.end_time)}
                              </td>
                            ))}
                          </tr>
                        </tbody>
                      </table>
                    </div>
                  </div>
                ));
              })()}

              {/* Charts View */}
              {activeView === 'charts' && (
              <div className="space-y-6 animate-in fade-in duration-300">
                <div className="flex justify-between items-center">
                    <h3 className="text-lg font-medium text-gray-800 dark:text-gray-100">Metrics Comparison</h3>
                    <div className="flex gap-4 text-sm">
                        <label className="flex items-center gap-2 cursor-pointer">
                            <input 
                                type="checkbox" 
                                checked={showTrainMetrics} 
                                onChange={e => { setShowTrainMetrics(e.target.checked); }}
                                className="rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                            />
                            <span className="text-gray-700 dark:text-gray-300">Train</span>
                        </label>
                        <label className="flex items-center gap-2 cursor-pointer">
                            <input 
                                type="checkbox" 
                                checked={showTestMetrics} 
                                onChange={e => { setShowTestMetrics(e.target.checked); }}
                                className="rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                            />
                            <span className="text-gray-700 dark:text-gray-300">Test</span>
                        </label>
                        <label className="flex items-center gap-2 cursor-pointer">
                            <input 
                                type="checkbox" 
                                checked={showValMetrics} 
                                onChange={e => { setShowValMetrics(e.target.checked); }}
                                className="rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                            />
                            <span className="text-gray-700 dark:text-gray-300">Validation</span>
                        </label>
                        <label className="flex items-center gap-2 cursor-pointer">
                            <input 
                                type="checkbox" 
                                checked={showCvMetrics} 
                                onChange={e => { setShowCvMetrics(e.target.checked); }}
                                className="rounded border-gray-300 text-purple-600 focus:ring-purple-500"
                            />
                            <span className="text-gray-700 dark:text-gray-300">Cross-Validation</span>
                        </label>
                    </div>
                </div>

                {/* Metric Selector Tabs */}
                {availableMetrics.length > 0 && (
                    <div className="flex flex-wrap gap-2 border-b border-gray-200 dark:border-gray-700 pb-2">
                        {availableMetrics.map(metric => (
                            <button
                                key={metric}
                                onClick={() => { setSelectedMetric(metric); }}
                                className={`px-3 py-1.5 text-xs font-medium rounded-md transition-colors ${
                                    activeMetric === metric
                                        ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400'
                                        : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800'
                                }`}
                            >
                                {metric.toUpperCase()}
                            </button>
                        ))}
                    </div>
                )}

                {activeMetric && metricGroups.has(activeMetric) && (
                    <div className="bg-white dark:bg-gray-800 p-6 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700">
                        <div className="h-[300px] w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={metricsData} margin={{ top: 5, right: 30, left: 30, bottom: 40 }}>
                            <CartesianGrid strokeDasharray="3 3" stroke="#374151" opacity={0.1} />
                            <XAxis dataKey="name" stroke="#6B7280" fontSize={12} />
                            <YAxis stroke="#6B7280" fontSize={12} />
                            <Tooltip 
                                shared={false}
                                cursor={{ fill: 'rgba(107, 114, 128, 0.1)' }}
                                contentStyle={{ backgroundColor: '#1F2937', borderColor: '#374151', color: '#F3F4F6' }}
                                itemStyle={{ color: '#F3F4F6' }}
                            />
                            <Legend />
                            {metricGroups.get(activeMetric)?.map((key) => {
                                const { type } = parseMetricKey(key);
                                // Colors: Train=Blue, Test=Green, Val=Orange, Other=Purple
                                let color = '#8884d8';
                                if (type === 'train') color = '#3b82f6'; // blue-500
                                if (type === 'test') color = '#22c55e'; // green-500
                                if (type === 'val') color = '#f97316'; // orange-500
                                if (type === 'other') color = '#a855f7'; // purple-500
                                
                                return <Bar key={key} dataKey={key} fill={color} name={`${type} (${activeMetric})`} />;
                            })}
                            </BarChart>
                        </ResponsiveContainer>
                        </div>
                    </div>
                )}
              </div>
              )}

              {/* Table View */}
              {activeView === 'table' && (
              <div className="bg-white dark:bg-gray-800 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 overflow-hidden animate-in fade-in duration-300">
                <div className="p-4 border-b border-gray-200 dark:border-gray-700">
                  <h3 className="text-lg font-medium text-gray-800 dark:text-gray-100">Detailed Comparison</h3>
                </div>
                <div className="overflow-x-auto">
                  <table className="w-full text-xs text-left">
                    <thead className="text-xs text-gray-700 uppercase bg-gray-50 dark:bg-gray-900/50 dark:text-gray-400">
                      <tr>
                        <th className="px-4 py-2">Parameter / Metric</th>
                        {selectedJobs.map(job => (
                          <th key={job.job_id} className="px-4 py-2 font-mono break-all min-w-[100px]">
                            {shortRunId(job)}
                          </th>
                        ))}
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                      {/* Model Type */}
                      <tr className="bg-white dark:bg-gray-800">
                        <td className="px-4 py-2 font-medium text-gray-900 dark:text-gray-100">Model Type</td>
                        {selectedJobs.map(job => (
                          <td key={job.job_id} className="px-4 py-2 text-gray-500 dark:text-gray-400">
                            <div className="flex items-center gap-1.5">
                              {job.model_type}
                              {job.branch_index != null && (
                                <span className="inline-flex items-center gap-0.5 px-1.5 py-0.5 rounded-full bg-purple-100 dark:bg-purple-900/30 text-purple-700 dark:text-purple-400 text-[10px] font-semibold">
                                  <GitBranch className="w-2.5 h-2.5" /> Path {String.fromCharCode(65 + (job.branch_index ?? 0))}
                                </span>
                              )}
                              {job.promoted_at && (
                                <span className="inline-flex items-center gap-0.5 px-1.5 py-0.5 rounded-full bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400 text-[10px] font-semibold">
                                  <Trophy className="w-2.5 h-2.5" /> Winner
                                </span>
                              )}
                            </div>
                          </td>
                        ))}
                      </tr>
                      {/* Metrics Section in Table */}
                      <tr 
                        className="bg-gray-50/50 dark:bg-gray-900/20 cursor-pointer hover:bg-gray-100 dark:hover:bg-gray-800/50 transition-colors"
                        onClick={() => { setIsMetricsExpanded(!isMetricsExpanded); }}
                      >
                        <td className="px-4 py-2 font-medium text-gray-900 dark:text-gray-100 flex items-center gap-2" colSpan={selectedJobs.length + 1}>
                          {isMetricsExpanded ? <ChevronDown className="w-3 h-3" /> : <ChevronRight className="w-3 h-3" />}
                          Key Metrics
                        </td>
                      </tr>
                      {isMetricsExpanded && metricKeys.map(metricKey => (
                        <tr key={metricKey} className="bg-white dark:bg-gray-800 hover:bg-gray-50 dark:hover:bg-gray-700/50">
                          <td className="px-4 py-1.5 text-gray-500 dark:text-gray-400 pl-8">
                            {metricKey === 'best_score'
                              ? `Best Score (${formatMetricName(getJobScoringMetric(selectedJobs[0])) || 'CV'})`
                              : metricKey.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase())}
                          </td>
                          {selectedJobs.map(job => {
                             const m = (job.metrics || job.result?.metrics || {}) as Record<string, unknown>;
                             const val = m[metricKey];
                             return (
                                <td key={job.job_id} className="px-4 py-1.5 font-mono text-gray-600 dark:text-gray-300">
                                  {typeof val === 'number' ? (metricKey.endsWith('_std') ? val.toFixed(6) : val.toFixed(4)) : '-'}
                                </td>
                             );
                          })}
                        </tr>
                      ))}
                      {/* Hyperparameters (actual model params only) */}
                      <tr 
                        className="bg-gray-50/50 dark:bg-gray-900/20 cursor-pointer hover:bg-gray-100 dark:hover:bg-gray-800/50 transition-colors"
                        onClick={() => { setIsParamsExpanded(!isParamsExpanded); }}
                      >
                        <td className="px-4 py-2 font-medium text-gray-900 dark:text-gray-100 flex items-center gap-2" colSpan={selectedJobs.length + 1}>
                          {isParamsExpanded ? <ChevronDown className="w-3 h-3" /> : <ChevronRight className="w-3 h-3" />}
                          Hyperparameters
                        </td>
                      </tr>
                      {/* Extract actual model hyperparameters: best_params for advanced, nested hyperparameters for basic */}
                      {isParamsExpanded && (() => {
                        const getModelParams = (job: any): Record<string, any> => {
                          const hp = job.hyperparameters as Record<string, any> | undefined;
                          if (!hp) return {};
                          if (job.job_type === 'advanced_tuning') {
                            // For advanced tuning, hyperparameters IS the best_params (or search_space) directly
                            return hp;
                          }
                          // Basic training: extract the nested 'hyperparameters' dict (actual model params)
                          const nested = hp.hyperparameters;
                          if (nested && typeof nested === 'object' && !Array.isArray(nested)) {
                            return nested as Record<string, any>;
                          }
                          return {};
                        };
                        const allKeys = Array.from(new Set(selectedJobs.flatMap(job => Object.keys(getModelParams(job)))));
                        if (allKeys.length === 0) {
                          return (
                            <tr className="bg-white dark:bg-gray-800">
                              <td className="px-4 py-1.5 text-gray-400 dark:text-gray-500 pl-8 italic" colSpan={selectedJobs.length + 1}>
                                Default parameters (none customized)
                              </td>
                            </tr>
                          );
                        }
                        return allKeys.map(paramKey => (
                          <tr key={paramKey} className="bg-white dark:bg-gray-800 hover:bg-gray-50 dark:hover:bg-gray-700/50">
                            <td className="px-4 py-1.5 text-gray-500 dark:text-gray-400 pl-8">{paramKey}</td>
                            {selectedJobs.map(job => {
                              const params = getModelParams(job);
                              const val = params[paramKey];
                              return (
                                <td key={job.job_id} className="px-4 py-1.5 font-mono text-gray-600 dark:text-gray-300">
                                  {val === undefined ? '-' : typeof val === 'object' ? JSON.stringify(val) : String(val)}
                                </td>
                              );
                            })}
                          </tr>
                        ));
                      })()}

                      {/* Training Configuration */}
                      <tr 
                        className="bg-gray-50/50 dark:bg-gray-900/20 cursor-pointer hover:bg-gray-100 dark:hover:bg-gray-800/50 transition-colors"
                        onClick={() => { setIsTuningExpanded(!isTuningExpanded); }}
                      >
                        <td className="px-4 py-2 font-medium text-gray-900 dark:text-gray-100 flex items-center gap-2" colSpan={selectedJobs.length + 1}>
                          {isTuningExpanded ? <ChevronDown className="w-3 h-3" /> : <ChevronRight className="w-3 h-3" />}
                          Training Configuration
                        </td>
                      </tr>
                      {isTuningExpanded && (
                        <>
                          {['Target Column', 'CV Enabled', 'CV Method', 'CV Folds', 'CV Shuffle', 'CV Random State', ...(selectedJobs.some(j => j.job_type === 'advanced_tuning') ? ['Strategy', 'Strategy Params', 'Metric', 'Trials'] : [])].map(field => (
                            <tr key={field} className="bg-white dark:bg-gray-800 hover:bg-gray-50 dark:hover:bg-gray-700/50">
                              <td className="px-4 py-1.5 text-gray-500 dark:text-gray-400 pl-8">{field}</td>
                              {selectedJobs.map(job => {
                                // Resolve config: for advanced tuning use job.config or graph node params,
                                // for basic training use job.hyperparameters (which contains full node params)
                                let cfg: Record<string, any> | null = null;
                                if (job.job_type === 'advanced_tuning') {
                                  const nodeParams = (job.config as Record<string, any>) || 
                                    (job.graph?.nodes as any[])?.find((n: any) => n.node_id === job.node_id)?.params;
                                  cfg = nodeParams || null;
                                } else {
                                  cfg = (job.hyperparameters as Record<string, any>) || 
                                    (job.graph?.nodes as any[])?.find((n: any) => n.node_id === job.node_id)?.params || null;
                                }

                                if (!cfg) {
                                  return <td key={job.job_id} className="px-4 py-1.5 text-gray-400">-</td>;
                                }

                                // For advanced tuning, CV params are inside tuning_config
                                const tuningConfig = cfg.tuning_config as Record<string, any> | undefined;
                                const cvSource = job.job_type === 'advanced_tuning' && tuningConfig ? tuningConfig : cfg;

                                let value: string | number = '-';
                                if (field === 'Target Column') value = cfg.target_column || job.target_column || '-';
                                if (field === 'CV Enabled') value = cvSource.cv_enabled ? 'Yes' : 'No';
                                if (field === 'CV Method') value = cvSource.cv_enabled ? (cvSource.cv_type || 'Unknown') : '-';
                                if (field === 'CV Folds') value = cvSource.cv_enabled ? (cvSource.cv_folds ?? '-') : '-';
                                if (field === 'CV Shuffle') value = cvSource.cv_enabled ? (cvSource.cv_shuffle ? 'Yes' : 'No') : '-';
                                if (field === 'CV Random State') value = cvSource.cv_enabled ? (cvSource.cv_random_state ?? '-') : '-';
                                if (field === 'Strategy') value = tuningConfig?.strategy || tuningConfig?.search_strategy || '-';
                                if (field === 'Strategy Params') value = tuningConfig?.strategy_params && Object.keys(tuningConfig.strategy_params).length > 0 ? JSON.stringify(tuningConfig.strategy_params) : '-';
                                if (field === 'Metric') value = tuningConfig?.metric || '-';
                                if (field === 'Trials') value = tuningConfig?.n_trials || '-';

                                return (
                                  <td key={job.job_id} className="px-4 py-1.5 font-mono text-gray-600 dark:text-gray-300 capitalize">
                                    {value}
                                  </td>
                                );
                              })}
                            </tr>
                          ))}
                        </>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
              )}

              {/* Evaluation View */}
              {activeView === 'evaluation' && (
                <div className="space-y-6 animate-in fade-in duration-300">
                    {/* Job Selector if multiple */}
                    {selectedJobIds.length > 1 && (
                        <div className="flex gap-2 overflow-x-auto pb-2">
                            {selectedJobIds.map(id => (
                                <button
                                    key={id}
                                    onClick={() => { void fetchEvaluationData(id); }}
                                    className={`px-3 py-1 text-xs font-mono rounded border whitespace-nowrap ${
                                        evalJobId === id 
                                            ? 'bg-blue-100 border-blue-300 text-blue-700 dark:bg-blue-900/30 dark:border-blue-700 dark:text-blue-300'
                                            : 'bg-white border-gray-200 text-gray-600 dark:bg-gray-800 dark:border-gray-700 dark:text-gray-400'
                                    }`}
                                >
                                    {id}
                                </button>
                            ))}
                        </div>
                    )}

                    {isEvalLoading ? (
                        <div className="h-64 flex items-center justify-center">
                            <LoadingState message="Loading evaluation data..." />
                        </div>
                    ) : evalError ? (
                        <div className="h-64 flex items-center justify-center">
                            <ErrorState error={evalError} />
                        </div>
                    ) : !evaluationData ? (
                        <div className="h-64 flex items-center justify-center text-gray-400 italic text-center">
                            <p>Select a completed job to view evaluation details.</p>
                            <p className="text-xs mt-2 opacity-70">(Note: Only jobs run after this update have evaluation artifacts)</p>
                        </div>
                    ) : (
                        <div className="space-y-6">
                            {/* Controls for Evaluation View */}
                            <div className="flex flex-col gap-2 bg-white dark:bg-gray-800 p-4 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700">
                                <div className="flex justify-between items-center">
                                    <div className="flex gap-4 text-sm">
                                        <label className="flex items-center gap-2 cursor-pointer">
                                            <input
                                                type="checkbox"
                                                checked={showTrainMetrics}
                                                onChange={e => { setShowTrainMetrics(e.target.checked); }}
                                                className="rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                                            />
                                            <span className="text-gray-700 dark:text-gray-300">Train</span>
                                        </label>
                                        <label className="flex items-center gap-2 cursor-pointer">
                                            <input
                                                type="checkbox"
                                                checked={showTestMetrics}
                                                onChange={e => { setShowTestMetrics(e.target.checked); }}
                                                className="rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                                            />
                                            <span className="text-gray-700 dark:text-gray-300">Test</span>
                                        </label>
                                        <label className="flex items-center gap-2 cursor-pointer">
                                            <input
                                                type="checkbox"
                                                checked={showValMetrics}
                                                onChange={e => { setShowValMetrics(e.target.checked); }}
                                                className="rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                                            />
                                            <span className="text-gray-700 dark:text-gray-300">Validation</span>
                                        </label>
                                        <label className="flex items-center gap-2 cursor-pointer">
                                            <input
                                                type="checkbox"
                                                checked={showCvMetrics}
                                                onChange={e => { setShowCvMetrics(e.target.checked); }}
                                                className="rounded border-gray-300 text-purple-600 focus:ring-purple-500"
                                            />
                                            <span className="text-gray-700 dark:text-gray-300">Cross-Validation</span>
                                        </label>
                                    </div>

                                    {evaluationData.problem_type === 'classification' && evaluationData.splits.train?.y_proba && (() => {
                                        const proba = evaluationData.splits.train.y_proba!;
                                        return (
                                            <div className="flex items-center gap-2">
                                                <span className="text-sm text-gray-500 dark:text-gray-400">Target Class (ROC):</span>
                                                <select
                                                    className="bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-600 text-gray-900 dark:text-gray-100 text-sm rounded-lg focus:ring-blue-500 focus:border-blue-500 block p-1.5"
                                                    value={selectedRocClass || ''}
                                                    onChange={(e) => { setSelectedRocClass(e.target.value); }}
                                                >
                                                    {proba.classes.map((c: string | number, idx: number) => {
                                                        const label = proba.labels?.[idx] ?? c;
                                                        return (
                                                            <option key={String(c)} value={String(label)}>{String(label)}</option>
                                                        );
                                                    })}
                                                </select>
                                            </div>
                                        );
                                    })()}
                                </div>

                                {evaluationData.problem_type === 'classification' && evaluationData.splits.train?.y_proba?.labels && (() => {
                                    const proba = evaluationData.splits.train.y_proba!;
                                    return (
                                        <div className="w-full text-xs text-gray-500 dark:text-gray-400">
                                            Mapping: {proba.classes.map((c, idx) => `${String(c)}→${String(proba.labels?.[idx] ?? c)}`).join(', ')}
                                        </div>
                                    );
                                })()}
                            </div>

                            <div className="flex flex-col gap-6">
                            {/* Render charts for each split */}
                            {Object.entries(evaluationData.splits)
                                .filter(([splitName]) => {
                                    if (splitName === 'train' && !showTrainMetrics) return false;
                                    if (splitName === 'test' && !showTestMetrics) return false;
                                    if (splitName === 'validation' && !showValMetrics) return false;
                                    return true;
                                })
                                .map(([splitName, splitData]: [string, EvaluationSplit]) => {
                                const data = splitData.y_true.map((y: unknown, i: number) => ({
                                    x: y,
                                    y: splitData.y_pred[i]
                                }));
                                
                                return (
                                    <div key={splitName} className="bg-white dark:bg-gray-800 p-4 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700">
                                        <h4 className="text-sm font-medium text-gray-700 dark:text-gray-300 mb-4 capitalize">{splitName} Set</h4>
                                        
                                        {evaluationData.problem_type === 'regression' ? (
                                            <div className="grid grid-cols-1 gap-8">
                                                {/* Scatter Plot: Actual vs Predicted */}
                                                <div className="h-[300px] relative group" id={`${splitName}-actual-pred`}>
                                                    <div className="absolute top-0 right-0 z-10 opacity-0 group-hover:opacity-100 transition-opacity" data-export-ignore="true">
                                                       <button 
                                                         onClick={() => void handleDownload(`${splitName}-actual-pred`, `${splitName}_actual_vs_predicted`)}
                                                         disabled={downloadingChart === `${splitName}-actual-pred`}
                                                         className="p-1.5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600 rounded shadow-sm text-gray-500 hover:text-blue-600 disabled:opacity-50"
                                                         title="Download Graph"
                                                       >
                                                          {downloadingChart === `${splitName}-actual-pred` ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : doneChart === `${splitName}-actual-pred` ? <Check className="w-3.5 h-3.5 text-green-500" /> : <Download className="w-3.5 h-3.5" />}
                                                       </button>
                                                    </div>
                                                    <h5 className="text-xs font-medium text-gray-500 dark:text-gray-400 mb-2 text-center">Actual vs Predicted</h5>
                                                    <ResponsiveContainer width="100%" height="100%">
                                                        <ScatterChart margin={{ top: 20, right: 30, bottom: 40, left: 30 }}>
                                                            <CartesianGrid strokeDasharray="3 3" opacity={0.2} />
                                                            <XAxis 
                                                                type="number" 
                                                                dataKey="x" 
                                                                name="Actual" 
                                                                unit="" 
                                                                label={{ value: 'Actual Values', position: 'bottom', offset: 0, fontSize: 12 }} 
                                                                tick={{ fontSize: 11 }}
                                                            />
                                                            <YAxis 
                                                                type="number" 
                                                                dataKey="y" 
                                                                name="Predicted" 
                                                                unit="" 
                                                                label={{ value: 'Predicted Values', angle: -90, position: 'insideLeft', style: { textAnchor: 'middle' }, fontSize: 12 }} 
                                                                tick={{ fontSize: 11 }}
                                                            />
                                                            <Tooltip 
                                                                cursor={{ strokeDasharray: '3 3' }}
                                                                content={({ active, payload }) => {
                                                                    if (active && payload && payload.length) {
                                                                        const data = payload[0].payload;
                                                                        return (
                                                                            <div className="bg-white dark:bg-gray-800 p-2 border border-gray-200 dark:border-gray-700 shadow-sm rounded text-xs">
                                                                                <p className="font-medium">Actual: {data.x.toFixed(4)}</p>
                                                                                <p className="font-medium">Predicted: {data.y.toFixed(4)}</p>
                                                                                <p className="text-gray-500">Error: {(data.y - data.x).toFixed(4)}</p>
                                                                            </div>
                                                                        );
                                                                    }
                                                                    return null;
                                                                }}
                                                            />
                                                            {/* Reference Line for Perfect Prediction (y=x) */}
                                                            <Line 
                                                                dataKey="x" 
                                                                stroke="#ccc" 
                                                                strokeDasharray="3 3" 
                                                                dot={false} 
                                                                activeDot={false} 
                                                                legendType="none"
                                                                isAnimationActive={false}
                                                            />
                                                            <Scatter name="Predictions" data={data} fill="#8884d8" fillOpacity={0.6} />
                                                        </ScatterChart>
                                                    </ResponsiveContainer>
                                                </div>

                                                {/* Residual Plot: Residuals vs Predicted */}
                                                <div className="h-[300px] relative group" id={`${splitName}-residuals`}>
                                                    <div className="absolute top-0 right-0 z-10 opacity-0 group-hover:opacity-100 transition-opacity" data-export-ignore="true">
                                                       <button 
                                                         onClick={() => void handleDownload(`${splitName}-residuals`, `${splitName}_residuals`)}
                                                         disabled={downloadingChart === `${splitName}-residuals`}
                                                         className="p-1.5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600 rounded shadow-sm text-gray-500 hover:text-blue-600 disabled:opacity-50"
                                                         title="Download Graph"
                                                       >
                                                          {downloadingChart === `${splitName}-residuals` ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : doneChart === `${splitName}-residuals` ? <Check className="w-3.5 h-3.5 text-green-500" /> : <Download className="w-3.5 h-3.5" />}
                                                       </button>
                                                    </div>
                                                    <h5 className="text-xs font-medium text-gray-500 dark:text-gray-400 mb-2 text-center">Residuals vs Predicted</h5>
                                                    <ResponsiveContainer width="100%" height="100%">
                                                        <ScatterChart margin={{ top: 20, right: 30, bottom: 40, left: 30 }}>
                                                            <CartesianGrid strokeDasharray="3 3" opacity={0.2} />
                                                            <XAxis 
                                                                type="number" 
                                                                dataKey="y" 
                                                                name="Predicted" 
                                                                unit="" 
                                                                label={{ value: 'Predicted Values', position: 'bottom', offset: 0, fontSize: 12 }} 
                                                                tick={{ fontSize: 11 }}
                                                            />
                                                            <YAxis 
                                                                type="number" 
                                                                dataKey="residual" 
                                                                name="Residual" 
                                                                unit="" 
                                                                label={{ value: 'Residuals (Actual - Predicted)', angle: -90, position: 'insideLeft', style: { textAnchor: 'middle' }, fontSize: 12 }} 
                                                                tick={{ fontSize: 11 }}
                                                            />
                                                            <Tooltip 
                                                                cursor={{ strokeDasharray: '3 3' }}
                                                                content={({ active, payload }) => {
                                                                    if (active && payload && payload.length) {
                                                                        const data = payload[0].payload;
                                                                        return (
                                                                            <div className="bg-white dark:bg-gray-800 p-2 border border-gray-200 dark:border-gray-700 shadow-sm rounded text-xs">
                                                                                <p className="font-medium">Predicted: {data.y.toFixed(4)}</p>
                                                                                <p className="font-medium">Residual: {data.residual.toFixed(4)}</p>
                                                                            </div>
                                                                        );
                                                                    }
                                                                    return null;
                                                                }}
                                                            />
                                                            {/* Zero Line */}
                                                            <ReferenceLine y={0} stroke="#ccc" strokeDasharray="3 3" />
                                                            <Scatter 
                                                                name="Residuals" 
                                                                data={data.map((d: unknown) => {
                                                                    const val = d as { x: number; y: number };
                                                                    return { ...val, residual: val.x - val.y };
                                                                })} 
                                                                fill="#82ca9d" 
                                                                fillOpacity={0.6} 
                                                            />
                                                        </ScatterChart>
                                                    </ResponsiveContainer>
                                                </div>
                                            </div>
                                        ) : (
                                            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                                                {/* Confusion Matrix */}
                                                <div className="h-[300px] flex flex-col items-center justify-center relative group" id={`${splitName}-confusion-matrix`}>
                                                    <div className="absolute top-0 right-0 z-10 opacity-0 group-hover:opacity-100 transition-opacity" data-export-ignore="true">
                                                       <button 
                                                         onClick={() => void handleDownload(`${splitName}-confusion-matrix`, `${splitName}_confusion_matrix`)}
                                                         disabled={downloadingChart === `${splitName}-confusion-matrix`}
                                                         className="p-1.5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600 rounded shadow-sm text-gray-500 hover:text-blue-600 disabled:opacity-50"
                                                         title="Download Graph"
                                                       >
                                                          {downloadingChart === `${splitName}-confusion-matrix` ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : doneChart === `${splitName}-confusion-matrix` ? <Check className="w-3.5 h-3.5 text-green-500" /> : <Download className="w-3.5 h-3.5" />}
                                                       </button>
                                                    </div>
                                                    {(() => {
                                                        const proba = splitData.y_proba;
                                                        const classOrder = proba?.classes;

                                                        let yTrueForCm: (string | number)[] = splitData.y_true;
                                                        let yPredForCm: (string | number)[] = splitData.y_pred;
                                                        if (proba?.labels && proba.labels.length === proba.classes.length) {
                                                            const labelToClass = new Map<string, string | number>();
                                                            proba.labels.forEach((label, idx) => {
                                                                labelToClass.set(String(label), proba.classes[idx]);
                                                            });
                                                            yTrueForCm = splitData.y_true.map(y => labelToClass.get(String(y)) ?? y);
                                                            yPredForCm = splitData.y_pred.map(y => labelToClass.get(String(y)) ?? y);
                                                        }

                                                        const { classes, matrix } = calculateConfusionMatrix(yTrueForCm, yPredForCm, classOrder);
                                                        return (
                                                            <div className="flex flex-col items-center">
                                                                <div className="flex">
                                                                    <div className="w-8"></div> {/* Y-axis label spacer */}
                                                                    <div className="flex ml-2"> {/* Added margin-left to align with matrix */}
                                                                        {classes.map(c => (
                                                                            <div key={String(c)} className="w-16 text-center text-xs font-medium text-gray-500 dark:text-gray-400 pb-2">
                                                                                Pred {String(c)}
                                                                            </div>
                                                                        ))}
                                                                    </div>
                                                                </div>
                                                                <div className="flex">
                                                                    <div className="flex flex-col justify-center mr-2">
                                                                        {classes.map(c => (
                                                                            <div key={String(c)} className="h-16 flex items-center justify-end text-xs font-medium text-gray-500 dark:text-gray-400 pr-2">
                                                                                True {String(c)}
                                                                            </div>
                                                                        ))}
                                                                    </div>
                                                                    <div className="border border-gray-200 dark:border-gray-700">
                                                                        {matrix.map((row, i) => (
                                                                            <div key={i} className="flex">
                                                                                {row.map((count, j) => {
                                                                                    // Calculate intensity
                                                                                    const max = Math.max(...matrix.flat());
                                                                                    const intensity = max > 0 ? count / max : 0;
                                                                                    return (
                                                                                        <div 
                                                                                            key={j} 
                                                                                            className="w-16 h-16 flex items-center justify-center text-sm font-mono border border-gray-100 dark:border-gray-800"
                                                                                            style={{
                                                                                                backgroundColor: `rgba(59, 130, 246, ${intensity * 0.8 + 0.1})`, // Blue base
                                                                                                color: intensity > 0.5 ? 'white' : 'inherit'
                                                                                            }}
                                                                                            title={`True: ${classes[i]}, Pred: ${classes[j]}, Count: ${count}`}
                                                                                        >
                                                                                            {count}
                                                                                        </div>
                                                                                    );
                                                                                })}
                                                                            </div>
                                                                        ))}
                                                                    </div>
                                                                </div>
                                                                <div className="mt-4 text-xs text-gray-400">
                                                                    Confusion Matrix
                                                                </div>
                                                            </div>
                                                        );
                                                    })()}
                                                </div>

                                                {/* ROC Curve (if available) */}
                                                {splitData.y_proba && (
                                                    <div className="h-[300px] w-full relative group" id={`${splitName}-roc`}>
                                                        <div className="absolute top-0 right-0 z-10 opacity-0 group-hover:opacity-100 transition-opacity" data-export-ignore="true">
                                                           <button 
                                                             onClick={() => void handleDownload(`${splitName}-roc`, `${splitName}_roc_curve`)}
                                                             disabled={downloadingChart === `${splitName}-roc`}
                                                             className="p-1.5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600 rounded shadow-sm text-gray-500 hover:text-blue-600 disabled:opacity-50"
                                                             title="Download Graph"
                                                           >
                                                              {downloadingChart === `${splitName}-roc` ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : doneChart === `${splitName}-roc` ? <Check className="w-3.5 h-3.5 text-green-500" /> : <Download className="w-3.5 h-3.5" />}
                                                           </button>
                                                        </div>
                                                        <h5 className="text-xs font-medium text-gray-500 dark:text-gray-400 mb-2 text-center">ROC Curve</h5>
                                                        {(() => {
                                                            if (!selectedRocClass) return <div className="text-center text-xs text-gray-400">Select a class</div>;
                                                            const rocData = calculateROC(splitData.y_true, splitData.y_proba!, selectedRocClass);
                                                            if (!rocData) return <div className="text-center text-xs text-gray-400">ROC not available (multiclass or missing proba)</div>;
                                                            
                                                            return (
                                                                <ResponsiveContainer width="100%" height="100%">
                                                                    <LineChart data={rocData} margin={{ top: 5, right: 30, bottom: 40, left: 30 }}>
                                                                        <CartesianGrid strokeDasharray="3 3" opacity={0.1} />
                                                                        <XAxis type="number" dataKey="fpr" domain={[0, 1]} label={{ value: 'False Positive Rate', position: 'bottom', offset: 0, fontSize: 12 }} />
                                                                        <YAxis type="number" dataKey="tpr" domain={[0, 1]} label={{ value: 'True Positive Rate', angle: -90, position: 'left', fontSize: 12 }} />
                                                                        <Tooltip />
                                                                        <Line type="monotone" dataKey="tpr" stroke="#8884d8" dot={false} strokeWidth={2} />
                                                                        {/* Diagonal reference line */}
                                                                        <Line dataKey="fpr" stroke="#ccc" strokeDasharray="3 3" dot={false} />
                                                                    </LineChart>
                                                                </ResponsiveContainer>
                                                            );
                                                        })()}
                                                    </div>
                                                )}
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                        </div>
                    )}
                </div>
              )}

              {/* Feature Importance View */}
              {activeView === 'importance' && hasFeatureImportances && (
                <div className="space-y-6 animate-in fade-in duration-300">
                  <h3 className="text-lg font-medium text-gray-800 dark:text-gray-100">Feature Importance Comparison</h3>
                  {(() => {
                    // Collect all unique features across selected jobs
                    const allFeatures = new Set<string>();
                    featureImportancesByJob.forEach(j => {
                      if (j.importances) Object.keys(j.importances).forEach(f => allFeatures.add(f));
                    });

                    // Build chart data: each feature as a row, each job as a bar
                    const jobsWithData = featureImportancesByJob.filter(j => j.importances !== null);
                    if (jobsWithData.length === 0) return null;

                    // Rank features by average importance (descending), take top 15
                    const featureAvg = Array.from(allFeatures).map(f => {
                      let sum = 0;
                      let count = 0;
                      jobsWithData.forEach(j => {
                        const val = j.importances?.[f];
                        if (val !== undefined) { sum += val; count++; }
                      });
                      return { feature: f, avg: count > 0 ? sum / count : 0 };
                    });
                    featureAvg.sort((a, b) => b.avg - a.avg);
                    const topFeatures = featureAvg.slice(0, 15).map(f => f.feature);

                    const chartData = topFeatures.map(feature => {
                      const row: Record<string, string | number> = { feature };
                      jobsWithData.forEach(j => {
                        const shortId = j.jobId.slice(0, 8);
                        const label = j.modelType !== 'unknown' ? `${j.modelType} (${shortId})` : shortId;
                        row[label] = j.importances?.[feature] ?? 0;
                      });
                      return row;
                    });

                    const barColors = ['#8884d8', '#82ca9d', '#ffc658', '#ff7300', '#0088fe', '#00C49F', '#ff6b6b', '#4ecdc4'];
                    const barKeys = jobsWithData.map((j, _i) => {
                      const shortId = j.jobId.slice(0, 8);
                      return j.modelType !== 'unknown' ? `${j.modelType} (${shortId})` : shortId;
                    });

                    return (
                      <div className="bg-white dark:bg-gray-800 rounded-lg border border-gray-200 dark:border-gray-700 p-6 relative group" id="feature-importance-chart">
                        <div className="absolute top-4 right-4 z-10 opacity-0 group-hover:opacity-100 transition-opacity" data-export-ignore="true">
                          <button
                            onClick={() => void handleDownload('feature-importance-chart', 'feature_importance_comparison')}
                            disabled={downloadingChart === 'feature-importance-chart'}
                            className="p-1.5 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-600 rounded shadow-sm text-gray-500 hover:text-blue-600 disabled:opacity-50"
                            title="Download Graph"
                          >
                            {downloadingChart === 'feature-importance-chart' ? <Loader2 className="w-3.5 h-3.5 animate-spin" /> : doneChart === 'feature-importance-chart' ? <Check className="w-3.5 h-3.5 text-green-500" /> : <Download className="w-3.5 h-3.5" />}
                          </button>
                        </div>
                        <div className="h-[500px]">
                          <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={chartData} layout="vertical" margin={{ top: 5, right: 30, bottom: 5, left: 120 }}>
                              <CartesianGrid strokeDasharray="3 3" opacity={0.1} />
                              <XAxis type="number" tick={{ fontSize: 12 }} />
                              <YAxis type="category" dataKey="feature" tick={{ fontSize: 11 }} width={110} />
                              <Tooltip
                                contentStyle={{ backgroundColor: 'rgba(0,0,0,0.85)', border: 'none', borderRadius: '8px', color: '#fff' }}
                                formatter={(value: number) => value.toFixed(4)}
                              />
                              <Legend />
                              {barKeys.map((key, i) => (
                                <Bar key={key} dataKey={key} fill={barColors[i % barColors.length]} radius={[0, 4, 4, 0]} />
                              ))}
                            </BarChart>
                          </ResponsiveContainer>
                        </div>
                        {topFeatures.length < allFeatures.size && (
                          <p className="text-xs text-gray-400 dark:text-gray-500 mt-2 text-center">
                            Showing top {topFeatures.length} of {allFeatures.size} features
                          </p>
                        )}
                      </div>
                    );
                  })()}
                </div>
              )}

            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { useJobStore } from '../../core/store/useJobStore';
import { X, RefreshCw, CheckCircle, AlertCircle, Clock, ArrowLeft, Database, Terminal, Square, FileText, LayoutDashboard, ChevronDown, Zap, CheckCircle2, Search, Filter } from 'lucide-react';
import { JobInfo, jobsApi } from '../../core/api/jobs';
import { useEscapeKey } from '../../core/hooks/useEscapeKey';
import { formatMetricName } from '../../core/utils/format';

const formatMetricValue = (key: string, value: number): string => {
  if (key.endsWith('_std')) return value.toFixed(6);
  return value.toFixed(4);
};

/** Extract the scoring metric name from a job's result or config. */
const getScoringMetric = (job: JobInfo): string | undefined => {
  const result = job.result as Record<string, unknown> | undefined;
  if (result?.scoring_metric) return result.scoring_metric as string;
  const config = job.config as Record<string, unknown> | undefined;
  const tuning = config?.tuning_config as Record<string, unknown> | undefined;
  return tuning?.metric as string | undefined;
};

/** Renders feature_importances from result.metrics or result directly as a sorted bar table. */
const FeatureImportancesSection: React.FC<{ result: Record<string, unknown> }> = ({ result }) => {
  const metrics = result.metrics as Record<string, unknown> | undefined;
  const raw = (metrics?.feature_importances ?? result.feature_importances) as Record<string, number> | undefined;
  if (!raw || typeof raw !== 'object') return null;

  const sorted = Object.entries(raw).sort(([, a], [, b]) => b - a).slice(0, 5);
  if (sorted.length === 0) return null;
  const maxVal = sorted[0][1] || 1;

  return (
    <div className="space-y-2">
      <h4 className="text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">Feature Importances</h4>
      <div className="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg p-3 max-h-64 overflow-y-auto">
        {sorted.map(([feature, importance]) => (
          <div key={feature} className="flex items-center gap-2 py-1">
            <span className="text-xs text-gray-600 dark:text-gray-300 w-32 truncate shrink-0" title={feature}>{feature}</span>
            <div className="flex-1 h-4 bg-gray-100 dark:bg-gray-700 rounded overflow-hidden">
              <div
                className="h-full bg-blue-500 dark:bg-blue-400 rounded"
                style={{ width: `${(importance / maxVal) * 100}%` }}
              />
            </div>
            <span className="text-xs font-mono text-gray-500 dark:text-gray-400 w-14 text-right shrink-0">{importance.toFixed(4)}</span>
          </div>
        ))}
      </div>
    </div>
  );
};

export const JobsDrawer: React.FC = () => {
  const { 
    isDrawerOpen, 
    toggleDrawer, 
    jobs, 
    isLoading, 
    activeTab, 
    setTab,
    fetchJobs,
    hasMore,
    loadMoreJobs,
    activeParallelRun
  } = useJobStore();

  const [selectedJob, setSelectedJob] = useState<JobInfo | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [modelFilter, setModelFilter] = useState<string>('all');
  const [showFilters, setShowFilters] = useState(false);

  useEscapeKey(toggleDrawer, isDrawerOpen);

  // Reset to list view whenever the drawer re-opens
  useEffect(() => {
    if (isDrawerOpen) setSelectedJob(null);
  }, [isDrawerOpen]);

  if (!isDrawerOpen) return null;

  const tabJobs = jobs.filter(job => job.job_type === activeTab);
  
  // Derive unique model types and statuses from current tab's jobs
  const modelTypes = [...new Set(tabJobs.map(j => j.model_type).filter(Boolean))] as string[];
  const statuses = [...new Set(tabJobs.map(j => j.status))];

  const filteredJobs = tabJobs.filter(job => {
    if (statusFilter !== 'all' && job.status !== statusFilter) return false;
    if (modelFilter !== 'all' && job.model_type !== modelFilter) return false;
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      const matchesId = job.job_id.toLowerCase().includes(q);
      const matchesDataset = (job.dataset_name || job.dataset_id || '').toLowerCase().includes(q);
      const matchesModel = (job.model_type || '').toLowerCase().includes(q);
      if (!matchesId && !matchesDataset && !matchesModel) return false;
    }
    return true;
  });

  return (
    <div className="fixed inset-0 z-50 flex justify-center items-center">
      {/* Backdrop */}
      <div 
        className="absolute inset-0 bg-black/50 backdrop-blur-sm"
        onClick={() => toggleDrawer(false)}
      />
      
      {/* Modal Content */}
      <div className="relative w-[1200px] max-w-[95vw] h-[85vh] bg-white dark:bg-gray-800 shadow-2xl rounded-lg flex flex-col border border-gray-200 dark:border-gray-700 overflow-hidden transition-all">
        
        {selectedJob ? (
            <JobDetailsView job={selectedJob} onBack={() => { setSelectedJob(null); }} onClose={() => toggleDrawer(false)} />
        ) : (
            <>
                {/* Header */}
                <div className="p-4 border-b border-gray-100 dark:border-gray-700 flex justify-between items-center bg-gray-50 dark:bg-gray-800/50">
                <h2 className="font-semibold text-gray-800 dark:text-gray-100">Job History</h2>
                <div className="flex items-center gap-2">
                    <button 
                    onClick={() => fetchJobs()}
                    className={`p-1.5 rounded hover:bg-gray-200 dark:hover:bg-gray-700 text-gray-500 dark:text-gray-400 ${isLoading ? 'animate-spin' : ''}`}
                    title="Refresh"
                    >
                    <RefreshCw className="w-4 h-4" />
                    </button>
                    <button 
                    onClick={() => toggleDrawer(false)}
                    className="p-1.5 rounded hover:bg-gray-200 dark:hover:bg-gray-700 text-gray-500 dark:text-gray-400"
                    >
                    <X className="w-4 h-4" />
                    </button>
                </div>
                </div>

                {/* Parallel Run Progress Banner */}
                {activeParallelRun && (() => {
                  const total = activeParallelRun.jobIds.length;
                  const TERMINAL = new Set(['completed', 'failed', 'cancelled']);
                  const doneCount = activeParallelRun.jobIds.filter(id => {
                    const j = jobs.find(job => job.job_id === id);
                    return j && TERMINAL.has(j.status);
                  }).length;
                  const pct = Math.round((doneCount / total) * 100);
                  const isDone = doneCount === total;
                  return (
                    <div className={`px-4 py-2.5 border-b flex items-center gap-3 ${
                      isDone
                        ? 'bg-green-50 dark:bg-green-900/30 border-green-200 dark:border-green-700/50'
                        : 'bg-amber-50 dark:bg-amber-900/30 border-amber-200 dark:border-amber-700/50'
                    }`}>
                      {isDone
                        ? <CheckCircle2 className="w-4 h-4 text-green-600 dark:text-green-400 shrink-0" />
                        : <Zap className="w-4 h-4 text-amber-600 dark:text-amber-400 shrink-0" />
                      }
                      <span className={`text-sm font-medium ${
                        isDone
                          ? 'text-green-800 dark:text-green-200'
                          : 'text-amber-800 dark:text-amber-200'
                      }`}>
                        {isDone ? 'All branches complete!' : `Parallel Run: ${doneCount}/${total} branches complete`}
                      </span>
                      <div className={`flex-1 h-2 rounded-full overflow-hidden ${
                        isDone ? 'bg-green-200 dark:bg-green-800' : 'bg-amber-200 dark:bg-amber-800'
                      }`}>
                        <div
                          className={`h-full rounded-full transition-all duration-500 ${
                            isDone ? 'bg-green-500 dark:bg-green-400' : 'bg-amber-500 dark:bg-amber-400'
                          }`}
                          style={{ width: `${pct}%` }}
                        />
                      </div>
                      <span className={`text-xs font-mono shrink-0 ${
                        isDone ? 'text-green-600 dark:text-green-400' : 'text-amber-600 dark:text-amber-400'
                      }`}>{pct}%</span>
                    </div>
                  );
                })()}

                {/* Tabs */}
                <div className="flex border-b border-gray-200 dark:border-gray-700">
                <button
                    className={`flex-1 py-3 text-sm font-medium border-b-2 transition-colors ${
                    activeTab === 'advanced_tuning' 
                        ? 'border-purple-500 text-purple-600 dark:text-purple-400 bg-purple-50/50 dark:bg-purple-900/20' 
                        : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200'
                    }`}
                    onClick={() => setTab('advanced_tuning')}
                >
                    Advanced Training
                </button>
                <button
                    className={`flex-1 py-3 text-sm font-medium border-b-2 transition-colors ${
                    activeTab === 'basic_training' 
                        ? 'border-blue-500 text-blue-600 dark:text-blue-400 bg-blue-50/50 dark:bg-blue-900/20' 
                        : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200'
                    }`}
                    onClick={() => setTab('basic_training')}
                >
                    Standard Training
                </button>
                </div>

                {/* Filter Bar */}
                <div className="px-4 py-2 border-b border-gray-200 dark:border-gray-700 bg-white dark:bg-gray-800 space-y-2">
                  <div className="flex items-center gap-2">
                    <div className="relative flex-1">
                      <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3.5 h-3.5 text-gray-400 pointer-events-none z-10" />
                      <input
                        type="text"
                        placeholder="Search by job ID, dataset, or model..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="w-full pl-8 pr-3 py-1.5 text-xs bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-md focus:outline-none focus:ring-1 focus:ring-blue-500 text-gray-700 dark:text-gray-200 placeholder-gray-400"
                      />
                    </div>
                    <button
                      onClick={() => setShowFilters(!showFilters)}
                      className={`flex items-center gap-1.5 px-2.5 py-1.5 text-xs rounded-md border transition-colors ${
                        showFilters || statusFilter !== 'all' || modelFilter !== 'all'
                          ? 'bg-blue-50 dark:bg-blue-900/30 border-blue-300 dark:border-blue-700 text-blue-600 dark:text-blue-400'
                          : 'bg-gray-50 dark:bg-gray-900 border-gray-200 dark:border-gray-700 text-gray-500 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800'
                      }`}
                    >
                      <Filter className="w-3.5 h-3.5" />
                      Filters
                      {(statusFilter !== 'all' || modelFilter !== 'all') && (
                        <span className="w-4 h-4 flex items-center justify-center bg-blue-500 text-white rounded-full text-[10px] font-bold">
                          {(statusFilter !== 'all' ? 1 : 0) + (modelFilter !== 'all' ? 1 : 0)}
                        </span>
                      )}
                    </button>
                  </div>
                  {showFilters && (
                    <div className="flex items-center gap-3">
                      <div className="flex items-center gap-1.5">
                        <label className="text-[10px] font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">Status</label>
                        <select
                          value={statusFilter}
                          onChange={(e) => setStatusFilter(e.target.value)}
                          className="text-xs bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded px-2 py-1 text-gray-700 dark:text-gray-200 focus:outline-none focus:ring-1 focus:ring-blue-500"
                        >
                          <option value="all">All</option>
                          {statuses.map(s => (
                            <option key={s} value={s}>{s.charAt(0).toUpperCase() + s.slice(1)}</option>
                          ))}
                        </select>
                      </div>
                      <div className="flex items-center gap-1.5">
                        <label className="text-[10px] font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">Model</label>
                        <select
                          value={modelFilter}
                          onChange={(e) => setModelFilter(e.target.value)}
                          className="text-xs bg-gray-50 dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded px-2 py-1 text-gray-700 dark:text-gray-200 focus:outline-none focus:ring-1 focus:ring-blue-500"
                        >
                          <option value="all">All</option>
                          {modelTypes.map(m => (
                            <option key={m} value={m}>{m.replace(/_/g, ' ')}</option>
                          ))}
                        </select>
                      </div>
                      {(statusFilter !== 'all' || modelFilter !== 'all') && (
                        <button
                          onClick={() => { setStatusFilter('all'); setModelFilter('all'); }}
                          className="text-[10px] text-blue-500 hover:underline"
                        >
                          Clear all
                        </button>
                      )}
                    </div>
                  )}
                </div>

                {/* List Header */}
                <div className="grid grid-cols-12 gap-4 px-6 py-2 bg-gray-50 dark:bg-gray-900/50 border-b border-gray-200 dark:border-gray-700 text-xs font-medium text-gray-500 dark:text-gray-400">
                    <div className="col-span-2">Status</div>
                    <div className="col-span-2">Dataset / Model</div>
                    <div className="col-span-3">Job ID</div>
                    <div className="col-span-2">Started</div>
                    <div className="col-span-1">Duration</div>
                    <div className="col-span-2">Score</div>
                </div>

                {/* List */}
                <div className="flex-1 overflow-y-auto p-4 space-y-2 bg-gray-50/30 dark:bg-gray-900/30">
                {filteredJobs.length === 0 ? (
                    <div className="text-center py-10 text-gray-400 dark:text-gray-500 text-sm">
                    {searchQuery || statusFilter !== 'all' || modelFilter !== 'all'
                      ? 'No jobs match the current filters.'
                      : `No ${activeTab === 'advanced_tuning' ? 'advanced training' : 'training'} jobs found.`
                    }
                    </div>
                ) : (
                    <>
                        {filteredJobs.map(job => (
                            <JobRow key={job.job_id} job={job} onClick={() => { setSelectedJob(job); }} />
                        ))}
                        
                        {hasMore && (
                            <div className="flex justify-center pt-2 pb-4">
                                <button 
                                    onClick={() => loadMoreJobs()}
                                    disabled={isLoading}
                                    className="text-xs text-blue-600 dark:text-blue-400 hover:underline disabled:opacity-50 flex items-center gap-1"
                                >
                                    {isLoading ? <RefreshCw className="w-3 h-3 animate-spin" /> : <ChevronDown className="w-3 h-3" />}
                                    Load More History
                                </button>
                            </div>
                        )}
                    </>
                )}
                </div>
            </>
        )}
      </div>
    </div>
  );
};

const JobDetailsView: React.FC<{ job: JobInfo; onBack: () => void; onClose: () => void }> = ({ job: initialJob, onBack, onClose }) => {
    const { cancelJob } = useJobStore();
    const [job, setJob] = useState<JobInfo>(initialJob);
    const [activeTab, setActiveTab] = useState<'overview' | 'logs'>('overview');
    const [isCancelling, setIsCancelling] = useState(false);
    const logsEndRef = useRef<HTMLDivElement>(null);

    // Poll for updates if running
    useEffect(() => {
        let interval: ReturnType<typeof setInterval>;
        
        const fetchDetails = async () => {
            try {
                const updatedJob = await jobsApi.getJob(initialJob.job_id);
                setJob(updatedJob);
            } catch (e) {
                console.error("Failed to fetch job details", e);
            }
        };

        void fetchDetails(); // Initial fetch

        if (job.status === 'running' || job.status === 'queued') {
            interval = setInterval(() => { void fetchDetails(); }, 2000);
        }

        return () => {
            if (interval) clearInterval(interval);
        };
    }, [initialJob.job_id, job.status]);

    // Auto-scroll logs
    useEffect(() => {
        if (activeTab === 'logs' && logsEndRef.current) {
            logsEndRef.current.scrollIntoView({ behavior: 'smooth' });
        }
    }, [job.logs, activeTab]);

    const handleCancel = async () => {
        if (!confirm('Are you sure you want to stop this job?')) return;
        setIsCancelling(true);
        try {
            await cancelJob(job.job_id);
        } catch (e) {
            alert('Failed to cancel job');
        } finally {
            setIsCancelling(false);
        }
    };

    return (
        <div className="flex flex-col h-full">
            {/* Header */}
            <div className="p-4 border-b border-gray-100 dark:border-gray-700 flex justify-between items-center bg-gray-50 dark:bg-gray-800/50">
                <div className="flex items-center gap-3">
                    <button onClick={onBack} className="p-1 hover:bg-gray-200 dark:hover:bg-gray-700 rounded text-gray-500">
                        <ArrowLeft className="w-4 h-4" />
                    </button>
                    <div>
                        <h2 className="font-semibold text-gray-800 dark:text-gray-100 flex items-center gap-2">
                            Job Details
                            <span className="text-xs font-normal text-gray-500 font-mono bg-gray-100 dark:bg-gray-700 px-1.5 py-0.5 rounded">
                                {job.job_id.slice(0, 8)}
                            </span>
                        </h2>
                    </div>
                </div>
                <div className="flex items-center gap-2">
                    {(job.status === 'running' || job.status === 'queued') && (
                        <button 
                            onClick={() => { void handleCancel(); }}
                            disabled={isCancelling}
                            className="flex items-center gap-1 px-3 py-1.5 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 hover:bg-red-100 dark:hover:bg-red-900/40 rounded text-xs font-medium transition-colors border border-red-200 dark:border-red-800"
                        >
                            <Square className="w-3 h-3 fill-current" />
                            {isCancelling ? 'Stopping...' : 'Stop Job'}
                        </button>
                    )}
                    <button onClick={onClose} className="p-1.5 rounded hover:bg-gray-200 dark:hover:bg-gray-700 text-gray-500 dark:text-gray-400">
                        <X className="w-4 h-4" />
                    </button>
                </div>
            </div>

            {/* Tabs */}
            <div className="flex border-b border-gray-200 dark:border-gray-700 px-4">
                <button
                    className={`py-3 px-4 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${
                    activeTab === 'overview' 
                        ? 'border-blue-500 text-blue-600 dark:text-blue-400' 
                        : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200'
                    }`}
                    onClick={() => { setActiveTab('overview'); }}
                >
                    <LayoutDashboard className="w-4 h-4" />
                    Overview
                </button>
                <button
                    className={`py-3 px-4 text-sm font-medium border-b-2 transition-colors flex items-center gap-2 ${
                    activeTab === 'logs' 
                        ? 'border-blue-500 text-blue-600 dark:text-blue-400' 
                        : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700 dark:hover:text-gray-200'
                    }`}
                    onClick={() => { setActiveTab('logs'); }}
                >
                    <FileText className="w-4 h-4" />
                    Live Logs
                    {job.status === 'running' && <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />}
                </button>
            </div>

            <div className="flex-1 overflow-y-auto p-6">
                {activeTab === 'overview' ? (
                    <div className="space-y-6">
                        {/* Status Section */}
                        <div className="grid grid-cols-3 gap-4">
                            <div className="p-4 bg-gray-50 dark:bg-gray-900/50 rounded-lg border border-gray-100 dark:border-gray-700">
                                <div className="text-xs text-gray-500 dark:text-gray-400 mb-1">Status</div>
                                <div className="font-medium capitalize flex items-center gap-2 text-gray-800 dark:text-gray-200">
                                    {job.status}
                                </div>
                            </div>
                            <div className="p-4 bg-gray-50 dark:bg-gray-900/50 rounded-lg border border-gray-100 dark:border-gray-700">
                                <div className="text-xs text-gray-500 dark:text-gray-400 mb-1">Dataset</div>
                                <div className="font-medium text-gray-800 dark:text-gray-200 flex items-center gap-2">
                                    <Database className="w-3 h-3 text-gray-400" />
                                    {job.dataset_name || job.dataset_id || 'Unknown'}
                                </div>
                            </div>
                            <div className="p-4 bg-gray-50 dark:bg-gray-900/50 rounded-lg border border-gray-100 dark:border-gray-700">
                                <div className="text-xs text-gray-500 dark:text-gray-400 mb-1">Duration</div>
                                <div className="font-medium text-gray-800 dark:text-gray-200 font-mono">
                                    {job.start_time && job.end_time 
                                        ? `${Math.round((new Date(job.end_time).getTime() - new Date(job.start_time).getTime()) / 1000)}s` 
                                        : '-'}
                                </div>
                            </div>
                        </div>

                        {/* Error Section */}
                        {job.error && (
                            <div className="p-4 bg-red-50 dark:bg-red-900/20 border border-red-100 dark:border-red-900/30 rounded-lg">
                                <h3 className="text-sm font-medium text-red-800 dark:text-red-300 mb-2 flex items-center gap-2">
                                    <AlertCircle className="w-4 h-4" />
                                    Error Log
                                </h3>
                                <pre className="text-xs text-red-700 dark:text-red-400 whitespace-pre-wrap font-mono">
                                    {job.error}
                                </pre>
                            </div>
                        )}

                        {/* Results Section */}
                        {job.result && (
                            <div className="space-y-4">
                                <div className="flex items-center justify-between">
                                    <h3 className="text-sm font-medium text-gray-800 dark:text-gray-200 flex items-center gap-2">
                                        <Terminal className="w-4 h-4" />
                                        Execution Results
                                    </h3>
                                    {job.status === 'completed' && (
                                        <span className="text-xs px-2 py-1 bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400 rounded-full flex items-center gap-1 border border-green-200 dark:border-green-800 font-medium">
                                            <CheckCircle className="w-3 h-3" /> Model Ready
                                        </span>
                                    )}
                                </div>
                                
                                {job.job_type === 'basic_training' && !!(job.result as Record<string, unknown>).metrics && (
                                    <div className="space-y-4">
                                        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                                            {Object.entries((job.result as Record<string, unknown>).metrics as Record<string, unknown>)
                                                .filter(([, v]) => typeof v === 'number' || typeof v === 'string')
                                                .map(([k, v]) => (
                                                <div key={k} className={`p-3 border rounded-lg ${k.startsWith('cv_') ? 'bg-purple-50 dark:bg-purple-900/20 border-purple-200 dark:border-purple-800' : 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700'}`}>
                                                    <div className="text-xs text-gray-500 dark:text-gray-400 mb-1 capitalize">{k.replace(/_/g, ' ')}</div>
                                                    <div className={`font-mono font-medium ${k.startsWith('cv_') ? 'text-purple-600 dark:text-purple-400' : 'text-blue-600 dark:text-blue-400'}`}>
                                                        {typeof v === 'number' ? formatMetricValue(k, v) : String(v)}
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                        <FeatureImportancesSection result={job.result as Record<string, unknown>} />
                                    </div>
                                )}

                                {job.job_type === 'advanced_tuning' && (
                                    <div className="space-y-4">
                                        {/* Tuning Configuration */}
                                        {job.graph && (
                                            <div className="p-4 bg-gray-50 dark:bg-gray-900/50 rounded-lg border border-gray-100 dark:border-gray-700">
                                                <h4 className="text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-3">Tuning Configuration</h4>
                                                <div className="grid grid-cols-2 gap-4 text-xs">
                                                    {(() => {
                                                        const node = (job.graph?.nodes as any[])?.find((n: any) => n.node_id === job.node_id);
                                                        const config = Object.keys((job.config as any)?.tuning_config || {}).length > 0 
                                                            ? (job.config as any)?.tuning_config 
                                                            : node?.params?.tuning_config;
                                                        if (!config) return <div className="text-gray-400 col-span-2">No configuration found</div>;
                                                        
                                                        return (
                                                            <>
                                                                <div>
                                                                    <span className="text-gray-500">Strategy:</span>
                                                                    <span className="ml-2 font-mono text-gray-700 dark:text-gray-300 capitalize">{config.strategy || config.search_strategy || '-'}</span>
                                                                </div>
                                                                <div>
                                                                    <span className="text-gray-500">Strategy Params:</span>
                                                                    <span className="ml-2 font-mono text-gray-700 dark:text-gray-300">
                                                                        {config.strategy_params && Object.keys(config.strategy_params).length > 0 ? JSON.stringify(config.strategy_params) : '-'}
                                                                    </span>
                                                                </div>
                                                                <div>
                                                                    <span className="text-gray-500">Metric:</span>
                                                                    <span className="ml-2 font-mono text-gray-700 dark:text-gray-300">{config.metric || '-'}</span>
                                                                </div>
                                                                <div>
                                                                    <span className="text-gray-500">Trials:</span>
                                                                    <span className="ml-2 font-mono text-gray-700 dark:text-gray-300">{config.n_trials || '-'}</span>
                                                                </div>
                                                                <div>
                                                                    <span className="text-gray-500">CV Enabled:</span>
                                                                    <span className="ml-2 font-mono text-gray-700 dark:text-gray-300">{config.cv_enabled ? 'Yes' : 'No'}</span>
                                                                </div>
                                                                {config.cv_enabled && (
                                                                    <>
                                                                        <div>
                                                                            <span className="text-gray-500">CV Method:</span>
                                                                            <span className="ml-2 font-mono text-gray-700 dark:text-gray-300">{config.cv_type || 'Unknown'}</span>
                                                                        </div>
                                                                        <div>
                                                                            <span className="text-gray-500">Folds:</span>
                                                                            <span className="ml-2 font-mono text-gray-700 dark:text-gray-300">{config.cv_folds}</span>
                                                                        </div>
                                                                        <div>
                                                                            <span className="text-gray-500">Shuffle:</span>
                                                                            <span className="ml-2 font-mono text-gray-700 dark:text-gray-300">{config.cv_shuffle ? 'Yes' : 'No'}</span>
                                                                        </div>
                                                                    </>
                                                                )}
                                                            </>
                                                        );
                                                    })()}
                                                </div>
                                            </div>
                                        )}

                                        {/* Best Score */}
                                        {(job.result as Record<string, unknown>).best_score !== undefined && (
                                            <div className="p-3 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg w-fit">
                                                <div className="text-xs text-gray-500 dark:text-gray-400 mb-1">
                                                    Best Score{getScoringMetric(job) ? ` (${formatMetricName(getScoringMetric(job))})` : ''}
                                                </div>
                                                <div className="font-mono font-bold text-lg text-purple-600 dark:text-purple-400">
                                                    {Number((job.result as Record<string, unknown>).best_score).toFixed(4)}
                                                </div>
                                            </div>
                                        )}

                                        {/* Full Metrics (Train/Test/Val) */}
                                        {!!(job.result as Record<string, unknown>).metrics && (
                                            <div className="space-y-2">
                                                <h4 className="text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">Evaluation Metrics</h4>
                                                <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
                                                    {Object.entries((job.result as Record<string, unknown>).metrics as Record<string, unknown>)
                                                        .filter(([k, v]) => !['best_score', 'best_params', 'trials'].includes(k) && (typeof v === 'number' || typeof v === 'string'))
                                                        .map(([k, v]) => (
                                                        <div key={k} className={`p-3 border rounded-lg ${k.startsWith('cv_') ? 'bg-purple-50 dark:bg-purple-900/20 border-purple-200 dark:border-purple-800' : 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700'}`}>
                                                            <div className="text-xs text-gray-500 dark:text-gray-400 mb-1 capitalize">{k.replace(/_/g, ' ')}</div>
                                                            <div className={`font-mono font-medium ${k.startsWith('cv_') ? 'text-purple-600 dark:text-purple-400' : 'text-blue-600 dark:text-blue-400'}`}>
                                                                {typeof v === 'number' ? formatMetricValue(k, v as number) : String(v)}
                                                            </div>
                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        )}

                            <FeatureImportancesSection result={job.result as Record<string, unknown>} />
                                        
                                        {/* Best Params */}
                                        {!!(job.result as Record<string, unknown>).best_params && (
                                            <div className="bg-gray-900 text-gray-100 p-4 rounded-lg font-mono text-xs overflow-x-auto">
                                                <div className="text-gray-500 mb-2"># Best Hyperparameters</div>
                                                <pre>{JSON.stringify((job.result as Record<string, unknown>).best_params, null, 2)}</pre>
                                            </div>
                                        )}
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                ) : (
                    <div className="bg-gray-900 rounded-lg p-4 min-h-[400px] font-mono text-xs text-gray-300 overflow-x-auto">
                        {job.logs && job.logs.length > 0 ? (
                            job.logs.map((log, i) => (
                                <div key={i} className="mb-1 border-b border-gray-800 pb-1 last:border-0">
                                    {log}
                                </div>
                            ))
                        ) : (
                            <div className="text-gray-500 italic">No logs available yet...</div>
                        )}
                        <div ref={logsEndRef} />
                    </div>
                )}
            </div>
        </div>
    );
};

const JobRow: React.FC<{ job: JobInfo; onClick: () => void }> = ({ job, onClick }) => {
  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'completed': 
      case 'succeeded':
        return <CheckCircle className="w-4 h-4 text-green-500 dark:text-green-400" />;
      case 'failed': return <AlertCircle className="w-4 h-4 text-red-500 dark:text-red-400" />;
      case 'running': return <RefreshCw className="w-4 h-4 text-blue-500 dark:text-blue-400 animate-spin" />;
      default: return <Clock className="w-4 h-4 text-gray-400 dark:text-gray-500" />;
    }
  };

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'completed': return 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 hover:bg-gray-50 dark:hover:bg-gray-700/50';
      case 'failed': return 'bg-red-50/30 dark:bg-red-900/10 border-red-100 dark:border-red-900/30 hover:bg-red-50/50 dark:hover:bg-red-900/20';
      case 'running': return 'bg-blue-50/30 dark:bg-blue-900/10 border-blue-100 dark:border-blue-900/30 hover:bg-blue-50/50 dark:hover:bg-blue-900/20';
      default: return 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700';
    }
  };

  const formatDate = (dateStr: string | null) => {
    if (!dateStr) return '-';
    return new Date(dateStr).toLocaleString(undefined, {
      month: 'short', day: 'numeric', hour: '2-digit', minute: '2-digit'
    });
  };

  const getDuration = (start: string | null, end: string | null) => {
      if (!start || !end) return '-';
      const diff = new Date(end).getTime() - new Date(start).getTime();
      const seconds = Math.floor(diff / 1000);
      if (seconds < 60) return `${seconds}s`;
      const minutes = Math.floor(seconds / 60);
      return `${minutes}m ${seconds % 60}s`;
  };

  return (
    <div 
        onClick={onClick}
        className={`grid grid-cols-12 gap-4 p-3 rounded-lg border text-sm items-center transition-colors cursor-pointer ${getStatusColor(job.status)}`}
    >
      {/* Status */}
      <div className="col-span-2 flex items-center gap-2">
        {getStatusIcon(job.status)}
        <span className="font-medium text-gray-700 dark:text-gray-300 capitalize truncate">
          {job.status}
        </span>
      </div>

      {/* Dataset & Model */}
      <div className="col-span-2 flex flex-col justify-center text-xs text-gray-600 dark:text-gray-400 truncate">
        <div className="flex items-center gap-1" title={job.dataset_name || job.dataset_id}>
            <Database className="w-3 h-3" />
            <span className="truncate">{job.dataset_name || job.dataset_id || '-'}</span>
        </div>
        <div className="flex items-center gap-1 mt-0.5 text-[10px] text-gray-500">
            <span className="font-medium truncate">{job.model_type || 'Unknown Model'}</span>
            {job.job_type === 'advanced_tuning' && job.search_strategy && (
                <span className="text-gray-400 truncate">({job.search_strategy})</span>
            )}
        </div>
      </div>

      {/* Job ID */}
      <div className="col-span-3 font-mono text-xs text-gray-500 dark:text-gray-400 break-all" title={job.job_id}>
        {job.job_id}
      </div>

      {/* Started */}
      <div className="col-span-2 text-gray-600 dark:text-gray-400 text-xs">
        {formatDate(job.start_time)}
      </div>

      {/* Duration */}
      <div className="col-span-1 text-gray-600 dark:text-gray-400 text-xs font-mono">
        {getDuration(job.start_time, job.end_time)}
      </div>

      {/* Score */}
      <div className="col-span-2 flex items-center gap-2">
        {job.error ? (
            <span className="text-red-600 dark:text-red-400 text-xs truncate" title={job.error}>
                Error
            </span>
        ) : job.status === 'completed' && job.result ? (
            job.job_type === 'basic_training' && !!(job.result as { metrics?: Record<string, unknown> }).metrics ? (
               <div className="flex flex-wrap gap-1">
                 {Object.entries((job.result as { metrics: Record<string, unknown> }).metrics).slice(0, 1).map(([k, v]) => (
                   <span key={k} className="text-[10px] bg-gray-100 dark:bg-gray-700 px-1.5 py-0.5 rounded text-gray-600 dark:text-gray-300 border border-gray-200 dark:border-gray-600">
                     {k}: {Number(v).toFixed(3)}
                   </span>
                 ))}
               </div>
            ) : job.job_type === 'advanced_tuning' ? (
               <div className="flex flex-wrap gap-1">
                 {(job.result as { best_score?: number }).best_score !== undefined && (
                   <span className="text-[10px] bg-purple-50 dark:bg-purple-900/20 px-1.5 py-0.5 rounded text-purple-700 dark:text-purple-300 border border-purple-200 dark:border-purple-800">
                     {formatMetricName(getScoringMetric(job)) || 'Score'}: {Number((job.result as { best_score?: number }).best_score).toFixed(4)}
                   </span>
                 )}
                 {!(job.result as Record<string, unknown>).best_score && !!(job.result as Record<string, unknown>).best_params && (
                   <span className="text-[10px] text-gray-500 dark:text-gray-400">Params found</span>
                 )}
               </div>
            ) : <span className="text-gray-400 text-xs">-</span>
        ) : (
            <span className="text-gray-400 text-xs">-</span>
        )}
      </div>
    </div>
  );
};

import React, { useEffect } from 'react';
import { X } from 'lucide-react';

export type ModalSize = 'sm' | 'md' | 'lg' | 'xl' | '2xl' | '3xl' | '4xl' | '5xl' | '6xl' | '7xl' | 'full';

const sizeClass: Record<ModalSize, string> = {
  sm: 'max-w-sm',
  md: 'max-w-md',
  lg: 'max-w-lg',
  xl: 'max-w-xl',
  '2xl': 'max-w-2xl',
  '3xl': 'max-w-3xl',
  '4xl': 'max-w-4xl',
  '5xl': 'max-w-5xl',
  '6xl': 'max-w-6xl',
  '7xl': 'max-w-7xl',
  full: 'max-w-[95vw]',
};

export interface ModalShellProps {
  isOpen: boolean;
  onClose: () => void;
  title?: React.ReactNode;
  /** Optional content rendered to the right of the title (e.g. action buttons). */
  headerExtra?: React.ReactNode;
  size?: ModalSize;
  /** Tailwind z-index class. Defaults to z-50. Use z-[100] for modals on top of other modals. */
  zIndex?: string;
  /** Click-outside dismisses by default. Set false to require explicit close (e.g. forms). */
  dismissOnBackdrop?: boolean;
  /** Escape dismisses by default. */
  dismissOnEscape?: boolean;
  /** Hide the X close button in the header. */
  hideCloseButton?: boolean;
  /** Override aria-labelledby. Defaults to a generated id when title is a string. */
  ariaLabelledBy?: string;
  className?: string;
  /** Body content. Wrapped in a flex-1 overflow-y-auto container by default. */
  children: React.ReactNode;
  /** Optional footer rendered outside the scrollable body. */
  footer?: React.ReactNode;
}

/**
 * Shared modal wrapper. Centralizes the backdrop, panel, header, close button,
 * Escape handling, and animate-in styles previously duplicated across ~8 modals.
 */
export const ModalShell: React.FC<ModalShellProps> = ({
  isOpen,
  onClose,
  title,
  headerExtra,
  size = '3xl',
  zIndex = 'z-50',
  dismissOnBackdrop = true,
  dismissOnEscape = true,
  hideCloseButton = false,
  ariaLabelledBy,
  className,
  children,
  footer,
}) => {
  useEffect(() => {
    if (!isOpen || !dismissOnEscape) return;
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    window.addEventListener('keydown', handler);
    return () => window.removeEventListener('keydown', handler);
  }, [isOpen, dismissOnEscape, onClose]);

  if (!isOpen) return null;

  const titleId = ariaLabelledBy ?? (typeof title === 'string' ? `modal-title-${title.replace(/\s+/g, '-').toLowerCase()}` : undefined);

  return (
    <div
      className={`fixed inset-0 ${zIndex} flex items-center justify-center bg-black/50 backdrop-blur-sm p-4`}
      onClick={(e) => {
        if (dismissOnBackdrop && e.target === e.currentTarget) onClose();
      }}
    >
      <div
        role="dialog"
        aria-modal="true"
        aria-labelledby={titleId}
        className={`bg-white dark:bg-slate-900 rounded-xl shadow-2xl w-full ${sizeClass[size]} max-h-[85vh] flex flex-col border border-slate-200 dark:border-slate-700 animate-in fade-in zoom-in-95 duration-200 ${className ?? ''}`}
      >
        {(title || !hideCloseButton || headerExtra) && (
          <div className="flex items-center justify-between gap-3 p-6 border-b border-slate-200 dark:border-slate-700">
            {title && (
              <h2 id={titleId} className="text-xl font-bold text-slate-900 dark:text-slate-100 flex-1 truncate">
                {title}
              </h2>
            )}
            <div className="flex items-center gap-2">
              {headerExtra}
              {!hideCloseButton && (
                <button
                  onClick={onClose}
                  className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-300 transition-colors rounded focus-ring"
                  aria-label="Close"
                  type="button"
                >
                  <X size={24} />
                </button>
              )}
            </div>
          </div>
        )}
        <div className="flex-1 overflow-y-auto">{children}</div>
        {footer && (
          <div className="border-t border-slate-200 dark:border-slate-700 p-4">{footer}</div>
        )}
      </div>
    </div>
  );
};

