                        className="rounded border-gray-300 text-blue-600 focus:ring-blue-500"
                        disabled={isLoadingDefs}
                   />
                   Customize
               </label>
           </div>
        </div>
        
        {!useCustomParams ? (
            <div className="text-center py-8 bg-gray-50 dark:bg-gray-900/50 rounded-lg border border-dashed border-gray-200 dark:border-gray-700">
                <p className="text-sm text-gray-500 dark:text-gray-400">
                    Using default hyperparameters.
                </p>
                <button
                    onClick={() => { setShowParamsModal(true); }}
                    className="mt-3 text-xs flex items-center gap-1.5 px-3 py-1.5 mx-auto bg-purple-50 dark:bg-purple-900/20 text-purple-600 dark:text-purple-400 rounded-md border border-purple-200 dark:border-purple-800 hover:bg-purple-100 dark:hover:bg-purple-900/40 transition-colors shadow-sm"
                >
                    <Download className="w-3 h-3" />
                    Load Best Params
                </button>
            </div>
        ) : (
            <div className="space-y-3">
              <div className="flex justify-end mb-2">
                   <button
                      onClick={() => { setShowParamsModal(true); }}
                      className="text-xs flex items-center gap-1.5 px-2 py-1 text-purple-600 dark:text-purple-400 hover:bg-purple-50 dark:hover:bg-purple-900/20 rounded transition-colors"
                    >
                      <Download className="w-3 h-3" />
                      Load Best
                   </button>
              </div>
              
              {isLoadingDefs ? (
                  <div className="flex justify-center py-4">
                      <Loader2 className="w-5 h-5 animate-spin text-blue-500" />
                  </div>
              ) : (
                  hyperparameters.map((param) => (
                    <div key={param.name} className="bg-gray-50 dark:bg-gray-800/50 border border-gray-200 dark:border-gray-700 rounded-lg p-3">
                      <div className="flex justify-between items-center mb-2">
                          <label className="block text-xs font-medium text-gray-700 dark:text-gray-300">
                            {param.label}
                          </label>
                          {param.description && <HelpTooltip text={param.description} />}
                      </div>
                      {param.type === 'select' ? (
                        <select
                          value={(config.hyperparameters[param.name] ?? param.default) as string | number | readonly string[] | undefined}
                          onChange={(e) => onChange({
                            ...config,
                            hyperparameters: { ...config.hyperparameters, [param.name]: e.target.value }
                          })}
                          className="w-full border border-gray-300 dark:border-gray-600 rounded-lg p-2 text-sm bg-white dark:bg-gray-800 dark:text-gray-100 focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none transition-all"
                        >
                          {param.options?.map((opt: { label: string; value: unknown }) => (
                            <option key={String(opt.value)} value={String(opt.value)}>{opt.label}</option>
                          ))}
                        </select>
                      ) : (
                        <HyperparameterInput
                          type={param.type}
                          value={config.hyperparameters[param.name] ?? param.default}
                          onChange={(val) => onChange({
                            ...config,
                            hyperparameters: { ...config.hyperparameters, [param.name]: val }
                          })}
                          step={param.step}
                          min={param.min}
                          max={param.max}
                        />
                      )}
                    </div>
                  ))
              )}
              {hyperparameters.length === 0 && !isLoadingDefs && (
                 <p className="text-sm text-gray-500 dark:text-gray-400 italic text-center py-4">
                   No parameters available.
                 </p>
              )}
            </div>
        )}
    </div>
  );

  return (
    <div className="flex flex-col h-full" ref={containerRef}>
      {showInfo && (
        <div className="mb-4 p-2 bg-blue-50 dark:bg-blue-900/20 border border-blue-100 dark:border-blue-800 rounded text-xs text-blue-700 dark:text-blue-300 flex justify-between items-start gap-2">
          <span>Train a model using fixed parameters or defaults.</span>
          <button 
            onClick={() => {
                setShowInfo(false);
                sessionStorage.setItem('hide_info_model_training', 'true');
            }} 
            className="text-blue-400 hover:text-blue-600 dark:hover:text-blue-200"
          >
            <X className="w-3 h-3" />
          </button>
        </div>
      )}

      <BestParamsModal 
        isOpen={showParamsModal} 
        onClose={() => { setShowParamsModal(false); }}
        modelType={config.model_type}
        availableModels={availableModels}
        onSelect={(result) => {
            // result contains { params, modelType }
            // If model type differs, we update it too
            const res = result as { modelType?: string; params: Record<string, unknown> };
            if (res.modelType && res.modelType !== config.model_type) {
                onChange({ 
                    ...config, 
                    model_type: res.modelType,
                    hyperparameters: res.params 
                });
            } else {
                onChange({ ...config, hyperparameters: res.params });
            }
        }}
      />
      
      {/* Mobile/Narrow Tabs */}
      {!isWide && (
        <div className="flex border-b border-gray-200 dark:border-gray-700 mb-4">
          <button
            className={`flex-1 py-2.5 text-xs font-medium text-center border-b-2 transition-colors ${
              activeTab === 'model' 
                ? 'border-blue-500 text-blue-600 dark:text-blue-400' 
                : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700'
            }`}
            onClick={() => { setActiveTab('model'); }}
          >
            Configuration
          </button>
          <button
            className={`flex-1 py-2.5 text-xs font-medium text-center border-b-2 transition-colors ${
              activeTab === 'params' 
                ? 'border-blue-500 text-blue-600 dark:text-blue-400' 
                : 'border-transparent text-gray-500 dark:text-gray-400 hover:text-gray-700'
            }`}
            onClick={() => { setActiveTab('params'); }}
          >
            Hyperparameters
          </button>
        </div>
      )}

      <div className="flex-1 overflow-y-auto px-1 pb-4 custom-scrollbar">
        {isWide ? (
            <div className="grid grid-cols-2 gap-6 h-full">
                <div className="overflow-y-auto pr-2">{ModelConfigSection}</div>
                <div className="overflow-y-auto pl-2 border-l border-gray-100 dark:border-gray-800">{HyperparametersSection}</div>
            </div>
        ) : (
            <>
                {activeTab === 'model' && ModelConfigSection}
                {activeTab === 'params' && HyperparametersSection}
            </>
        )}
      </div>

      {/* Footer */}
      <div className="pt-4 mt-auto border-t border-gray-100 dark:border-gray-700 flex flex-col gap-3 items-center">
        <button
          onClick={() => { void handleTrain(); }}
          className="w-full max-w-xs flex items-center justify-center gap-2 px-6 py-2.5 text-white rounded-lg shadow-lg transition-all hover:shadow-xl hover:-translate-y-0.5 active:translate-y-0"
          style={{ background: 'var(--main-gradient)' }}
        >
          <Play className="w-4 h-4 fill-current" />
          <span className="text-sm font-semibold">Start Training</span>
        </button>
      </div>
    </div>
  );
};

import React from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { Split } from 'lucide-react';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';
import { useGraphStore } from '../../../core/store/useGraphStore';
import { getIncomers } from '@xyflow/react';

interface FeatureTargetSplitConfig {
  target_column: string;
  datasetId?: string;
}

const FeatureTargetSplitSettings: React.FC<{ config: FeatureTargetSplitConfig; onChange: (c: FeatureTargetSplitConfig) => void; nodeId?: string }> = ({
  config,
  onChange,
  nodeId,
}) => {
  // Recursive search for datasetId
  const nodes = useGraphStore((state) => state.nodes);
  const edges = useGraphStore((state) => state.edges);

  const findUpstreamDatasetId = (currentNodeId: string): string | undefined => {
    const visited = new Set<string>();
    const queue = [currentNodeId];
    
    while (queue.length > 0) {
      const id = queue.shift();
      if (!id) continue;
      if (visited.has(id)) continue;
      visited.add(id);
      
      const node = nodes.find(n => n.id === id);
      if (!node) continue;
      
      // If this is NOT the current node, check if it has datasetId
      if (id !== currentNodeId && node.data?.datasetId) {
        return node.data.datasetId as string;
      }
      
      const incomers = getIncomers(node, nodes, edges);
      for (const incomer of incomers) {
        queue.push(incomer.id);
      }
    }
    return undefined;
  };

  const upstreamDatasetId = findUpstreamDatasetId(nodeId || '');

  React.useEffect(() => {
    if (upstreamDatasetId && config.datasetId !== upstreamDatasetId) {
      onChange({ ...config, datasetId: upstreamDatasetId });
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [upstreamDatasetId, config.datasetId, onChange]);

  const { data: schema } = useDatasetSchema(upstreamDatasetId || config.datasetId);
  const columns = schema ? Object.values(schema.columns).map(c => c.name) : [];

  return (
    <div className="p-4 space-y-4">
      <div className="space-y-2">
        <label className="text-sm font-medium">Target Column</label>
        <select
          className="w-full p-2 border rounded bg-background text-sm"
          value={config.target_column}
          onChange={(e) => onChange({ ...config, target_column: e.target.value })}
        >
          <option value="">-- Select Target --</option>
          {columns.map(col => (
            <option key={col} value={col}>{col}</option>
          ))}
        </select>
        <p className="text-xs text-muted-foreground">
          This column will be separated as the target (y), and all other columns will be features (X).
        </p>
      </div>
    </div>
  );
};

export const FeatureTargetSplitNode: NodeDefinition<FeatureTargetSplitConfig> = {
  type: 'feature_target_split',
  label: 'Feature-Target Split',
  category: 'Preprocessing',
  description: 'Separate features (X) from target (y).',
  icon: Split,
  inputs: [{ id: 'in', label: 'Data', type: 'dataset' }],
  outputs: [
    { id: 'X', label: 'Features (X)', type: 'dataset' },
    { id: 'y', label: 'Target (y)', type: 'dataset' }
  ],
  settings: FeatureTargetSplitSettings,
  validate: (config) => {
    if (!config.target_column) {
      return { isValid: false, message: 'Target column is required.' };
    }
    return { isValid: true };
  },
  getDefaultConfig: () => ({
    target_column: '',
  }),
};

import React from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { Split } from 'lucide-react';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';

interface TrainTestSplitConfig {
  test_size: number;
  validation_size?: number;
  random_state: number;
  stratify: boolean;
  shuffle: boolean;
  target_column?: string;
  datasetId?: string;
}

const TrainTestSplitSettings: React.FC<{ config: TrainTestSplitConfig; onChange: (c: TrainTestSplitConfig) => void; nodeId?: string }> = ({
  config,
  onChange,
  nodeId,
}) => {
  const upstreamData = useUpstreamData(nodeId || '');
  
  // Find datasetId from upstream data (injected by useUpstreamData hook)
  const upstreamDatasetId = upstreamData.find(d => d.datasetId)?.datasetId as string | undefined;
  
  // Check if an upstream node (like FeatureTargetSplitter) has already defined a target column
  const upstreamTargetColumn = upstreamData.find((d: Record<string, unknown>) => d.target_column)?.target_column as string | undefined;

  React.useEffect(() => {
    const updates: Partial<TrainTestSplitConfig> = {};
    
    // Propagate datasetId
    if (upstreamDatasetId && config.datasetId !== upstreamDatasetId) {
      updates.datasetId = upstreamDatasetId;
    }
    
    // Propagate target_column if upstream has it and we don't (or if we want to enforce it)
    if (upstreamTargetColumn && config.target_column !== upstreamTargetColumn) {
      updates.target_column = upstreamTargetColumn;
    }

    if (Object.keys(updates).length > 0) {
      onChange({ ...config, ...updates });
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [upstreamDatasetId, upstreamTargetColumn, config.datasetId, config.target_column, onChange]);

  const { data: schema, isLoading } = useDatasetSchema(upstreamDatasetId || config.datasetId);
  const columns = schema ? Object.values(schema.columns).map(c => c.name) : [];

  const valSize = config.validation_size || 0;
  const trainSize = 1 - config.test_size - valSize;

  // Responsive Layout Logic
  const containerRef = React.useRef<HTMLDivElement>(null);
  const [isWide, setIsWide] = React.useState(false);

  React.useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setIsWide(entry.contentRect.width > 450); // Switch to 2-column layout if wider than 450px
      }
    });
    observer.observe(containerRef.current);
    return () => { observer.disconnect(); };
  }, []);

  return (
    <div ref={containerRef} className={`flex flex-col h-full w-full bg-background ${isWide ? 'overflow-hidden' : 'overflow-y-auto'}`}>
      {/* Top Status Bar (Always Visible) */}
      <div className="shrink-0 p-4 pb-0 space-y-2">
        {!upstreamDatasetId && !config.datasetId && (
          <div className="p-2 bg-yellow-50 text-yellow-800 text-xs rounded border border-yellow-200">
            Connect a dataset node to see available columns.
          </div>
        )}
        
        {isLoading && (
          <div className="text-xs text-muted-foreground animate-pulse">
            Loading schema...
          </div>
        )}
      </div>

      {/* Main Content Area - Responsive Grid/Flex */}
      <div className={`flex-1 min-h-0 p-4 gap-4 ${isWide ? 'grid grid-cols-2' : 'flex flex-col'}`}>
        
        {/* Left Column: Split Ratios & Random State */}
        <div className={`space-y-4 ${isWide ? 'overflow-y-auto pr-2' : 'shrink-0'}`}>
          <div className="space-y-2">
            <label className="text-sm font-medium">Test Size (0.0 - 1.0)</label>
            <input
              type="number"
              step="0.05"
              min="0.05"
              max="0.95"
              className="w-full p-2 border rounded bg-background text-sm"
              value={config.test_size}
              onChange={(e) => onChange({ ...config, test_size: parseFloat(e.target.value) })}
            />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium">Validation Size (0.0 - 1.0)</label>
            <input
              type="number"
              step="0.05"
              min="0.00"
              max="0.95"
              className="w-full p-2 border rounded bg-background text-sm"
              value={valSize}
              onChange={(e) => onChange({ ...config, validation_size: parseFloat(e.target.value) })}
            />
            <p className="text-xs text-muted-foreground">
              {Math.round(trainSize * 100)}% Training, {Math.round(valSize * 100)}% Validation, {Math.round(config.test_size * 100)}% Testing
            </p>
            {trainSize <= 0 && (
              <p className="text-xs text-red-500 font-medium">
                Error: Total split size exceeds 100%
              </p>
            )}
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium">Random State</label>
            <input
              type="number"
              className="w-full p-2 border rounded bg-background text-sm"
              value={config.random_state}
              onChange={(e) => onChange({ ...config, random_state: parseInt(e.target.value) })}
            />
          </div>
        </div>

        {/* Right Column: Options & Stratification */}
        <div className={`space-y-4 ${isWide ? 'overflow-y-auto pl-2 border-l' : 'shrink-0 pt-4 border-t'}`}>
          <div className="flex items-center gap-2">
            <input
              type="checkbox"
              id="shuffle"
              checked={config.shuffle}
              onChange={(e) => onChange({ ...config, shuffle: e.target.checked })}
            />
            <label htmlFor="shuffle" className="text-sm font-medium">
              Shuffle Data
            </label>
          </div>

          <div className="flex items-center gap-2">
            <input
              type="checkbox"
              id="stratify"
              checked={config.stratify}
              onChange={(e) => onChange({ ...config, stratify: e.target.checked })}
            />
            <label htmlFor="stratify" className="text-sm font-medium">
              Stratify by Target
            </label>
          </div>

          <div className="space-y-2 pl-6 border-l-2 border-muted">
            <label className="text-sm font-medium">Target Column</label>
            <select
              className="w-full p-2 border rounded bg-background text-sm"
              value={config.target_column ?? ''}
              onChange={(e) => onChange({ ...config, target_column: e.target.value })}
              disabled={!config.stratify}
            >
              <option value="">-- Select Target --</option>
              {columns.map(col => (
                <option key={col} value={col}>{col}</option>
              ))}
            </select>
            <p className="text-xs text-muted-foreground">
              Required for stratification. If input is already separated (X, y), this is ignored.
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

export const TrainTestSplitNode: NodeDefinition<TrainTestSplitConfig> = {
  type: 'TrainTestSplitter', // Matches backend registry ID
  label: 'Train-Test Split',
  category: 'Preprocessing',
  description: 'Split data into training and testing sets.',
  icon: Split,
  inputs: [{ id: 'in', label: 'Data', type: 'dataset' }],
  outputs: [
    { id: 'train', label: 'Train', type: 'dataset' },
    { id: 'validation', label: 'Validation', type: 'dataset' },
    { id: 'test', label: 'Test', type: 'dataset' }
  ],
  settings: TrainTestSplitSettings,
  validate: (config) => {
    if (config.test_size <= 0 || config.test_size >= 1) {
      return { isValid: false, message: 'Test size must be between 0 and 1.' };
    }
    const valSize = config.validation_size || 0;
    if (valSize < 0 || valSize >= 1) {
      return { isValid: false, message: 'Validation size must be between 0 and 1.' };
    }
    if (config.test_size + valSize >= 1) {
      return { isValid: false, message: 'Sum of Test and Validation sizes must be less than 1.' };
    }
    return { isValid: true };
  },
  getDefaultConfig: () => ({
    test_size: 0.2,
    validation_size: 0.0,
    random_state: 42,
    stratify: false,
    shuffle: true,
  }),
};

import React, { useEffect, useState, useCallback } from 'react';
import { Activity, Loader2, Database, AlertCircle, RefreshCw, Check, X } from 'lucide-react';
import { jobsApi, JobInfo } from '../../../../core/api/jobs';
import { RegistryItem } from '../../../../core/api/registry';
import { formatMetricName } from '../../../../core/utils/format';

export interface BestParamsModalProps {
    isOpen: boolean;
    onClose: () => void;
    /** Initial model_type whose history to load. */
    modelType: string;
    /** Models offered in the dropdown selector. */
    availableModels?: RegistryItem[];
    /** When set, each row shows an "Apply" button; omit for read-only view. */
    onSelect?: (payload: { params: unknown; modelType: string }) => void;
    /** Color theme; matches the parent settings panel (Basic = blue, Advanced = purple). */
    theme?: 'blue' | 'purple';
}

/**
 * Shared "Best Parameters History" modal used by both BasicTrainingSettings
 * and AdvancedTuningSettings. Theme colors and the optional `onSelect` Apply
 * button are the only differences between the two callers.
 */
export const BestParamsModal: React.FC<BestParamsModalProps> = ({
    isOpen,
    onClose,
    modelType: initialModelType,
    availableModels = [],
    onSelect,
    theme = 'blue',
}) => {
    const [currentModelType, setCurrentModelType] = useState(initialModelType);
    const [jobs, setJobs] = useState<JobInfo[]>([]);
    const [isLoading, setIsLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const colors = theme === 'purple'
        ? { iconBg: 'bg-purple-100 dark:bg-purple-900/30', iconText: 'text-purple-600 dark:text-purple-400', spinner: 'text-purple-500', ring: 'focus:ring-purple-500', hoverBorder: 'hover:border-purple-200 dark:hover:border-purple-800' }
        : { iconBg: 'bg-blue-100 dark:bg-blue-900/30',     iconText: 'text-blue-600 dark:text-blue-400',     spinner: 'text-blue-500',     ring: 'focus:ring-blue-500',     hoverBorder: 'hover:border-blue-200 dark:hover:border-blue-800' };

    useEffect(() => {
        if (isOpen) setCurrentModelType(initialModelType);
    }, [isOpen, initialModelType]);

    const fetchJobs = useCallback(() => {
        if (!currentModelType) return;
        setIsLoading(true);
        setError(null);
        jobsApi.getTuningHistory(currentModelType)
            .then(data => { setJobs(data); })
            .catch(err => {
                console.error("Failed to fetch jobs", err);
                setError("Failed to load history.");
            })
            .finally(() => { setIsLoading(false); });
    }, [currentModelType]);

    useEffect(() => {
        if (isOpen) fetchJobs();
    }, [isOpen, fetchJobs]);

    if (!isOpen) return null;

    return (
        <div className="fixed inset-0 z-[100] flex justify-center items-center p-4">
            <div className="absolute inset-0 bg-black/50 backdrop-blur-sm" onClick={onClose} />
            <div className="relative w-full max-w-2xl max-h-[85vh] bg-white dark:bg-gray-800 shadow-2xl rounded-xl flex flex-col border border-gray-200 dark:border-gray-700 overflow-hidden animate-in fade-in zoom-in duration-200">
                <div className="p-4 border-b border-gray-100 dark:border-gray-700 flex justify-between items-center bg-gray-50/50 dark:bg-gray-800/50">
                    <div className="flex items-center gap-3">
                        <div className={`p-2 ${colors.iconBg} rounded-lg`}>
                            <Activity className={`w-5 h-5 ${colors.iconText}`} />
                        </div>
                        <div>
                            <h3 className="font-semibold text-gray-900 dark:text-gray-100">Best Parameters History</h3>
                            <div className="flex items-center gap-2 mt-1">
                                <span className="text-xs text-gray-500 dark:text-gray-400">
                                    {onSelect ? 'Select parameters for:' : 'View parameters for:'}
                                </span>
                                <select
                                    value={currentModelType}
                                    onChange={(e) => { setCurrentModelType(e.target.value); }}
                                    className={`text-xs border border-gray-200 dark:border-gray-700 rounded px-2 py-0.5 bg-white dark:bg-gray-800 text-gray-700 dark:text-gray-300 focus:ring-1 ${colors.ring} outline-none`}
                                >
                                    {availableModels.length > 0 ? (
                                        availableModels.map(model => (
                                            <option key={model.id} value={model.id}>{model.name}</option>
                                        ))
                                    ) : (
                                        <>
                                            <option value="random_forest_classifier">Random Forest Classifier</option>
                                            <option value="logistic_regression">Logistic Regression</option>
                                            <option value="ridge_regression">Ridge Regression</option>
                                            <option value="random_forest_regressor">Random Forest Regressor</option>
                                        </>
                                    )}
                                </select>
                            </div>
                        </div>
                    </div>
                    <div className="flex items-center gap-2">
                        <button
                            onClick={fetchJobs}
                            className="p-2 rounded-lg hover:bg-gray-200 dark:hover:bg-gray-700 text-gray-500 transition-colors"
                            title="Refresh"
                        >
                            <RefreshCw className={`w-4 h-4 ${isLoading ? 'animate-spin' : ''}`} />
                        </button>
                        <button onClick={onClose} className="p-2 rounded-lg hover:bg-gray-200 dark:hover:bg-gray-700 text-gray-500 transition-colors">
                            <X className="w-4 h-4" />
                        </button>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto p-4 space-y-3 bg-gray-50/30 dark:bg-gray-900/30">
                    {isLoading ? (
                        <div className="flex flex-col items-center justify-center py-12 text-gray-400">
                            <Loader2 className={`w-8 h-8 animate-spin mb-2 ${colors.spinner}`} />
                            <p className="text-sm">Loading history...</p>
                        </div>
                    ) : error ? (
                        <div className="text-center py-12 text-red-500 bg-red-50 dark:bg-red-900/10 rounded-lg border border-red-100 dark:border-red-900/20">
                            <AlertCircle className="w-8 h-8 mx-auto mb-2" />
                            <p className="text-sm">{error}</p>
                            <button onClick={fetchJobs} className="mt-2 text-xs underline hover:text-red-600">Try Again</button>
                        </div>
                    ) : jobs.length === 0 ? (
                        <div className="text-center py-12 text-gray-500 dark:text-gray-400 bg-white dark:bg-gray-800 rounded-lg border border-dashed border-gray-300 dark:border-gray-700">
                            <Database className="w-8 h-8 mx-auto mb-2 opacity-50" />
                            <p className="text-sm">No completed optimization jobs found.</p>
                            <p className="text-xs opacity-70 mt-1">Run an optimization job to see results here.</p>
                        </div>
                    ) : (
                        jobs.map(job => (
                            <div key={job.job_id} className={`group bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl p-4 hover:shadow-md ${colors.hoverBorder} transition-all`}>
                                <div className="flex justify-between items-start mb-3">
                                    <div className="space-y-1">
                                        <div className="flex items-center gap-2">
                                            <span className="text-xs font-mono bg-gray-100 dark:bg-gray-700 px-2 py-0.5 rounded text-gray-600 dark:text-gray-300">
                                                #{job.job_id.slice(0, 8)}
                                            </span>
                                            <span className="text-xs text-gray-400">
                                                {job.end_time ? new Date(job.end_time).toLocaleString() : 'Unknown Date'}
                                            </span>
                                        </div>
                                        <div className="flex items-center gap-3 mt-1">
                                            {typeof job.result?.best_score === 'number' && (
                                                <div className="flex items-center gap-1">
                                                    <span className="text-xs font-medium text-gray-500">
                                                        {formatMetricName((job.result as Record<string, unknown>).scoring_metric as string) || 'Score'}:
                                                    </span>
                                                    <span className="text-sm font-bold text-green-600 dark:text-green-400">
                                                        {job.result.best_score.toFixed(4)}
                                                    </span>
                                                </div>
                                            )}
                                            <span className="text-[10px] px-1.5 py-0.5 bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400 rounded-full flex items-center gap-1">
                                                <Check className="w-3 h-3" /> Model Ready
                                            </span>
                                        </div>
                                    </div>
                                    {onSelect && job.result?.best_params != null && (
                                        <button
                                            onClick={() => {
                                                onSelect({ params: job.result!.best_params, modelType: currentModelType });
                                                onClose();
                                            }}
                                            className="text-xs bg-blue-600 hover:bg-blue-700 text-white px-3 py-1.5 rounded-md transition-colors flex items-center gap-1 shadow-sm shadow-blue-500/20"
                                        >
                                            <Check className="w-3 h-3" />
                                            Apply
                                        </button>
                                    )}
                                </div>
                            </div>
                        ))
                    )}
                </div>
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Save, RotateCcw, HelpCircle } from 'lucide-react';
import { ModalShell } from '../../../../components/shared';

export interface StrategyConfig {
    // Halving
    factor?: number;
    min_resources?: string | number;
    resource?: string;

    // Optuna
    pruner?: 'median' | 'hyperband' | 'none';
    sampler?: 'tpe' | 'random' | 'cmaes';
    timeout?: number | '';
}

interface StrategySettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSave: (config: StrategyConfig) => void;
    strategy: string;
    initialConfig?: StrategyConfig;
}

const Tooltip: React.FC<{ text: string }> = ({ text }) => (
    <div className="group relative flex items-center">
        <HelpCircle className="w-3.5 h-3.5 text-gray-400 cursor-help" />
        <div className="absolute top-full mt-2 left-0 hidden group-hover:block w-56 p-2.5 bg-gray-900 text-white text-xs rounded-md shadow-xl z-[200]">
            {text}
            <div className="absolute bottom-full left-1 border-4 border-transparent border-b-gray-900" />
        </div>
    </div>
);

export const StrategySettingsModal: React.FC<StrategySettingsModalProps> = ({
    isOpen,
    onClose,
    onSave,
    strategy,
    initialConfig
}) => {
    const isHalving = strategy === 'halving_grid' || strategy === 'halving_random';
    const isOptuna = strategy === 'optuna';

    const defaultHalving: StrategyConfig = { factor: 3, min_resources: 'exhaust', resource: 'n_samples' };
    const defaultOptuna: StrategyConfig = { pruner: 'median', sampler: 'tpe', timeout: '' };

    const [config, setConfig] = useState<StrategyConfig>({});

    useEffect(() => {
        if (isOpen) {
            if (initialConfig && Object.keys(initialConfig).length > 0) {
                setConfig(initialConfig);
            } else {
                setConfig(isHalving ? defaultHalving : defaultOptuna);
            }
        }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [isOpen, strategy, initialConfig]);

    if (!isHalving && !isOptuna) return null;

    const handleSave = () => {
        const finalConfig = { ...config };
        if (isOptuna && (finalConfig.timeout === '' || finalConfig.timeout === undefined)) {
            delete finalConfig.timeout;
        } else if (isOptuna && typeof finalConfig.timeout === 'string') {
            finalConfig.timeout = parseInt(finalConfig.timeout, 10);
        }
        
        onSave(finalConfig);
        onClose();
    };

    const handleReset = () => {
        setConfig(isHalving ? defaultHalving : defaultOptuna);
    };

    return (
        <ModalShell
            isOpen={isOpen}
            onClose={onClose}
            zIndex="z-[100]"
            size="md"
            title={isHalving ? 'Successive Halving Settings' : 'Optuna Settings'}
            footer={
                <div className="flex justify-between gap-3">
                    <button
                        onClick={handleReset}
                        className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-gray-700 dark:text-gray-300 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700 transition"
                    >
                        <RotateCcw size={16} />
                        Reset
                    </button>

                    <button
                        onClick={handleSave}
                        className="flex items-center gap-2 px-4 py-2 text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 rounded-lg transition shadow-sm"
                    >
                        <Save size={16} />
                        Apply Settings
                    </button>
                </div>
            }
        >
            <div className="p-5 space-y-4">
                    {isHalving && (
                        <>
                            <div>
                                <div className="flex items-center gap-1.5 mb-1">
                                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
                                        Factor
                                    </label>
                                    <Tooltip text="The rate at which candidate combinations are reduced in each iteration. For example, a factor of 3 means only the best 1/3 of candidates survive to the next round." />
                                </div>
                                <input
                                    type="number"
                                    min="2"
                                    value={config.factor ?? 3}
                                    onChange={(e) => setConfig({ ...config, factor: parseInt(e.target.value, 10) })}
                                    className="w-full text-sm border-gray-300 dark:border-gray-600 rounded-lg p-2.5 bg-gray-50 dark:bg-gray-900 dark:text-white border focus:ring-2 focus:ring-blue-500"
                                />
                                <p className="text-xs text-gray-500 mt-1">Typical values are 2 or 3.</p>
                            </div>

                            <div>
                                <div className="flex items-center gap-1.5 mb-1">
                                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
                                        Min Resources
                                    </label>
                                    <Tooltip text="'exhaust' automatically calculates the maximum resources to use. Alternatively, input an integer like 10 or 100 to set the starting budget explicitly." />
                                </div>
                                <input
                                    type="text"
                                    value={config.min_resources ?? 'exhaust'}
                                    onChange={(e) => setConfig({ ...config, min_resources: e.target.value })}
                                    className="w-full text-sm border-gray-300 dark:border-gray-600 rounded-lg p-2.5 bg-gray-50 dark:bg-gray-900 dark:text-white border focus:ring-2 focus:ring-blue-500"
                                    placeholder="e.g., 'exhaust', 'smallest', or an integer"
                                />
                                <p className="text-xs text-gray-500 mt-1">Starting budget for the first iteration.</p>
                            </div>

                            <div>
                                <div className="flex items-center gap-1.5 mb-1">
                                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
                                        Resource
                                    </label>
                                    <Tooltip text="Determines how resources are limited during fast initial rounds. 'n_samples' limits the amount of training data used, while 'n_estimators' limits the number of trees in ensemble models." />
                                </div>
                                <select
                                    value={config.resource ?? 'n_samples'}
                                    onChange={(e) => setConfig({ ...config, resource: e.target.value })}
                                    className="w-full text-sm border-gray-300 dark:border-gray-600 rounded-lg p-2.5 bg-gray-50 dark:bg-gray-900 dark:text-white border focus:ring-2 focus:ring-blue-500"
                                >
                                    <option value="n_samples">n_samples (Rows of Data)</option>
                                    <option value="n_estimators">n_estimators (Trees)</option>
                                </select>
                                <p className="text-xs text-gray-500 mt-1">What defines the training budget.</p>
                            </div>
                        </>
                    )}

                    {isOptuna && (
                        <>
                            <div>
                                <div className="flex items-center gap-1.5 mb-1">
                                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
                                        Sampler
                                    </label>
                                    <Tooltip text="TPE provides smart Bayesian learning based on past trials. Random is purely blind chance. CMA-ES is advanced evolutionary sampling meant for complex continuous search spaces." />
                                </div>
                                <select
                                    value={config.sampler ?? 'tpe'}
                                    onChange={(e) => setConfig({ ...config, sampler: e.target.value as any })}
                                    className="w-full text-sm border-gray-300 dark:border-gray-600 rounded-lg p-2.5 bg-gray-50 dark:bg-gray-900 dark:text-white border focus:ring-2 focus:ring-blue-500"
                                >
                                    <option value="tpe">TPE (Bayesian Optimization)</option>
                                    <option value="random">Random Sampler</option>
                                    <option value="cmaes">CMA-ES</option>
                                </select>
                                <p className="text-xs text-gray-500 mt-1">Algorithm to suggest new parameters.</p>
                            </div>

                            <div>
                                <div className="flex items-center gap-1.5 mb-1">
                                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
                                        Pruner
                                    </label>
                                    <Tooltip text="Median prunes trials worse than the median of previous runs. Hyperband is an aggressively fast early-stopping algorithm. None disables early stopping." />
                                </div>
                                <select
                                    value={config.pruner ?? 'median'}
                                    onChange={(e) => setConfig({ ...config, pruner: e.target.value as any })}
                                    className="w-full text-sm border-gray-300 dark:border-gray-600 rounded-lg p-2.5 bg-gray-50 dark:bg-gray-900 dark:text-white border focus:ring-2 focus:ring-blue-500"
                                >
                                    <option value="median">Median Pruner</option>
                                    <option value="hyperband">Hyperband Pruner</option>
                                    <option value="none">None (No Pruning)</option>
                                </select>
                                <p className="text-xs text-gray-500 mt-1">Algorithm to kill bad trials early.</p>
                            </div>

                            <div>
                                <div className="flex items-center gap-1.5 mb-1">
                                    <label className="block text-sm font-medium text-gray-700 dark:text-gray-300">
                                        Timeout (Seconds)
                                    </label>
                                    <Tooltip text="Set a hard time limit for the entire Optuna study. Regardless of N-Trials, optimization will yield the best found parameters once time is up." />
                                </div>
                                <input
                                    type="number"
                                    min="1"
                                    value={config.timeout ?? ''}
                                    onChange={(e) => setConfig({ ...config, timeout: e.target.value ? parseInt(e.target.value, 10) : '' })}
                                    className="w-full text-sm border-gray-300 dark:border-gray-600 rounded-lg p-2.5 bg-gray-50 dark:bg-gray-900 dark:text-white border focus:ring-2 focus:ring-blue-500"
                                    placeholder="e.g. 300 (Optional)"
                                />
                                <p className="text-xs text-gray-500 mt-1">Stop tuning after X seconds.</p>
                            </div>
                        </>
                    )}
                </div>
        </ModalShell>
    );
};

import React, { useState, useRef, useEffect } from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { ArrowLeftRight, Plus, Trash2, Search, Info, ChevronDown, ChevronUp } from 'lucide-react';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';

// --- Types ---

interface AliasReplacementConfig {
  columns: string[];
  mode: 'custom' | 'canonicalize_country_codes' | 'normalize_boolean' | 'punctuation';
  custom_pairs: Record<string, string>;
}

// --- Components ---

const ColumnSelector: React.FC<{
  columns: string[];
  selected: string[];
  onChange: (selected: string[]) => void;
}> = ({ columns, selected, onChange }) => {
  const [search, setSearch] = useState('');
  
  const filtered = columns.filter(c => c.toLowerCase().includes(search.toLowerCase()));

  const toggle = (col: string) => {
    if (selected.includes(col)) {
      onChange(selected.filter(c => c !== col));
    } else {
      onChange([...selected, col]);
    }
  };

  return (
    <div className="border rounded bg-background overflow-hidden flex flex-col max-h-40">
      <div className="flex items-center px-2 py-1.5 border-b bg-muted/20">
        <Search size={12} className="text-muted-foreground mr-1.5" />
        <input
          className="flex-1 bg-transparent text-xs outline-none placeholder:text-muted-foreground/70"
          placeholder="Search columns..."
          value={search}
          onChange={e => { setSearch(e.target.value); }}
        />
      </div>
      <div className="overflow-y-auto p-1 space-y-0.5">
        {filtered.length > 0 ? (
          filtered.map(col => {
            const isSelected = selected.includes(col);
            return (
              <div
                key={col}
                onClick={() => { toggle(col); }}
                className={`
                  flex items-center gap-2 px-2 py-1.5 rounded text-xs cursor-pointer transition-colors
                  ${isSelected ? 'bg-blue-50 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300 font-medium' : 'hover:bg-gray-100 dark:hover:bg-gray-800 text-gray-700 dark:text-gray-300'}
                `}
              >
                <div className={`
                  w-3 h-3 rounded border flex items-center justify-center
                  ${isSelected ? 'border-blue-500 bg-blue-500 text-white' : 'border-gray-400 dark:border-gray-600'}
                `}>
                  {isSelected && <div className="w-1.5 h-1.5 bg-white rounded-full" />}
                </div>
                <span className="truncate">{col}</span>
              </div>
            );
          })
        ) : (
          <div className="p-2 text-xs text-gray-500 text-center italic">No columns found</div>
        )}
      </div>
    </div>
  );
};

const CustomPairEditor: React.FC<{
  pairs: Record<string, string>;
  onChange: (pairs: Record<string, string>) => void;
}> = ({ pairs, onChange }) => {
  const [newKey, setNewKey] = useState('');
  const [newValue, setNewValue] = useState('');

  const addPair = () => {
    if (newKey && newValue) {
      onChange({ ...pairs, [newKey]: newValue });
      setNewKey('');
      setNewValue('');
    }
  };

  const removePair = (key: string) => {
    const newPairs = { ...pairs };
    Reflect.deleteProperty(newPairs, key);
    onChange(newPairs);
  };

  return (
    <div className="space-y-3">
      <div className="flex gap-2 items-end">
        <div className="flex-1 space-y-1">
          <label className="text-[10px] text-gray-500 uppercase font-semibold">Alias (Old)</label>
          <input
            className="w-full text-xs rounded border border-gray-300 dark:border-gray-600 px-2 py-1.5"
            placeholder="e.g. NY"
            value={newKey}
            onChange={(e) => { setNewKey(e.target.value); }}
          />
        </div>
        <div className="flex-1 space-y-1">
          <label className="text-[10px] text-gray-500 uppercase font-semibold">Canonical (New)</label>
          <input
            className="w-full text-xs rounded border border-gray-300 dark:border-gray-600 px-2 py-1.5"
            placeholder="e.g. New York"
            value={newValue}
            onChange={(e) => { setNewValue(e.target.value); }}
            
          />
        </div>
        <button
          onClick={addPair}
          disabled={!newKey || !newValue}
          className="p-1.5 bg-blue-600 text-white rounded hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed"
        >
          <Plus size={16} />
        </button>
      </div>

      <div className="space-y-2 max-h-40 overflow-y-auto border rounded-md p-2 bg-gray-50 dark:bg-gray-800/50">
        {Object.entries(pairs).length === 0 ? (
          <div className="text-center text-xs text-gray-500 py-2">No custom aliases defined.</div>
        ) : (
          Object.entries(pairs).map(([key, val]) => (
            <div key={key} className="flex items-center justify-between bg-white dark:bg-gray-800 p-2 rounded border border-gray-200 dark:border-gray-700 text-xs">
              <div className="flex items-center gap-2 overflow-hidden">
                <span className="font-medium text-red-600 truncate max-w-[80px]">{key}</span>
                <ArrowLeftRight size={12} className="text-gray-400 shrink-0" />
                <span className="font-medium text-green-600 truncate max-w-[80px]">{val}</span>
              </div>
              <button onClick={() => { removePair(key); }} className="text-gray-400 hover:text-red-500">
                <Trash2 size={14} />
              </button>
            </div>
          ))
        )}
      </div>
    </div>
  );
};

const AliasReplacementSettings: React.FC<{ config: AliasReplacementConfig; onChange: (c: AliasReplacementConfig) => void; nodeId?: string }> = ({
  config,
  onChange,
  nodeId,
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [isWide, setIsWide] = useState(false);
  const [showInfo, setShowInfo] = useState(true);

  const upstreamData = useUpstreamData(nodeId || '');
  const datasetId = upstreamData.find((d: Record<string, unknown>) => d.datasetId)?.datasetId as string | undefined;
  const { data: schema } = useDatasetSchema(datasetId);
  
  // Filter for text columns only
  const textColumns = schema 
    ? Object.values(schema.columns)
      .filter((c) => {
        const dtype = String(c.dtype).toLowerCase();
        return dtype.includes('object') || dtype.includes('string') || dtype.includes('category') || dtype.includes('text');
      })
      .map((c) => c.name)
    : [];

  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setIsWide(entry.contentRect.width > 400);
      }
    });
    observer.observe(containerRef.current);
    return () => { observer.disconnect(); };
  }, []);

  return (
    <div ref={containerRef} className={`flex flex-col h-full w-full bg-white dark:bg-gray-900 ${isWide ? 'overflow-hidden' : 'overflow-y-auto'}`}>
      <div className={`flex-1 min-h-0 p-4 gap-4 ${isWide ? 'grid grid-cols-2' : 'flex flex-col'}`}>
        
        {/* Left Column: Column Selection */}
        <div className={`space-y-4 ${isWide ? 'overflow-y-auto pr-2' : 'shrink-0'}`}>
          <div>
            <label className="text-sm font-medium text-gray-700 dark:text-gray-300 mb-2 block">
              Target Columns ({config.columns.length})
            </label>
            <ColumnSelector 
              columns={textColumns} 
              selected={config.columns} 
              onChange={(cols) => onChange({ ...config, columns: cols })} 
            />
            <p className="text-xs text-gray-500 mt-1">Only text/categorical columns are shown.</p>
          </div>
        </div>

        {/* Right Column: Settings */}
        <div className={`space-y-4 ${isWide ? 'overflow-y-auto pl-2 border-l border-gray-100 dark:border-gray-700' : 'shrink-0 pt-4 border-t border-gray-100 dark:border-gray-700'}`}>
          <div className="bg-blue-50 dark:bg-blue-900/20 rounded-md border border-blue-100 dark:border-blue-800 overflow-hidden">
            <button 
              onClick={() => { setShowInfo(!showInfo); }}
              className="w-full flex items-center gap-2 p-3 text-left hover:bg-blue-100/50 dark:hover:bg-blue-900/30 transition-colors"
            >
              <Info className="text-blue-600 dark:text-blue-400 shrink-0" size={16} />
              <span className="text-xs font-semibold text-blue-800 dark:text-blue-200 flex-1">
                About Alias Replacement
              </span>
              {showInfo ? (
                <ChevronUp size={14} className="text-blue-600 dark:text-blue-400" />
              ) : (
                <ChevronDown size={14} className="text-blue-600 dark:text-blue-400" />
              )}
            </button>
            
            {showInfo && (
              <div className="px-3 pb-3 text-xs text-blue-800 dark:text-blue-200 pl-9">
                <p>Standardize data by mapping multiple variations (aliases) to a single canonical value. Useful for country codes, boolean strings, or custom synonyms.</p>
              </div>
            )}
          </div>

          <div>
            <label className="text-sm font-medium text-gray-700 dark:text-gray-300 mb-2 block">
              Replacement Mode
            </label>
            <select
              className="w-full text-xs rounded border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2"
              value={config.mode}
              onChange={(e) => onChange({ ...config, mode: e.target.value as AliasReplacementConfig['mode'] })}
            >
              <option value="custom">Custom Mapping</option>
              <option value="canonicalize_country_codes">Canonicalize Country Codes</option>
              <option value="normalize_boolean">Normalize Booleans (yes/no -&gt; True/False)</option>
              <option value="punctuation">Remove Punctuation</option>
            </select>
            <p className="text-[10px] text-gray-500 mt-1">
              {config.mode === 'custom' && "Define your own alias mappings below."}
              {config.mode === 'canonicalize_country_codes' && "Standardizes country codes (e.g. 'USA', 'U.S.A.' -> 'US')."}
              {config.mode === 'normalize_boolean' && "Converts 'yes', 'y', '1' to True and 'no', 'n', '0' to False."}
              {config.mode === 'punctuation' && "Removes common punctuation characters from text."}
            </p>
          </div>

          {config.mode === 'custom' && (
            <div>
              <label className="text-sm font-medium text-gray-700 dark:text-gray-300 mb-2 block">
                Custom Aliases
              </label>
              <CustomPairEditor
                pairs={config.custom_pairs}
                onChange={(pairs) => onChange({ ...config, custom_pairs: pairs })}
              />
            </div>
          )}
        </div>

      </div>
    </div>
  );
};

export const AliasReplacementNode: NodeDefinition<AliasReplacementConfig> = {
  type: 'AliasReplacement',
  label: 'Alias Replacement',
  category: 'Preprocessing',
  description: 'Standardize values by mapping aliases to canonical forms.',
  icon: ArrowLeftRight,
  inputs: [{ id: 'in', label: 'Data', type: 'dataset' }],
  outputs: [{ id: 'out', label: 'Standardized Data', type: 'dataset' }],
  settings: AliasReplacementSettings,
  validate: (config) => {
    if (config.columns.length === 0) return { isValid: false, message: 'Select at least one column.' };
    if (config.mode === 'custom' && Object.keys(config.custom_pairs).length === 0) {
      return { isValid: false, message: 'Add at least one alias pair for custom mode.' };
    }
    return { isValid: true };
  },
  getDefaultConfig: () => ({
    columns: [],
    mode: 'custom',
    custom_pairs: {},
  }),
};

import React, { useState, useRef, useEffect } from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { BarChart3 } from 'lucide-react';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';

interface BinningConfig {
  columns: string[];
  strategy: 'equal_width' | 'equal_frequency' | 'kmeans' | 'custom';
  n_bins: number;
  label_format: 'ordinal' | 'range' | 'bin_index';
  output_suffix?: string;
  drop_original?: boolean;
  custom_bins?: Record<string, number[]>; // Map column -> edges
  custom_labels?: Record<string, string[]>; // Map column -> labels
  precision?: number;
}

const CustomBinInput: React.FC<{
  value: number[] | undefined;
  onChange: (val: number[]) => void;
}> = ({ value, onChange }) => {
  const [text, setText] = useState(value?.join(', ') || '');
  const lastValueRef = useRef(value);

  useEffect(() => {
    if (JSON.stringify(value) !== JSON.stringify(lastValueRef.current)) {
      setText(value?.join(', ') || '');
      lastValueRef.current = value;
    }
  }, [value]);

  const handleBlur = () => {
    const edges = text.split(',').map(s => parseFloat(s.trim())).filter(n => !isNaN(n)).sort((a, b) => a - b);
    onChange(edges);
  };

  return (
    <input 
      type="text"
      className="w-full p-1 text-xs border rounded bg-background text-foreground"
      placeholder="0, 10, 20, 100..."
      value={text}
      onChange={(e) => { setText(e.target.value); }}
      onBlur={handleBlur}
    />
  );
};

const BinningSettings: React.FC<{ config: BinningConfig; onChange: (c: BinningConfig) => void; nodeId?: string }> = ({
  config,
  onChange,
  nodeId,
}) => {
  const upstreamData = useUpstreamData(nodeId || '');
  const datasetId = upstreamData.find(d => d.datasetId)?.datasetId as string | undefined;
  const { data: schema, isLoading } = useDatasetSchema(datasetId);
  
  // Responsive Layout
  const containerRef = useRef<HTMLDivElement>(null);
  const [isWide, setIsWide] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setIsWide(entry.contentRect.width > 450);
      }
    });
    observer.observe(containerRef.current);
    return () => { observer.disconnect(); };
  }, []);

  // Filter for numeric columns only
  const numericColumns = schema 
    ? Object.values(schema.columns)
        .filter(c => ['int', 'float', 'number'].some(t => c.dtype.toLowerCase().includes(t)))
        .map(c => c.name)
    : [];

  const filteredColumns = numericColumns.filter(c => c.toLowerCase().includes(searchTerm.toLowerCase()));

  const handleSelectAll = () => {
    onChange({ ...config, columns: filteredColumns });
  };

  const handleDeselectAll = () => {
    const newCols = config.columns.filter(c => !filteredColumns.includes(c));
    onChange({ ...config, columns: newCols });
  };

  const toggleColumn = (col: string) => {
    if (config.columns.includes(col)) {
      onChange({ ...config, columns: config.columns.filter(c => c !== col) });
    } else {
      onChange({ ...config, columns: [...config.columns, col] });
    }
  };

  return (
    <div ref={containerRef} className="p-4 space-y-4 h-full overflow-y-auto">
      {!datasetId && (
        <div className="p-2 bg-yellow-50 text-yellow-800 text-xs rounded border border-yellow-200">
          Connect a dataset node to see available columns.
        </div>
      )}

      <div className={`grid gap-4 ${isWide ? 'grid-cols-2' : 'grid-cols-1'}`}>
        {/* Left Column: Settings */}
        <div className="space-y-4">
          <div className="space-y-2">
            <label className="block text-sm font-medium">Binning Strategy</label>
            <select
              className="w-full p-2 border rounded bg-background focus:ring-1 focus:ring-primary outline-none"
              value={config.strategy}
              onChange={(e) => onChange({ ...config, strategy: e.target.value as BinningConfig['strategy'] })}
            >
              <option value="equal_width">Equal Width (Uniform)</option>
              <option value="equal_frequency">Equal Frequency (Quantile)</option>
              <option value="kmeans">K-Means Clustering</option>
              <option value="custom">Custom Edges</option>
            </select>
            <p className="text-[10px] text-muted-foreground">
              {config.strategy === 'equal_width' && "Bins have equal width ranges."}
              {config.strategy === 'equal_frequency' && "Bins have equal number of records."}
              {config.strategy === 'kmeans' && "Bins based on K-Means clustering centers."}
              {config.strategy === 'custom' && "Define specific bin edges for each column."}
            </p>
          </div>

          {config.strategy !== 'custom' && (
            <div className="space-y-2">
              <label className="block text-sm font-medium">Number of Bins</label>
              <input
                type="number"
                min={2}
                max={100}
                className="w-full p-2 border rounded bg-background focus:ring-1 focus:ring-primary outline-none"
                value={config.n_bins}
                onChange={(e) => onChange({ ...config, n_bins: parseInt(e.target.value) || 5 })}
              />
            </div>
          )}

          {config.strategy === 'custom' && (
             <div className="space-y-2 border rounded p-2 bg-muted/10">
               <label className="block text-xs font-medium">Custom Edges</label>
               {config.columns.length === 0 ? (
                 <div className="text-xs text-muted-foreground">Select columns first.</div>
               ) : (
                 <div className="space-y-2 max-h-40 overflow-y-auto">
                   {config.columns.map(col => (
                     <div key={col} className="space-y-1">
                       <label className="text-[10px] font-medium">{col}</label>
                       <CustomBinInput
                         value={config.custom_bins?.[col]}
                         onChange={(edges) => onChange({
                           ...config,
                           custom_bins: { ...config.custom_bins, [col]: edges }
                         })}
                       />
                     </div>
                   ))}
                 </div>
               )}
             </div>
          )}

          <div className="space-y-2">
            <label className="block text-sm font-medium">Label Format</label>
            <select
              className="w-full p-2 border rounded bg-background focus:ring-1 focus:ring-primary outline-none"
              value={config.label_format}
              onChange={(e) => onChange({ ...config, label_format: e.target.value as BinningConfig['label_format'] })}
            >
              <option value="ordinal">Ordinal (0, 1, 2...)</option>
              <option value="range">Range Intervals ([0-10], [10-20]...)</option>
              <option value="bin_index">Bin Index</option>
            </select>
          </div>

          {config.label_format === 'range' && (
            <div className="space-y-2">
              <label className="block text-sm font-medium">Precision (Decimals)</label>
              <input
                type="number"
                min={0}
                max={10}
                className="w-full p-2 border rounded bg-background focus:ring-1 focus:ring-primary outline-none"
                value={config.precision ?? 3}
                onChange={(e) => onChange({ ...config, precision: parseInt(e.target.value) || 0 })}
              />
              <p className="text-[10px] text-muted-foreground">
                Number of decimal places to show in interval labels (e.g. 2 gives [0.00, 10.00]).
              </p>
            </div>
          )}

          <div className="space-y-2 pt-2 border-t">
            <div className="flex items-center gap-2">
              <input
                type="checkbox"
                id="drop_original"
                checked={config.drop_original}
                onChange={(e) => onChange({ ...config, drop_original: e.target.checked })}
                className="rounded border-gray-300 text-primary focus:ring-primary"
              />
              <label htmlFor="drop_original" className="text-sm">Drop Original Columns</label>
            </div>
            
            {!config.drop_original && (
              <div className="space-y-1">
                <label className="text-xs font-medium text-muted-foreground">Output Suffix</label>
                <input
                  type="text"
                  className="w-full p-1.5 border rounded text-xs"
                  placeholder="_binned"
                  value={config.output_suffix || ''}
                  onChange={(e) => onChange({ ...config, output_suffix: e.target.value })}
                />
              </div>
            )}
          </div>
        </div>

        {/* Right Column: Column Selection */}
        <div className="space-y-2 flex flex-col h-full min-h-[200px]">
          <label className="block text-sm font-medium">Target Columns</label>
          
          <div className="flex gap-2">
            <input 
              className="w-full px-2 py-1 text-xs border rounded bg-background text-foreground" 
              placeholder="Search columns..." 
              value={searchTerm}
              onChange={e => { setSearchTerm(e.target.value); }}
            />
          </div>

          <div className="flex gap-2 text-xs border-b pb-1">
            <button onClick={handleSelectAll} className="text-primary hover:underline">Select All</button>
            <span className="text-muted-foreground">|</span>
            <button onClick={handleDeselectAll} className="text-muted-foreground hover:underline">None</button>
            <span className="ml-auto text-muted-foreground">{config.columns.length} selected</span>
          </div>

          <div className="flex-1 border rounded bg-background overflow-y-auto p-2 max-h-[300px]">
            {isLoading ? (
              <div className="text-xs text-muted-foreground p-2">Loading columns...</div>
            ) : filteredColumns.length === 0 ? (
               <div className="text-xs text-muted-foreground p-2 text-center">
                 {numericColumns.length === 0 ? "No numeric columns found." : `No columns match "${searchTerm}"`}
               </div>
            ) : (
              <div className="space-y-1">
                {filteredColumns.map(col => (
                  <label key={col} className="flex items-center gap-2 text-xs cursor-pointer hover:bg-accent/50 p-1 rounded">
                    <input
                      type="checkbox"
                      checked={config.columns.includes(col)}
                      onChange={() => { toggleColumn(col); }}
                      className="rounded border-gray-300 text-primary focus:ring-primary"
                    />
                    <span className="truncate" title={col}>{col}</span>
                  </label>
                ))}
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export const BinningNode: NodeDefinition = {
  type: 'BinningNode',
  label: 'Binning / Discretization',
  description: 'Convert continuous variables into discrete bins.',
  icon: BarChart3,
  category: 'Preprocessing',
  inputs: [{ id: 'in', type: 'dataset', label: 'Dataset' }],
  outputs: [{ id: 'out', type: 'dataset', label: 'Binned' }],
  validate: (config: BinningConfig) => {
    if (config.columns.length === 0) {
      return { isValid: false, message: 'Select at least one column to bin.' };
    }
    if (config.n_bins < 2) {
      return { isValid: false, message: 'Number of bins must be at least 2.' };
    }
    return { isValid: true };
  },
  settings: BinningSettings,
  getDefaultConfig: () => ({
    columns: [],
    strategy: 'equal_width',
    n_bins: 5,
    label_format: 'ordinal',
    output_suffix: '_binned',
    drop_original: false
  })
};

import React, { useRef, useState, useEffect } from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { FileType2, Plus, Trash2, Activity } from 'lucide-react';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';
import { useGraphStore } from '../../../core/store/useGraphStore';

interface CastTypeConfig {
  column_types: Record<string, string>;
}

const TARGET_TYPES = [
  { value: 'float', label: 'Float (Decimal)' },
  { value: 'int', label: 'Integer' },
  { value: 'string', label: 'String (Text)' },
  { value: 'category', label: 'Category' },
  { value: 'bool', label: 'Boolean' },
  { value: 'datetime', label: 'Datetime' },
];

const CastTypeSettings: React.FC<{ config: CastTypeConfig; onChange: (c: CastTypeConfig) => void; nodeId?: string }> = ({
  config,
  onChange,
  nodeId,
}) => {
  const upstreamData = useUpstreamData(nodeId || '');
  const datasetId = upstreamData.find(d => d.datasetId)?.datasetId as string | undefined;
  const { data: schema, isLoading } = useDatasetSchema(datasetId);
  const columns = schema ? Object.values(schema.columns).map(c => c.name) : [];

  const executionResult = useGraphStore((state) => state.executionResult);
  const nodeResult = nodeId ? executionResult?.node_results[nodeId] : null;
  const metrics: Record<string, unknown> | null =
    nodeResult?.metrics && typeof nodeResult.metrics === 'object'
      ? (nodeResult.metrics as Record<string, unknown>)
      : null;

  // Responsive Layout Logic
  const containerRef = useRef<HTMLDivElement>(null);
  const [isWide, setIsWide] = useState(false);

  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setIsWide(entry.contentRect.width > 450);
      }
    });
    observer.observe(containerRef.current);
    return () => { observer.disconnect(); };
  }, []);

  const handleAdd = () => {
    if (columns.length === 0) return;
    // Default to first available column and float
    const newCol = columns.find(c => !config.column_types[c]) || columns[0];
    onChange({
      ...config,
      column_types: { ...config.column_types, [newCol]: 'float' }
    });
  };

  const handleRemove = (col: string) => {
    const newTypes = { ...config.column_types };
    Reflect.deleteProperty(newTypes, col);
    onChange({ ...config, column_types: newTypes });
  };

  const handleUpdateColumn = (oldCol: string, newCol: string) => {
    if (oldCol === newCol) return;
    const type = config.column_types[oldCol];
    const newTypes = { ...config.column_types };
    Reflect.deleteProperty(newTypes, oldCol);
    newTypes[newCol] = type;
    onChange({ ...config, column_types: newTypes });
  };

  const handleUpdateType = (col: string, newType: string) => {
    onChange({
      ...config,
      column_types: { ...config.column_types, [col]: newType }
    });
  };

  return (
    <div ref={containerRef} className="p-4 space-y-4 h-full overflow-y-auto">
      {!datasetId && (
        <div className="p-2 bg-yellow-50 text-yellow-800 text-xs rounded border border-yellow-200">
          Connect a dataset node to see available columns.
        </div>
      )}
      
      {isLoading && !!datasetId && (
        <div className="text-xs text-muted-foreground animate-pulse">
          Loading schema...
        </div>
      )}

      <div className="space-y-2">
        <div className="flex items-center justify-between">
          <label className="text-sm font-medium">Casting Rules</label>
          <button
            onClick={handleAdd}
            disabled={!datasetId || columns.length === 0}
            className="p-1.5 bg-primary text-primary-foreground rounded hover:bg-primary/90 disabled:opacity-50 transition-colors"
            title="Add Casting Rule"
          >
            <Plus className="w-4 h-4" />
          </button>
        </div>

        <div className={`space-y-2 ${isWide ? 'grid grid-cols-2 gap-2 space-y-0' : ''}`}>
          {Object.entries(config.column_types).map(([col, type]) => (
            <div key={col} className="flex items-center gap-2 p-2 border rounded bg-muted/10 group">
              <div className="flex-1 space-y-2 min-w-0">
                <select
                  className="w-full p-1.5 text-sm border rounded bg-background focus:ring-1 focus:ring-primary outline-none"
                  value={col}
                  onChange={(e) => { handleUpdateColumn(col, e.target.value); }}
                >
                  {columns.map(c => (
                    <option key={c} value={c} disabled={c !== col && !!config.column_types[c]}>
                      {c}
                    </option>
                  ))}
                </select>
                <select
                  className="w-full p-1.5 text-sm border rounded bg-background focus:ring-1 focus:ring-primary outline-none"
                  value={type}
                  onChange={(e) => { handleUpdateType(col, e.target.value); }}
                >
                  {TARGET_TYPES.map(t => (
                    <option key={t.value} value={t.value}>{t.label}</option>
                  ))}
                </select>
              </div>
              <button
                onClick={() => { handleRemove(col); }}
                className="p-1.5 text-muted-foreground hover:text-destructive hover:bg-destructive/10 rounded transition-colors"
                title="Remove Rule"
              >
                <Trash2 className="w-4 h-4" />
              </button>
            </div>
          ))}
          
          {Object.keys(config.column_types).length === 0 && (
            <div className={`text-xs text-muted-foreground italic border border-dashed rounded p-8 text-center ${isWide ? 'col-span-2' : ''}`}>
              No casting rules defined. Click + to add one.
            </div>
          )}
        </div>
      </div>

      {/* Feedback Section */}
      {metrics && (metrics.cast_errors !== undefined || metrics.casted_columns_count !== undefined) && (
        <div className="mt-4 p-3 bg-muted/30 rounded-md border border-border">
          <div className="flex items-center gap-2 mb-2 text-sm font-semibold text-primary">
            <Activity size={14} />
            <span>Last Run Results</span>
          </div>
          <div className="space-y-1 text-xs">
            {metrics.casted_columns_count !== undefined && (
              <div className="flex justify-between">
                <span className="text-muted-foreground">Columns Casted:</span>
                <span className="font-medium">{String(metrics.casted_columns_count)}</span>
              </div>
            )}
            {metrics.cast_errors !== undefined && (
              <div className="flex justify-between">
                <span className="text-muted-foreground">Errors Encountered:</span>
                <span className="font-medium text-destructive">{String(metrics.cast_errors)}</span>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export const CastTypeNode: NodeDefinition<CastTypeConfig> = {
  type: 'casting',
  label: 'Cast Types',
  category: 'Preprocessing',
  description: 'Cast columns to specific data types.',
  icon: FileType2,
  inputs: [{ id: 'in', label: 'Data', type: 'dataset' }],
  outputs: [{ id: 'out', label: 'Casted Data', type: 'dataset' }],
  settings: CastTypeSettings,
  validate: (_config) => ({ isValid: true }),
  getDefaultConfig: () => ({
    column_types: {},
  }),
};

