import React, { useState, useRef, useEffect } from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { Hash, Activity } from 'lucide-react';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';
import { useGraphStore } from '../../../core/store/useGraphStore';
import { RecommendationsPanel } from '../../../components/panels/RecommendationsPanel';

interface EncodingConfig {
  method: 'onehot' | 'ordinal' | 'label' | 'target' | 'hash' | 'dummy';
  columns: string[];
  // OneHot/Dummy specific
  drop_first?: boolean;
  drop_original?: boolean;
  handle_unknown?: 'error' | 'ignore';
  // Hash specific
  n_features?: number;
  // Target specific
  target_column?: string;
  // Label/Ordinal specific
  unknown_value?: number; // For Ordinal
  missing_code?: number; // For Label
}

const EncodingSettings: React.FC<{ config: EncodingConfig; onChange: (c: EncodingConfig) => void; nodeId?: string }> = ({
  config,
  onChange,
  nodeId,
}) => {
  const upstreamData = useUpstreamData(nodeId || '');
  const datasetId = upstreamData.find(d => d.datasetId)?.datasetId as string | undefined;
  const { data: schema, isLoading } = useDatasetSchema(datasetId);
  const [searchTerm, setSearchTerm] = useState('');
  const containerRef = useRef<HTMLDivElement>(null);
  const [isWide, setIsWide] = useState(false);
  
  const executionResult = useGraphStore((state) => state.executionResult);
  const nodeResult = nodeId ? executionResult?.node_results[nodeId] : null;
  const metrics: Record<string, unknown> | null =
    nodeResult?.metrics && typeof nodeResult.metrics === 'object'
      ? (nodeResult.metrics as Record<string, unknown>)
      : null;
  const categoriesCount: Record<string, unknown> | null =
    metrics?.categories_count && typeof metrics.categories_count === 'object'
      ? (metrics.categories_count as Record<string, unknown>)
      : null;
  const classesCount: Record<string, unknown> | null =
    metrics?.classes_count && typeof metrics.classes_count === 'object'
      ? (metrics.classes_count as Record<string, unknown>)
      : null;
  const recommendations = executionResult?.recommendations || [];

  const filteredRecommendations = recommendations.filter(rec => 
    rec.suggested_node_type === 'encoding' || 
    rec.type.includes('encoding') ||
    rec.type.includes('cardinality')
  );

  // Responsive layout logic
  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setIsWide(entry.contentRect.width > 400);
      }
    });
    observer.observe(containerRef.current);
    return () => { observer.disconnect(); };
  }, []);

  const categoricalColumns = schema 
    ? Object.values(schema.columns)
        .filter(c => ['object', 'string', 'category', 'bool'].some(t => c.dtype.toLowerCase().includes(t)))
        .map(c => c.name)
    : [];

  const filteredColumns = categoricalColumns.filter(c => 
    c.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const handleSelectAll = () => {
    onChange({ ...config, columns: [...categoricalColumns] });
  };

  const handleDeselectAll = () => {
    onChange({ ...config, columns: [] });
  };

  return (
    <div ref={containerRef} className="p-4 space-y-4">
      {!datasetId && (
        <div className="p-2 bg-yellow-50 text-yellow-800 text-xs rounded border border-yellow-200">
          Connect a dataset node to see available columns.
        </div>
      )}
      
      {isLoading && !!datasetId && (
        <div className="text-xs text-muted-foreground animate-pulse">
          Loading schema...
        </div>
      )}

      <div className={`grid gap-4 ${isWide ? 'grid-cols-2' : 'grid-cols-1'}`}>
        {/* Method Selection */}
        <div className="space-y-2">
          <label className="block text-sm font-medium">Encoding Method</label>
          <select
            className="w-full p-2 border rounded bg-background focus:ring-1 focus:ring-primary outline-none"
            value={config.method}
            onChange={(e) => onChange({ ...config, method: e.target.value as EncodingConfig['method'] })}
          >
            <option value="onehot">One-Hot Encoding</option>
            <option value="dummy">Dummy Encoding</option>
            <option value="label">Label Encoding</option>
            <option value="ordinal">Ordinal Encoding</option>
            <option value="target">Target Encoding</option>
            <option value="hash">Hash Encoding</option>
          </select>
          <p className="text-xs text-muted-foreground">
            {config.method === 'onehot' && "Creates binary columns for each category."}
            {config.method === 'dummy' && "Like One-Hot but drops first category to avoid collinearity."}
            {config.method === 'label' && "Assigns a unique integer to each category."}
            {config.method === 'ordinal' && "Encodes categories as ordered integers."}
            {config.method === 'target' && "Encodes categories based on target mean."}
            {config.method === 'hash' && "Maps categories to a fixed number of features."}
          </p>
          
          <div className="pt-2">
            <label className="flex items-center gap-2 text-sm">
                <input
                  type="checkbox"
                  checked={config.drop_original !== false} // Default to true
                  onChange={(e) => onChange({ ...config, drop_original: e.target.checked })}
                  className="rounded border-gray-300"
                />
                Drop Original Column
            </label>
            <p className="text-[10px] text-muted-foreground ml-5">
                If unchecked, keeps the original column alongside encoded features.
            </p>
          </div>
        </div>

        {/* Method Specific Settings */}
        <div className="space-y-2">
          {(config.method === 'onehot' || config.method === 'dummy') && (
            <div className="space-y-2 p-3 bg-muted/20 rounded border h-full">
              <label className="flex items-center gap-2 text-sm">
                <input
                  type="checkbox"
                  checked={config.method === 'dummy' ? true : (config.drop_first || false)}
                  disabled={config.method === 'dummy'}
                  onChange={(e) => onChange({ ...config, drop_first: e.target.checked })}
                  className="rounded border-gray-300"
                />
                Drop First Category
              </label>
              <div className="space-y-1">
                <label className="block text-xs font-medium">Handle Unknown</label>
                <select
                  className="w-full p-1 text-sm border rounded"
                  value={config.handle_unknown || 'ignore'}
                  onChange={(e) => onChange({ ...config, handle_unknown: e.target.value as EncodingConfig['handle_unknown'] })}
                  title="How to handle categories seen in test data but not in training data."
                >
                  <option value="ignore">Ignore (Zeros)</option>
                  <option value="error">Raise Error</option>
                </select>
                <p className="text-[10px] text-muted-foreground">
                  "Ignore" produces all-zeros for unknown categories.
                </p>
              </div>
            </div>
          )}

          {config.method === 'target' && (
            <div className="space-y-2 p-3 bg-muted/20 rounded border h-full">
              <label className="block text-sm font-medium">Target Column</label>
              <select
                className="w-full p-2 border rounded bg-background text-sm"
                value={config.target_column || ''}
                onChange={(e) => onChange({ ...config, target_column: e.target.value })}
              >
                <option value="">Select a target column...</option>
                {schema && Object.values(schema.columns).map(col => (
                  <option key={col.name} value={col.name}>{col.name} ({col.dtype})</option>
                ))}
              </select>
              <p className="text-xs text-muted-foreground">
                The column to use for calculating target statistics.
              </p>
            </div>
          )}

          {config.method === 'hash' && (
            <div className="space-y-2 p-3 bg-muted/20 rounded border h-full">
              <label className="block text-sm font-medium">Number of Features</label>
              <input
                type="number"
                min="1"
                className="w-full p-2 border rounded"
                value={config.n_features || 8}
                onChange={(e) => onChange({ ...config, n_features: parseInt(e.target.value) })}
              />
            </div>
          )}

          {config.method === 'ordinal' && (
            <div className="space-y-2 p-3 bg-muted/20 rounded border h-full">
              <label className="block text-sm font-medium">Unknown Value</label>
              <input
                type="number"
                className="w-full p-2 border rounded"
                value={config.unknown_value ?? -1}
                onChange={(e) => onChange({ ...config, unknown_value: parseInt(e.target.value) })}
                title="Integer to assign for unknown categories."
              />
              <p className="text-xs text-muted-foreground">
                Value assigned to unknown categories (default: -1).
              </p>
            </div>
          )}

          {config.method === 'label' && (
            <div className="space-y-2 p-3 bg-muted/20 rounded border h-full">
              <label className="block text-sm font-medium">Missing/Unknown Code</label>
              <input
                type="number"
                className="w-full p-2 border rounded"
                value={config.missing_code ?? -1}
                onChange={(e) => onChange({ ...config, missing_code: parseInt(e.target.value) })}
                title="Integer to assign for missing or unknown categories."
              />
              <p className="text-xs text-muted-foreground">
                Value assigned to missing/unknown categories (default: -1).
              </p>
            </div>
          )}
        </div>
      </div>

      {/* Column Selection */}
      <div>
        <div className="flex items-center justify-between mb-2">
          <label className="block text-sm font-medium">Columns to Encode</label>
          <span className="text-xs text-muted-foreground">
            {config.columns.length} selected
          </span>
        </div>

        <div className="space-y-2 mb-2">
          <input 
            type="text" 
            placeholder="Search columns..." 
            className="block w-full px-3 py-1.5 text-sm bg-background border rounded-md shadow-sm focus:ring-1 focus:ring-primary outline-none"
            value={searchTerm}
            onChange={(e) => { setSearchTerm(e.target.value); }}
          />
          <div className="flex gap-2 text-xs justify-end">
            <button onClick={handleSelectAll} className="text-primary hover:text-primary/80 font-medium transition-colors">Select All</button>
            <span className="text-border">|</span>
            <button onClick={handleDeselectAll} className="text-primary hover:text-primary/80 font-medium transition-colors">Deselect All</button>
          </div>
        </div>

        {categoricalColumns.length > 0 ? (
          <div className="space-y-1 max-h-40 overflow-y-auto border rounded p-2 bg-background">
            {filteredColumns.map(col => (
              <label key={col} className="flex items-center gap-2 text-sm hover:bg-accent/50 p-1 rounded cursor-pointer">
                <input
                  type="checkbox"
                  className="rounded border-gray-300 text-primary focus:ring-primary"
                  checked={config.columns.includes(col)}
                  onChange={(e) => {
                    const newCols = e.target.checked
                      ? [...config.columns, col]
                      : config.columns.filter(c => c !== col);
                    onChange({ ...config, columns: newCols });
                  }}
                />
                {col}
              </label>
            ))}
            {filteredColumns.length === 0 && (
              <div className="text-xs text-muted-foreground text-center py-2">
                No columns match "{searchTerm}"
              </div>
            )}
          </div>
        ) : (
          <div className="text-xs text-muted-foreground italic border rounded p-4 text-center">
            No categorical columns found
          </div>
        )}
      </div>

      {/* Recommendations Section */}
      {filteredRecommendations.length > 0 && (
        <RecommendationsPanel recommendations={filteredRecommendations} />
      )}

      {/* Feedback Section */}
      {metrics && (
        <div className="mt-4 p-3 bg-muted/30 rounded-md border border-border">
          <div className="flex items-center gap-2 mb-2 text-sm font-semibold text-primary">
            <Activity size={14} />
            <span>Last Run Results</span>
          </div>
          <div className="space-y-1 text-xs">
            {metrics.encoded_columns_count !== undefined && (
              <div className="flex justify-between">
                <span className="text-muted-foreground">Columns Encoded:</span>
                <span className="font-medium">{String(metrics.encoded_columns_count)}</span>
              </div>
            )}
            {metrics.new_features_count !== undefined && (
              <div className="flex justify-between">
                <span className="text-muted-foreground">New Features Created:</span>
                <span className="font-medium text-primary">{String(metrics.new_features_count)}</span>
              </div>
            )}
            
            {/* Detailed Counts */}
            {categoriesCount && (
              <div className="mt-2 border-t pt-2">
                <span className="text-muted-foreground block mb-1 font-medium">Categories Found:</span>
                <div className="grid grid-cols-2 gap-x-4 gap-y-1">
                  {Object.entries(categoriesCount).map(([col, count]) => (
                    <div key={col} className="flex justify-between text-[10px]">
                      <span className="truncate max-w-[100px]" title={col}>{col}:</span>
                      <span className="font-mono">{String(count)}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
            {classesCount && (
              <div className="mt-2 border-t pt-2">
                <span className="text-muted-foreground block mb-1 font-medium">Classes Found:</span>
                <div className="grid grid-cols-2 gap-x-4 gap-y-1">
                  {Object.entries(classesCount).map(([col, count]) => (
                    <div key={col} className="flex justify-between text-[10px]">
                      <span className="truncate max-w-[100px]" title={col}>{col}:</span>
                      <span className="font-mono">{String(count)}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export const EncodingNode: NodeDefinition<EncodingConfig> = {
  type: 'encoding',
  label: 'Encoding',
  category: 'Preprocessing',
  description: 'Encode categorical variables.',
  icon: Hash,
  inputs: [{ id: 'in', label: 'Data', type: 'dataset' }],
  outputs: [{ id: 'out', label: 'Encoded Data', type: 'dataset' }],
  settings: EncodingSettings,
  validate: (config) => {
    if (config.columns.length === 0) return { isValid: false, error: 'Select at least one column' };
    return { isValid: true };
  },
  getDefaultConfig: () => ({
    method: 'onehot',
    columns: [],
    drop_first: false,
    handle_unknown: 'ignore',
    n_features: 8,
    unknown_value: -1,
    missing_code: -1
  }),
};

import React, { useState } from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { Calculator, Trash2, Calendar, Percent, GitCompare, Search, Check, ChevronDown, ChevronRight, FunctionSquare, Info, Lightbulb, Activity } from 'lucide-react';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';
import { useRecommendations } from '../../../core/hooks/useRecommendations';
import { RecommendationsPanel } from '../../../components/panels/RecommendationsPanel';
import { Recommendation } from '../../../core/api/client';
import { useGraphStore } from '../../../core/store/useGraphStore';

interface MathOperation {
  operation_type: 'arithmetic' | 'datetime_extract' | 'ratio' | 'similarity' | 'group_agg';
  method: string;
  input_columns: string[];
  secondary_columns?: string[]; // For arithmetic (second operand)
  constants?: number[];
  output_column?: string;
  datetime_features?: string[]; // For datetime_extract

  isExpanded?: boolean; // UI state
}

interface FeatureGenerationConfig {
  operations: MathOperation[];
}

const OPERATION_TYPES = [
  { value: 'arithmetic', label: 'Arithmetic', icon: Calculator },
  { value: 'datetime_extract', label: 'Date Extraction', icon: Calendar },
  { value: 'ratio', label: 'Ratio', icon: Percent },
  { value: 'similarity', label: 'Similarity', icon: GitCompare },
  { value: 'group_agg', label: 'Group Agg', icon: FunctionSquare },
];

const ARITHMETIC_METHODS = ['add', 'subtract', 'multiply', 'divide'];
const DATE_METHODS = ['year', 'month', 'day', 'weekday', 'hour', 'quarter', 'is_weekend'];
const SIMILARITY_METHODS = ['ratio', 'token_sort_ratio', 'token_set_ratio'];
const GROUP_AGG_METHODS = ['mean', 'sum', 'count', 'min', 'max', 'std', 'median'];

// --- Helper Components ---

const ColumnSelector: React.FC<{
  columns: string[];
  selected: string[];
  onChange: (selected: string[]) => void;
  label?: string;
  single?: boolean;
}> = ({ columns, selected, onChange, label, single }) => {
  const [search, setSearch] = useState('');
  
  const filtered = columns.filter(c => c.toLowerCase().includes(search.toLowerCase()));

  const toggle = (col: string) => {
    if (single) {
      onChange([col]);
    } else {
      if (selected.includes(col)) {
        onChange(selected.filter(c => c !== col));
      } else {
        onChange([...selected, col]);
      }
    }
  };

  return (
    <div className="space-y-1.5">
      {label && <label className="text-xs font-medium text-muted-foreground">{label}</label>}
      <div className="border rounded bg-background overflow-hidden flex flex-col">
        <div className="flex items-center px-2 py-1.5 border-b bg-muted/20">
          <Search size={12} className="text-muted-foreground mr-1.5" />
          <input
            className="flex-1 bg-transparent text-xs outline-none placeholder:text-muted-foreground/70"
            placeholder="Search columns..."
            value={search}
            onChange={e => { setSearch(e.target.value); }}
          />
        </div>
        <div className="max-h-32 overflow-y-auto p-1 space-y-0.5">
          {filtered.length > 0 ? (
            filtered.map(col => {
              const isSelected = selected.includes(col);
              return (
                <div
                  key={col}
                  onClick={() => { toggle(col); }}
                  className={`
                    flex items-center gap-2 px-2 py-1.5 rounded text-xs cursor-pointer transition-colors
                    ${isSelected ? 'bg-primary/10 text-primary font-medium' : 'hover:bg-accent text-foreground'}
                  `}
                >
                  <div className={`
                    w-3 h-3 rounded border flex items-center justify-center
                    ${isSelected ? 'border-primary bg-primary text-primary-foreground' : 'border-muted-foreground/40'}
                  `}>
                    {isSelected && <Check size={8} strokeWidth={4} />}
                  </div>
                  <span className="truncate">{col}</span>
                </div>
              );
            })
          ) : (
            <div className="p-2 text-xs text-muted-foreground text-center italic">No columns found</div>
          )}
        </div>
      </div>
    </div>
  );
};

const FeatureGenerationSettings: React.FC<{ config: FeatureGenerationConfig; onChange: (c: FeatureGenerationConfig) => void; nodeId?: string }> = ({
  config,
  onChange,
  nodeId,
}) => {
  const upstreamData = useUpstreamData(nodeId || '');
  const datasetId = upstreamData.find(d => d.datasetId)?.datasetId as string | undefined;
  const { data: schema } = useDatasetSchema(datasetId);
  
  const executionResult = useGraphStore((state) => state.executionResult);
  const nodeResult = nodeId ? executionResult?.node_results[nodeId] : null;
  const metrics: Record<string, unknown> | null =
    nodeResult?.metrics && typeof nodeResult.metrics === 'object'
      ? (nodeResult.metrics as Record<string, unknown>)
      : null;
  const generatedFeatures: string[] =
    metrics && Array.isArray(metrics.generated_features)
      ? (metrics.generated_features as unknown[]).map((v) => String(v))
      : [];

  const [showRecommendations, setShowRecommendations] = useState(false);



  const allColumns = schema ? Object.values(schema.columns).map(c => c.name) : [];
  const numericColumns = schema 
    ? Object.values(schema.columns)
        .filter(c => ['int', 'float', 'number'].some(t => c.dtype.toLowerCase().includes(t)))
        .map(c => c.name)
    : [];
  const dateColumns = schema
    ? Object.values(schema.columns)
        .filter(c => ['date', 'time'].some(t => c.dtype.toLowerCase().includes(t)))
        .map(c => c.name)
    : [];
  const stringColumns = schema
    ? Object.values(schema.columns)
        .filter(c => ['string', 'object', 'text'].some(t => c.dtype.toLowerCase().includes(t)))
        .map(c => c.name)
    : [];

  // Recommendations
  const recommendations = useRecommendations(nodeId || '', {
    types: ['feature_generation'],
    suggestedNodeTypes: ['FeatureGenerationNode'],
    scope: 'column'
  });

  const handleApplyRecommendation = (_rec: Recommendation) => {
    // console.log("Applying recommendation:", _rec);
  };

  const addOperation = (type: MathOperation['operation_type']) => {
    const newOp: MathOperation = {
      operation_type: type,
      method: type === 'arithmetic' ? 'add' : 
              type === 'similarity' ? 'ratio' : 
              type === 'group_agg' ? 'mean' : 'year',
      input_columns: [],
      output_column: '',
      datetime_features: type === 'datetime_extract' ? ['year'] : undefined,
      isExpanded: true
    };
    onChange({ operations: [...(config.operations || []), newOp] });
  };

  const updateOperation = (index: number, updates: Partial<MathOperation>) => {
    const newOps = [...(config.operations || [])];
    newOps[index] = { ...newOps[index], ...updates };
    onChange({ operations: newOps });
  };

  const removeOperation = (index: number, e: React.MouseEvent) => {
    e.stopPropagation();
    const newOps = [...(config.operations || [])];
    newOps.splice(index, 1);
    onChange({ operations: newOps });
  };

  const toggleExpand = (index: number) => {
    const newOps = [...(config.operations || [])];
    newOps[index] = { ...newOps[index], isExpanded: !newOps[index].isExpanded };
    onChange({ operations: newOps });
  };

  const generateDefaultName = (op: MathOperation, index: number) => {
    return `${op.operation_type}_${index}`;
  };

  return (
    <div className="flex h-full">
      {/* Left Sidebar: Tools */}
      <div className="w-20 border-r bg-muted/10 flex flex-col items-center py-4 gap-2 overflow-y-auto shrink-0">
        <span className="text-[10px] font-bold text-muted-foreground mb-2 uppercase tracking-wider">Add</span>
        {OPERATION_TYPES.map(t => (
          <button
            key={t.value}
            onClick={() => { addOperation(t.value as MathOperation['operation_type']); }}
            className="flex flex-col items-center justify-center gap-1 p-1.5 rounded-md border bg-card hover:bg-accent hover:border-primary/50 transition-all group w-16 h-14 shadow-sm"
            title={t.label}
          >
            <t.icon size={18} className="text-muted-foreground group-hover:text-primary" />
            <span className="text-[9px] font-medium text-muted-foreground group-hover:text-foreground text-center leading-tight line-clamp-2">
              {t.label.replace(' ', '\n')}
            </span>
          </button>
        ))}
      </div>

      {/* Right Main: Content */}
      <div className="flex-1 flex flex-col min-w-0 bg-background">
      {/* Recommendations Toggle */}
      {recommendations.length > 0 && (
        <div className="border-b bg-muted/10">
          <button 
            onClick={() => { setShowRecommendations(!showRecommendations); }}
            className="w-full flex items-center justify-between px-4 py-2 text-xs font-medium text-muted-foreground hover:text-primary hover:bg-muted/20 transition-colors"
          >
            <div className="flex items-center gap-2">
              <Lightbulb size={14} className={recommendations.length > 0 ? "text-yellow-500" : ""} />
              <span>Recommendations ({recommendations.length})</span>
            </div>
            {showRecommendations ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
          </button>
          
          {showRecommendations && (
            <div className="p-4 bg-muted/5 border-t">
              <RecommendationsPanel
                recommendations={recommendations}
                onApply={handleApplyRecommendation}
                className="mb-0"
              />
            </div>
          )}
        </div>
      )}



      {/* Main Content Area - Scrollable */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 min-h-0">
        {(config.operations || []).map((op, idx) => (
          <div key={idx} className="border rounded-lg bg-card shadow-sm overflow-hidden">
            {/* Header */}
            <div 
              className="flex items-center justify-between px-3 py-2 bg-muted/30 border-b cursor-pointer hover:bg-muted/50 transition-colors"
              onClick={() => { toggleExpand(idx); }}
            >
              <div className="flex items-center gap-2">
                {op.isExpanded ? <ChevronDown size={14} className="text-muted-foreground" /> : <ChevronRight size={14} className="text-muted-foreground" />}
                <span className="text-[10px] font-bold uppercase tracking-wider text-primary bg-primary/10 px-1.5 py-0.5 rounded">
                  {op.operation_type === 'datetime_extract' ? 'Date' : op.operation_type.replace('_', ' ')}
                </span>
                {['arithmetic', 'similarity', 'group_agg'].includes(op.operation_type) && (
                  <select
                    className="text-sm border-none bg-transparent font-semibold focus:ring-0 cursor-pointer hover:text-primary"
                    value={op.method}
                    onClick={(e) => { e.stopPropagation(); }}
                    onChange={(e) => { updateOperation(idx, { method: e.target.value }); }}
                  >
                    {(op.operation_type === 'arithmetic' ? ARITHMETIC_METHODS : 
                      op.operation_type === 'similarity' ? SIMILARITY_METHODS :
                      op.operation_type === 'group_agg' ? GROUP_AGG_METHODS :
                      []).map(m => (
                      <option key={m} value={m}>{m.replace('_', ' ')}</option>
                    ))}
                  </select>
                )}
              </div>
              <button
                onClick={(e) => { removeOperation(idx, e); }}
                className="text-muted-foreground hover:text-destructive transition-colors p-1 rounded-full hover:bg-destructive/10"
              >
                <Trash2 size={14} />
              </button>
            </div>

            {/* Body */}
            {op.isExpanded && (
            <div className="p-3 space-y-4">
              


              {/* ARITHMETIC */}
              {op.operation_type === 'arithmetic' && (
                <div className="flex flex-col gap-3">
                  <div className="text-[10px] text-muted-foreground bg-muted/20 p-1.5 rounded border border-muted/20">
                    {op.method === 'divide' 
                      ? 'Performs row-by-row division (Col A / Col B) for each record.' 
                      : 'Performs row-by-row arithmetic between two columns.'}
                  </div>
                  <ColumnSelector
                    label="Column A (Left Operand)"
                    columns={numericColumns}
                    selected={op.input_columns.slice(0, 1)}
                    onChange={(cols) => { updateOperation(idx, { input_columns: cols }); }}
                    single
                  />
                  
                  <div className="flex items-center gap-2">
                     <div className="h-px bg-border flex-1"></div>
                     <span className="text-lg font-bold text-muted-foreground bg-muted/20 w-8 h-8 rounded flex items-center justify-center">
                      {op.method === 'add' ? '+' : op.method === 'subtract' ? '-' : op.method === 'multiply' ? '×' : '÷'}
                    </span>
                     <div className="h-px bg-border flex-1"></div>
                  </div>

                  <ColumnSelector
                    label="Column B (Right Operand)"
                    columns={numericColumns}
                    selected={op.secondary_columns?.slice(0, 1) || []}
                    onChange={(cols) => { updateOperation(idx, { secondary_columns: cols }); }}
                    single
                  />
                </div>
              )}

              {/* RATIO */}
              {op.operation_type === 'ratio' && (
                <div className="space-y-3">
                  <div className="text-[10px] text-muted-foreground bg-muted/20 p-1.5 rounded border border-muted/20">
                    Calculates aggregate ratio: <strong>Sum(Numerator) / Sum(Denominator)</strong>.
                  </div>
                  <ColumnSelector
                    label="Numerator (Sum)"
                    columns={numericColumns}
                    selected={op.input_columns}
                    onChange={(cols) => { updateOperation(idx, { input_columns: cols }); }}
                  />
                  
                  <div className="relative flex items-center justify-center">
                    <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-dashed"></div></div>
                    <span className="relative bg-card px-2 text-xs text-muted-foreground font-medium">Divided By</span>
                  </div>

                  <ColumnSelector
                    label="Denominator (Sum)"
                    columns={numericColumns}
                    selected={op.secondary_columns || []}
                    onChange={(cols) => { updateOperation(idx, { secondary_columns: cols }); }}
                  />
                </div>
              )}

              {/* SIMILARITY */}
              {op.operation_type === 'similarity' && (
                <div className="flex flex-col gap-3">
                  <div className="text-[10px] text-muted-foreground bg-muted/20 p-1.5 rounded border border-muted/20 space-y-1">
                    <p>Calculates string similarity score (0-100) between two text columns.</p>
                    <ul className="list-disc pl-3 space-y-0.5 opacity-80">
                      <li><strong>Ratio:</strong> Strict character matching (Levenshtein). "apple banana" != "banana apple".</li>
                      <li><strong>Token Sort:</strong> Sorts words alphabetically then compares. "apple banana" == "banana apple".</li>
                      <li><strong>Token Set:</strong> Compares intersection of words. Handles duplicates/subsets well.</li>
                    </ul>
                  </div>
                  <ColumnSelector
                    label="String A"
                    columns={stringColumns}
                    selected={op.input_columns.slice(0, 1)}
                    onChange={(cols) => updateOperation(idx, { input_columns: cols })}
                    single
                  />
                  
                  <div className="flex items-center gap-2">
                     <div className="h-px bg-border flex-1"></div>
                     <span className="text-xs font-bold text-muted-foreground bg-muted/20 px-2 py-1 rounded">vs</span>
                     <div className="h-px bg-border flex-1"></div>
                  </div>

                  <ColumnSelector
                    label="String B"
                    columns={stringColumns}
                    selected={op.secondary_columns?.slice(0, 1) || []}
                    onChange={(cols) => updateOperation(idx, { secondary_columns: cols })}
                    single
                  />
                </div>
              )}

              {/* GROUP AGG */}
              {op.operation_type === 'group_agg' && (
                <div className="space-y-3">
                  <div className="text-[10px] text-muted-foreground bg-muted/20 p-1.5 rounded border border-muted/20">
                    Calculates aggregate statistics (e.g., Mean Salary) grouped by a categorical column (e.g., Department) and assigns it back to each row.
                  </div>
                  <ColumnSelector
                    label="Group By (Categorical)"
                    columns={stringColumns.length > 0 ? stringColumns : allColumns}
                    selected={op.input_columns.slice(0, 1)}
                    onChange={(cols) => updateOperation(idx, { input_columns: cols })}
                    single
                  />
                  
                  <div className="relative flex items-center justify-center">
                    <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-dashed"></div></div>
                    <span className="relative bg-card px-2 text-xs text-muted-foreground font-medium">Target Column</span>
                  </div>

                  <ColumnSelector
                    label="Target (Numeric)"
                    columns={numericColumns}
                    selected={op.secondary_columns?.slice(0, 1) || []}
                    onChange={(cols) => updateOperation(idx, { secondary_columns: cols })}
                    single
                  />
                </div>
              )}

              {/* DATE EXTRACT */}
              {op.operation_type === 'datetime_extract' && (
                <div className="space-y-3">
                  <ColumnSelector
                    label="Date Column"
                    columns={dateColumns.length > 0 ? dateColumns : allColumns}
                    selected={op.input_columns.slice(0, 1)}
                    onChange={(cols) => updateOperation(idx, { input_columns: cols })}
                    single
                  />
                  
                  <div className="space-y-1.5">
                    <label className="text-xs font-medium text-muted-foreground">Features to Extract</label>
                    <div className="grid grid-cols-2 gap-2">
                      {DATE_METHODS.map(method => (
                        <label key={method} className="flex items-center gap-2 text-xs p-1.5 border rounded hover:bg-accent cursor-pointer transition-colors">
                          <input
                            type="checkbox"
                            className="rounded border-muted-foreground/40 text-primary focus:ring-0"
                            checked={(op.datetime_features || []).includes(method)}
                            onChange={(e) => {
                              const current = op.datetime_features || [];
                              const newFeatures = e.target.checked
                                ? [...current, method]
                                : current.filter(f => f !== method);
                              updateOperation(idx, { datetime_features: newFeatures });
                            }}
                          />
                          <span className="capitalize">{method.replace('_', ' ')}</span>
                        </label>
                      ))}
                    </div>
                  </div>
                </div>
              )}

              {/* Output Name */}
              <div className="pt-2">
                <label className="text-[10px] font-medium text-muted-foreground uppercase tracking-wider mb-1 block">Output Column Name</label>
                <input
                  type="text"
                  className="w-full text-xs border rounded px-2 py-1.5 bg-background focus:border-primary focus:ring-1 focus:ring-primary outline-none transition-all"
                  placeholder={generateDefaultName(op, idx)}
                  value={op.output_column || ''}
                  onChange={(e) => { updateOperation(idx, { output_column: e.target.value }); }}
                />
              </div>
            </div>
            )}
          </div>
        ))}

        {(!config.operations || config.operations.length === 0) && (
          <div className="flex flex-col items-center justify-center py-12 border-2 border-dashed rounded-lg bg-muted/5 text-muted-foreground">
            <Calculator size={32} className="mb-2 opacity-20" />
            <p className="text-xs font-medium">No operations added</p>
            <p className="text-[10px] opacity-70">Select a type above to start</p>
          </div>
        )}

        {/* Feedback Section */}
        {metrics && (
          <div className="border rounded-lg bg-muted/10 p-4">
            <div className="flex items-center gap-2 mb-3 text-sm font-semibold text-primary">
              <Activity size={14} />
              <span>Last Run Results</span>
            </div>
            
            <div className="space-y-2 text-xs">
              {generatedFeatures.length > 0 ? (
                <>
                  <div className="flex justify-between items-center">
                    <span className="text-muted-foreground">New Features Created:</span>
                    <span className="font-medium text-primary bg-primary/10 px-2 py-0.5 rounded-full">
                      {generatedFeatures.length}
                    </span>
                  </div>
                  
                  <div className="pt-2">
                    <span className="text-[10px] text-muted-foreground uppercase tracking-wider font-semibold mb-1.5 block">Generated Columns</span>
                    <div className="flex flex-wrap gap-1.5">
                      {generatedFeatures.map((f) => (
                        <span key={f} className="px-2 py-1 bg-background border rounded text-[10px] font-mono text-foreground shadow-sm">
                          {f}
                        </span>
                      ))}
                    </div>
                  </div>
                </>
              ) : (
                <div className="flex items-center gap-2 text-muted-foreground italic">
                  <Info size={12} />
                  <span>No features generated in last run.</span>
                </div>
              )}
            </div>
          </div>
        )}
      </div>
      </div>
    </div>
  );
};

export const FeatureGenerationNode: NodeDefinition = {
  type: 'FeatureGenerationNode',
  label: 'Feature Generation',
  description: 'Create new features via math, stats, or date extraction.',
  icon: Calculator,
  category: 'Preprocessing',
  inputs: [{ id: 'in', type: 'dataset', label: 'Dataset' }],
  outputs: [{ id: 'out', type: 'dataset', label: 'Enhanced' }],
  validate: (config: FeatureGenerationConfig) => {
    if (!config.operations?.length) {
      return { isValid: false, message: 'Add at least one operation.' };
    }
    for (const op of config.operations) {

      if (op.operation_type === 'arithmetic' && (op.input_columns.length === 0 || (!op.secondary_columns?.length && !op.constants?.length))) {
        return { isValid: false, message: 'Arithmetic requires two operands.' };
      }
      if (op.operation_type === 'datetime_extract' && op.input_columns.length === 0) {
        return { isValid: false, message: 'Select a date column.' };
      }
      if (op.operation_type === 'group_agg' && (op.input_columns.length === 0 || !op.secondary_columns?.length)) {
        return { isValid: false, message: 'Select both Group By and Target columns.' };
      }
    }
    return { isValid: true };
  },
  settings: FeatureGenerationSettings,
  getDefaultConfig: () => ({
    operations: []
  })
};

import React, { useState, useRef, useEffect } from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { Filter } from 'lucide-react';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';
import { useGraphStore } from '../../../core/store/useGraphStore';
import { getIncomers } from '@xyflow/react';

interface FeatureSelectionConfig {
  method: 
    | 'variance_threshold' 
    | 'correlation_threshold'
    | 'select_k_best' 
    | 'select_percentile' 
    | 'select_fpr' 
    | 'select_fdr' 
    | 'select_fwe' 
    | 'generic_univariate_select'
    | 'select_from_model' 
    | 'rfe';
  
  // Common
  target_column?: string;
  datasetId?: string;
  problem_type?: 'auto' | 'classification' | 'regression';

  // Method Specific
  threshold?: number | string; // Variance, Correlation, SelectFromModel (can be "median")
  correlation_method?: 'pearson' | 'kendall' | 'spearman';
  k?: number; // SelectKBest, RFE
  percentile?: number; // SelectPercentile
  alpha?: number; // FPR, FDR, FWE
  score_func?: string; // Univariate methods
  mode?: 'k_best' | 'percentile' | 'fpr' | 'fdr' | 'fwe'; // Generic
  param?: number; // Generic
  estimator?: 'RandomForest' | 'LogisticRegression' | 'LinearRegression' | 'auto'; // Model based
  step?: number; // RFE
  drop_columns?: boolean;
}

const FeatureSelectionSettings: React.FC<{ config: FeatureSelectionConfig; onChange: (c: FeatureSelectionConfig) => void; nodeId?: string }> = ({
  config,
  onChange,
  nodeId,
}) => {
  const upstreamData = useUpstreamData(nodeId || '');
  
  // Recursive search for datasetId
  const nodes = useGraphStore((state) => state.nodes);
  const edges = useGraphStore((state) => state.edges);
  const executionResult = useGraphStore((state) => state.executionResult);

  const findUpstreamDatasetId = (currentNodeId: string): string | undefined => {
    const visited = new Set<string>();
    const queue = [currentNodeId];
    
    while (queue.length > 0) {
      const id = queue.shift();
      if (!id) continue;
      if (visited.has(id)) continue;
      visited.add(id);
      
      const node = nodes.find(n => n.id === id);
      if (!node) continue;
      
      // If this is NOT the current node, check if it has datasetId
      if (id !== currentNodeId && node.data?.datasetId) {
        return node.data.datasetId as string;
      }
      
      const incomers = getIncomers(node, nodes, edges);
      for (const incomer of incomers) {
        queue.push(incomer.id);
      }
    }
    return undefined;
  };

  const upstreamDatasetId = findUpstreamDatasetId(nodeId || '');
  const upstreamTargetColumn = upstreamData.find((d: Record<string, unknown>) => d.target_column)?.target_column as string | undefined;

  // Auto-detect target and dataset
  useEffect(() => {
    const updates: Partial<FeatureSelectionConfig> = {};
    if (upstreamDatasetId && config.datasetId !== upstreamDatasetId) {
      updates.datasetId = upstreamDatasetId;
    }
    if (upstreamTargetColumn && config.target_column !== upstreamTargetColumn) {
      updates.target_column = upstreamTargetColumn;
    }
    if (Object.keys(updates).length > 0) {
      onChange({ ...config, ...updates });
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [upstreamDatasetId, upstreamTargetColumn, config.datasetId, config.target_column, onChange]);

  const { data: schema, isLoading } = useDatasetSchema(upstreamDatasetId || config.datasetId);
  const columns = schema ? Object.values(schema.columns).map(c => c.name) : [];

  // Responsive Layout
  const containerRef = useRef<HTMLDivElement>(null);
  const [isWide, setIsWide] = useState(false);

  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setIsWide(entry.contentRect.width > 450);
      }
    });
    observer.observe(containerRef.current);
    return () => { observer.disconnect(); };
  }, []);

  // Helper to determine available score functions based on problem type
  const getScoreFunctions = () => {
    const type = config.problem_type || 'auto';
    if (type === 'classification') {
      return [
        { value: 'f_classif', label: 'ANOVA F-value' },
        { value: 'mutual_info_classif', label: 'Mutual Information' },
        { value: 'chi2', label: 'Chi-squared' },
      ];
    } else if (type === 'regression') {
      return [
        { value: 'f_regression', label: 'F-value' },
        { value: 'mutual_info_regression', label: 'Mutual Information' },
        { value: 'r_regression', label: 'Pearson Correlation' },
      ];
    }
    return [
      { value: 'f_classif', label: 'ANOVA F-value (Classif)' },
      { value: 'f_regression', label: 'F-value (Reg)' },
      { value: 'mutual_info_classif', label: 'Mutual Info (Classif)' },
      { value: 'mutual_info_regression', label: 'Mutual Info (Reg)' },
    ];
  };

  const isUnivariate = [
    'select_k_best', 'select_percentile', 'select_fpr', 'select_fdr', 'select_fwe', 'generic_univariate_select'
  ].includes(config.method);

  const isModelBased = ['select_from_model', 'rfe'].includes(config.method);

  const renderFeedback = () => {
    const result = executionResult?.node_results[nodeId || ''];
    if (!result) return null;
    
    const metrics = result.metrics || {};
    const dropped = metrics.dropped_columns as string[] | undefined;
    const scores = metrics.feature_scores as Record<string, number> | undefined;
    const pvalues = metrics.p_values as Record<string, number> | undefined;
    const importances = metrics.feature_importances as Record<string, number> | undefined;
    const variances = metrics.variances as Record<string, number> | undefined;
    const ranking = metrics.ranking as Record<string, number> | undefined;
    
    return (
      <div className="mt-4 p-3 bg-muted/50 rounded border text-xs space-y-3">
        <div className="font-medium text-muted-foreground">Execution Feedback</div>
        
        {result.error && (
          <div className="p-2 bg-destructive/10 text-destructive rounded border border-destructive/20">
            {result.error}
          </div>
        )}

        {/* Dropped Columns Section */}
        {dropped && dropped.length > 0 ? (
          <div>
            <div className="font-medium text-muted-foreground mb-1 flex justify-between items-center">
               <span>Dropped Columns ({dropped.length})</span>
            </div>
            <div className="max-h-40 overflow-y-auto bg-background p-2 rounded border space-y-1">
              {dropped.map(col => {
                const score = scores?.[col];
                const pval = pvalues?.[col];
                const imp = importances?.[col];
                const variance = variances?.[col];
                const rank = ranking?.[col];
                
                return (
                  <div key={col} className="flex justify-between items-center border-b border-border/50 last:border-0 pb-1 last:pb-0">
                    <span className="truncate max-w-[120px] font-medium text-destructive" title={col}>{col}</span>
                    <div className="flex flex-col items-end text-[10px] text-muted-foreground">
                      {score !== undefined && <span>Score: {score.toFixed(4)}</span>}
                      {pval !== undefined && <span>p-val: {pval.toExponential(2)}</span>}
                      {imp !== undefined && <span>Imp: {imp.toFixed(4)}</span>}
                      {variance !== undefined && <span>Var: {variance.toFixed(4)}</span>}
                      {rank !== undefined && <span>Rank: {rank}</span>}
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        ) : (
           result.status === 'success' && (
             <div className="text-green-600 text-[10px] space-y-1">
               <div>No columns were dropped.</div>
               {config.method === 'variance_threshold' && (
                 <div className="text-muted-foreground italic">
                   All features have variance &gt; {config.threshold ?? 0}. Try increasing the threshold.
                 </div>
               )}
               {config.method === 'select_k_best' && (
                 <div className="text-muted-foreground italic">
                   K ({config.k ?? 10}) is likely larger than or equal to the number of features. Try reducing K.
                 </div>
               )}
               {config.method === 'correlation_threshold' && (
                 <div className="text-muted-foreground italic">
                   No feature pairs found with correlation &gt; {config.threshold ?? 0.95}.
                 </div>
               )}
             </div>
           )
        )}

        {/* Top Features Section */}
        {(scores || importances) && (
           <div>
             <div className="font-medium text-muted-foreground mb-1">Top 5 Features</div>
             <div className="max-h-32 overflow-y-auto bg-background p-2 rounded border space-y-1">
                {Object.entries(scores || importances || {})
                   .sort(([, a], [, b]) => (b as number) - (a as number))
                   .slice(0, 5)
                   .map(([col, val]) => (
                     <div key={col} className="flex justify-between items-center">
                        <span className="truncate max-w-[120px]" title={col}>{col}</span>
                        <span className="font-mono text-[10px]">{(val as number).toFixed(4)}</span>
                     </div>
                   ))
                }
             </div>
           </div>
        )}
      </div>
    );
  };

  return (
    <div ref={containerRef} className={`flex flex-col h-full w-full bg-background ${isWide ? 'overflow-hidden' : 'overflow-y-auto'}`}>
      {/* Top Status Bar */}
      <div className="shrink-0 p-4 pb-0 space-y-2">
        {!upstreamDatasetId && (
          <div className="p-2 bg-yellow-50 text-yellow-800 text-xs rounded border border-yellow-200">
            Connect a dataset node to configure.
          </div>
        )}
        {isLoading && !!upstreamDatasetId && (
          <div className="text-xs text-muted-foreground animate-pulse">Loading schema...</div>
        )}
      </div>

      {/* Main Content */}
      <div className={`flex-1 min-h-0 p-4 gap-4 ${isWide ? 'grid grid-cols-2' : 'flex flex-col'}`}>
        
        {/* Left Column: Method & Target */}
        <div className={`space-y-4 ${isWide ? 'overflow-y-auto pr-2' : 'shrink-0'}`}>
          <div className="space-y-2">
            <label className="text-sm font-medium">Selection Method</label>
            <select
              className="w-full p-2 border rounded bg-background text-sm"
              value={config.method}
              onChange={(e) => onChange({ ...config, method: e.target.value as FeatureSelectionConfig['method'] })}
            >
              <optgroup label="Simple">
                <option value="variance_threshold">Variance Threshold</option>
                <option value="correlation_threshold">Correlation Threshold</option>
              </optgroup>
              <optgroup label="Univariate">
                <option value="select_k_best">Select K Best</option>
                <option value="select_percentile">Select Percentile</option>
                <option value="select_fpr">False Positive Rate (FPR)</option>
                <option value="select_fdr">False Discovery Rate (FDR)</option>
                <option value="select_fwe">Family-wise Error (FWE)</option>
                <option value="generic_univariate_select">Generic Univariate</option>
              </optgroup>
              <optgroup label="Model Based">
                <option value="select_from_model">Select From Model</option>
                <option value="rfe">Recursive Feature Elimination (RFE)</option>
              </optgroup>
            </select>
          </div>

          {config.method !== 'variance_threshold' && config.method !== 'correlation_threshold' && (
            <div className="space-y-2">
              <label className="text-sm font-medium">Target Column</label>
              {upstreamTargetColumn ? (
                <div className="p-2 bg-muted rounded text-sm text-muted-foreground border">
                  {upstreamTargetColumn} <span className="text-xs italic">(Auto-detected)</span>
                </div>
              ) : (
                <select
                  className="w-full p-2 border rounded bg-background text-sm"
                  value={config.target_column ?? ''}
                  onChange={(e) => onChange({ ...config, target_column: e.target.value })}
                >
                  <option value="">Select Target...</option>
                  {columns.map(col => (
                    <option key={col} value={col}>{col}</option>
                  ))}
                </select>
              )}
              <p className="text-xs text-muted-foreground">Required for supervised selection methods.</p>
            </div>
          )}

          {(isUnivariate || isModelBased) && (
             <div className="space-y-2">
               <label className="text-sm font-medium">Problem Type</label>
               <select
                 className="w-full p-2 border rounded bg-background text-sm"
                 value={config.problem_type ?? 'auto'}
                 onChange={(e) => onChange({ ...config, problem_type: e.target.value as FeatureSelectionConfig['problem_type'] })}
               >
                 <option value="auto">Auto-detect</option>
                 <option value="classification">Classification</option>
                 <option value="regression">Regression</option>
               </select>
             </div>
          )}
          
          {/* Feedback Section - Show here if wide (Left Column) */}
          {isWide && renderFeedback()}
        </div>

        {/* Right Column: Parameters */}
        <div className={`space-y-4 ${isWide ? 'overflow-y-auto pl-2 border-l' : 'shrink-0 border-t pt-4'}`}>
          <h4 className="text-xs font-semibold uppercase text-muted-foreground mb-2">Parameters</h4>
          
          {/* Variance Threshold */}
          {config.method === 'variance_threshold' && (
            <div className="space-y-2">
              <label className="text-sm font-medium">Threshold</label>
              <input
                type="number"
                step="0.01"
                className="w-full p-2 border rounded bg-background text-sm"
                value={config.threshold ?? 0}
                onChange={(e) => onChange({ ...config, threshold: parseFloat(e.target.value) })}
              />
              <p className="text-xs text-muted-foreground">Features with variance lower than this will be removed.</p>
            </div>
          )}

          {/* Correlation Threshold */}
          {config.method === 'correlation_threshold' && (
            <>
              <div className="space-y-2">
                <label className="text-sm font-medium">Threshold</label>
                <input
                  type="number"
                  step="0.01"
                  max="1"
                  min="0"
                  className="w-full p-2 border rounded bg-background text-sm"
                  value={config.threshold ?? 0.95}
                  onChange={(e) => onChange({ ...config, threshold: parseFloat(e.target.value) })}
                />
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium">Method</label>
                <select
                  className="w-full p-2 border rounded bg-background text-sm"
                  value={config.correlation_method ?? 'pearson'}
                  onChange={(e) => onChange({ ...config, correlation_method: e.target.value as FeatureSelectionConfig['correlation_method'] })}
                >
                  <option value="pearson">Pearson</option>
                  <option value="spearman">Spearman</option>
                  <option value="kendall">Kendall</option>
                </select>
              </div>
            </>
          )}

          {/* Univariate Common: Score Function */}
          {isUnivariate && (
            <div className="space-y-2">
              <label className="text-sm font-medium">Scoring Function</label>
              <select
                className="w-full p-2 border rounded bg-background text-sm"
                value={config.score_func ?? ''}
                onChange={(e) => onChange({ ...config, score_func: e.target.value })}
              >
                <option value="">Auto (Default)</option>
                {getScoreFunctions().map(f => (
                  <option key={f.value} value={f.value}>{f.label}</option>
                ))}
              </select>
            </div>
          )}

          {/* K Best / RFE */}
          {(config.method === 'select_k_best' || config.method === 'rfe') && (
            <div className="space-y-2">
              <label className="text-sm font-medium">K (Number of Features)</label>
              <input
                type="number"
                className="w-full p-2 border rounded bg-background text-sm"
                value={config.k ?? 10}
                onChange={(e) => onChange({ ...config, k: parseInt(e.target.value) })}
              />
            </div>
          )}

          {/* Percentile */}
          {config.method === 'select_percentile' && (
            <div className="space-y-2">
              <label className="text-sm font-medium">Percentile</label>
              <input
                type="number"
                className="w-full p-2 border rounded bg-background text-sm"
                value={config.percentile ?? 10}
                onChange={(e) => onChange({ ...config, percentile: parseInt(e.target.value) })}
              />
            </div>
          )}

          {/* Alpha (FPR, FDR, FWE) */}
          {['select_fpr', 'select_fdr', 'select_fwe'].includes(config.method) && (
            <div className="space-y-2">
              <label className="text-sm font-medium">Alpha (Significance)</label>
              <input
                type="number"
                step="0.001"
                className="w-full p-2 border rounded bg-background text-sm"
                value={config.alpha ?? 0.05}
                onChange={(e) => onChange({ ...config, alpha: parseFloat(e.target.value) })}
              />
            </div>
          )}

          {/* Generic Univariate */}
          {config.method === 'generic_univariate_select' && (
            <>
              <div className="space-y-2">
                <label className="text-sm font-medium">Mode</label>
                <select
                  className="w-full p-2 border rounded bg-background text-sm"
                  value={config.mode ?? 'k_best'}
                  onChange={(e) => onChange({ ...config, mode: e.target.value as FeatureSelectionConfig['mode'] })}
                >
                  <option value="k_best">K Best</option>
                  <option value="percentile">Percentile</option>
                  <option value="fpr">FPR</option>
                  <option value="fdr">FDR</option>
                  <option value="fwe">FWE</option>
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-medium">Parameter</label>
                <input
                  type="number"
                  step="0.001"
                  className="w-full p-2 border rounded bg-background text-sm"
                  value={config.param ?? 1e-5}
                  onChange={(e) => onChange({ ...config, param: parseFloat(e.target.value) })}
                />
                <p className="text-xs text-muted-foreground">Value for the selected mode (e.g., k, percentile, or alpha).</p>
              </div>
            </>
          )}

          {/* Model Based Common */}
          {isModelBased && (
            <div className="space-y-2">
              <label className="text-sm font-medium">Estimator</label>
              <select
                className="w-full p-2 border rounded bg-background text-sm"
                value={config.estimator ?? 'auto'}
                onChange={(e) => onChange({ ...config, estimator: e.target.value as FeatureSelectionConfig['estimator'] })}
              >
                <option value="auto">Auto</option>
                <option value="RandomForest">Random Forest</option>
                <option value="LogisticRegression">Logistic Regression</option>
                <option value="LinearRegression">Linear Regression</option>
              </select>
            </div>
          )}

          {/* Select From Model Specific */}
          {config.method === 'select_from_model' && (
            <div className="space-y-2">
              <label className="text-sm font-medium">Threshold</label>
              <input
                type="text"
                className="w-full p-2 border rounded bg-background text-sm"
                placeholder="e.g., median, mean, 1.25*mean"
                value={config.threshold ?? 'median'}
                onChange={(e) => onChange({ ...config, threshold: e.target.value })}
              />
              <p className="text-xs text-muted-foreground">String (e.g. "median") or float.</p>
            </div>
          )}

          {/* RFE Specific */}
          {config.method === 'rfe' && (
            <div className="space-y-2">
              <label className="text-sm font-medium">Step</label>
              <input
                type="number"
                min="1"
                className="w-full p-2 border rounded bg-background text-sm"
                value={config.step ?? 1}
                onChange={(e) => onChange({ ...config, step: parseInt(e.target.value) })}
              />
              <p className="text-xs text-muted-foreground">Features to remove at each iteration.</p>
            </div>
          )}

          {/* Drop Columns Checkbox */}
          <div className="flex items-center space-x-2 pt-2 border-t">
            <input
              type="checkbox"
              id="drop_columns"
              className="rounded border-gray-300"
              checked={config.drop_columns !== false}
              onChange={(e) => onChange({ ...config, drop_columns: e.target.checked })}
            />
            <label htmlFor="drop_columns" className="text-sm font-medium">
              Drop Columns
            </label>
          </div>
          <p className="text-xs text-muted-foreground">
            If unchecked, columns will be identified but not removed from the dataset.
          </p>

          {/* Feedback Section - Show here if NOT wide (Mobile/Narrow) */}
          {!isWide && renderFeedback()}
        </div>
      </div>
    </div>
  );
};

export const FeatureSelectionNode: NodeDefinition<FeatureSelectionConfig> = {
  type: 'feature_selection',
  label: 'Feature Selection',
  category: 'Preprocessing',
  description: 'Select the most important features.',
  icon: Filter,
  inputs: [{ id: 'in', label: 'Data', type: 'dataset' }],
  outputs: [{ id: 'out', label: 'Selected', type: 'dataset' }],
  settings: FeatureSelectionSettings,
  validate: (config) => {
    if (config.method !== 'variance_threshold' && !config.target_column) {
      return { isValid: false, message: 'Target column is required for this method.' };
    }
    return { isValid: true };
  },
  getDefaultConfig: () => ({
    method: 'select_k_best',
    k: 10,
  }),
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { PaintBucket } from 'lucide-react';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';
import { useRecommendations } from '../../../core/hooks/useRecommendations';
import { RecommendationsPanel } from '../../../components/panels/RecommendationsPanel';
import { Recommendation } from '../../../core/api/client';
import { useGraphStore } from '../../../core/store/useGraphStore';

interface ImputationConfig {
  columns: string[];
  method: 'simple' | 'knn' | 'iterative';
  
  // Simple Imputer
  strategy: 'mean' | 'median' | 'most_frequent' | 'constant';
  fill_value?: string | number;

  // KNN Imputer
  n_neighbors?: number;
  weights?: 'uniform' | 'distance';

  // Iterative Imputer
  max_iter?: number;
  estimator?: 'bayesian_ridge' | 'decision_tree' | 'extra_trees' | 'knn';
  random_state?: number;
}

const ImputationSettings: React.FC<{ config: ImputationConfig; onChange: (c: ImputationConfig) => void; nodeId?: string }> = ({
  config,
  onChange,
  nodeId,
}) => {
  const upstreamData = useUpstreamData(nodeId || '');
  const datasetId = upstreamData.find(d => d.datasetId)?.datasetId as string | undefined;
  const { data: schema, isLoading } = useDatasetSchema(datasetId);
  const availableColumns = useMemo(() => schema ? Object.values(schema.columns).map(c => c.name) : [], [schema]);
  
  const executionResult = useGraphStore((state) => state.executionResult);
  const nodeResult = nodeId ? executionResult?.node_results[nodeId] : null;
  const metrics: Record<string, unknown> | null =
    nodeResult?.metrics && typeof nodeResult.metrics === 'object'
      ? (nodeResult.metrics as Record<string, unknown>)
      : null;
  const fillValues: Record<string, unknown> | null =
    metrics?.fill_values && typeof metrics.fill_values === 'object'
      ? (metrics.fill_values as Record<string, unknown>)
      : null;
  const missingCounts: Record<string, unknown> | null =
    metrics?.missing_counts && typeof metrics.missing_counts === 'object'
      ? (metrics.missing_counts as Record<string, unknown>)
      : null;

  // Responsive Layout Logic
  const containerRef = useRef<HTMLDivElement>(null);
  const [isWide, setIsWide] = useState(false);

  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setIsWide(entry.contentRect.width > 450);
      }
    });
    observer.observe(containerRef.current);
    return () => { observer.disconnect(); };
  }, []);
  
  const recommendations = useRecommendations(nodeId || '', {
    types: ['imputation'],
    suggestedNodeTypes: ['SimpleImputer', 'KNNImputer', 'IterativeImputer'],
    scope: 'column'
  });

  const handleApplyRecommendation = (rec: Recommendation) => {
    if (rec.target_columns.length > 0) {
      const newCols = Array.from(new Set([...config.columns, ...rec.target_columns]));
      // Apply strategy if recommended (assuming recommendation might contain params)
      // For now just columns
      onChange({ ...config, columns: newCols });
    }
  };
  
  const [searchTerm, setSearchTerm] = useState('');

  const filteredColumns = useMemo(() => {
    return availableColumns.filter(c => c.toLowerCase().includes(searchTerm.toLowerCase()));
  }, [availableColumns, searchTerm]);

  const handleSelectAll = () => {
    onChange({ ...config, columns: filteredColumns });
  };

  const handleDeselectAll = () => {
    const newCols = config.columns.filter(c => !filteredColumns.includes(c));
    onChange({ ...config, columns: newCols });
  };

  const renderFeedback = () => (
    metrics ? (
      <div className="mt-4 p-3 bg-muted/50 rounded border text-xs">
        <div className="font-medium text-muted-foreground mb-2">Execution Feedback</div>
        
        {fillValues && (
          <div className="space-y-1">
            <span className="text-muted-foreground block mb-1 font-medium">Imputed Values:</span>
            <div className="grid grid-cols-2 gap-x-4 gap-y-1 max-h-32 overflow-y-auto">
              {Object.entries(fillValues).map(([col, val]) => (
                <div key={col} className="flex justify-between text-[10px]">
                  <span className="truncate max-w-[100px]" title={col}>{col}:</span>
                  <span className="font-mono">{typeof val === 'number' ? val.toFixed(4) : String(val)}</span>
                </div>
              ))}
            </div>
          </div>
        )}

        {missingCounts && (
          <div className="space-y-1 mt-2">
            <span className="text-muted-foreground block mb-1 font-medium">Missing Values Filled:</span>
            <div className="grid grid-cols-2 gap-x-4 gap-y-1 max-h-32 overflow-y-auto">
              {Object.entries(missingCounts).map(([col, count]) => (
                <div key={col} className="flex justify-between text-[10px]">
                  <span className="truncate max-w-[100px]" title={col}>{col}:</span>
                  <span className="font-mono">{String(count)}</span>
                </div>
              ))}
            </div>
            {metrics.total_missing !== undefined && (
               <div className="text-[10px] text-muted-foreground mt-1 pt-1 border-t">
                  Total Filled: <span className="font-mono font-medium">{String(metrics.total_missing)}</span>
               </div>
            )}
          </div>
        )}
        
        {/* Generic success message if no specific metrics but successful */}
        {!fillValues && !missingCounts && nodeResult?.status === 'success' && (
          <div className="text-green-600">Imputation completed successfully.</div>
        )}
      </div>
    ) : null
  );

  return (
    <div ref={containerRef} className={`flex flex-col h-full w-full bg-background ${isWide ? 'overflow-hidden' : 'overflow-y-auto'}`}>
      {/* Top Status Bar */}
      <div className="shrink-0 p-4 pb-0 space-y-2">
        {!datasetId && (
          <div className="p-2 bg-yellow-50 text-yellow-800 text-xs rounded border border-yellow-200">
            Connect a dataset node to see available columns.
          </div>
        )}
        
        {isLoading && !!datasetId && (
          <div className="text-xs text-muted-foreground animate-pulse">
            Loading schema...
          </div>
        )}
      </div>

      {/* Main Content Area */}
      <div className={`flex-1 min-h-0 p-4 gap-4 ${isWide ? 'grid grid-cols-2' : 'flex flex-col'}`}>
        
        {/* Left Column (Settings) */}
        <div className={`space-y-4 ${isWide ? 'overflow-y-auto pr-2' : 'shrink-0'}`}>
          {/* Recommendations */}
          {recommendations.length > 0 && (
            <div className="shrink-0">
              <RecommendationsPanel 
                recommendations={recommendations} 
                onApply={handleApplyRecommendation}
              />
            </div>
          )}

          <div>
            <label className="block text-sm font-medium mb-1">Imputation Method</label>
            <select
              className="w-full p-2 border rounded bg-background text-sm"
              value={config.method || 'simple'}
              onChange={(e) => onChange({ ...config, method: e.target.value as ImputationConfig['method'] })}
            >
              <option value="simple">Simple Imputer (Univariate)</option>
              <option value="knn">KNN Imputer (Multivariate)</option>
              <option value="iterative">Iterative Imputer (MICE)</option>
            </select>
          </div>

          {/* Simple Imputer Settings */}
          {(config.method === 'simple' || !config.method) && (
            <>
              <div>
                <label className="block text-sm font-medium mb-1">Strategy</label>
                <select
                  className="w-full p-2 border rounded bg-background text-sm"
                  value={config.strategy}
                  onChange={(e) => onChange({ ...config, strategy: e.target.value as ImputationConfig['strategy'] })}
                >
                  <option value="mean">Mean (Average)</option>
                  <option value="median">Median (Middle Value)</option>
                  <option value="most_frequent">Most Frequent (Mode)</option>
                  <option value="constant">Constant Value</option>
                </select>
                <p className="text-[10px] text-muted-foreground mt-1">
                  {config.strategy === 'mean' && 'Replaces missing values with the mean of the column. (Numeric only)'}
                  {config.strategy === 'median' && 'Replaces missing values with the median. (Robust to outliers)'}
                  {config.strategy === 'most_frequent' && 'Replaces missing with the most common value. (Categorical/Numeric)'}
                  {config.strategy === 'constant' && 'Replaces missing values with a specific value.'}
                </p>
              </div>

              {config.strategy === 'constant' && (
                <div>
                  <label className="block text-sm font-medium mb-1">Fill Value</label>
                  <input
                    type="text"
                    className="w-full p-2 border rounded bg-background text-sm"
                    value={config.fill_value || ''}
                    onChange={(e) => onChange({ ...config, fill_value: e.target.value })}
                    placeholder="Enter value..."
                  />
                </div>
              )}
            </>
          )}

          {/* KNN Imputer Settings */}
          {config.method === 'knn' && (
            <>
              <div>
                <label className="block text-sm font-medium mb-1">Number of Neighbors</label>
                <input
                  type="number"
                  min="1"
                  className="w-full p-2 border rounded bg-background text-sm"
                  value={config.n_neighbors || 5}
                  onChange={(e) => onChange({ ...config, n_neighbors: parseInt(e.target.value) })}
                />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">Weights</label>
                <select
                  className="w-full p-2 border rounded bg-background text-sm"
                  value={config.weights || 'uniform'}
                  onChange={(e) => onChange({ ...config, weights: e.target.value as ImputationConfig['weights'] })}
                >
                  <option value="uniform">Uniform</option>
                  <option value="distance">Distance</option>
                </select>
                <p className="text-[10px] text-muted-foreground mt-1">
                  Uniform: All points in each neighborhood are weighted equally.
                  Distance: Weight points by the inverse of their distance.
                </p>
              </div>
            </>
          )}

          {/* Iterative Imputer Settings */}
          {config.method === 'iterative' && (
            <>
              <div>
                <label className="block text-sm font-medium mb-1">Max Iterations</label>
                <input
                  type="number"
                  min="1"
                  className="w-full p-2 border rounded bg-background text-sm"
                  value={config.max_iter || 10}
                  onChange={(e) => onChange({ ...config, max_iter: parseInt(e.target.value) })}
                />
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">Estimator</label>
                <select
                  className="w-full p-2 border rounded bg-background text-sm"
                  value={config.estimator || 'bayesian_ridge'}
                  onChange={(e) => onChange({ ...config, estimator: e.target.value as ImputationConfig['estimator'] })}
                >
                  <option value="bayesian_ridge">Bayesian Ridge</option>
                  <option value="decision_tree">Decision Tree</option>
                  <option value="extra_trees">Extra Trees</option>
                  <option value="knn">KNN</option>
                </select>
                <p className="text-[10px] text-muted-foreground mt-1">
                  The estimator to use for the imputation steps.
                </p>
              </div>
              <div>
                <label className="block text-sm font-medium mb-1">Random State</label>
                <input
                  type="number"
                  className="w-full p-2 border rounded bg-background text-sm"
                  value={config.random_state ?? 0}
                  onChange={(e) => onChange({ ...config, random_state: parseInt(e.target.value) })}
                />
              </div>
            </>
          )}

          {/* Feedback Section - Only show here if wide */}
          {isWide && renderFeedback()}
        </div>

        {/* Right Column (Column Selection) */}
        <div className={`flex flex-col h-full min-h-[200px] border rounded-md overflow-hidden ${isWide ? '' : 'shrink-0'}`}>
          <div className="p-2 border-b bg-muted/30 flex flex-col gap-2">
            <div className="flex items-center justify-between">
              <span className="text-xs font-medium text-muted-foreground">Target Columns ({config.columns.length})</span>
              <div className="flex gap-1">
                <button onClick={handleSelectAll} className="text-[10px] px-2 py-1 hover:bg-accent rounded">All</button>
                <button onClick={handleDeselectAll} className="text-[10px] px-2 py-1 hover:bg-accent rounded">None</button>
              </div>
            </div>
            <input
              type="text"
              placeholder="Search columns..."
              className="w-full text-xs p-1.5 border rounded bg-background"
              value={searchTerm}
              onChange={(e) => { setSearchTerm(e.target.value); }}
            />
          </div>
          
          <div className="flex-1 overflow-y-auto p-2 space-y-1">
            {filteredColumns.length > 0 ? (
              filteredColumns.map(col => (
                <label key={col} className="flex items-center justify-between gap-2 text-sm hover:bg-accent/50 p-1.5 rounded cursor-pointer select-none">
                  <div className="flex items-center gap-2 overflow-hidden">
                    <input
                      type="checkbox"
                      checked={config.columns.includes(col)}
                      onChange={(e) => {
                        const newCols = e.target.checked
                          ? [...config.columns, col]
                          : config.columns.filter(c => c !== col);
                        onChange({ ...config, columns: newCols });
                      }}
                      className="rounded border-gray-300 text-primary focus:ring-primary shrink-0"
                    />
                    <span className="truncate" title={col}>{col}</span>
                  </div>
                  {missingCounts && missingCounts[col] !== undefined && (
                    <span
                      className="text-[10px] text-muted-foreground font-mono shrink-0 bg-muted px-1.5 py-0.5 rounded"
                      title={`${String(missingCounts[col])} missing values filled`}
                    >
                      {String(missingCounts[col])}
                    </span>
                  )}
                </label>
              ))
            ) : (
              <div className="p-4 text-center text-xs text-muted-foreground">
                {availableColumns.length === 0 ? 'No columns available' : 'No matches found'}
              </div>
            )}
          </div>
        </div>
        
        {/* Feedback Section - Show here if NOT wide (mobile/narrow) */}
        {!isWide && renderFeedback()}
      </div>
    </div>
  );
};

export const ImputationNode: NodeDefinition<ImputationConfig> = {
  type: 'imputation_node',
  label: 'Imputation',
  category: 'Preprocessing',
  description: 'Fill missing values using Simple, KNN, or Iterative strategies.',
  icon: PaintBucket,
  inputs: [{ id: 'in', label: 'Data', type: 'dataset' }],
  outputs: [{ id: 'out', label: 'Cleaned Data', type: 'dataset' }],
  settings: ImputationSettings,
  validate: (config) => {
    if (config.columns.length === 0) return { isValid: false, message: 'Select at least one column' };
    if (config.method === 'simple' && config.strategy === 'constant' && (config.fill_value === undefined || config.fill_value === '')) {
      return { isValid: false, message: 'Fill value is required for Constant strategy' };
    }
    return { isValid: true };
  },
  getDefaultConfig: () => ({
    columns: [],
    method: 'simple',
    strategy: 'mean',
    fill_value: 0,
    n_neighbors: 5,
    weights: 'uniform',
    max_iter: 10,
    estimator: 'bayesian_ridge',
    random_state: 0
  })
};

import React, { useState, useRef, useEffect } from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { AlertTriangle, Search, Info, ChevronDown, ChevronUp } from 'lucide-react';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';

// --- Types ---

interface InvalidValueReplacementConfig {
  columns: string[];
  mode: 'negative_to_nan' | 'zero_to_nan' | 'percentage_bounds' | 'age_bounds' | 'custom_range';
  min_value?: number;
  max_value?: number;
}

// --- Components ---

const ColumnSelector: React.FC<{
  columns: string[];
  selected: string[];
  onChange: (selected: string[]) => void;
}> = ({ columns, selected, onChange }) => {
  const [search, setSearch] = useState('');
  
  const filtered = columns.filter(c => c.toLowerCase().includes(search.toLowerCase()));

  const toggle = (col: string) => {
    if (selected.includes(col)) {
      onChange(selected.filter(c => c !== col));
    } else {
      onChange([...selected, col]);
    }
  };

  return (
    <div className="border rounded bg-background overflow-hidden flex flex-col max-h-40">
      <div className="flex items-center px-2 py-1.5 border-b bg-muted/20">
        <Search size={12} className="text-muted-foreground mr-1.5" />
        <input
          className="flex-1 bg-transparent text-xs outline-none placeholder:text-muted-foreground/70"
          placeholder="Search columns..."
          value={search}
          onChange={e => { setSearch(e.target.value); }}
        />
      </div>
      <div className="overflow-y-auto p-1 space-y-0.5">
        {filtered.length > 0 ? (
          filtered.map(col => {
            const isSelected = selected.includes(col);
            return (
              <div
                key={col}
                onClick={() => { toggle(col); }}
                className={`
                  flex items-center gap-2 px-2 py-1.5 rounded text-xs cursor-pointer transition-colors
                  ${isSelected ? 'bg-blue-50 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300 font-medium' : 'hover:bg-gray-100 dark:hover:bg-gray-800 text-gray-700 dark:text-gray-300'}
                `}
              >
                <div className={`
                  w-3 h-3 rounded border flex items-center justify-center
                  ${isSelected ? 'border-blue-500 bg-blue-500 text-white' : 'border-gray-400 dark:border-gray-600'}
                `}>
                  {isSelected && <div className="w-1.5 h-1.5 bg-white rounded-full" />}
                </div>
                <span className="truncate">{col}</span>
              </div>
            );
          })
        ) : (
          <div className="p-2 text-xs text-gray-500 text-center italic">No columns found</div>
        )}
      </div>
    </div>
  );
};

const InvalidValueSettings: React.FC<{ config: InvalidValueReplacementConfig; onChange: (c: InvalidValueReplacementConfig) => void; nodeId?: string }> = ({
  config,
  onChange,
  nodeId,
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [isWide, setIsWide] = useState(false);
  const [showInfo, setShowInfo] = useState(true);

  const upstreamData = useUpstreamData(nodeId || '');
  const datasetId = upstreamData.find((d: unknown) => (d as Record<string, unknown>).datasetId)?.datasetId as string | undefined;
  const { data: schema } = useDatasetSchema(datasetId);
  
  // Filter for numeric columns only
  const numericColumns: string[] = schema 
    ? Object.values(schema.columns)
        .filter((c: unknown) => ['int', 'float', 'number'].some(t => ((c as Record<string, unknown>).dtype as string).toLowerCase().includes(t)))
        .map((c: unknown) => String((c as Record<string, unknown>).name))
    : [];

  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setIsWide(entry.contentRect.width > 400);
      }
    });
    observer.observe(containerRef.current);
    return () => { observer.disconnect(); };
  }, []);

  return (
    <div ref={containerRef} className={`flex flex-col h-full w-full bg-white dark:bg-gray-900 ${isWide ? 'overflow-hidden' : 'overflow-y-auto'}`}>
      <div className={`flex-1 min-h-0 p-4 gap-4 ${isWide ? 'grid grid-cols-2' : 'flex flex-col'}`}>
        
        {/* Left Column: Column Selection */}
        <div className={`space-y-4 ${isWide ? 'overflow-y-auto pr-2' : 'shrink-0'}`}>
          <div>
            <label className="text-sm font-medium text-gray-700 dark:text-gray-300 mb-2 block">
              Target Columns ({config.columns.length})
            </label>
            <ColumnSelector 
              columns={numericColumns} 
              selected={config.columns} 
              onChange={(cols) => onChange({ ...config, columns: cols })} 
            />
            <p className="text-xs text-gray-500 mt-1">Only numeric columns are shown.</p>
          </div>
        </div>

        {/* Right Column: Settings */}
        <div className={`space-y-4 ${isWide ? 'overflow-y-auto pl-2 border-l border-gray-100 dark:border-gray-700' : 'shrink-0 pt-4 border-t border-gray-100 dark:border-gray-700'}`}>
          <div className="bg-blue-50 dark:bg-blue-900/20 rounded-md border border-blue-100 dark:border-blue-800 overflow-hidden">
            <button 
              onClick={() => { setShowInfo(!showInfo); }}
              className="w-full flex items-center gap-2 p-3 text-left hover:bg-blue-100/50 dark:hover:bg-blue-900/30 transition-colors"
            >
              <Info className="text-blue-600 dark:text-blue-400 shrink-0" size={16} />
              <span className="text-xs font-semibold text-blue-800 dark:text-blue-200 flex-1">
                About Invalid Value Replacement
              </span>
              {showInfo ? (
                <ChevronUp size={14} className="text-blue-600 dark:text-blue-400" />
              ) : (
                <ChevronDown size={14} className="text-blue-600 dark:text-blue-400" />
              )}
            </button>
            
            {showInfo && (
              <div className="px-3 pb-3 text-xs text-blue-800 dark:text-blue-200 pl-9">
                <p>Use this node to handle data quality issues by replacing invalid numeric values (like negative ages or out-of-bounds sensor readings) with NaN (Missing).</p>
              </div>
            )}
          </div>

          <div>
            <label className="text-sm font-medium text-gray-700 dark:text-gray-300 mb-2 block">
              Replacement Mode
            </label>
            <select
              className="w-full text-xs rounded border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2"
              value={config.mode}
              onChange={(e) => onChange({ ...config, mode: e.target.value as InvalidValueReplacementConfig['mode'] })}
            >
              <option value="negative_to_nan">Negative to NaN</option>
              <option value="zero_to_nan">Zero to NaN</option>
              <option value="percentage_bounds">Percentage Bounds (0-100)</option>
              <option value="age_bounds">Age Bounds (0-120)</option>
              <option value="custom_range">Custom Range</option>
            </select>
            <p className="text-[10px] text-gray-500 mt-1">
              {config.mode === 'negative_to_nan' && "Replaces all negative values (< 0) with NaN."}
              {config.mode === 'zero_to_nan' && "Replaces all zero values (== 0) with NaN."}
              {config.mode === 'percentage_bounds' && "Replaces values outside 0-100 range with NaN."}
              {config.mode === 'age_bounds' && "Replaces values outside 0-120 range with NaN."}
              {config.mode === 'custom_range' && "Replaces values outside the specified Min/Max range with NaN."}
            </p>
          </div>

          {(config.mode === 'custom_range' || config.mode === 'percentage_bounds' || config.mode === 'age_bounds') && (
            <div className="grid grid-cols-2 gap-2">
              <div>
                <label className="text-[10px] text-gray-500 uppercase font-semibold">Min Value</label>
                <input
                  type="number"
                  className="w-full text-xs rounded border border-gray-300 dark:border-gray-600 px-2 py-1.5"
                  placeholder={config.mode === 'percentage_bounds' ? '0' : 'Min'}
                  value={config.min_value ?? ''}
                  onChange={(e) => onChange({ ...config, min_value: e.target.value ? parseFloat(e.target.value) : undefined })}
                />
              </div>
              <div>
                <label className="text-[10px] text-gray-500 uppercase font-semibold">Max Value</label>
                <input
                  type="number"
                  className="w-full text-xs rounded border border-gray-300 dark:border-gray-600 px-2 py-1.5"
                  placeholder={config.mode === 'percentage_bounds' ? '100' : 'Max'}
                  value={config.max_value ?? ''}
                  onChange={(e) => onChange({ ...config, max_value: e.target.value ? parseFloat(e.target.value) : undefined })}
                />
              </div>
              <p className="col-span-2 text-[10px] text-gray-500">
                Values outside this range will be replaced with NaN.
              </p>
            </div>
          )}
        </div>

      </div>
    </div>
  );
};

export const InvalidValueReplacementNode: NodeDefinition<InvalidValueReplacementConfig> = {
  type: 'InvalidValueReplacement',
  label: 'Invalid Value Replacement',
  category: 'Preprocessing',
  description: 'Replace invalid or out-of-range values with NaN.',
  icon: AlertTriangle,
  inputs: [{ id: 'in', label: 'Data', type: 'dataset' }],
  outputs: [{ id: 'out', label: 'Cleaned Data', type: 'dataset' }],
  settings: InvalidValueSettings,
  validate: (config) => {
    if (config.columns.length === 0) return { isValid: false, message: 'Select at least one column.' };
    if (config.mode === 'custom_range' && config.min_value === undefined && config.max_value === undefined) {
      return { isValid: false, message: 'Specify at least a min or max value for custom range.' };
    }
    return { isValid: true };
  },
  getDefaultConfig: () => ({
    columns: [],
    mode: 'negative_to_nan',
  }),
};

import React, { useState, useMemo } from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { Flag, Activity } from 'lucide-react';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';
import { useGraphStore } from '../../../core/store/useGraphStore';

interface MissingIndicatorConfig {
  columns: string[];
  flag_suffix: string;
}

const MissingIndicatorSettings: React.FC<{ config: MissingIndicatorConfig; onChange: (c: MissingIndicatorConfig) => void; nodeId?: string }> = ({
  config,
  onChange,
  nodeId,
}) => {
  const upstreamData = useUpstreamData(nodeId || '');
  const datasetId = upstreamData.find(d => d.datasetId)?.datasetId as string | undefined;
  const { data: schema, isLoading } = useDatasetSchema(datasetId);
  const availableColumns = useMemo(() => schema ? Object.values(schema.columns).map(c => c.name) : [], [schema]);

  const executionResult = useGraphStore((state) => state.executionResult);
  const nodeResult = nodeId ? executionResult?.node_results[nodeId] : null;
  const metrics = (nodeResult?.metrics && typeof nodeResult.metrics === 'object')
    ? (nodeResult.metrics as Record<string, unknown>)
    : null;

  const [searchTerm, setSearchTerm] = useState('');

  const filteredColumns = useMemo(() => {
    return availableColumns.filter(c => c.toLowerCase().includes(searchTerm.toLowerCase()));
  }, [availableColumns, searchTerm]);

  const handleSelectAll = () => {
    onChange({ ...config, columns: filteredColumns });
  };

  const handleDeselectAll = () => {
    const newCols = config.columns.filter(c => !filteredColumns.includes(c));
    onChange({ ...config, columns: newCols });
  };

  return (
    <div className="p-4 space-y-4">
      {!datasetId && (
        <div className="p-2 bg-yellow-50 text-yellow-800 text-xs rounded border border-yellow-200">
          Connect a dataset node to see available columns.
        </div>
      )}
      
      {isLoading && !!datasetId && (
        <div className="text-xs text-muted-foreground animate-pulse">
          Loading schema...
        </div>
      )}

      <div>
        <label className="block text-sm font-medium mb-1">Indicator Suffix</label>
        <input
          type="text"
          className="w-full p-2 border rounded bg-background focus:ring-1 focus:ring-primary outline-none"
          value={config.flag_suffix}
          onChange={(e) => onChange({ ...config, flag_suffix: e.target.value })}
          placeholder="_was_missing"
        />
        <p className="text-xs text-muted-foreground mt-1">
          Suffix added to the new indicator columns (e.g., "Age_was_missing").
        </p>
      </div>

      <div>
        <div className="flex items-center justify-between mb-2">
          <label className="block text-sm font-medium">Target Columns (Optional)</label>
          <span className="text-xs text-muted-foreground">
            {config.columns.length} selected
          </span>
        </div>
        <p className="text-xs text-muted-foreground mb-2">
          Create indicators for these columns. If empty, all columns with missing values are used.
        </p>

        {/* Search & Actions */}
        <div className="space-y-2 mb-2">
          <input 
            type="text" 
            placeholder="Search columns..." 
            className="block w-full px-3 py-1.5 text-sm bg-background border rounded-md shadow-sm focus:ring-1 focus:ring-primary outline-none"
            value={searchTerm}
            onChange={(e) => { setSearchTerm(e.target.value); }}
          />
          <div className="flex gap-2 text-xs justify-end">
            <button onClick={handleSelectAll} className="text-primary hover:text-primary/80 font-medium transition-colors">Select All</button>
            <span className="text-border">|</span>
            <button onClick={handleDeselectAll} className="text-primary hover:text-primary/80 font-medium transition-colors">Deselect All</button>
          </div>
        </div>

        {availableColumns.length > 0 ? (
          <div className="space-y-1 max-h-40 overflow-y-auto border rounded p-2 bg-background">
            {filteredColumns.map(col => (
              <label key={col} className="flex items-center gap-2 text-sm hover:bg-accent/50 p-1 rounded cursor-pointer">
                <input
                  type="checkbox"
                  className="rounded border-gray-300 text-primary focus:ring-primary"
                  checked={config.columns.includes(col)}
                  onChange={(e) => {
                    const newCols = e.target.checked
                      ? [...config.columns, col]
                      : config.columns.filter(c => c !== col);
                    onChange({ ...config, columns: newCols });
                  }}
                />
                {col}
              </label>
            ))}
            {filteredColumns.length === 0 && (
              <div className="text-xs text-muted-foreground text-center py-2">
                No columns match "{searchTerm}"
              </div>
            )}
          </div>
        ) : (
          <div className="text-xs text-muted-foreground italic border rounded p-4 text-center">
            No columns available
          </div>
        )}
      </div>

      {/* Feedback Section */}
      {(() => {
        const indicatorsCreated = metrics?.missing_indicators_created;
        const indicatorColumns = Array.isArray(metrics?.missing_indicators_columns)
          ? (metrics?.missing_indicators_columns as unknown[])
          : [];

        if (indicatorsCreated === undefined) return null;

        return (
        <div className="mt-4 p-3 bg-muted/30 rounded-md border border-border">
          <div className="flex items-center gap-2 mb-2 text-sm font-semibold text-primary">
            <Activity size={14} />
            <span>Last Run Results</span>
          </div>
          <div className="space-y-1 text-xs">
            <div className="flex justify-between">
              <span className="text-muted-foreground">Indicators Created:</span>
              <span className="font-medium text-primary">{String(indicatorsCreated)}</span>
            </div>
            {indicatorColumns.length > 0 && (
              <div className="pt-1 border-t mt-1">
                <span className="text-muted-foreground block mb-1">New Columns:</span>
                <div className="flex flex-wrap gap-1">
                  {indicatorColumns.map((col: unknown) => {
                    const colKey = String(col);
                    return (
                      <span key={colKey} className="px-1.5 py-0.5 bg-background border rounded text-[10px] font-mono">
                        {colKey}
                      </span>
                    );
                  })}
                </div>
              </div>
            )}
          </div>
        </div>
        );
      })()}
    </div>
  );
};

export const MissingIndicatorNode: NodeDefinition<MissingIndicatorConfig> = {
  type: 'MissingIndicator',
  label: 'Missing Indicator',
  category: 'Preprocessing',
  description: 'Create binary indicators for missing values.',
  icon: Flag,
  inputs: [{ id: 'in', label: 'Data', type: 'dataset' }],
  outputs: [{ id: 'out', label: 'Augmented Data', type: 'dataset' }],
  settings: MissingIndicatorSettings,
  validate: (_config) => ({ isValid: true }),
  getDefaultConfig: () => ({
    columns: [],
    flag_suffix: '_was_missing',
  }),
};

import React, { useState, useRef, useEffect } from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { Scissors } from 'lucide-react';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';
import { useGraphStore } from '../../../core/store/useGraphStore';
import { getIncomers } from '@xyflow/react';
import { useRecommendations } from '../../../core/hooks/useRecommendations';
import { RecommendationsPanel } from '../../../components/panels/RecommendationsPanel';
import { Recommendation } from '../../../core/api/client';

interface OutlierConfig {
  method: 'iqr' | 'zscore' | 'winsorize' | 'elliptic_envelope';
  columns: string[];
  
  // IQR
  multiplier?: number;
  
  // Z-Score
  threshold?: number;
  
  // Winsorize
  lower_percentile?: number;
  upper_percentile?: number;
  
  // Elliptic Envelope
  contamination?: number;
}

const OutlierSettings: React.FC<{ config: OutlierConfig; onChange: (c: OutlierConfig) => void; nodeId?: string }> = ({
  config,
  onChange,
  nodeId,
}) => {
  // Recursive search for datasetId
  const nodes = useGraphStore((state) => state.nodes);
  const edges = useGraphStore((state) => state.edges);
  
  const findUpstreamDatasetId = (currentNodeId: string): string | undefined => {
    const visited = new Set<string>();
    const queue = [currentNodeId];
    
    while (queue.length > 0) {
      const id = queue.shift();
      if (!id) continue;
      if (visited.has(id)) continue;
      visited.add(id);
      
      const node = nodes.find(n => n.id === id);
      if (!node) continue;
      
      // If this is NOT the current node, check if it has datasetId
      if (id !== currentNodeId && node.data?.datasetId) {
        return node.data.datasetId as string;
      }
      
      const incomers = getIncomers(node, nodes, edges);
      for (const incomer of incomers) {
        queue.push(incomer.id);
      }
    }
    return undefined;
  };

  const datasetId = findUpstreamDatasetId(nodeId || '');
  const { data: schema, isLoading } = useDatasetSchema(datasetId);
  
  const backendRecommendations = useRecommendations(nodeId || '', {
    types: ['outlier_removal', 'cleaning'],
    suggestedNodeTypes: ['OutlierRemoval', 'outlier'],
    scope: 'column'
  });

  const executionResult = useGraphStore((state) => state.executionResult);
  const nodeResult = nodeId ? executionResult?.node_results[nodeId] : null;
  
  // Responsive Layout
  const containerRef = useRef<HTMLDivElement>(null);
  const [isWide, setIsWide] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setIsWide(entry.contentRect.width > 450);
      }
    });
    observer.observe(containerRef.current);
    return () => { observer.disconnect(); };
  }, []);

  // Filter for numeric columns only
  const numericColumns = schema 
    ? Object.values(schema.columns)
        .filter(c => ['int', 'float', 'number'].some(t => c.dtype.toLowerCase().includes(t)))
        .map(c => c.name)
    : [];

  const filteredColumns = numericColumns.filter(c => c.toLowerCase().includes(searchTerm.toLowerCase()));

  const handleSelectAll = () => {
    onChange({ ...config, columns: filteredColumns });
  };

  const handleDeselectAll = () => {
    const newCols = config.columns.filter(c => !filteredColumns.includes(c));
    onChange({ ...config, columns: newCols });
  };

  const renderFeedback = () => {
    if (!nodeResult || !nodeResult.metrics) return null;
    const m = nodeResult.metrics;
    
    // Check for rows removed (common for IQR, ZScore, Elliptic)
    const rowsRemoved = m.rows_removed as number | undefined;
    const rowsRemaining = m.rows_remaining as number | undefined;
    const rowsTotal = m.rows_total as number | undefined ?? ((rowsRemoved ?? 0) + (rowsRemaining ?? 0));
    
    // Check for bounds (IQR, Winsorize)
    const bounds = m.bounds as Record<string, { lower: number, upper: number }> | undefined;
    
    // Check for stats (ZScore)
    const stats = m.stats as Record<string, { mean: number, std: number }> | undefined;

    // Check for contamination (Elliptic Envelope)
    const contamination = m.contamination as number | undefined;

    // Check for warnings
    const warnings = m.warnings as string[] | undefined;

    // Check for values clipped (Winsorize)
    const valuesClipped = m.values_clipped as number | undefined;

    if (rowsRemoved === undefined && !bounds && !stats && contamination === undefined && !warnings && valuesClipped === undefined) return null;

    const getTargetExplanation = () => {
        switch (config.method) {
            case 'iqr': return "Removes statistical outliers (IQR)";
            case 'zscore': return "Removes deviations > 3σ";
            case 'winsorize': return "Clips extreme values";
            case 'elliptic_envelope': return "Detects multivariate anomalies";
            default: return "";
        }
    };

    return (
      <div className="mt-4 p-3 bg-muted/50 rounded border text-xs space-y-3">
        <div className="flex justify-between items-center">
            <div className="font-medium text-muted-foreground">Execution Feedback</div>
            <div className="text-[10px] text-primary/80 bg-primary/5 px-1.5 py-0.5 rounded border border-primary/10" title="Goal of the selected method">
                {getTargetExplanation()}
            </div>
        </div>
        
        {warnings && warnings.length > 0 && (
          <div className="p-2 bg-yellow-50 text-yellow-800 rounded border border-yellow-200">
            <div className="font-medium mb-1">Warnings</div>
            <ul className="list-disc list-inside space-y-0.5">
              {warnings.map((w, i) => (
                <li key={i} className="truncate" title={w}>{w}</li>
              ))}
            </ul>
          </div>
        )}
        
        {config.method === 'winsorize' ? (
             <div className="flex justify-between items-center p-2 bg-background rounded border">
                <span className="text-muted-foreground">Values Clipped</span>
                <div className="text-right">
                    <span className="font-mono font-medium text-blue-600">{valuesClipped ?? 0}</span>
                    <span className="text-[10px] text-muted-foreground block">
                        (Replaced with bounds)
                    </span>
                </div>
             </div>
        ) : (
            <div className="flex justify-between items-center p-2 bg-background rounded border">
                <span className="text-muted-foreground">Rows Removed</span>
                <div className="text-right">
                <div className="flex items-center justify-end gap-1">
                    <span className="font-mono font-medium text-destructive">{rowsRemoved ?? 0}</span>
                    {rowsTotal > 0 && (
                        <span className="text-[10px] text-muted-foreground">
                            ({(((rowsRemoved ?? 0) / rowsTotal) * 100).toFixed(1)}%)
                        </span>
                    )}
                </div>
                {rowsRemaining !== undefined && (
                    <span className="text-[10px] text-muted-foreground block">
                        {rowsRemaining} remaining
                    </span>
                )}
                </div>
            </div>
        )}

        {contamination !== undefined && (
           <div className="flex justify-between items-center p-2 bg-background rounded border">
            <span className="text-muted-foreground">Contamination</span>
            <span className="font-mono font-medium">{(contamination * 100).toFixed(1)}%</span>
          </div>
        )}

        {bounds && (
          <div>
            <div className="font-medium text-muted-foreground mb-1">Calculated Bounds</div>
            <div className="max-h-32 overflow-y-auto bg-background p-2 rounded border space-y-1">
              {Object.entries(bounds).map(([col, bound]) => (
                <div key={col} className="flex justify-between items-center border-b border-border/50 last:border-0 pb-1 last:pb-0">
                  <span className="truncate max-w-[100px] font-medium" title={col}>{col}</span>
                  <span className="font-mono text-[10px] text-muted-foreground">
                    [{bound.lower.toFixed(2)}, {bound.upper.toFixed(2)}]
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}

        {stats && (
          <div>
            <div className="font-medium text-muted-foreground mb-1">Z-Score Stats</div>
            <div className="max-h-32 overflow-y-auto bg-background p-2 rounded border space-y-1">
              {Object.entries(stats).map(([col, stat]) => (
                <div key={col} className="flex justify-between items-center border-b border-border/50 last:border-0 pb-1 last:pb-0">
                  <span className="truncate max-w-[100px] font-medium" title={col}>{col}</span>
                  <span className="font-mono text-[10px] text-muted-foreground">
                    μ={stat.mean.toFixed(2)}, σ={stat.std.toFixed(2)}
                  </span>
                </div>
              ))}
            </div>
          </div>
        )}
      </div>
    );
  };

  const renderRecommendations = () => {
    // Combine backend recommendations with runtime feedback
    const runtimeRecommendations: Recommendation[] = [];
    
    if (nodeResult && nodeResult.metrics) {
        const m = nodeResult.metrics;
        const rowsRemoved = m.rows_removed as number | undefined;
        const rowsTotal = m.rows_total as number | undefined;
        
        // If rowsTotal is missing but we have rowsRemoved, we can still give some feedback
        const effectiveRowsTotal = rowsTotal ?? (m[`${config.method === 'elliptic_envelope' ? 'EllipticEnvelope' : config.method === 'zscore' ? 'ZScore' : config.method === 'winsorize' ? 'Winsorize' : 'IQR'}_rows_total`] as number | undefined);

        if (rowsRemoved !== undefined && effectiveRowsTotal !== undefined && effectiveRowsTotal > 0) {
            const lossRatio = rowsRemoved / effectiveRowsTotal;
            if (lossRatio > 0.2) {
                runtimeRecommendations.push({
                    rule_id: 'high_data_loss',
                    type: 'warning',
                    description: "High data loss (>20%).",
                    reasoning: "Consider relaxing parameters (e.g., higher IQR multiplier or Z-Score threshold) or using Winsorization to clip values instead of removing rows.",
                    suggested_node_type: 'OutlierRemoval',
                    suggested_params: {},
                    confidence: 1.0,
                    target_columns: []
                });
            } else if (lossRatio === 0) {
                if (config.method !== 'winsorize') {
                    runtimeRecommendations.push({
                        rule_id: 'no_outliers',
                        type: 'info',
                        description: "No outliers detected.",
                        reasoning: "If you suspect outliers, try tightening the parameters (e.g., lower IQR multiplier).",
                        suggested_node_type: 'OutlierRemoval',
                        suggested_params: {},
                        confidence: 1.0,
                        target_columns: []
                    });
                }
            }
        }

        if (config.method === 'elliptic_envelope') {
            runtimeRecommendations.push({
                rule_id: 'elliptic_stochastic',
                type: 'info',
                description: "Stochastic Method",
                reasoning: "Elliptic Envelope is stochastic. Results may vary slightly between runs.",
                suggested_node_type: 'OutlierRemoval',
                suggested_params: {},
                confidence: 1.0,
                target_columns: []
            });
        }
    }

    const allRecommendations = [...backendRecommendations, ...runtimeRecommendations];

    if (allRecommendations.length === 0) return null;

    return (
        <div className="mt-4">
            <RecommendationsPanel recommendations={allRecommendations} />
        </div>
    );
  };

  return (
    <div ref={containerRef} className={`flex flex-col h-full w-full bg-background ${isWide ? 'overflow-hidden' : 'overflow-y-auto'}`}>
      {/* Top Status Bar */}
      <div className="shrink-0 p-4 pb-0 space-y-2">
        {!datasetId && (
          <div className="p-2 bg-yellow-50 text-yellow-800 text-xs rounded border border-yellow-200">
            Connect a dataset node to see available columns.
          </div>
        )}
      </div>
      
      {/* Main Content */}
      <div className={`flex-1 min-h-0 p-4 gap-4 ${isWide ? 'grid grid-cols-2' : 'flex flex-col'}`}>
        
        {/* Left Column: Settings */}
        <div className={`space-y-4 ${isWide ? 'overflow-y-auto pr-2' : 'shrink-0'}`}>
          <div>
            <label className="block text-sm font-medium mb-1">Method</label>
            <select
              className="w-full p-2 border rounded bg-background text-sm"
              value={config.method}
              onChange={(e) => onChange({ ...config, method: e.target.value as OutlierConfig['method'] })}
            >
              <option value="iqr">IQR (Interquartile Range)</option>
              <option value="zscore">Z-Score (Standard Deviation)</option>
              <option value="winsorize">Winsorize (Clip Values)</option>
              <option value="elliptic_envelope">Elliptic Envelope (Multivariate)</option>
            </select>
            <p className="text-[10px] text-muted-foreground mt-1">
              {config.method === 'iqr' && 'Removes rows with values outside Q1/Q3 ± multiplier * IQR.'}
              {config.method === 'zscore' && 'Removes rows with values more than N standard deviations from mean.'}
              {config.method === 'winsorize' && 'Clips values to specified percentiles instead of removing rows.'}
              {config.method === 'elliptic_envelope' && 'Fits a robust covariance estimate to detect outliers.'}
            </p>
          </div>

          {/* IQR Params */}
          {config.method === 'iqr' && (
            <div className="space-y-2">
              <label className="block text-sm font-medium">Multiplier</label>
              <input
                type="number"
                step="0.1"
                className="w-full p-2 border rounded bg-background text-sm"
                value={config.multiplier ?? 1.5}
                onChange={(e) => onChange({ ...config, multiplier: parseFloat(e.target.value) })}
              />
              <p className="text-xs text-muted-foreground">Usually 1.5 for outliers, 3.0 for extreme outliers.</p>
            </div>
          )}

          {/* Z-Score Params */}
          {config.method === 'zscore' && (
            <div className="space-y-2">
              <label className="block text-sm font-medium">Threshold (Sigma)</label>
              <input
                type="number"
                step="0.1"
                className="w-full p-2 border rounded bg-background text-sm"
                value={config.threshold ?? 3.0}
                onChange={(e) => onChange({ ...config, threshold: parseFloat(e.target.value) })}
              />
              <p className="text-xs text-muted-foreground">Number of standard deviations to tolerate.</p>
            </div>
          )}

          {/* Winsorize Params */}
          {config.method === 'winsorize' && (
            <div className="space-y-2">
              <label className="block text-sm font-medium">Percentiles</label>
              <div className="flex gap-2 items-center">
                <div className="flex-1">
                  <label className="text-[10px] text-muted-foreground">Lower</label>
                  <input
                    type="number"
                    className="w-full p-2 border rounded bg-background text-sm"
                    value={config.lower_percentile ?? 5.0}
                    onChange={(e) => onChange({ ...config, lower_percentile: parseFloat(e.target.value) })}
                  />
                </div>
                <div className="flex-1">
                  <label className="text-[10px] text-muted-foreground">Upper</label>
                  <input
                    type="number"
                    className="w-full p-2 border rounded bg-background text-sm"
                    value={config.upper_percentile ?? 95.0}
                    onChange={(e) => onChange({ ...config, upper_percentile: parseFloat(e.target.value) })}
                  />
                </div>
              </div>
            </div>
          )}

          {/* Elliptic Envelope Params */}
          {config.method === 'elliptic_envelope' && (
            <div className="space-y-2">
              <label className="block text-sm font-medium">Contamination</label>
              <input
                type="number"
                step="0.01"
                min="0"
                max="0.5"
                className="w-full p-2 border rounded bg-background text-sm"
                value={config.contamination ?? 0.01}
                onChange={(e) => onChange({ ...config, contamination: parseFloat(e.target.value) })}
              />
              <p className="text-xs text-muted-foreground">Expected proportion of outliers in the dataset.</p>
            </div>
          )}
          
          {/* Feedback Section (Wide) */}
          {isWide && (
            <>
                {renderFeedback()}
                {renderRecommendations()}
            </>
          )}
        </div>
        
        {/* Right Column: Columns */}
        <div className={`flex flex-col h-full min-h-[200px] border rounded-md overflow-hidden ${isWide ? '' : 'shrink-0'}`}>
           <div className="p-2 border-b bg-muted/30 flex flex-col gap-2">
              <div className="flex items-center justify-between">
                <span className="text-xs font-medium text-muted-foreground">Numeric Columns ({config.columns.length})</span>
                <div className="flex gap-1">
                  <button onClick={handleSelectAll} className="text-[10px] px-2 py-1 hover:bg-accent rounded">All</button>
                  <button onClick={handleDeselectAll} className="text-[10px] px-2 py-1 hover:bg-accent rounded">None</button>
                </div>
              </div>
              <input
                type="text"
                placeholder="Search columns..."
                className="w-full text-xs p-1.5 border rounded bg-background"
                value={searchTerm}
                onChange={(e) => { setSearchTerm(e.target.value); }}
              />
           </div>
           <div className="flex-1 overflow-y-auto p-2 space-y-1">
            {filteredColumns.length > 0 ? (
                filteredColumns.map(col => (
                  <label key={col} className="flex items-center gap-2 text-sm hover:bg-accent/50 p-1.5 rounded cursor-pointer select-none">
                    <input
                      type="checkbox"
                      checked={config.columns.includes(col)}
                      onChange={(e) => {
                        const newCols = e.target.checked
                          ? [...config.columns, col]
                          : config.columns.filter(c => c !== col);
                        onChange({ ...config, columns: newCols });
                      }}
                      className="rounded border-gray-300 text-primary focus:ring-primary"
                    />
                    <span className="truncate" title={col}>{col}</span>
                  </label>
                ))
            ) : (
              <div className="text-xs text-muted-foreground italic p-4 text-center">
                {isLoading ? 'Loading schema...' : (numericColumns.length === 0 ? 'No numeric columns found' : 'No matches found')}
              </div>
            )}
           </div>
        </div>

        {/* Feedback Section (Narrow) */}
        {!isWide && (
            <>
                {renderFeedback()}
                {renderRecommendations()}
            </>
        )}

      </div>
    </div>
  );
};

export const OutlierNode: NodeDefinition = {
  type: 'outlier',
  label: 'Outlier Removal',
  category: 'Preprocessing',
  description: 'Detect and remove or clip outliers.',
  icon: Scissors,
  inputs: [{ id: 'in', type: 'dataset', label: 'Dataset' }],
  outputs: [{ id: 'out', type: 'dataset', label: 'Cleaned' }],
  settings: OutlierSettings,
  validate: (config: OutlierConfig) => {
    if (config.columns.length === 0) {
      return { isValid: false, message: 'Select at least one column.' };
    }
    return { isValid: true };
  },
  getDefaultConfig: () => ({
    method: 'iqr',
    columns: [],
    multiplier: 1.5,
    threshold: 3.0,
    lower_percentile: 5.0,
    upper_percentile: 95.0,
    contamination: 0.01
  })
};

import React, { useState } from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { Zap, Search, ChevronDown, ChevronRight, Info } from 'lucide-react';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';

interface PolynomialFeaturesConfig {
  columns: string[];
  degree: number;
  interaction_only: boolean;
  include_bias: boolean;
  output_prefix: string;
  include_input_features: boolean;
  isExpanded?: boolean;
}

const ColumnSelector: React.FC<{
  columns: string[];
  selected: string[];
  onChange: (selected: string[]) => void;
  label?: string;
}> = ({ columns, selected, onChange, label }) => {
  const [search, setSearch] = useState('');
  
  const filtered = columns.filter(c => c.toLowerCase().includes(search.toLowerCase()));

  const toggle = (col: string) => {
    if (selected.includes(col)) {
      onChange(selected.filter(c => c !== col));
    } else {
      onChange([...selected, col]);
    }
  };

  return (
    <div className="space-y-1.5">
      {label && <label className="text-xs font-medium text-muted-foreground">{label}</label>}
      <div className="border rounded bg-background overflow-hidden flex flex-col">
        <div className="flex items-center px-2 py-1.5 border-b bg-muted/20">
          <Search size={12} className="text-muted-foreground mr-1.5" />
          <input
            className="flex-1 bg-transparent text-xs outline-none placeholder:text-muted-foreground/70"
            placeholder="Search columns..."
            value={search}
            onChange={e => { setSearch(e.target.value); }}
          />
        </div>
        <div className="max-h-32 overflow-y-auto p-1 space-y-0.5">
          {filtered.length > 0 ? (
            filtered.map(col => {
              const isSelected = selected.includes(col);
              return (
                <div
                  key={col}
                  onClick={() => { toggle(col); }}
                  className={`
                    flex items-center gap-2 px-2 py-1.5 rounded text-xs cursor-pointer transition-colors
                    ${isSelected ? 'bg-primary/10 text-primary font-medium' : 'hover:bg-accent text-foreground'}
                  `}
                >
                  <div className={`
                    w-3 h-3 rounded border flex items-center justify-center
                    ${isSelected ? 'border-primary bg-primary text-primary-foreground' : 'border-muted-foreground/40'}
                  `}>
                    {isSelected && <div className="w-1.5 h-1.5 bg-current rounded-sm" />}
                  </div>
                  <span className="truncate">{col}</span>
                </div>
              );
            })
          ) : (
            <div className="p-2 text-xs text-muted-foreground text-center">No columns found</div>
          )}
        </div>
      </div>
      <div className="text-[10px] text-muted-foreground text-right">
        {selected.length} selected
      </div>
    </div>
  );
};

export const PolynomialFeaturesNode: NodeDefinition = {
  type: 'PolynomialFeaturesNode',
  label: 'Polynomial Features',
  description: 'Generate polynomial and interaction features.',
  category: 'Preprocessing',
  icon: Zap,
  inputs: [{ id: 'in', label: 'Input Dataset', type: 'dataset' }],
  outputs: [{ id: 'out', label: 'Transformed Data', type: 'dataset' }],
  
  getDefaultConfig: () => ({
    columns: [],
    degree: 2,
    interaction_only: false,
    include_bias: false,
    output_prefix: 'poly',
    include_input_features: false,
    isExpanded: true
  }),

  settings: function PolynomialFeaturesSettings({ config, onChange, nodeId }) {
    const upstreamData = useUpstreamData(nodeId || '');
    const datasetId = upstreamData.find((d) => d.datasetId)?.datasetId as string | undefined;
    const { data: schema } = useDatasetSchema(datasetId);
    
    // Filter for numeric columns as polynomial features usually apply to numbers
    const numericColumns = schema ? Object.values(schema.columns)
      .filter((col) => ['int', 'float', 'number', 'double', 'long'].some(t => col.dtype.toLowerCase().includes(t)))
      .map((col) => col.name) : [];

    const updateConfig = (updates: Partial<PolynomialFeaturesConfig>) => {
      onChange({ ...config, ...updates });
    };

    const toggleExpand = () => {
      updateConfig({ isExpanded: !config.isExpanded });
    };

    return (
      <div className="space-y-2 min-w-[280px]">
        <div className="border rounded-md bg-card">
          <div 
            className="flex items-center justify-between p-2 cursor-pointer hover:bg-accent/50 transition-colors"
            onClick={toggleExpand}
          >
            <div className="flex items-center gap-2">
              <Zap size={14} className="text-primary" />
              <span className="text-sm font-medium">Configuration</span>
            </div>
            {config.isExpanded ? <ChevronDown size={14} /> : <ChevronRight size={14} />}
          </div>

          {config.isExpanded && (
            <div className="p-3 space-y-4 border-t">
              
              <ColumnSelector
                label="Input Columns (Numeric)"
                columns={numericColumns}
                selected={config.columns || []}
                onChange={(cols) => updateConfig({ columns: cols })}
              />

              <div className="space-y-3">
                <div className="space-y-1.5">
                  <label className="text-xs font-medium text-muted-foreground flex items-center gap-1">
                    Degree
                    <div className="group relative">
                      <Info size={10} className="cursor-help" />
                      <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-1 hidden group-hover:block w-48 p-2 bg-popover text-popover-foreground text-[10px] rounded border shadow-lg z-50">
                        The degree of the polynomial features. Default = 2.
                      </div>
                    </div>
                  </label>
                  <input
                    type="number"
                    min={2}
                    max={5}
                    className="w-full px-2 py-1.5 text-xs border rounded bg-background"
                    value={config.degree || 2}
                    onChange={(e) => updateConfig({ degree: parseInt(e.target.value) || 2 })}
                  />
                </div>

                <div className="space-y-1.5">
                  <label className="text-xs font-medium text-muted-foreground">Output Prefix</label>
                  <input
                    type="text"
                    className="w-full px-2 py-1.5 text-xs border rounded bg-background"
                    value={config.output_prefix || 'poly'}
                    onChange={(e) => updateConfig({ output_prefix: e.target.value })}
                  />
                </div>

                <div className="space-y-2 pt-1">
                  <label className="flex items-center gap-2 cursor-pointer">
                    <input
                      type="checkbox"
                      className="rounded border-muted"
                      checked={config.interaction_only || false}
                      onChange={(e) => updateConfig({ interaction_only: e.target.checked })}
                    />
                    <span className="text-xs">Interaction Only</span>
                  </label>
                  <p className="text-[10px] text-muted-foreground pl-5">
                    If true, only interaction features are produced: features that are products of at most degree distinct input features.
                  </p>

                  <label className="flex items-center gap-2 cursor-pointer">
                    <input
                      type="checkbox"
                      className="rounded border-muted"
                      checked={config.include_bias || false}
                      onChange={(e) => updateConfig({ include_bias: e.target.checked })}
                    />
                    <span className="text-xs">Include Bias</span>
                  </label>
                  
                  <label className="flex items-center gap-2 cursor-pointer">
                    <input
                      type="checkbox"
                      className="rounded border-muted"
                      checked={config.include_input_features || false}
                      onChange={(e) => updateConfig({ include_input_features: e.target.checked })}
                    />
                    <span className="text-xs">Include Input Features</span>
                  </label>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  },

  validate: (data) => {
    if (!data.columns || data.columns.length === 0) {
      return { isValid: false, message: 'Select at least one input column.' };
    }
    if (data.degree < 2) {
      return { isValid: false, message: 'Degree must be at least 2.' };
    }
    return { isValid: true };
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { NodeDefinition, ValidationResult } from '../../../core/types/nodes';
import { Activity, ChevronDown, ChevronUp } from 'lucide-react';
import { useGraphStore } from '../../../core/store/useGraphStore';
import { RecommendationsPanel } from '../../../components/panels/RecommendationsPanel';
import { useRecommendations } from '../../../core/hooks/useRecommendations';
import { Recommendation, ColumnProfile } from '../../../core/api/client';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';

// --- Types ---

interface ResamplingConfig {
  type: 'oversampling' | 'undersampling';
  method: string;
  target_column: string;
  sampling_strategy: string;
  random_state: number;
  // Oversampling
  k_neighbors?: number;
  m_neighbors?: number;
  kind?: string;
  out_step?: number;
  cluster_balance_threshold?: number;
  density_exponent?: string;
  // Undersampling
  replacement?: boolean;
  version?: number;
  n_neighbors?: number;
  kind_sel?: string;
}

// --- Components ---

const LastRunResults: React.FC<{ nodeId: string }> = ({ nodeId }) => {
  const executionResult = useGraphStore((state) => state.executionResult);
    const nodeResult = nodeId
        ? (executionResult?.node_results?.[nodeId] as
                | { metrics?: Record<string, unknown>; error?: string }
                | undefined)
        : undefined;
  
  if (!nodeResult) return null;

  // Helper to format metrics
  const renderMetrics = (metrics: Record<string, unknown>) => {
    // metrics is typed as Record<string, unknown>, so it's always truthy if it exists on the type.
    // Assuming strict null checks, if metrics is not optional, this check is redundant.
    // However, if it can be null/undefined, the check is valid.
    // Based on the error "Unnecessary conditional, value is always truthy", metrics is guaranteed.
    
    return (
      <div className="space-y-1">
        {Object.entries(metrics).map(([key, value]) => {
          if (typeof value === 'object' && value !== null) {
             return (
               <div key={key} className="mt-1">
                 <span className="font-medium text-gray-700 dark:text-gray-300">{key.replace(/_/g, ' ')}:</span>
                 <div className="pl-2 border-l-2 border-gray-200 dark:border-gray-700 ml-1">
                    {renderMetrics(value as Record<string, unknown>)}
                 </div>
               </div>
             );
          }
          return (
            <div key={key} className="flex justify-between text-[10px]">
              <span className="text-gray-600 dark:text-gray-400 capitalize">{key.replace(/_/g, ' ')}:</span>
              <span className="font-mono text-gray-900 dark:text-gray-100">{String(value)}</span>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="mt-6 p-4 border rounded-md bg-gray-50 dark:bg-gray-800 dark:border-gray-700">
      <h4 className="text-sm font-medium mb-2 text-gray-900 dark:text-gray-100">Last Run Results</h4>
      <div className="text-xs space-y-1 text-gray-600 dark:text-gray-300">
        {nodeResult.metrics && (
            <div className="mt-2">
                {renderMetrics(nodeResult.metrics)}
            </div>
        )}
        {nodeResult.error && (
            <div className="mt-2 text-red-500 break-words">
                Error: {nodeResult.error}
            </div>
        )}
        {!nodeResult.metrics && !nodeResult.error && (
            <div className="italic text-gray-500">No metrics available</div>
        )}
      </div>
    </div>
  );
};

const ResamplingSettings: React.FC<{ config: ResamplingConfig; onChange: (c: ResamplingConfig) => void; nodeId?: string }> = ({
  config,
  onChange,
  nodeId,
}) => {
  // Responsive Layout Logic
  const containerRef = useRef<HTMLDivElement>(null);
  const [isWide, setIsWide] = useState(false);
  const [showRecommendations, setShowRecommendations] = useState(true);

  // Upstream Data for Target Column Suggestion
    const upstreamDataRaw = useUpstreamData(nodeId || '') as unknown;
    const upstreamData: Record<string, unknown>[] = Array.isArray(upstreamDataRaw)
        ? (upstreamDataRaw.filter(Boolean) as Record<string, unknown>[])
        : [];

    const datasetId = upstreamData.find((d) => typeof d.datasetId === 'string')?.datasetId as
        | string
        | undefined;
  const { data: schema } = useDatasetSchema(datasetId);
  
  // Try to find a target column from upstream nodes configuration
    const upstreamTarget = upstreamData.find((d) => {
        const cfg = d.config;
        if (!cfg || typeof cfg !== 'object') return false;
        const target = (cfg as Record<string, unknown>).target_column;
        return typeof target === 'string' && target.trim().length > 0;
    });
    const targetColumn = upstreamTarget
        ? (((upstreamTarget.config as Record<string, unknown>).target_column as string) ?? undefined)
        : undefined;

  // Auto-fill target column if empty and available in schema or upstream
  useEffect(() => {
      if (!config.target_column) {
          if (upstreamTarget && targetColumn) {
               onChange({ ...config, target_column: targetColumn });
          } else if (schema?.columns) {
               // Simple heuristic: check for 'target' or 'class' or column_type
               const potentialTarget = Object.values(schema.columns).find((c: ColumnProfile) => 
                   c.name.toLowerCase() === 'target' || 
                   c.name.toLowerCase() === 'class' ||
                   c.column_type === 'target'
               );
               if (potentialTarget) {
                   onChange({ ...config, target_column: potentialTarget.name });
               }
          }
      }
    }, [schema, upstreamTarget, targetColumn, config.target_column, config, onChange]);

  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setIsWide(entry.contentRect.width > 400);
      }
    });
    observer.observe(containerRef.current);
    return () => { observer.disconnect(); };
  }, []);

  // Recommendations
  const recommendations = useRecommendations(nodeId || '', {
    types: ['resampling'],
    suggestedNodeTypes: ['ResamplingNode'],
  });

  const handleApplyRecommendation = (rec: Recommendation) => {
    if (rec.suggested_params) {
        onChange({ ...config, ...rec.suggested_params });
    }
  };

  const handleChange = (key: keyof ResamplingConfig, value: unknown) => {
    const newConfig = { ...config, [key]: value };
    
    // Reset method defaults when type changes
    if (key === 'type') {
        if (value === 'oversampling') {
            newConfig.method = 'smote';
        } else {
            newConfig.method = 'random_under_sampling';
        }
    }
    
    onChange(newConfig);
  };

  return (
    <div ref={containerRef} className={`flex flex-col h-full w-full bg-white dark:bg-gray-900 ${isWide ? 'overflow-hidden' : 'overflow-y-auto'}`}>
      
      <div className={`flex-1 min-h-0 p-4 gap-4 ${isWide ? 'grid grid-cols-2' : 'flex flex-col'}`}>
        
        {/* Left Column (Main Settings) */}
        <div className={`space-y-4 ${isWide ? 'overflow-y-auto pr-2' : 'shrink-0'}`}>
            
            <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Resampling Type</label>
                <select 
                    className="w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2 text-sm text-gray-900 dark:text-gray-100 focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                    value={config.type}
                    onChange={(e) => { handleChange('type', e.target.value as ResamplingConfig['type']); }}
                >
                    <option value="oversampling">Oversampling (Minority)</option>
                    <option value="undersampling">Undersampling (Majority)</option>
                </select>
            </div>

            <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Method</label>
                <select 
                    className="w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2 text-sm text-gray-900 dark:text-gray-100 focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                    value={config.method}
                    onChange={(e) => { handleChange('method', e.target.value); }}
                >
                    {config.type === 'oversampling' ? (
                        <>
                            <option value="smote">SMOTE</option>
                            <option value="adasyn">ADASYN</option>
                            <option value="borderline_smote">Borderline SMOTE</option>
                            <option value="svm_smote">SVM SMOTE</option>
                            <option value="kmeans_smote">KMeans SMOTE</option>
                            <option value="smote_tomek">SMOTE + Tomek</option>
                        </>
                    ) : (
                        <>
                            <option value="random_under_sampling">Random Under Sampling</option>
                            <option value="nearmiss">NearMiss</option>
                            <option value="tomek_links">Tomek Links</option>
                            <option value="edited_nearest_neighbours">Edited Nearest Neighbours</option>
                        </>
                    )}
                </select>
                <p className="text-xs text-gray-500 dark:text-gray-400">
                    {config.type === 'oversampling' 
                        ? 'Generate synthetic samples for the minority class.' 
                        : 'Remove samples from the majority class.'}
                </p>
            </div>

            <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Target Column</label>
                <div className="relative">
                    <input 
                        type="text"
                        className="w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2 text-sm text-gray-900 dark:text-gray-100 focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                        placeholder="e.g., target"
                        value={config.target_column}
                        onChange={(e) => { handleChange('target_column', e.target.value); }}
                        list="target-column-suggestions"
                    />
                    {schema?.columns && (
                        <datalist id="target-column-suggestions">
                            {Object.values(schema.columns).map((col: ColumnProfile) => (
                                <option key={col.name} value={col.name} />
                            ))}
                        </datalist>
                    )}
                </div>
                <p className="text-xs text-gray-500 dark:text-gray-400">
                    {upstreamTarget ? 'Auto-detected from upstream node.' : 'The column containing the class labels.'}
                </p>
            </div>

            <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Sampling Strategy</label>
                <select 
                    className="w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2 text-sm text-gray-900 dark:text-gray-100 focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                    value={config.sampling_strategy}
                    onChange={(e) => { handleChange('sampling_strategy', e.target.value); }}
                >
                    <option value="auto">Auto (Resample all classes but majority)</option>
                    <option value="minority">Minority (Resample only minority class)</option>
                    <option value="not minority">Not Minority (Resample all but minority)</option>
                    <option value="not majority">Not Majority (Resample all but majority)</option>
                    <option value="all">All (Resample all classes)</option>
                </select>
                <p className="text-xs text-gray-500 dark:text-gray-400">Defines which classes to resample.</p>
            </div>

            <div className="space-y-2">
                <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Random State</label>
                <input 
                    type="number"
                    className="w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2 text-sm text-gray-900 dark:text-gray-100 focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                    value={config.random_state}
                    onChange={(e) => { handleChange('random_state', parseInt(e.target.value)); }}
                />
            </div>

        </div>

        {/* Right Column (Advanced Params & Results) */}
        <div className={`space-y-4 ${isWide ? 'overflow-y-auto pl-2 border-l border-gray-100 dark:border-gray-700' : 'shrink-0 pt-4 border-t border-gray-100 dark:border-gray-700'}`}>
            
            {/* Method Specific Params */}
            {config.type === 'oversampling' && (
                <>
                    {['smote', 'adasyn', 'borderline_smote', 'svm_smote', 'kmeans_smote'].includes(config.method) && (
                        <div className="space-y-2">
                            <label className="text-sm font-medium text-gray-700 dark:text-gray-300">k Neighbors</label>
                            <input 
                                type="number"
                                className="w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2 text-sm text-gray-900 dark:text-gray-100 focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                                value={config.k_neighbors ?? 5}
                                onChange={(e) => { handleChange('k_neighbors', parseInt(e.target.value)); }}
                            />
                        </div>
                    )}
                    
                    {['borderline_smote', 'svm_smote'].includes(config.method) && (
                        <div className="space-y-2">
                            <label className="text-sm font-medium text-gray-700 dark:text-gray-300">m Neighbors</label>
                            <input 
                                type="number"
                                className="w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2 text-sm text-gray-900 dark:text-gray-100 focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                                value={config.m_neighbors ?? 10}
                                onChange={(e) => { handleChange('m_neighbors', parseInt(e.target.value)); }}
                            />
                        </div>
                    )}

                    {config.method === 'borderline_smote' && (
                        <div className="space-y-2">
                            <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Kind</label>
                            <select 
                                className="w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2 text-sm text-gray-900 dark:text-gray-100 focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                                value={config.kind ?? 'borderline-1'}
                                onChange={(e) => { handleChange('kind', e.target.value); }}
                            >
                                <option value="borderline-1">Borderline-1</option>
                                <option value="borderline-2">Borderline-2</option>
                            </select>
                        </div>
                    )}

                    {config.method === 'svm_smote' && (
                        <div className="space-y-2">
                            <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Out Step</label>
                            <input 
                                type="number"
                                step="0.1"
                                className="w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2 text-sm text-gray-900 dark:text-gray-100 focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                                value={config.out_step ?? 0.5}
                                onChange={(e) => { handleChange('out_step', parseFloat(e.target.value)); }}
                            />
                        </div>
                    )}

                    {config.method === 'kmeans_smote' && (
                        <>
                            <div className="space-y-2">
                                <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Cluster Balance Threshold</label>
                                <input 
                                    type="number"
                                    step="0.1"
                                    className="w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2 text-sm text-gray-900 dark:text-gray-100 focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                                    value={config.cluster_balance_threshold ?? 0.1}
                                    onChange={(e) => { handleChange('cluster_balance_threshold', parseFloat(e.target.value)); }}
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Density Exponent</label>
                                <input 
                                    type="text"
                                    className="w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2 text-sm text-gray-900 dark:text-gray-100 focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                                    value={config.density_exponent ?? 'auto'}
                                    onChange={(e) => { handleChange('density_exponent', e.target.value); }}
                                />
                            </div>
                        </>
                    )}
                </>
            )}

            {config.type === 'undersampling' && config.method === 'random_under_sampling' && (
                <div className="flex items-center justify-between p-3 border rounded-md bg-gray-50 dark:bg-gray-800 dark:border-gray-700">
                    <div>
                        <label className="text-sm font-medium text-gray-700 dark:text-gray-300 block">Replacement</label>
                        <span className="text-xs text-gray-500 dark:text-gray-400">Sample with replacement</span>
                    </div>
                    <input 
                        type="checkbox"
                        className="h-4 w-4 rounded border-gray-300 dark:border-gray-600 text-blue-600 focus:ring-blue-500"
                        checked={config.replacement ?? false}
                        onChange={(e) => { handleChange('replacement', e.target.checked); }}
                    />
                </div>
            )}

            {config.type === 'undersampling' && config.method === 'nearmiss' && (
                <div className="space-y-2">
                    <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Version</label>
                    <select 
                        className="w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2 text-sm text-gray-900 dark:text-gray-100 focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                        value={config.version ?? 1}
                        onChange={(e) => { handleChange('version', parseInt(e.target.value)); }}
                    >
                        <option value="1">1</option>
                        <option value="2">2</option>
                        <option value="3">3</option>
                    </select>
                </div>
            )}

            {config.type === 'undersampling' && config.method === 'edited_nearest_neighbours' && (
                <>
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-700 dark:text-gray-300">n Neighbors</label>
                        <input 
                            type="number"
                            className="w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2 text-sm text-gray-900 dark:text-gray-100 focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                            value={config.n_neighbors ?? 3}
                            onChange={(e) => { handleChange('n_neighbors', parseInt(e.target.value)); }}
                        />
                    </div>
                    <div className="space-y-2">
                        <label className="text-sm font-medium text-gray-700 dark:text-gray-300">Selection Kind</label>
                        <select 
                            className="w-full rounded-md border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-2 text-sm text-gray-900 dark:text-gray-100 focus:border-blue-500 focus:ring-1 focus:ring-blue-500"
                            value={config.kind_sel ?? 'all'}
                            onChange={(e) => { handleChange('kind_sel', e.target.value); }}
                        >
                            <option value="all">All</option>
                            <option value="mode">Mode</option>
                        </select>
                    </div>
                </>
            )}

            {recommendations.length > 0 && (
                <div className="mt-0 border rounded-md overflow-hidden border-gray-200 dark:border-gray-700">
                    <button 
                        className="w-full flex items-center justify-between p-3 bg-gray-50 dark:bg-gray-800 hover:bg-gray-100 dark:hover:bg-gray-700 transition-colors"
                        onClick={() => { setShowRecommendations(!showRecommendations); }}
                    >
                        <span className="text-sm font-medium text-gray-900 dark:text-gray-100">
                            Recommendations ({recommendations.length})
                        </span>
                        {showRecommendations ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
                    </button>
                    
                    {showRecommendations && (
                        <div className="p-3 bg-white dark:bg-gray-900 border-t border-gray-200 dark:border-gray-700">
                            <RecommendationsPanel 
                                recommendations={recommendations} 
                                onApply={handleApplyRecommendation}
                            />
                        </div>
                    )}
                </div>
            )}

            {nodeId && <LastRunResults nodeId={nodeId} />}
        </div>
      </div>
    </div>
  );
};

// --- Node Definition ---

const validate = (data: ResamplingConfig): ValidationResult => {
  if (!data.target_column) {
    return { isValid: false, message: 'Target column is required for resampling.' };
  }
  
  if (data.type === 'oversampling') {
    if (['smote', 'adasyn', 'borderline_smote', 'svm_smote', 'kmeans_smote'].includes(data.method)) {
       if ((data.k_neighbors ?? 5) < 1) {
           return { isValid: false, message: 'k_neighbors must be at least 1.' };
       }
    }
  }

  return { isValid: true };
};

export const ResamplingNode: NodeDefinition<ResamplingConfig> = {
  type: 'ResamplingNode',
  label: 'Resampling',
  category: 'Preprocessing',
  description: 'Balance dataset classes using oversampling or undersampling techniques.',
    icon: Activity as unknown as React.FC<any>,
  inputs: [{ id: 'in', label: 'Data', type: 'dataset' }],
  outputs: [{ id: 'out', label: 'Balanced Data', type: 'dataset' }],
  settings: ResamplingSettings,
  validate: validate,
  getDefaultConfig: () => ({
    type: 'oversampling',
    method: 'smote',
    target_column: '',
    sampling_strategy: 'auto',
    random_state: 42,
    k_neighbors: 5,
    replacement: false,
    version: 1,
    n_neighbors: 3,
    kind_sel: 'all'
  })
};

import React, { useState, useRef, useEffect } from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { Scaling } from 'lucide-react';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';
import { useGraphStore } from '../../../core/store/useGraphStore';

interface ScalingConfig {
  columns: string[];
  method: 'standard' | 'minmax' | 'maxabs' | 'robust';
  
  // Standard Scaler
  with_mean?: boolean;
  with_std?: boolean;

  // MinMax Scaler
  feature_range_min?: number;
  feature_range_max?: number;

  // Robust Scaler
  quantile_range_min?: number;
  quantile_range_max?: number;
  with_centering?: boolean;
  with_scaling?: boolean;
}

const ScalingSettings: React.FC<{ config: ScalingConfig; onChange: (c: ScalingConfig) => void; nodeId?: string }> = ({
  config,
  onChange,
  nodeId,
}) => {
  const upstreamData = useUpstreamData(nodeId || '');
  const datasetId = upstreamData.find(d => d.datasetId)?.datasetId as string | undefined;
  const { data: schema, isLoading } = useDatasetSchema(datasetId);
  
  const executionResult = useGraphStore((state) => state.executionResult);
  const nodeResult = nodeId ? executionResult?.node_results[nodeId] : null;
  
  // Responsive Layout
  const containerRef = useRef<HTMLDivElement>(null);
  const [isWide, setIsWide] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setIsWide(entry.contentRect.width > 450);
      }
    });
    observer.observe(containerRef.current);
    return () => { observer.disconnect(); };
  }, []);

  // Filter for numeric columns only, as scaling only applies to them
  const numericColumns = schema 
    ? Object.values(schema.columns)
        .filter(c => ['int', 'float', 'number'].some(t => c.dtype.toLowerCase().includes(t)))
        .map(c => c.name)
    : [];

  const filteredColumns = numericColumns.filter(c => c.toLowerCase().includes(searchTerm.toLowerCase()));

  const handleSelectAll = () => {
    onChange({ ...config, columns: filteredColumns });
  };

  const handleDeselectAll = () => {
    const newCols = config.columns.filter(c => !filteredColumns.includes(c));
    onChange({ ...config, columns: newCols });
  };

  const renderFeedback = () => {
    if (!nodeResult || !nodeResult.metrics) return null;
    const m = nodeResult.metrics;
    const cols = m.columns as string[] | undefined;
    
    if (!cols) return null;

    const getTargetExplanation = () => {
      switch (config.method) {
        case 'standard': return "Target: μ ≈ 0, σ ≈ 1";
        case 'minmax': return `Target: ${config.feature_range_min ?? 0} to ${config.feature_range_max ?? 1}`;
        case 'robust': return "Target: Median ≈ 0, IQR ≈ 1";
        case 'maxabs': return "Target: MaxAbs = 1";
        default: return "";
      }
    };

    return (
      <div className="mt-4 p-3 bg-muted/50 rounded border text-xs space-y-2">
        <div className="flex justify-between items-center">
          <div className="font-medium text-muted-foreground">Scaling Statistics</div>
          <div className="text-[10px] text-primary/80 bg-primary/5 px-1.5 py-0.5 rounded border border-primary/10" title="Values close to these targets indicate successful scaling.">
             {getTargetExplanation()}
          </div>
        </div>
        <div className="max-h-40 overflow-y-auto bg-background p-2 rounded border space-y-1">
          {cols.map((col, idx) => {
            let details = "";
            if (config.method === 'standard') {
               const mean = m.mean ? (m.mean as number[])[idx] : undefined;
               const scale = m.scale ? (m.scale as number[])[idx] : undefined;
               if (typeof mean === 'number') details = `μ=${mean.toFixed(2)}, σ=${typeof scale === 'number' ? scale.toFixed(2) : '-'}`;
            } else if (config.method === 'minmax') {
               const min = m.data_min ? (m.data_min as number[])[idx] : undefined;
               const max = m.data_max ? (m.data_max as number[])[idx] : undefined;
               if (typeof min === 'number') details = `Min=${min.toFixed(2)}, Max=${typeof max === 'number' ? max.toFixed(2) : '-'}`;
            } else if (config.method === 'robust') {
               const center = m.center ? (m.center as number[])[idx] : undefined;
               const scale = m.scale ? (m.scale as number[])[idx] : undefined;
               if (typeof center === 'number') details = `Med=${center.toFixed(2)}, IQR=${typeof scale === 'number' ? scale.toFixed(2) : '-'}`;
            } else if (config.method === 'maxabs') {
               const maxAbs = m.max_abs ? (m.max_abs as number[])[idx] : undefined;
               if (typeof maxAbs === 'number') details = `MaxAbs=${maxAbs.toFixed(2)}`;
            }

            return (
              <div key={col} className="flex justify-between items-center border-b border-border/50 last:border-0 pb-1 last:pb-0">
                <span className="truncate max-w-[100px] font-medium" title={col}>{col}</span>
                <span className="font-mono text-[10px] text-muted-foreground">{details}</span>
              </div>
            );
          })}
        </div>
      </div>
    );
  };

  return (
    <div ref={containerRef} className={`flex flex-col h-full w-full bg-background ${isWide ? 'overflow-hidden' : 'overflow-y-auto'}`}>
      {/* Top Status Bar */}
      <div className="shrink-0 p-4 pb-0 space-y-2">
        {!datasetId && (
          <div className="p-2 bg-yellow-50 text-yellow-800 text-xs rounded border border-yellow-200">
            Connect a dataset node to see available columns.
          </div>
        )}
      </div>
      
      {/* Main Content */}
      <div className={`flex-1 min-h-0 p-4 gap-4 ${isWide ? 'grid grid-cols-2' : 'flex flex-col'}`}>
        
        {/* Left Column: Settings */}
        <div className={`space-y-4 ${isWide ? 'overflow-y-auto pr-2' : 'shrink-0'}`}>
          <div>
            <label className="block text-sm font-medium mb-1">Scaling Method</label>
            <select
              className="w-full p-2 border rounded bg-background text-sm"
              value={config.method}
              onChange={(e) => onChange({ ...config, method: e.target.value as ScalingConfig['method'] })}
            >
              <option value="standard">Standard Scaler (Z-Score)</option>
              <option value="minmax">MinMax Scaler (0-1)</option>
              <option value="maxabs">MaxAbs Scaler</option>
              <option value="robust">Robust Scaler (Outlier Safe)</option>
            </select>
            <p className="text-[10px] text-muted-foreground mt-1">
              {config.method === 'standard' && 'Centers data around 0 with unit variance.'}
              {config.method === 'minmax' && 'Scales data to a fixed range [0, 1].'}
              {config.method === 'maxabs' && 'Scales data by its maximum absolute value.'}
              {config.method === 'robust' && 'Scales data using statistics that are robust to outliers.'}
            </p>
          </div>

          {/* Standard Scaler Params */}
          {config.method === 'standard' && (
            <div className="space-y-2 border-t pt-2">
              <label className="flex items-center gap-2 text-sm cursor-pointer">
                <input
                  type="checkbox"
                  checked={config.with_mean ?? true}
                  onChange={(e) => onChange({ ...config, with_mean: e.target.checked })}
                  className="rounded border-gray-300 text-primary focus:ring-primary"
                />
                <span>Center Data (with_mean)</span>
              </label>
              <label className="flex items-center gap-2 text-sm cursor-pointer">
                <input
                  type="checkbox"
                  checked={config.with_std ?? true}
                  onChange={(e) => onChange({ ...config, with_std: e.target.checked })}
                  className="rounded border-gray-300 text-primary focus:ring-primary"
                />
                <span>Scale Variance (with_std)</span>
              </label>
            </div>
          )}

          {/* MinMax Scaler Params */}
          {config.method === 'minmax' && (
            <div className="space-y-2 border-t pt-2">
              <label className="block text-sm font-medium">Feature Range</label>
              <div className="flex gap-2 items-center">
                <input
                  type="number"
                  className="w-full p-2 border rounded bg-background text-sm"
                  placeholder="Min (0)"
                  value={config.feature_range_min ?? 0}
                  onChange={(e) => onChange({ ...config, feature_range_min: parseFloat(e.target.value) })}
                />
                <span className="text-muted-foreground">-</span>
                <input
                  type="number"
                  className="w-full p-2 border rounded bg-background text-sm"
                  placeholder="Max (1)"
                  value={config.feature_range_max ?? 1}
                  onChange={(e) => onChange({ ...config, feature_range_max: parseFloat(e.target.value) })}
                />
              </div>
            </div>
          )}

          {/* Robust Scaler Params */}
          {config.method === 'robust' && (
            <div className="space-y-2 border-t pt-2">
              <label className="block text-sm font-medium">Quantile Range</label>
              <div className="flex gap-2 items-center">
                <input
                  type="number"
                  className="w-full p-2 border rounded bg-background text-sm"
                  placeholder="Min (25.0)"
                  value={config.quantile_range_min ?? 25.0}
                  onChange={(e) => onChange({ ...config, quantile_range_min: parseFloat(e.target.value) })}
                />
                <span className="text-muted-foreground">-</span>
                <input
                  type="number"
                  className="w-full p-2 border rounded bg-background text-sm"
                  placeholder="Max (75.0)"
                  value={config.quantile_range_max ?? 75.0}
                  onChange={(e) => onChange({ ...config, quantile_range_max: parseFloat(e.target.value) })}
                />
              </div>
              <div className="space-y-2 mt-2">
                <label className="flex items-center gap-2 text-sm cursor-pointer">
                  <input
                    type="checkbox"
                    checked={config.with_centering ?? true}
                    onChange={(e) => onChange({ ...config, with_centering: e.target.checked })}
                    className="rounded border-gray-300 text-primary focus:ring-primary"
                  />
                  <span>Center Data (Median)</span>
                </label>
                <label className="flex items-center gap-2 text-sm cursor-pointer">
                  <input
                    type="checkbox"
                    checked={config.with_scaling ?? true}
                    onChange={(e) => onChange({ ...config, with_scaling: e.target.checked })}
                    className="rounded border-gray-300 text-primary focus:ring-primary"
                  />
                  <span>Scale Data (IQR)</span>
                </label>
              </div>
            </div>
          )}
          
          {/* Feedback Section (Wide) */}
          {isWide && renderFeedback()}
        </div>
        
        {/* Right Column: Columns */}
        <div className={`flex flex-col h-full min-h-[200px] border rounded-md overflow-hidden ${isWide ? '' : 'shrink-0'}`}>
           <div className="p-2 border-b bg-muted/30 flex flex-col gap-2">
              <div className="flex items-center justify-between">
                <span className="text-xs font-medium text-muted-foreground">Numeric Columns ({config.columns.length})</span>
                <div className="flex gap-1">
                  <button onClick={handleSelectAll} className="text-[10px] px-2 py-1 hover:bg-accent rounded">All</button>
                  <button onClick={handleDeselectAll} className="text-[10px] px-2 py-1 hover:bg-accent rounded">None</button>
                </div>
              </div>
              <input
                type="text"
                placeholder="Search columns..."
                className="w-full text-xs p-1.5 border rounded bg-background"
                value={searchTerm}
                onChange={(e) => { setSearchTerm(e.target.value); }}
              />
           </div>
           <div className="flex-1 overflow-y-auto p-2 space-y-1">
            {filteredColumns.length > 0 ? (
                filteredColumns.map(col => (
                  <label key={col} className="flex items-center gap-2 text-sm hover:bg-accent/50 p-1.5 rounded cursor-pointer select-none">
                    <input
                      type="checkbox"
                      checked={config.columns.includes(col)}
                      onChange={(e) => {
                        const newCols = e.target.checked
                          ? [...config.columns, col]
                          : config.columns.filter(c => c !== col);
                        onChange({ ...config, columns: newCols });
                      }}
                      className="rounded border-gray-300 text-primary focus:ring-primary"
                    />
                    <span className="truncate" title={col}>{col}</span>
                  </label>
                ))
            ) : (
              <div className="text-xs text-muted-foreground italic p-4 text-center">
                {isLoading ? 'Loading schema...' : (numericColumns.length === 0 ? 'No numeric columns found' : 'No matches found')}
              </div>
            )}
           </div>
        </div>

        {/* Feedback Section (Narrow) */}
        {!isWide && renderFeedback()}

      </div>
    </div>
  );
};

export const ScalingNode: NodeDefinition<ScalingConfig> = {
  type: 'scale_numeric_features',
  label: 'Scaling',
  category: 'Preprocessing',
  description: 'Scale numeric features to a standard range.',
  icon: Scaling, // Note: You might need to import a real icon or use a placeholder if 'Scaling' doesn't exist in lucide-react
  inputs: [{ id: 'in', label: 'Data', type: 'dataset' }],
  outputs: [{ id: 'out', label: 'Scaled Data', type: 'dataset' }],
  settings: ScalingSettings,
  validate: (config) => ({ 
    isValid: config.columns.length > 0,
    message: config.columns.length === 0 ? 'Select at least one column' : undefined
  }),
  getDefaultConfig: () => ({
    columns: [],
    method: 'standard',
  }),
};

import React, { useState, useRef, useEffect } from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { Eraser, Plus, Trash2, Search, Wand2, Info, ChevronDown, ChevronUp } from 'lucide-react';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';

// --- Types ---

interface TextOperation {
  op: 'trim' | 'case' | 'remove_special' | 'regex';
  mode: string;
  replacement?: string; // For remove_special
  pattern?: string; // For regex custom
  repl?: string; // For regex custom
}

interface TextCleaningConfig {
  columns: string[];
  operations: TextOperation[];
}

// --- Components ---

const ColumnSelector: React.FC<{
  columns: string[];
  selected: string[];
  onChange: (selected: string[]) => void;
}> = ({ columns, selected, onChange }) => {
  const [search, setSearch] = useState('');
  
  const filtered = columns.filter(c => c.toLowerCase().includes(search.toLowerCase()));

  const toggle = (col: string) => {
    if (selected.includes(col)) {
      onChange(selected.filter(c => c !== col));
    } else {
      onChange([...selected, col]);
    }
  };

  return (
    <div className="border rounded bg-background overflow-hidden flex flex-col max-h-40">
      <div className="flex items-center px-2 py-1.5 border-b bg-muted/20">
        <Search size={12} className="text-muted-foreground mr-1.5" />
        <input
          className="flex-1 bg-transparent text-xs outline-none placeholder:text-muted-foreground/70"
          placeholder="Search columns..."
          value={search}
          onChange={e => { setSearch(e.target.value); }}
        />
      </div>
      <div className="overflow-y-auto p-1 space-y-0.5">
        {filtered.length > 0 ? (
          filtered.map(col => {
            const isSelected = selected.includes(col);
            return (
              <div
                key={col}
                onClick={() => { toggle(col); }}
                className={`
                  flex items-center gap-2 px-2 py-1.5 rounded text-xs cursor-pointer transition-colors
                  ${isSelected ? 'bg-blue-50 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300 font-medium' : 'hover:bg-gray-100 dark:hover:bg-gray-800 text-gray-700 dark:text-gray-300'}
                `}
              >
                <div className={`
                  w-3 h-3 rounded border flex items-center justify-center
                  ${isSelected ? 'border-blue-500 bg-blue-500 text-white' : 'border-gray-400 dark:border-gray-600'}
                `}>
                  {isSelected && <div className="w-1.5 h-1.5 bg-white rounded-full" />}
                </div>
                <span className="truncate">{col}</span>
              </div>
            );
          })
        ) : (
          <div className="p-2 text-xs text-gray-500 text-center italic">No columns found</div>
        )}
      </div>
    </div>
  );
};

const OperationEditor: React.FC<{
  operation: TextOperation;
  onChange: (op: TextOperation) => void;
  onDelete: () => void;
}> = ({ operation, onChange, onDelete }) => {
  return (
    <div className="p-3 border rounded-md bg-gray-50 dark:bg-gray-800/50 border-gray-200 dark:border-gray-700 space-y-3">
      <div className="flex items-center justify-between">
        <select
          className="text-xs font-medium bg-transparent border-none focus:ring-0 p-0 text-gray-900 dark:text-gray-100"
          value={operation.op}
          onChange={(e) => {
            const newOp = e.target.value as TextOperation['op'];
            let defaultMode = 'both';
            if (newOp === 'case') defaultMode = 'lower';
            if (newOp === 'remove_special') defaultMode = 'keep_alphanumeric';
            if (newOp === 'regex') defaultMode = 'custom';
            onChange({ ...operation, op: newOp, mode: defaultMode });
          }}
        >
          <option value="trim">Trim Whitespace</option>
          <option value="case">Change Case</option>
          <option value="remove_special">Remove Special Chars</option>
          <option value="regex">Regex Replace</option>
        </select>
        <button onClick={onDelete} className="text-gray-400 hover:text-red-500 transition-colors">
          <Trash2 size={14} />
        </button>
      </div>

      <div className="space-y-2">
        {operation.op === 'trim' && (
          <select
            className="w-full text-xs rounded border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-1.5"
            value={operation.mode}
            onChange={(e) => onChange({ ...operation, mode: e.target.value })}
          >
            <option value="both">Both Ends</option>
            <option value="leading">Leading Only</option>
            <option value="trailing">Trailing Only</option>
          </select>
        )}

        {operation.op === 'case' && (
          <select
            className="w-full text-xs rounded border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-1.5"
            value={operation.mode}
            onChange={(e) => onChange({ ...operation, mode: e.target.value })}
          >
            <option value="lower">Lower Case</option>
            <option value="upper">Upper Case</option>
            <option value="title">Title Case</option>
            <option value="sentence">Sentence Case</option>
          </select>
        )}

        {operation.op === 'remove_special' && (
          <div className="space-y-2">
            <select
              className="w-full text-xs rounded border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-1.5"
              value={operation.mode}
              onChange={(e) => onChange({ ...operation, mode: e.target.value })}
            >
              <option value="keep_alphanumeric">Keep Alphanumeric</option>
              <option value="keep_alphanumeric_space">Keep Alphanumeric & Space</option>
              <option value="letters_only">Letters Only</option>
              <option value="digits_only">Digits Only</option>
            </select>
            <input
              type="text"
              className="w-full text-xs rounded border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-1.5"
              placeholder="Replacement (optional)"
              value={operation.replacement || ''}
              onChange={(e) => onChange({ ...operation, replacement: e.target.value })}
            />
          </div>
        )}

        {operation.op === 'regex' && (
          <div className="space-y-2">
            <select
              className="w-full text-xs rounded border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-1.5"
              value={operation.mode}
              onChange={(e) => onChange({ ...operation, mode: e.target.value })}
            >
              <option value="custom">Custom Pattern</option>
              <option value="collapse_whitespace">Collapse Whitespace</option>
              <option value="extract_digits">Extract Digits</option>
              <option value="normalize_slash_dates">Normalize Dates (MM/DD/YYYY)</option>
            </select>
            {operation.mode === 'custom' && (
              <>
                <div className="flex gap-1">
                  <input
                    type="text"
                    className="flex-1 min-w-0 text-xs rounded border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-1.5 font-mono"
                    placeholder="Regex Pattern"
                    value={operation.pattern || ''}
                    onChange={(e) => onChange({ ...operation, pattern: e.target.value })}
                  />
                  <button
                    className="p-1.5 bg-gray-100 dark:bg-gray-700 rounded border border-gray-300 dark:border-gray-600 text-gray-600 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-600"
                    title="Generate regex from literal text"
                    onClick={() => {
                      const text = prompt("Enter the exact text you want to match (it will be escaped):");
                      if (text) {
                        // Simple regex escape
                        const escaped = text.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
                        onChange({ ...operation, pattern: escaped });
                      }
                    }}
                  >
                    <Wand2 size={14} />
                  </button>
                </div>
                <input
                  type="text"
                  className="w-full text-xs rounded border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 p-1.5"
                  placeholder="Replacement"
                  value={operation.repl || ''}
                  onChange={(e) => onChange({ ...operation, repl: e.target.value })}
                />
              </>
            )}
          </div>
        )}
      </div>
    </div>
  );
};

const TextCleaningSettings: React.FC<{ config: TextCleaningConfig; onChange: (c: TextCleaningConfig) => void; nodeId?: string }> = ({
  config,
  onChange,
  nodeId,
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const [isWide, setIsWide] = useState(false);
  const [showInfo, setShowInfo] = useState(true);

  const upstreamData = useUpstreamData(nodeId || '');
  const datasetId = upstreamData.find((d: Record<string, unknown>) => d.datasetId)?.datasetId as string | undefined;
  const { data: schema } = useDatasetSchema(datasetId);
  
  // Filter for text columns only
  const textColumns = schema 
    ? Object.values(schema.columns)
      .filter((c) => {
        const dtype = String(c.dtype).toLowerCase();
        return dtype.includes('object') || dtype.includes('string') || dtype.includes('category') || dtype.includes('text');
      })
      .map((c) => c.name)
    : [];

  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setIsWide(entry.contentRect.width > 400);
      }
    });
    observer.observe(containerRef.current);
    return () => { observer.disconnect(); };
  }, []);

  const addOperation = () => {
    onChange({
      ...config,
      operations: [...config.operations, { op: 'trim', mode: 'both' }]
    });
  };

  const updateOperation = (index: number, op: TextOperation) => {
    const newOps = [...config.operations];
    newOps[index] = op;
    onChange({ ...config, operations: newOps });
  };

  const removeOperation = (index: number) => {
    const newOps = config.operations.filter((_, i) => i !== index);
    onChange({ ...config, operations: newOps });
  };

  return (
    <div ref={containerRef} className={`flex flex-col h-full w-full bg-white dark:bg-gray-900 ${isWide ? 'overflow-hidden' : 'overflow-y-auto'}`}>
      <div className={`flex-1 min-h-0 p-4 gap-4 ${isWide ? 'grid grid-cols-2' : 'flex flex-col'}`}>
        
        {/* Left Column: Column Selection */}
        <div className={`space-y-4 ${isWide ? 'overflow-y-auto pr-2' : 'shrink-0'}`}>
          <div>
            <label className="text-sm font-medium text-gray-700 dark:text-gray-300 mb-2 block">
              Target Columns ({config.columns.length})
            </label>
            <ColumnSelector 
              columns={textColumns} 
              selected={config.columns} 
              onChange={(cols) => onChange({ ...config, columns: cols })} 
            />
            <p className="text-xs text-gray-500 mt-1">Only text/categorical columns are shown.</p>
          </div>
        </div>

        {/* Right Column: Operations */}
        <div className={`space-y-4 ${isWide ? 'overflow-y-auto pl-2 border-l border-gray-100 dark:border-gray-700' : 'shrink-0 pt-4 border-t border-gray-100 dark:border-gray-700'}`}>
          <div className="bg-blue-50 dark:bg-blue-900/20 rounded-md border border-blue-100 dark:border-blue-800 overflow-hidden">
            <button 
              onClick={() => { setShowInfo(!showInfo); }}
              className="w-full flex items-center gap-2 p-3 text-left hover:bg-blue-100/50 dark:hover:bg-blue-900/30 transition-colors"
            >
              <Info className="text-blue-600 dark:text-blue-400 shrink-0" size={16} />
              <span className="text-xs font-semibold text-blue-800 dark:text-blue-200 flex-1">
                About Text Cleaning
              </span>
              {showInfo ? (
                <ChevronUp size={14} className="text-blue-600 dark:text-blue-400" />
              ) : (
                <ChevronDown size={14} className="text-blue-600 dark:text-blue-400" />
              )}
            </button>
            
            {showInfo && (
              <div className="px-3 pb-3 text-xs text-blue-800 dark:text-blue-200 pl-9">
                <p>Clean and standardize text columns by trimming whitespace, changing case, removing special characters, or applying custom regex patterns.</p>
              </div>
            )}
          </div>

          <div className="flex items-center justify-between">
            <label className="text-sm font-medium text-gray-700 dark:text-gray-300">
              Cleaning Operations
            </label>
            <button
              onClick={addOperation}
              className="flex items-center gap-1 text-xs font-medium text-blue-600 hover:text-blue-700 dark:text-blue-400 dark:hover:text-blue-300"
            >
              <Plus size={14} />
              Add Step
            </button>
          </div>

          <div className="space-y-3">
            {config.operations.length === 0 ? (
              <div className="text-center p-6 border-2 border-dashed border-gray-200 dark:border-gray-700 rounded-lg">
                <p className="text-xs text-gray-500">No operations added.</p>
                <button
                  onClick={addOperation}
                  className="mt-2 text-xs text-blue-600 hover:underline"
                >
                  Add your first cleaning step
                </button>
              </div>
            ) : (
              config.operations.map((op, idx) => (
                <OperationEditor
                  key={idx}
                  operation={op}
                  onChange={(newOp) => { updateOperation(idx, newOp); }}
                  onDelete={() => { removeOperation(idx); }}
                />
              ))
            )}
          </div>
        </div>

      </div>
    </div>
  );
};

export const TextCleaningNode: NodeDefinition<TextCleaningConfig> = {
  type: 'TextCleaning',
  label: 'Text Cleaning',
  category: 'Preprocessing',
  description: 'Clean and standardize text columns.',
  icon: Eraser,
  inputs: [{ id: 'in', label: 'Data', type: 'dataset' }],
  outputs: [{ id: 'out', label: 'Cleaned Data', type: 'dataset' }],
  settings: TextCleaningSettings,
  validate: (config) => {
    if (config.columns.length === 0) return { isValid: false, message: 'Select at least one column.' };
    if (config.operations.length === 0) return { isValid: false, message: 'Add at least one operation.' };
    return { isValid: true };
  },
  getDefaultConfig: () => ({
    columns: [],
    operations: [{ op: 'trim', mode: 'both' }],
  }),
};

import React, { useMemo, useState, useRef, useEffect } from 'react';
import { NodeDefinition } from '../../../core/types/nodes';
import { FunctionSquare, Plus, Trash2, Search, ChevronDown, ChevronRight } from 'lucide-react';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';
import { useRecommendations } from '../../../core/hooks/useRecommendations';
import { RecommendationsPanel } from '../../../components/panels/RecommendationsPanel';

interface TransformationRule {
  columns: string[];
  method: 'yeo-johnson' | 'box-cox' | 'log' | 'square_root' | 'cube_root' | 'reciprocal' | 'square' | 'exponential';
  params?: {
    standardize?: boolean;
    clip_threshold?: number;
  };
}

interface TransformationConfig {
  transformations: TransformationRule[];
}

const TRANSFORMATION_TYPES = {
  power: {
    label: 'Power Transforms',
    methods: [
      { value: 'yeo-johnson', label: 'Yeo-Johnson' },
      { value: 'box-cox', label: 'Box-Cox (>0 only)' }
    ]
  },
  simple: {
    label: 'Simple Math',
    methods: [
      { value: 'log', label: 'Log (log1p)' },
      { value: 'square_root', label: 'Square Root' },
      { value: 'cube_root', label: 'Cube Root' },
      { value: 'reciprocal', label: 'Reciprocal (1/x)' },
      { value: 'square', label: 'Square (x²)' },
      { value: 'exponential', label: 'Exponential (eˣ)' }
    ]
  }
} as const;

const getMethodType = (method: string): 'power' | 'simple' => {
  if (['yeo-johnson', 'box-cox'].includes(method)) return 'power';
  return 'simple';
};

const ColumnSelector: React.FC<{
  allColumns: string[];
  selectedColumns: string[];
  onChange: (cols: string[]) => void;
}> = ({ allColumns, selectedColumns, onChange }) => {
  const [search, setSearch] = useState("");
  
  const filteredColumns = useMemo(() => 
    allColumns.filter(c => c.toLowerCase().includes(search.toLowerCase())),
  [allColumns, search]);

  const handleSelectAll = () => {
    const newSelection = Array.from(new Set([...selectedColumns, ...filteredColumns]));
    onChange(newSelection);
  };

  const handleDeselectAll = () => {
    const newSelection = selectedColumns.filter(c => !filteredColumns.includes(c));
    onChange(newSelection);
  };

  const toggleColumn = (col: string) => {
    if (selectedColumns.includes(col)) {
      onChange(selectedColumns.filter(c => c !== col));
    } else {
      onChange([...selectedColumns, col]);
    }
  };

  return (
    <div className="space-y-2 border rounded p-2 bg-background">
      <div className="flex gap-2 items-center">
        <div className="relative flex-1">
           <Search className="absolute left-2 top-1/2 -translate-y-1/2 w-3 h-3 text-muted-foreground pointer-events-none z-10" />
           <input 
             className="w-full pl-7 pr-2 py-1 text-xs border rounded bg-background" 
             placeholder="Search columns..." 
             value={search}
             onChange={e => { setSearch(e.target.value); }}
           />
        </div>
      </div>
      <div className="flex gap-2 text-xs border-b pb-2">
        <button onClick={handleSelectAll} className="text-primary hover:underline font-medium">Select All</button>
        <span className="text-muted-foreground">|</span>
        <button onClick={handleDeselectAll} className="text-muted-foreground hover:underline">None</button>
        <span className="ml-auto text-muted-foreground">{selectedColumns.length} selected</span>
      </div>
      <div className="max-h-32 overflow-y-auto space-y-1 pt-1">
         {filteredColumns.length === 0 ? (
            <div className="text-xs text-muted-foreground p-2 text-center">No columns match "{search}"</div>
         ) : (
            filteredColumns.map(col => (
              <label key={col} className="flex items-center gap-2 text-xs cursor-pointer hover:bg-accent/50 p-1 rounded">
                <input
                  type="checkbox"
                  checked={selectedColumns.includes(col)}
                  onChange={() => { toggleColumn(col); }}
                  className="rounded border-gray-300 text-primary focus:ring-primary"
                />
                <span className="truncate" title={col}>{col}</span>
              </label>
            ))
         )}
      </div>
    </div>
  );
};

const TransformationSettings: React.FC<{ config: TransformationConfig; onChange: (c: TransformationConfig) => void; nodeId?: string }> = ({
  config: propConfig,
  onChange,
  nodeId,
}) => {
  // Defensive defaults
  const config = useMemo(() => propConfig || { transformations: [] }, [propConfig]);
  const transformations = useMemo(() => Array.isArray(config.transformations) ? config.transformations : [], [config.transformations]);

  const [expandedRules, setExpandedRules] = useState<number[]>([]);

  // Responsive Layout Logic
  const containerRef = useRef<HTMLDivElement>(null);
  const [isWide, setIsWide] = useState(false);

  useEffect(() => {
    if (!containerRef.current) return;
    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        setIsWide(entry.contentRect.width > 450);
      }
    });
    observer.observe(containerRef.current);
    return () => { observer.disconnect(); };
  }, []);

  const upstreamData = useUpstreamData(nodeId || '');
  const datasetId = upstreamData.find(d => d.datasetId)?.datasetId as string | undefined;
  const { data: schema } = useDatasetSchema(datasetId);
  
  const columns = useMemo(() => {
    if (!schema?.columns) return [];
    return Object.values(schema.columns)
        .filter(c => ['int', 'float', 'number'].some(t => c.dtype.toLowerCase().includes(t)))
        .map(c => c.name);
  }, [schema]);

  const addRule = () => {
    const newIndex = transformations.length;
    setExpandedRules(prev => [...prev, newIndex]);
    onChange({
      transformations: [...transformations, { columns: [], method: 'log', params: {} }]
    });
  };

  const updateRule = (index: number, updates: Partial<TransformationRule>) => {
    const current = [...transformations];
    current[index] = { ...current[index], ...updates };
    onChange({ transformations: current });
  };

  const removeRule = (index: number) => {
    const current = [...transformations];
    current.splice(index, 1);
    onChange({ transformations: current });
    setExpandedRules(prev => prev.filter(i => i !== index).map(i => i > index ? i - 1 : i));
  };

  const toggleRule = (index: number) => {
    setExpandedRules(prev => 
      prev.includes(index) ? prev.filter(i => i !== index) : [...prev, index]
    );
  };

  const handleTypeChange = (index: number, newType: 'power' | 'simple') => {
    const defaultMethod = TRANSFORMATION_TYPES[newType].methods[0].value;
    updateRule(index, { method: defaultMethod as TransformationRule['method'] });
  };

  const backendRecommendations = useRecommendations(nodeId || '', {
    types: ['transformation', 'preprocessing'],
    suggestedNodeTypes: ['TransformationNode'],
    scope: 'column'
  });

  return (
    <div ref={containerRef} className="p-4 space-y-6 h-full overflow-y-auto">
      <div className="flex justify-between items-center">
        <label className="text-sm font-medium">Transformation Rules</label>
        <button
          onClick={addRule}
          className="flex items-center gap-1 text-xs bg-primary text-primary-foreground px-2 py-1 rounded hover:bg-primary/90"
        >
          <Plus size={12} /> Add Rule
        </button>
      </div>

      <div className="space-y-4">
        {transformations.map((rule, idx) => {
          const currentType = getMethodType(rule.method);
          const isExpanded = expandedRules.includes(idx);
          const methodLabel = TRANSFORMATION_TYPES[currentType].methods.find(m => m.value === rule.method)?.label || rule.method;
          
          return (
            <div key={idx} className="border rounded bg-card shadow-sm overflow-hidden">
              {/* Header */}
              <div 
                className="flex items-center justify-between p-3 cursor-pointer hover:bg-accent/50 transition-colors"
                onClick={() => { toggleRule(idx); }}
              >
                <div className="flex items-center gap-2 overflow-hidden">
                  {isExpanded ? <ChevronDown size={16} className="text-muted-foreground flex-shrink-0" /> : <ChevronRight size={16} className="text-muted-foreground flex-shrink-0" />}
                  <div className="flex flex-col overflow-hidden">
                    <span className="text-sm font-medium truncate">{methodLabel}</span>
                    <span className="text-xs text-muted-foreground truncate">
                      {rule.columns.length === 0 ? 'No columns selected' : `${rule.columns.length} columns`}
                    </span>
                  </div>
                </div>
                <button
                  onClick={(e) => { e.stopPropagation(); removeRule(idx); }}
                  className="text-destructive hover:bg-destructive/10 p-1.5 rounded flex-shrink-0"
                  title="Remove rule"
                >
                  <Trash2 size={14} />
                </button>
              </div>

              {/* Body */}
              {isExpanded && (
                <div className={`p-3 border-t bg-accent/5 animate-in slide-in-from-top-2 duration-200 ${isWide ? 'grid grid-cols-2 gap-4' : 'space-y-3'}`}>
                  
                  {/* Left Column: Settings */}
                  <div className="flex flex-col gap-3">
                    <div className="flex flex-col gap-2">
                      <label className="text-xs font-medium text-muted-foreground">Method</label>
                      <select
                        className="w-full p-1.5 border rounded text-xs bg-background font-medium"
                        value={currentType}
                        onChange={(e) => { handleTypeChange(idx, e.target.value as 'power' | 'simple'); }}
                        onClick={(e) => { e.stopPropagation(); }}
                      >
                        <option value="simple">Simple Math</option>
                        <option value="power">Power Transform</option>
                      </select>

                      <select
                        className="w-full p-1.5 border rounded text-xs bg-background"
                        value={rule.method}
                        onChange={(e) => { updateRule(idx, { method: e.target.value as TransformationRule['method'] }); }}
                        onClick={(e) => { e.stopPropagation(); }}
                      >
                        {TRANSFORMATION_TYPES[currentType].methods.map(m => (
                          <option key={m.value} value={m.value}>{m.label}</option>
                        ))}
                      </select>
                    </div>

                    {(rule.method === 'yeo-johnson' || rule.method === 'box-cox') && (
                      <div className="flex items-center gap-2 pt-1" onClick={(e) => { e.stopPropagation(); }}>
                        <input
                          type="checkbox"
                          id={`std-${idx}`}
                          checked={rule.params?.standardize !== false}
                          onChange={(e) => { updateRule(idx, { params: { ...rule.params, standardize: e.target.checked } }); }}
                        />
                        <label htmlFor={`std-${idx}`} className="text-xs text-muted-foreground">Standardize result</label>
                      </div>
                    )}
                    
                    {rule.method === 'exponential' && (
                       <div className="flex flex-col gap-1 pt-1" onClick={(e) => { e.stopPropagation(); }}>
                         <label className="text-xs text-muted-foreground">Clip Threshold:</label>
                         <input
                           type="number"
                           className="w-full p-1 border rounded text-xs"
                           value={rule.params?.clip_threshold || 700}
                           onChange={(e) => { updateRule(idx, { params: { ...rule.params, clip_threshold: parseFloat(e.target.value) } }); }}
                         />
                       </div>
                    )}
                  </div>

                  {/* Right Column: Columns */}
                  <div className="space-y-1 min-w-0" onClick={(e) => { e.stopPropagation(); }}>
                    <label className="text-xs font-medium text-muted-foreground">Target Columns</label>
                    <ColumnSelector 
                      allColumns={columns}
                      selectedColumns={rule.columns}
                      onChange={(newCols) => { updateRule(idx, { columns: newCols }); }}
                    />
                  </div>
                </div>
              )}
            </div>
          );
        })}
        
        {transformations.length === 0 && (
          <div className="text-xs text-muted-foreground text-center py-8 border border-dashed rounded bg-muted/20">
            No transformation rules defined.<br/>Click "Add Rule" to start.
          </div>
        )}
      </div>

      <RecommendationsPanel
        recommendations={backendRecommendations || []}
        onApply={(rec) => {
          // Apply recommendation logic
          const r = rec as unknown as Record<string, unknown>;
          const method = (r.suggested_params as Record<string, unknown>).method || (r.params as Record<string, unknown>)?.method || 'log';
          const columns = (r.target_columns as string[]) || [];
          
          if (columns.length > 0) {
             const newIndex = transformations.length;
             setExpandedRules(prev => [...prev, newIndex]);
             onChange({
               transformations: [
                 ...transformations,
                 { columns, method: method as TransformationRule['method'], params: {} }
               ]
             });
          }
        }}
      />
    </div>
  );
};

export const TransformationNode: NodeDefinition<TransformationConfig> = {
  type: 'TransformationNode',
  label: 'Transformation',
  description: 'Apply mathematical transformations to features.',
  icon: FunctionSquare as unknown as React.FC<any>,
  category: 'Preprocessing',
  inputs: [{ id: 'in', type: 'dataset', label: 'Dataset' }],
  outputs: [{ id: 'out', type: 'dataset', label: 'Transformed' }],
  validate: (config: TransformationConfig) => {
    if (config.transformations.length === 0) {
      return { isValid: false, message: 'Add at least one transformation rule.' };
    }
    for (const rule of config.transformations) {
        if (rule.columns.length === 0) {
            return { isValid: false, message: 'Each rule must have at least one column selected.' };
        }
    }
    return { isValid: true };
  },
  settings: TransformationSettings,
  getDefaultConfig: () => ({
    transformations: []
  })
};

import React, { useState } from 'react';
import { Plus, Trash2, Search, ArrowRight } from 'lucide-react';
import { useUpstreamData } from '../../../core/hooks/useUpstreamData';
import { useDatasetSchema } from '../../../core/hooks/useDatasetSchema';

export interface ReplacementItem {
  old: unknown;
  new: unknown;
  oldType: 'string' | 'number' | 'boolean' | 'null' | 'nan';
  newType: 'string' | 'number' | 'boolean' | 'null' | 'nan';
}

export interface ValueReplacementConfig {
  columns: string[];
  replacements: ReplacementItem[];
}

type ValueReplacementValueType = ReplacementItem['oldType'];

const ColumnSelector: React.FC<{
  columns: string[];
  selected: string[];
  onChange: (selected: string[]) => void;
}> = ({ columns, selected, onChange }) => {
  const [search, setSearch] = useState('');
  
  const filtered = columns.filter(c => c.toLowerCase().includes(search.toLowerCase()));

  const toggle = (col: string) => {
    if (selected.includes(col)) {
      onChange(selected.filter(c => c !== col));
    } else {
      onChange([...selected, col]);
    }
  };

  return (
    <div className="border rounded bg-background overflow-hidden flex flex-col max-h-40">
      <div className="flex items-center px-2 py-1.5 border-b bg-muted/20">
        <Search size={12} className="text-muted-foreground mr-1.5" />
        <input
          className="flex-1 bg-transparent text-xs outline-none placeholder:text-muted-foreground/70"
          placeholder="Search columns..."
          value={search}
          onChange={e => { setSearch(e.target.value); }}
        />
      </div>
      <div className="overflow-y-auto p-1 space-y-0.5">
        {filtered.length > 0 ? (
          filtered.map(col => {
            const isSelected = selected.includes(col);
            return (
              <div
                key={col}
                onClick={() => { toggle(col); }}
                className={`
                  flex items-center gap-2 px-2 py-1.5 rounded text-xs cursor-pointer transition-colors
