                            <div className="flex items-center gap-1.5 px-3 py-2.5 border border-gray-200 dark:border-slate-600 rounded-md text-sm bg-gray-50 dark:bg-slate-900">
                                <FileUp size={14} className="text-green-500 shrink-0" />
                                <span className="text-slate-700 dark:text-slate-300 truncate max-w-[180px]">{file.name}</span>
                                <button type="button" onClick={() => setFile(null)} className="text-gray-400 hover:text-red-500 transition-colors ml-1">
                                    <X size={14} />
                                </button>
                            </div>
                        ) : (
                            <button
                                type="button"
                                onClick={() => fileInputRef.current?.click()}
                                className="flex items-center gap-2 px-3 py-2.5 border border-dashed border-gray-300 dark:border-slate-600 rounded-md text-sm text-gray-500 dark:text-gray-400 hover:border-blue-400 hover:text-blue-500 dark:hover:border-blue-500 transition-colors"
                            >
                                <Upload size={15} />
                                Upload CSV / Parquet
                            </button>
                        )}
                    </div>

                    {/* Run button */}
                    <button
                        onClick={handleCalculate}
                        disabled={loading || !selectedJob || !file}
                        className="flex items-center justify-center gap-2 px-5 py-2.5 bg-blue-600 text-white rounded-md text-sm font-medium hover:bg-blue-700 disabled:opacity-40 disabled:cursor-not-allowed transition-colors shrink-0"
                    >
                        {loading ? <Loader2 className="animate-spin" size={16} /> : <BarChart2 size={16} />}
                        {loading ? 'Analyzing...' : 'Run Analysis'}
                    </button>

                    {/* Refresh */}
                    <button
                        onClick={fetchJobs}
                        className="p-2.5 rounded-md hover:bg-gray-100 dark:hover:bg-slate-700 text-gray-400 transition-colors shrink-0"
                        title="Refresh jobs"
                    >
                        <RefreshCw size={16} className={refreshing ? "animate-spin" : ""} />
                    </button>

                    {/* Thresholds toggle */}
                    <button
                        onClick={() => setShowThresholds(p => !p)}
                        className={`p-2.5 rounded-md transition-colors shrink-0 ${showThresholds ? 'bg-blue-50 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400' : 'hover:bg-gray-100 dark:hover:bg-slate-700 text-gray-400'}`}
                        title="Drift thresholds"
                    >
                        <Settings size={16} />
                    </button>
                </div>

                {/* Threshold settings panel */}
                {showThresholds && (
                    <div className="px-4 pb-3 flex flex-wrap items-center gap-4 border-t border-gray-100 dark:border-slate-700 pt-3">
                        <span className="text-xs font-medium text-gray-500 dark:text-slate-400">Thresholds:</span>
                        {([
                            { key: 'psi' as const, label: 'PSI', step: 0.05, min: 0.01, max: 1 },
                            { key: 'ks' as const, label: 'KS p-value', step: 0.01, min: 0.001, max: 0.2 },
                            { key: 'wasserstein' as const, label: 'Wasserstein', step: 0.05, min: 0.01, max: 1 },
                            { key: 'kl' as const, label: 'KL Div', step: 0.05, min: 0.01, max: 1 },
                        ]).map(({ key, label, step, min, max }) => (
                            <label key={key} className="flex items-center gap-1.5 text-xs text-gray-600 dark:text-slate-400">
                                <span className="font-medium">{label}</span>
                                <input
                                    type="number"
                                    value={thresholds[key] ?? ''}
                                    onChange={e => setThresholds(prev => ({ ...prev, [key]: parseFloat(e.target.value) || undefined }))}
                                    step={step}
                                    min={min}
                                    max={max}
                                    className="w-20 px-2 py-1 text-xs border border-gray-200 dark:border-slate-600 rounded bg-white dark:bg-slate-900 dark:text-white focus:outline-none focus:ring-1 focus:ring-blue-500 tabular-nums"
                                />
                            </label>
                        ))}
                        <button
                            onClick={() => setThresholds({ psi: 0.2, ks: 0.05, wasserstein: 0.1, kl: 0.1 })}
                            className="text-[11px] text-gray-400 hover:text-gray-600 dark:hover:text-slate-300 transition-colors"
                        >
                            Reset defaults
                        </button>
                    </div>
                )}

                {/* Selected job metadata + description */}
                {selectedJobData && (
                    <div className="flex flex-wrap items-center gap-x-3 gap-y-1 px-4 pb-3 text-xs text-gray-500 dark:text-slate-400">
                        {selectedJobData.model_type && (
                            <span className="px-2 py-0.5 rounded bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-300 font-medium">{selectedJobData.model_type}</span>
                        )}
                        {selectedJobData.target_column && (
                            <span>Target: <span className="font-medium text-slate-600 dark:text-slate-300">{selectedJobData.target_column}</span></span>
                        )}
                        {selectedJobData.n_features != null && (
                            <span>{selectedJobData.n_features} features</span>
                        )}
                        {selectedJobData.n_rows != null && (
                            <span>{selectedJobData.n_rows.toLocaleString()} rows</span>
                        )}
                        {selectedJobData.best_metric && (
                            <span className="px-2 py-0.5 rounded bg-green-50 dark:bg-green-900/30 text-green-600 dark:text-green-300 font-medium tabular-nums">{selectedJobData.best_metric}</span>
                        )}
                        <span className="border-l border-gray-200 dark:border-slate-700 h-3" />
                        {editingDescription ? (
                            <div className="flex items-center gap-1.5 flex-1 min-w-0">
                                <input
                                    autoFocus
                                    value={descriptionDraft}
                                    onChange={e => setDescriptionDraft(e.target.value)}
                                    onKeyDown={e => { if (e.key === 'Enter') handleSaveDescription(); if (e.key === 'Escape') setEditingDescription(false); }}
                                    placeholder="Add a description..."
                                    className="flex-1 min-w-0 px-2 py-0.5 text-xs border border-gray-200 dark:border-slate-600 rounded bg-white dark:bg-slate-900 dark:text-white focus:outline-none focus:ring-1 focus:ring-blue-500"
                                />
                                <button onClick={handleSaveDescription} className="text-green-500 hover:text-green-600"><Check size={13} /></button>
                                <button onClick={() => setEditingDescription(false)} className="text-gray-400 hover:text-red-500"><X size={13} /></button>
                            </div>
                        ) : (
                            <button
                                onClick={() => { setDescriptionDraft(selectedJobData.description || ''); setEditingDescription(true); }}
                                className="flex items-center gap-1 hover:text-blue-500 transition-colors group"
                            >
                                <Pencil size={11} className="opacity-50 group-hover:opacity-100" />
                                <span className={selectedJobData.description ? '' : 'italic text-gray-400'}>
                                    {selectedJobData.description || 'Add description...'}
                                </span>
                            </button>
                        )}
                    </div>
                )}

                {error && (
                    <div className="mx-4 mb-4 p-3 bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-200 rounded-md flex items-center gap-2 border border-red-200 dark:border-red-800 text-sm">
                        <AlertTriangle size={16} className="shrink-0" />
                        {error}
                    </div>
                )}
            </div>

            {!report && !loading && (
                <div className="bg-white dark:bg-slate-800 rounded-lg shadow border dark:border-slate-700 p-12 text-center">
                    <div className="flex flex-col items-center gap-3 text-gray-400 dark:text-slate-500">
                        <Activity size={48} strokeWidth={1.2} />
                        <h2 className="text-lg font-medium text-gray-500 dark:text-slate-400">No Drift Report Yet</h2>
                        <p className="text-sm max-w-md">
                            Select a reference model from the dropdown above, upload current production data (CSV or Parquet), and click <strong>Run Analysis</strong> to compare distributions.
                        </p>
                    </div>
                </div>
            )}

            {evaluatedReport && (() => {
                const allCols = Object.values(evaluatedReport.column_drifts);
                const totalCols = allCols.length;
                const driftedCount = evaluatedReport.drifted_columns_count;
                const psiValues = allCols.map(c => c.metrics.find(m => m.metric === 'psi')?.value).filter((v): v is number => v != null);
                const avgPsi = psiValues.length > 0 ? psiValues.reduce((a, b) => a + b, 0) / psiValues.length : 0;
                const mostDrifted = [...allCols].sort((a, b) => {
                    const pa = a.metrics.find(m => m.metric === 'psi')?.value ?? 0;
                    const pb = b.metrics.find(m => m.metric === 'psi')?.value ?? 0;
                    return pb - pa;
                })[0];

                const hasSparklines = Object.keys(columnSparklines).length > 0;

                return (
                <div className="bg-white dark:bg-slate-800 p-6 rounded-lg shadow border dark:border-slate-700">
                    {/* Summary Cards */}
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
                        <div className="bg-gray-50 dark:bg-slate-900/50 rounded-lg p-4 border dark:border-slate-700">
                            <div className="flex items-center gap-2 text-xs text-gray-500 dark:text-slate-400 mb-1"><Columns size={13} /> Total Columns</div>
                            <div className="text-2xl font-bold tabular-nums">{totalCols}</div>
                            <div className="text-[11px] text-gray-400 mt-0.5">Ref: {evaluatedReport.reference_rows.toLocaleString()} rows | Cur: {evaluatedReport.current_rows.toLocaleString()} rows</div>
                        </div>
                        <div className={`rounded-lg p-4 border ${driftedCount > 0 ? 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800' : 'bg-green-50 dark:bg-green-900/20 border-green-200 dark:border-green-800'}`}>
                            <div className="flex items-center gap-2 text-xs text-gray-500 dark:text-slate-400 mb-1">{driftedCount > 0 ? <AlertTriangle size={13} /> : <CheckCircle size={13} />} Drifted</div>
                            <div className="text-2xl font-bold tabular-nums">{driftedCount} <span className="text-sm font-normal text-gray-400">/ {totalCols}</span></div>
                            <div className="text-[11px] text-gray-400 mt-0.5">{totalCols > 0 ? Math.round((driftedCount / totalCols) * 100) : 0}% of features</div>
                        </div>
                        <div className="bg-gray-50 dark:bg-slate-900/50 rounded-lg p-4 border dark:border-slate-700">
                            <div className="flex items-center gap-2 text-xs text-gray-500 dark:text-slate-400 mb-1"><Gauge size={13} /> Avg PSI</div>
                            <div className={`text-2xl font-bold tabular-nums ${avgPsi > 0.2 ? 'text-red-600 dark:text-red-400' : avgPsi > 0.1 ? 'text-amber-600 dark:text-amber-400' : ''}`}>{avgPsi.toFixed(4)}</div>
                            <div className="text-[11px] text-gray-400 mt-0.5">{avgPsi < 0.1 ? 'Stable' : avgPsi < 0.2 ? 'Minor drift' : 'Significant drift'}</div>
                        </div>
                        <div className="bg-gray-50 dark:bg-slate-900/50 rounded-lg p-4 border dark:border-slate-700">
                            <div className="flex items-center gap-2 text-xs text-gray-500 dark:text-slate-400 mb-1"><Target size={13} /> Most Drifted</div>
                            <div className="text-lg font-bold truncate" title={mostDrifted?.column}>{mostDrifted?.column ?? '—'}</div>
                            <div className="text-[11px] text-gray-400 mt-0.5">PSI: {(mostDrifted?.metrics.find(m => m.metric === 'psi')?.value ?? 0).toFixed(4)}</div>
                        </div>
                    </div>

                    {/* Schema Drift Section */}
                    {(() => {
                        const missing = evaluatedReport.missing_columns.filter(c => c.trim() !== '');
                        const added = evaluatedReport.new_columns.filter(c => c.trim() !== '');
                        if (missing.length === 0 && added.length === 0) return null;
                        return (
                        <div className="mb-6 grid grid-cols-1 md:grid-cols-2 gap-4">
                            {missing.length > 0 && (
                                <details className="group bg-red-50 dark:bg-red-900/20 rounded border border-red-200 dark:border-red-800">
                                    <summary className="font-semibold text-red-800 dark:text-red-200 p-4 flex items-center gap-2 cursor-pointer select-none list-none [&::-webkit-details-marker]:hidden">
                                        <ChevronDown size={14} className="transition-transform group-open:rotate-180 shrink-0" />
                                        <AlertTriangle size={16} className="shrink-0" /> Missing Columns
                                        <span className="ml-auto text-xs font-normal bg-red-200 dark:bg-red-800 px-2 py-0.5 rounded-full">{missing.length}</span>
                                    </summary>
                                    <div className="px-4 pb-4">
                                        <p className="text-[11px] text-red-600/70 dark:text-red-300/60 mb-2">Columns present in reference (training) data but missing from your uploaded file.</p>
                                        <ul className="list-disc list-inside text-sm text-red-700 dark:text-red-300">
                                            {missing.map(col => <li key={col}>{col}</li>)}
                                        </ul>
                                    </div>
                                </details>
                            )}
                            {added.length > 0 && (
                                <details className="group bg-blue-50 dark:bg-blue-900/20 rounded border border-blue-200 dark:border-blue-800">
                                    <summary className="font-semibold text-blue-800 dark:text-blue-200 p-4 flex items-center gap-2 cursor-pointer select-none list-none [&::-webkit-details-marker]:hidden">
                                        <ChevronDown size={14} className="transition-transform group-open:rotate-180 shrink-0" />
                                        <Info size={16} className="shrink-0" /> Extra Columns
                                        <span className="ml-auto text-xs font-normal bg-blue-200 dark:bg-blue-800 px-2 py-0.5 rounded-full">{added.length}</span>
                                    </summary>
                                    <div className="px-4 pb-4">
                                        <p className="text-[11px] text-blue-600/70 dark:text-blue-300/60 mb-2">Columns in your uploaded file that were not in the training data (e.g. target column, IDs, or dropped features). These are ignored during drift analysis.</p>
                                        <ul className="list-disc list-inside text-sm text-blue-700 dark:text-blue-300">
                                            {added.map(col => <li key={col}>{col}</li>)}
                                        </ul>
                                    </div>
                                </details>
                            )}
                        </div>
                        );
                    })()}

                    {/* Filter bar */}
                    <div className="flex items-center gap-3 mb-4">
                        <button
                            onClick={() => setShowOnlyDrifted(prev => !prev)}
                            className={`flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-medium transition-colors border ${
                                showOnlyDrifted
                                    ? 'bg-red-50 dark:bg-red-900/30 border-red-200 dark:border-red-700 text-red-700 dark:text-red-300'
                                    : 'border-gray-200 dark:border-slate-600 text-gray-500 dark:text-slate-400 hover:bg-gray-50 dark:hover:bg-slate-700'
                            }`}
                        >
                            <Filter size={12} />
                            {showOnlyDrifted ? 'Showing drifted only' : 'Show only drifted'}
                        </button>
                        {sortConfig && (
                            <button
                                onClick={() => setSortConfig(null)}
                                className="flex items-center gap-1 px-2 py-1.5 rounded-md text-xs text-gray-400 hover:text-gray-600 dark:hover:text-slate-300 transition-colors"
                            >
                                <X size={11} /> Clear sort
                            </button>
                        )}
                        <div className="ml-auto">
                            <button
                                onClick={exportCSV}
                                className="flex items-center gap-1.5 px-3 py-1.5 rounded-md text-xs font-medium border border-gray-200 dark:border-slate-600 text-gray-500 dark:text-slate-400 hover:bg-gray-50 dark:hover:bg-slate-700 transition-colors"
                                title="Download drift report as CSV"
                            >
                                <Download size={12} /> Export CSV
                            </button>
                        </div>
                    </div>

                    <div className="overflow-x-auto">
                        <table className="min-w-full divide-y divide-gray-200 dark:divide-slate-700">
                            <thead className="bg-gray-50 dark:bg-slate-900">
                                <tr>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider cursor-pointer select-none hover:text-gray-700 dark:hover:text-slate-300" onClick={() => handleSort('column')}>
                                        <span className="flex items-center gap-1">Column {renderSortIcon('column')}</span>
                                    </th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider cursor-pointer select-none hover:text-gray-700 dark:hover:text-slate-300" onClick={() => handleSort('status')}>
                                        <span className="flex items-center gap-1">Status {renderSortIcon('status')}</span>
                                    </th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider cursor-pointer select-none hover:text-gray-700 dark:hover:text-slate-300" onClick={() => handleSort('wasserstein')}>
                                        <span className="flex items-center gap-1">
                                            <MetricTooltip 
                                                label="Wasserstein" 
                                                tooltip="Measures distance between distributions. Lower is better. < 0.1 usually means stable." 
                                                icon={<Info className="w-3 h-3 text-slate-400" />}
                                            />
                                            {renderSortIcon('wasserstein')}
                                        </span>
                                    </th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider cursor-pointer select-none hover:text-gray-700 dark:hover:text-slate-300" onClick={() => handleSort('psi')}>
                                        <span className="flex items-center gap-1">
                                            <MetricTooltip 
                                                label="PSI" 
                                                tooltip="Population Stability Index. < 0.1: Stable, < 0.2: Minor Drift, > 0.2: Significant Drift." 
                                                icon={<Info className="w-3 h-3 text-slate-400" />}
                                            />
                                            {renderSortIcon('psi')}
                                        </span>
                                    </th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider cursor-pointer select-none hover:text-gray-700 dark:hover:text-slate-300" onClick={() => handleSort('kl')}>
                                        <span className="flex items-center gap-1">
                                            <MetricTooltip 
                                                label="KL Div" 
                                                tooltip="Kullback-Leibler Divergence. Measures how one probability distribution diverts from a second." 
                                                icon={<Info className="w-3 h-3 text-slate-400" />}
                                            />
                                            {renderSortIcon('kl')}
                                        </span>
                                    </th>
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider cursor-pointer select-none hover:text-gray-700 dark:hover:text-slate-300" onClick={() => handleSort('ks')}>
                                        <span className="flex items-center gap-1">
                                            <MetricTooltip 
                                                label="KS P-Value" 
                                                tooltip="Kolmogorov-Smirnov Test. p-value < 0.05 indicates the distributions are significantly different." 
                                                icon={<Info className="w-3 h-3 text-slate-400" />}
                                            />
                                            {renderSortIcon('ks')}
                                        </span>
                                    </th>
                                    {evaluatedReport.feature_importances && (
                                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider cursor-pointer select-none hover:text-gray-700 dark:hover:text-slate-300" onClick={() => handleSort('risk')}>
                                            <span className="flex items-center gap-1">
                                                <MetricTooltip 
                                                    label="Risk" 
                                                    tooltip="Combines drift status with feature importance. High = drifted + important feature. Helps prioritize which drifts to investigate." 
                                                    icon={<Info className="w-3 h-3 text-slate-400" />}
                                                />
                                                {renderSortIcon('risk')}
                                            </span>
                                        </th>
                                    )}
                                    <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">Actions</th>
                                    {hasSparklines && (
                                        <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider">
                                            <span className="flex items-center gap-1"><TrendingUp size={11} /> Trend</span>
                                        </th>
                                    )}
                                </tr>
                            </thead>
                            <tbody className="bg-white dark:bg-slate-800 divide-y divide-gray-200 dark:divide-slate-700">
                                {(() => {
                                    const fi = evaluatedReport.feature_importances;
                                    const maxImportance = fi ? Math.max(...Object.values(fi)) : 0;

                                    let rows = Object.values(evaluatedReport.column_drifts);

                                    // Filter
                                    if (showOnlyDrifted) {
                                        rows = rows.filter(c => c.drift_detected);
                                    }

                                    // Sort
                                    if (sortConfig) {
                                        rows = [...rows].sort((a, b) => {
                                            const getMetric = (col: typeof a, metric: string) => col.metrics.find(m => m.metric === metric)?.value ?? 0;
                                            let cmp = 0;
                                            switch (sortConfig.key) {
                                                case 'column': cmp = a.column.localeCompare(b.column); break;
                                                case 'status': cmp = (a.drift_detected ? 1 : 0) - (b.drift_detected ? 1 : 0); break;
                                                case 'wasserstein': cmp = getMetric(a, 'wasserstein_distance') - getMetric(b, 'wasserstein_distance'); break;
                                                case 'psi': cmp = getMetric(a, 'psi') - getMetric(b, 'psi'); break;
                                                case 'kl': cmp = getMetric(a, 'kl_divergence') - getMetric(b, 'kl_divergence'); break;
                                                case 'ks': cmp = getMetric(a, 'ks_test_p_value') - getMetric(b, 'ks_test_p_value'); break;
                                                case 'risk': cmp = (fi?.[a.column] ?? 0) - (fi?.[b.column] ?? 0); break;
                                            }
                                            return sortConfig.dir === 'asc' ? cmp : -cmp;
                                        });
                                    }

                                    if (rows.length === 0 && showOnlyDrifted) {
                                        return (
                                            <tr>
                                                <td colSpan={(fi ? 8 : 7) + (hasSparklines ? 1 : 0)} className="px-6 py-8 text-center text-gray-400 dark:text-slate-500 text-sm">
                                                    <CheckCircle size={20} className="inline mr-2 text-green-500" />
                                                    No drifted columns found — all features are stable.
                                                </td>
                                            </tr>
                                        );
                                    }

                                    return rows.map((col) => {
                                    const wasserstein = col.metrics.find(m => m.metric === 'wasserstein_distance');
                                    const psi = col.metrics.find(m => m.metric === 'psi');
                                    const kl = col.metrics.find(m => m.metric === 'kl_divergence');
                                    const ks = col.metrics.find(m => m.metric === 'ks_test_p_value');
                                    const isExpanded = expandedRows[col.column];

                                    // Feature importance risk
                                    const importance = fi?.[col.column];
                                    const importanceRank = fi ? Object.values(fi).filter(v => v > (importance ?? 0)).length + 1 : null;
                                    const isHighRisk = col.drift_detected && importanceRank != null && importanceRank <= 5;
                                    const isMediumRisk = col.drift_detected && importanceRank != null && importanceRank <= 15 && !isHighRisk;
                                    
                                    return (
                                        <React.Fragment key={col.column}>
                                            <tr className={col.drift_detected ? "bg-red-50 dark:bg-red-900/10" : ""}>
                                                <td className="px-6 py-4 whitespace-nowrap font-medium">{col.column}</td>
                                                <td className="px-6 py-4 whitespace-nowrap">
                                                    {col.drift_detected ? (
                                                        <span className="text-red-600 dark:text-red-400 flex items-center gap-1"><XCircle size={16} /> Drifted</span>
                                                    ) : (
                                                        <span className="text-green-600 dark:text-green-400 flex items-center gap-1"><CheckCircle size={16} /> Stable</span>
                                                    )}
                                                </td>
                                                <td className={`px-6 py-4 whitespace-nowrap tabular-nums ${wasserstein?.has_drift ? 'text-red-600 dark:text-red-400 font-bold' : ''}`}>
                                                    {wasserstein?.value?.toFixed(4) ?? '—'}
                                                </td>
                                                <td className={`px-6 py-4 whitespace-nowrap tabular-nums ${psi?.has_drift ? 'text-red-600 dark:text-red-400 font-bold' : ''}`}>
                                                    {psi?.value?.toFixed(4) ?? '—'}
                                                </td>
                                                <td className={`px-6 py-4 whitespace-nowrap tabular-nums ${kl?.has_drift ? 'text-red-600 dark:text-red-400 font-bold' : ''}`}>
                                                    {kl?.value?.toFixed(4) ?? '—'}
                                                </td>
                                                <td className={`px-6 py-4 whitespace-nowrap tabular-nums ${ks?.has_drift ? 'text-red-600 dark:text-red-400 font-bold' : ''}`}>
                                                    {ks?.value?.toFixed(4) ?? '—'}
                                                </td>
                                                {evaluatedReport.feature_importances && (
                                                    <td className="px-6 py-4 whitespace-nowrap">
                                                        {importance != null ? (
                                                            <div className="flex items-center gap-1.5">
                                                                {isHighRisk ? (
                                                                    <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-semibold bg-red-100 dark:bg-red-900/40 text-red-700 dark:text-red-300">
                                                                        <ShieldAlert size={12} /> High
                                                                    </span>
                                                                ) : isMediumRisk ? (
                                                                    <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-semibold bg-amber-100 dark:bg-amber-900/40 text-amber-700 dark:text-amber-300">
                                                                        <ShieldAlert size={12} /> Medium
                                                                    </span>
                                                                ) : (
                                                                    <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs bg-gray-100 dark:bg-slate-700 text-gray-500 dark:text-slate-400">
                                                                        <Shield size={12} /> Low
                                                                    </span>
                                                                )}
                                                                <div className="w-12 h-1.5 bg-gray-200 dark:bg-slate-700 rounded-full overflow-hidden" title={`Importance: ${(importance * 100 / maxImportance).toFixed(0)}%`}>
                                                                    <div className="h-full bg-indigo-500 rounded-full" style={{ width: `${maxImportance > 0 ? (importance / maxImportance) * 100 : 0}%` }} />
                                                                </div>
                                                            </div>
                                                        ) : (
                                                            <span className="text-xs text-gray-400">—</span>
                                                        )}
                                                    </td>
                                                )}
                                                <td className="px-6 py-4 whitespace-nowrap">
                                                    <button 
                                                        onClick={() => toggleRow(col.column)}
                                                        className="text-blue-600 hover:text-blue-800 dark:text-blue-400 dark:hover:text-blue-300 flex items-center gap-1 text-sm"
                                                    >
                                                        {isExpanded ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
                                                        {isExpanded ? "Hide" : "Details"}
                                                    </button>
                                                </td>
                                                {hasSparklines && (
                                                    <td className="px-6 py-4 whitespace-nowrap">
                                                        <Sparkline values={columnSparklines[col.column] ?? []} />
                                                    </td>
                                                )}
                                            </tr>
                                            {isExpanded && (
                                                <tr>
                                                    <td colSpan={(evaluatedReport.feature_importances ? 8 : 7) + (hasSparklines ? 1 : 0)} className="px-6 py-4 bg-gray-50 dark:bg-slate-900/50">
                                                        <div className="flex flex-col gap-4">
                                                            {col.suggestions && col.suggestions.length > 0 && (
                                                                <div className="bg-yellow-50 dark:bg-yellow-900/20 p-3 rounded border border-yellow-200 dark:border-yellow-800">
                                                                    <div className="flex items-start gap-2">
                                                                        <Lightbulb size={16} className="mt-0.5 shrink-0 text-yellow-600 dark:text-yellow-400" />
                                                                        <ul className="list-disc list-inside text-sm text-yellow-800 dark:text-yellow-200">
                                                                            {col.suggestions.map((s, i) => (
                                                                                <li key={i}>{s}</li>
                                                                            ))}
                                                                        </ul>
                                                                    </div>
                                                                </div>
                                                            )}
                                                            
                                                            {col.distribution && (
                                                                <div className="h-[350px] w-full bg-white dark:bg-slate-800 p-6 rounded border dark:border-slate-700 shadow-sm">
                                                                    <h4 className="text-sm font-semibold mb-6 flex items-center gap-2 text-slate-700 dark:text-slate-300">
                                                                        <BarChart2 size={16} /> Distribution Comparison
                                                                    </h4>
                                                                    <ResponsiveContainer width="100%" height="85%">
                                                                        <BarChart data={col.distribution.bins} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
                                                                            <CartesianGrid strokeDasharray="3 3" className="stroke-gray-200 dark:stroke-slate-700" vertical={false} />
                                                                            <XAxis 
                                                                                dataKey={(bin: any) => `${bin.bin_start.toFixed(2)}`} 
                                                                                className="text-xs"
                                                                                tick={{ fill: '#64748b' }}
                                                                                tickLine={false}
                                                                                axisLine={{ stroke: '#cbd5e1' }}
                                                                            />
                                                                            <YAxis 
                                                                                className="text-xs" 
                                                                                tick={{ fill: '#64748b' }} 
                                                                                tickLine={false}
                                                                                axisLine={false}
                                                                            />
                                                                            <RechartsTooltip 
                                                                                cursor={{ fill: 'rgba(0,0,0,0.05)' }}
                                                                                contentStyle={{ 
                                                                                    backgroundColor: '#1e293b', 
                                                                                    borderColor: '#334155', 
                                                                                    color: '#f8fafc',
                                                                                    borderRadius: '6px',
                                                                                    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
                                                                                }}
                                                                                itemStyle={{ color: '#f8fafc' }}
                                                                                labelStyle={{ color: '#94a3b8', marginBottom: '0.5rem' }}
                                                                            />
                                                                            <Legend 
                                                                                verticalAlign="top" 
                                                                                height={36}
                                                                                iconType="circle"
                                                                            />
                                                                            <Bar 
                                                                                dataKey="reference_count" 
                                                                                name="Reference (Training)" 
                                                                                fill="#94a3b8" 
                                                                                radius={[4, 4, 0, 0]} 
                                                                                barSize={30}
                                                                            />
                                                                            <Bar 
                                                                                dataKey="current_count" 
                                                                                name="Current (Production)" 
                                                                                fill="#3b82f6" 
                                                                                radius={[4, 4, 0, 0]} 
                                                                                barSize={30}
                                                                            />
                                                                        </BarChart>
                                                                    </ResponsiveContainer>
                                                                </div>
                                                            )}
                                                        </div>
                                                    </td>
                                                </tr>
                                            )}
                                        </React.Fragment>
                                    );
                                    });
                                })()}
                            </tbody>
                        </table>
                    </div>
                </div>
                );
            })()}

            {driftHistory.length > 1 && (
                <div className="bg-white dark:bg-slate-800 p-6 rounded-lg shadow border dark:border-slate-700 mt-6">
                    <h2 className="text-lg font-semibold mb-4 flex items-center gap-2">
                        <TrendingUp size={18} /> Drift History
                        <span className="text-xs font-normal text-gray-400 ml-1">({driftHistory.length} checks)</span>
                    </h2>
                    <div className="h-[280px]">
                        <ResponsiveContainer width="100%" height="100%">
                            <LineChart
                                data={[...driftHistory].reverse().map(h => ({
                                    date: h.created_at?.split('T')[0] ?? '',
                                    drifted: h.drifted_columns_count ?? 0,
                                    total: h.total_columns ?? 0,
                                    pct: h.total_columns ? Math.round(((h.drifted_columns_count ?? 0) / h.total_columns) * 100) : 0,
                                }))}
                                margin={{ top: 5, right: 30, left: 0, bottom: 5 }}
                            >
                                <CartesianGrid strokeDasharray="3 3" className="stroke-gray-200 dark:stroke-slate-700" vertical={false} />
                                <XAxis dataKey="date" tick={{ fill: '#64748b', fontSize: 11 }} tickLine={false} axisLine={{ stroke: '#cbd5e1' }} />
                                <YAxis tick={{ fill: '#64748b', fontSize: 11 }} tickLine={false} axisLine={false} />
                                <RechartsTooltip
                                    contentStyle={{ backgroundColor: '#1e293b', borderColor: '#334155', color: '#f8fafc', borderRadius: '6px' }}
                                    itemStyle={{ color: '#f8fafc' }}
                                    labelStyle={{ color: '#94a3b8' }}
                                    formatter={(value: number, name: string) => {
                                        if (name === 'Drifted Columns') return [value, name];
                                        if (name === 'Drift %') return [`${value}%`, name];
                                        return [value, name];
                                    }}
                                />
                                <Legend verticalAlign="top" height={36} iconType="circle" />
                                <Line type="monotone" dataKey="drifted" name="Drifted Columns" stroke="#ef4444" strokeWidth={2} dot={{ r: 3, fill: '#ef4444' }} />
                                <Line type="monotone" dataKey="pct" name="Drift %" stroke="#f59e0b" strokeWidth={2} dot={{ r: 3, fill: '#f59e0b' }} strokeDasharray="5 5" />
                            </LineChart>
                        </ResponsiveContainer>
                    </div>
                </div>
            )}
        </div>
    );
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { DatasetService } from '../core/api/datasets';
import { Dataset } from '../core/types/api';
import { FileUpload } from '../modules/nodes/data/FileUpload';
import { Trash2, Play, FileText, Calendar, Database, Plus, Eye, Loader2, XCircle, BarChart2, Download, Search, Filter } from 'lucide-react';
import { formatBytes } from '../core/utils/format';
import { DatasetPreviewModal } from '../components/data/DatasetPreviewModal';
import { AddSourceModal } from '../components/data/AddSourceModal';
import { IngestionJobsModal } from '../components/data/IngestionJobsModal';
import { LoadingState, EmptyState } from '../components/shared';

export const DataSources: React.FC = () => {
  const navigate = useNavigate();
  const [datasets, setDatasets] = useState<Dataset[]>([]);
  const [loading, setLoading] = useState(true);
  const [showUpload, setShowUpload] = useState(false);
  const [showAddSource, setShowAddSource] = useState(false);
  const [showIngestionJobs, setShowIngestionJobs] = useState(false);
  const [deletingId, setDeletingId] = useState<string | null>(null);
  const [cancellingId, setCancellingId] = useState<string | null>(null);
  const [previewDataset, setPreviewDataset] = useState<Dataset | null>(null);
  const [filterStatus, setFilterStatus] = useState<string>('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [filterType, setFilterType] = useState<string>('all');
  const [filterFormat, setFilterFormat] = useState<string>('all');
  const [showFilters, setShowFilters] = useState(false);

  const filteredDatasets = datasets.filter(d => {
    const status = d.source_metadata?.ingestion_status?.status || 'completed';
    if (filterStatus !== 'all' && status !== filterStatus) return false;
    if (filterType !== 'all' && d.type !== filterType) return false;
    if (filterFormat !== 'all' && (d.format || 'csv') !== filterFormat) return false;
    if (searchQuery) {
      const q = searchQuery.toLowerCase();
      const matchesName = d.name.toLowerCase().includes(q);
      const matchesId = (d.source_id || d.id).toLowerCase().includes(q);
      const matchesFormat = (d.format || 'csv').toLowerCase().includes(q);
      if (!matchesName && !matchesId && !matchesFormat) return false;
    }
    return true;
  });

  const activeFilterCount = (filterType !== 'all' ? 1 : 0) + (filterFormat !== 'all' ? 1 : 0);

  const fetchDatasets = async () => {
    // Don't set loading to true on subsequent polls to avoid flickering
    if (datasets.length === 0) setLoading(true);
    try {
      const data = await DatasetService.getAll();
      setDatasets(data);
    } catch (error) {
      console.error('Failed to fetch datasets:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    void fetchDatasets();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    // Poll every 5 seconds if there are pending jobs
    const interval = setInterval(() => {
      const hasPending = datasets.some(d => 
        d.source_metadata?.ingestion_status?.status === 'pending' || 
        d.source_metadata?.ingestion_status?.status === 'processing'
      );
      if (hasPending) {
        void fetchDatasets();
      }
    }, 5000);
    return () => { clearInterval(interval); };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [datasets]); // Re-run effect when datasets change to update "hasPending" check

  const handleDelete = async (id: string) => {
    if (!window.confirm('Are you sure you want to delete this dataset?')) return;
    
    setDeletingId(id);
    try {
      await DatasetService.delete(id);
      setDatasets(datasets.filter(d => d.id !== id));
    } catch (error) {
      console.error('Failed to delete dataset:', error);
      alert('Failed to delete dataset');
    } finally {
      setDeletingId(null);
    }
  };

  const handleCancel = async (id: string) => {
    if (!window.confirm('Are you sure you want to cancel this ingestion job?')) return;
    
    setCancellingId(id);
    try {
      await DatasetService.cancelIngestion(id);
      fetchDatasets();
    } catch (error) {
      console.error('Failed to cancel ingestion:', error);
      alert('Failed to cancel ingestion');
    } finally {
      setCancellingId(null);
    }
  };

  const handleUseInCanvas = (id: string) => {
    navigate(`/canvas?source_id=${id}`);
  };

  const handleUploadComplete = () => {
    setShowUpload(false);
    fetchDatasets();
  };

  const handleSourceCreated = () => {
    setShowAddSource(false);
    fetchDatasets();
  };

  const getStatusBadge = (dataset: Dataset) => {
    const status = dataset.source_metadata?.ingestion_status?.status;
    if (!status || status === 'completed') return null;

    if (status === 'failed') {
      return (
        <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-red-100 text-red-800 dark:bg-red-900/20 dark:text-red-400">
          Failed
        </span>
      );
    }

    if (status === 'cancelled') {
      return (
        <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-slate-100 text-slate-800 dark:bg-slate-800 dark:text-slate-400">
          Cancelled
        </span>
      );
    }

    return (
      <span className="inline-flex items-center gap-1 px-2 py-0.5 rounded text-xs font-medium bg-blue-100 text-blue-800 dark:bg-blue-900/20 dark:text-blue-400">
        <Loader2 size={12} className="animate-spin" />
        {status === 'processing' ? 'Processing...' : 'Pending...'}
      </span>
    );
  };

  return (
    <div className="p-8 space-y-6">
      <DatasetPreviewModal 
        dataset={previewDataset} 
        isOpen={!!previewDataset} 
        onClose={() => { setPreviewDataset(null); }}
      />

      <AddSourceModal
        isOpen={showAddSource}
        onClose={() => { setShowAddSource(false); }}
        onSuccess={handleSourceCreated}
      />

      <IngestionJobsModal
        isOpen={showIngestionJobs}
        onClose={() => { setShowIngestionJobs(false); }}
        datasets={datasets}
        onRefresh={fetchDatasets}
      />

      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold text-slate-900 dark:text-slate-100">Data Sources</h1>
          <p className="text-slate-500 dark:text-slate-400 mt-1">Manage your uploaded datasets and use them in experiments.</p>
        </div>
        <div className="flex gap-3">
          <button
            onClick={() => { setShowIngestionJobs(true); }}
            className="flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-md shadow-sm hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors text-slate-700 dark:text-slate-200"
          >
            <Calendar size={18} />
            Ingestion Jobs
          </button>
          <button
            onClick={() => { setShowAddSource(true); }}
            className="flex items-center gap-2 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-200 border border-slate-300 dark:border-slate-600 px-4 py-2 rounded-md shadow-sm transition-all hover:bg-slate-50 dark:hover:bg-slate-700"
          >
            <Database size={18} />
            Add Source
          </button>
          <button
            onClick={() => { setShowUpload(!showUpload); }}
            className="flex items-center gap-2 text-white px-4 py-2 rounded-md shadow-sm transition-all hover:opacity-90"
            style={{ background: 'var(--main-gradient)' }}
          >
            <Plus size={18} />
            {showUpload ? 'Cancel Upload' : 'Upload File'}
          </button>
        </div>
      </div>

      {showUpload && (
        <div className="bg-white dark:bg-slate-800 p-6 rounded-lg border border-slate-200 dark:border-slate-700 shadow-sm animate-in fade-in slide-in-from-top-4">
          <FileUpload onUploadComplete={handleUploadComplete} onCancel={() => { setShowUpload(false); }} />
        </div>
      )}

      <div className="flex flex-col gap-3 mb-4">
        <div className="flex items-center gap-3">
          <div className="relative flex-1 max-w-sm">
            <Search size={16} className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none z-10" />
            <input
              type="text"
              placeholder="Search datasets..."
              value={searchQuery}
              onChange={e => { setSearchQuery(e.target.value); }}
              className="w-full pl-8 pr-3 py-1.5 text-sm rounded-md border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-200 placeholder-slate-400 focus:outline-none focus:ring-1 focus:ring-blue-500"
            />
          </div>
          <button
            onClick={() => { setShowFilters(!showFilters); }}
            className={`flex items-center gap-1.5 px-3 py-1.5 text-sm rounded-md border transition-colors ${
              showFilters || filterType !== 'all'
                ? 'bg-blue-50 dark:bg-blue-900/20 border-blue-200 dark:border-blue-800 text-blue-700 dark:text-blue-300'
                : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700'
            }`}
          >
            <Filter size={14} />
            Filters
            {activeFilterCount > 0 && (
              <span className="ml-1 w-5 h-5 flex items-center justify-center rounded-full bg-blue-600 text-white text-xs">{activeFilterCount}</span>
            )}
          </button>
          {(searchQuery || filterStatus !== 'all' || filterType !== 'all' || filterFormat !== 'all') && (
            <button
              onClick={() => { setSearchQuery(''); setFilterStatus('all'); setFilterType('all'); setFilterFormat('all'); }}
              className="text-xs text-blue-600 dark:text-blue-400 hover:underline whitespace-nowrap"
            >
              Clear all
            </button>
          )}
        </div>

        {showFilters && (
          <div className="flex items-center gap-4 pl-1">
            <div className="flex items-center gap-2">
              <label className="text-xs text-slate-500 dark:text-slate-400 font-medium">Type</label>
              <select
                value={filterType}
                onChange={e => { setFilterType(e.target.value); }}
                className="px-2 py-1 text-sm rounded-md border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-200 focus:outline-none focus:ring-1 focus:ring-blue-500"
              >
                <option value="all">All types</option>
                {[...new Set(datasets.map(d => d.type))].map(t => (
                  <option key={t} value={t}>{t}</option>
                ))}
              </select>
            </div>
            <div className="flex items-center gap-2">
              <label className="text-xs text-slate-500 dark:text-slate-400 font-medium">Format</label>
              <select
                value={filterFormat}
                onChange={e => { setFilterFormat(e.target.value); }}
                className="px-2 py-1 text-sm rounded-md border border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-200 focus:outline-none focus:ring-1 focus:ring-blue-500"
              >
                <option value="all">All formats</option>
                {[...new Set(datasets.map(d => d.format || 'csv'))].map(f => (
                  <option key={f} value={f}>{f.toUpperCase()}</option>
                ))}
              </select>
            </div>
          </div>
        )}

        <div className="flex items-center gap-2 overflow-x-auto pb-1 scrollbar-hide">
          {['all', 'completed', 'processing', 'failed', 'cancelled'].map(status => (
            <button
              key={status}
              onClick={() => { setFilterStatus(status); }}
              className={`px-3 py-1.5 rounded-full text-sm font-medium transition-colors whitespace-nowrap ${
                filterStatus === status 
                  ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300' 
                  : 'bg-white dark:bg-slate-800 text-slate-600 border border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700'
              }`}
            >
              {status.charAt(0).toUpperCase() + status.slice(1)}
            </button>
          ))}
        </div>
      </div>

      <div className="bg-white dark:bg-slate-800 rounded-lg border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="text-xs text-slate-500 dark:text-slate-400 uppercase bg-slate-50 dark:bg-slate-800 border-b border-slate-200 dark:border-slate-700">
              <tr>
                <th className="px-3 py-4 font-semibold">Dataset Name</th>
                <th className="px-3 py-4 font-semibold">Type</th>
                <th className="px-6 py-4 font-semibold">Format</th>
                <th className="px-6 py-4 font-semibold">Size</th>
                <th className="px-6 py-4 font-semibold">Created</th>
                <th className="px-6 py-4 font-semibold text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200 dark:divide-slate-700 bg-white dark:bg-slate-900">
              {loading && datasets.length === 0 ? (
                <tr>
                  <td colSpan={6}>
                    <LoadingState message="Loading datasets..." />
                  </td>
                </tr>
              ) : filteredDatasets.length === 0 ? (
                <tr>
                  <td colSpan={6}>
                    {datasets.length === 0 ? (
                      <EmptyState
                        icon={<Database className="w-12 h-12 text-slate-300 dark:text-slate-600" />}
                        title="No datasets found"
                        description="Upload a dataset to get started with your analysis."
                      />
                    ) : (
                      <EmptyState title="No datasets match your search or filters" />
                    )}
                  </td>
                </tr>
              ) : (
                filteredDatasets.map((d) => (
                  <tr key={d.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                    <td className="px-3 py-4">
                      <div className="flex items-center gap-3">
                        <div className="p-2 bg-blue-50 dark:bg-blue-900/20 rounded text-blue-600 dark:text-blue-400">
                          <FileText size={18} />
                        </div>
                        <div>
                          <div className="font-medium text-slate-900 dark:text-slate-100 flex items-center gap-2">
                            {d.name}
                            {getStatusBadge(d)}
                          </div>
                          <div className="text-xs text-slate-500 dark:text-slate-400 font-mono mt-0.5" title="Dataset ID">
                            {d.source_id || d.id}
                          </div>
                        </div>
                      </div>
                    </td>
                    <td className="px-3 py-4">
                      <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium border ${
                        d.type === 's3' 
                          ? 'bg-orange-50 text-orange-700 border-orange-200 dark:bg-orange-900/20 dark:text-orange-400 dark:border-orange-800'
                          : d.type === 'file'
                          ? 'bg-slate-100 text-slate-700 border-slate-200 dark:bg-slate-800 dark:text-slate-300 dark:border-slate-700'
                          : 'bg-indigo-50 text-indigo-700 border-indigo-200 dark:bg-indigo-900/20 dark:text-indigo-400 dark:border-indigo-800'
                      }`}>
                        {d.type === 'file' ? 'Upload' : d.type.toUpperCase()}
                      </span>
                    </td>
                    <td className="px-6 py-4">
                      <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-slate-100 dark:bg-slate-800 text-slate-800 dark:text-slate-200 uppercase border border-slate-200 dark:border-slate-700">
                        {d.format || 'CSV'}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-slate-600 dark:text-slate-300">
                      <div className="flex flex-col">
                        <span className="font-medium">{formatBytes(d.size_bytes || 0)}</span>
                        <span className="text-xs text-slate-400 dark:text-slate-500">
                          {d.rows?.toLocaleString() || '-'} rows • {d.columns || '-'} cols
                        </span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-slate-600 dark:text-slate-300">
                      <div className="flex items-center gap-2">
                        <Calendar size={14} className="text-slate-400 dark:text-slate-500" />
                        {new Date(d.created_at).toLocaleDateString()}
                      </div>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex items-center justify-end gap-2">
                        {(!d.source_metadata?.ingestion_status?.status || d.source_metadata?.ingestion_status?.status === 'completed') && (
                          <>
                            <button
                              onClick={() => { setPreviewDataset(d); }}
                              className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-md transition-colors"
                              title="Preview Dataset"
                              aria-label="Preview dataset"
                            >
                              <Eye size={16} />
                            </button>
                            <button
                              onClick={() => { handleUseInCanvas(d.id); }}
                              className="flex items-center gap-1.5 px-3 py-1.5 text-sm font-medium text-blue-600 dark:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-md transition-colors"
                              title="Use in Canvas"
                            >
                              <Play size={16} />
                              Canvas
                            </button>
                            <button
                              onClick={() => { navigate(`/eda?dataset_id=${d.id}`); }}
                              className="flex items-center gap-1.5 px-3 py-1.5 text-sm font-medium text-purple-600 dark:text-purple-400 hover:bg-purple-50 dark:hover:bg-purple-900/20 rounded-md transition-colors"
                              title="Analyze with EDA"
                            >
                              <BarChart2 size={16} />
                              EDA
                            </button>
                            <button
                              onClick={() => { void DatasetService.exportData(d.id, 'csv'); }}
                              className="flex items-center gap-1.5 px-3 py-1.5 text-sm font-medium text-green-600 dark:text-green-400 hover:bg-green-50 dark:hover:bg-green-900/20 rounded-md transition-colors"
                              title="Download CSV"
                            >
                              <Download size={16} />
                              CSV
                            </button>
                          </>
                        )}
                        {(d.source_metadata?.ingestion_status?.status === 'pending' || d.source_metadata?.ingestion_status?.status === 'processing') && (
                          <button
                            onClick={() => { void handleCancel(d.id); }}
                            disabled={cancellingId === d.id}
                            className="p-2 text-slate-400 hover:text-orange-600 hover:bg-orange-50 dark:hover:bg-orange-900/20 rounded-md transition-colors disabled:opacity-50"
                            title="Cancel Ingestion"
                            aria-label="Cancel ingestion"
                          >
                            {cancellingId === d.id ? (
                              <div className="w-4 h-4 border-2 border-orange-600 border-t-transparent rounded-full animate-spin" />
                            ) : (
                              <XCircle size={16} />
                            )}
                          </button>
                        )}
                        <button
                          onClick={() => { void handleDelete(d.id); }}
                          disabled={deletingId === d.id}
                          className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-md transition-colors disabled:opacity-50"
                          title="Delete Dataset"
                          aria-label="Delete dataset"
                        >
                          {deletingId === d.id ? (
                            <div className="w-4 h-4 border-2 border-red-600 border-t-transparent rounded-full animate-spin" />
                          ) : (
                            <Trash2 size={16} />
                          )}
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useMemo, useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { DatasetService } from '../core/api/datasets';
import { EDAService } from '../core/api/eda';
import { JobsHistoryModal } from '../components/eda/JobsHistoryModal';
import { EDASidebar } from '../components/eda/EDASidebar';
import { DashboardTab } from '../components/eda/tabs/DashboardTab';
import { InsightsTab } from '../components/eda/tabs/InsightsTab';
import { PCATab } from '../components/eda/tabs/PCATab';
import { GeospatialTab } from '../components/eda/tabs/GeospatialTab';
import { TargetAnalysisTab } from '../components/eda/tabs/TargetAnalysisTab';
import { TimeSeriesTab } from '../components/eda/tabs/TimeSeriesTab';
import { VariablesTab } from '../components/eda/tabs/VariablesTab';
import { BivariateTab } from '../components/eda/tabs/BivariateTab';
import { OutliersTab } from '../components/eda/tabs/OutliersTab';
import { CorrelationsTab } from '../components/eda/tabs/CorrelationsTab';
import { SampleDataTab } from '../components/eda/tabs/SampleDataTab';
import { CausalTab } from '../components/eda/tabs/CausalTab';
import { RuleDiscoveryTab } from '../components/eda/tabs/RuleDiscoveryTab';
import { DecompositionTab } from '../components/eda/tabs/DecompositionTab';
import { Loader2, RefreshCw, AlertCircle, BarChart2, List, Play, HelpCircle, Target } from 'lucide-react';
import { downloadChart } from '../core/utils/chartUtils';
import { LoadingState, ErrorState } from '../components/shared';

export const EDAPage: React.FC = () => {
  const [searchParams] = useSearchParams();
  const [datasets, setDatasets] = useState<any[]>([]);
  const [selectedDataset, setSelectedDataset] = useState<number | null>(() => {
    const id = searchParams.get('dataset_id');
    return id ? Number(id) : null;
  });
  const [report, setReport] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [analyzing, setAnalyzing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [targetCol, setTargetCol] = useState<string>('');
  const [taskType, setTaskType] = useState<string>(''); // "Classification" or "Regression" or "" (Auto)
  const [excludedColsDraft, setExcludedColsDraft] = useState<string[]>([]);
  const [excludedColsApplied, setExcludedColsApplied] = useState<string[]>([]);
  const [filters, setFilters] = useState<any[]>([]);
  const [history, setHistory] = useState<any[]>([]);
  const [showHistoryModal, setShowHistoryModal] = useState(false);
  
  // Manual Filter State (Moved to FilterBar)

  // Scatter Plot State
  const [scatterX, setScatterX] = useState<string>('');
  const [scatterY, setScatterY] = useState<string>('');
  const [scatterZ, setScatterZ] = useState<string>('');
  const [scatterColor, setScatterColor] = useState<string>('');
  const [is3D, setIs3D] = useState(false);
  const [isPCA3D, setIsPCA3D] = useState(false);

  const profileForUi = useMemo(() => {
    const rawProfile = report?.profile_data;
    if (!rawProfile) return null;

    const excludedSet = new Set(excludedColsDraft);
    const filteredColumns: Record<string, any> = {};
    if (rawProfile.columns) {
      Object.entries(rawProfile.columns).forEach(([name, col]) => {
        if (!excludedSet.has(name)) {
          filteredColumns[name] = col;
        }
      });
    }

    return {
      ...rawProfile,
      columns: filteredColumns,
      excluded_columns: excludedColsDraft,
    };
  }, [report?.profile_data, excludedColsDraft]);

  useEffect(() => {
    loadDatasets();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (selectedDataset) {
      setReport(null); // Clear previous report to show loader
      setExcludedColsDraft([]); // Reset excluded columns
      setExcludedColsApplied([]);
      setFilters([]); // Reset filters
      setTargetCol(''); // Reset target column
      setScatterX('');
      setScatterY('');
      setScatterZ('');
      setScatterColor('');
      setActiveTab('dashboard'); // Reset active tab
      loadReport(selectedDataset);
      loadHistory(selectedDataset);
    } else {
      setReport(null);
      setHistory([]);
      setExcludedColsDraft([]);
      setExcludedColsApplied([]);
      setFilters([]);
      setTargetCol('');
      setScatterX('');
      setScatterY('');
      setScatterZ('');
      setScatterColor('');
      setActiveTab('dashboard');
    }
  }, [selectedDataset]);

  // Poll for status if pending
  useEffect(() => {
    let interval: any;
    if (report && report.status === 'PENDING') {
      interval = setInterval(() => {
        if (selectedDataset) {
            loadReport(selectedDataset, true);
            loadHistory(selectedDataset);
        }
      }, 3000);
    }
    return () => clearInterval(interval);
  }, [report, selectedDataset]);

  const loadDatasets = async () => {
    try {
      const data = await DatasetService.getUsable();
      setDatasets(data);
      if (data.length > 0 && !selectedDataset) {
        setSelectedDataset(Number(data[0].id));
      }
    } catch (err) {
      console.error("Failed to load datasets", err);
    }
  };

  const loadHistory = async (id: number) => {
    try {
        const data = await EDAService.getHistory(id);
        setHistory(data);
    } catch (err) {
        console.error("Failed to load history", err);
    }
  };

  const loadReport = async (id: number, silent = false) => {
    if (!silent) setLoading(true);
    setError(null);
    try {
      const data = await EDAService.getLatestReport(id);
      setReport(data);
    } catch (err: any) {
      if (err.response && err.response.status === 404) {
        setReport(null); // No report yet
      } else {
        // Only show error if not silent (polling)
        if (!silent) setError("Failed to load report");
      }
    } finally {
      if (!silent) setLoading(false);
    }
  };

  const loadSpecificReport = async (reportId: number) => {
    setLoading(true);
    try {
        const data = await EDAService.getReport(reportId);
        setReport(data);
    } catch (err) {
        setError("Failed to load report");
    } finally {
        setLoading(false);
    }
  };

  const runAnalysis = async (overrideExcluded?: string[] | any, overrideFilters?: any[]) => {
    const actualExcluded = Array.isArray(overrideExcluded) ? overrideExcluded : excludedColsApplied;
    const actualFilters = Array.isArray(overrideFilters) ? overrideFilters : filters;

    if (!selectedDataset) return;
    setAnalyzing(true);
    try {
      await EDAService.analyze(selectedDataset, targetCol || undefined, actualExcluded, actualFilters, taskType || undefined);
      // Reload immediately to get the PENDING state
      loadReport(selectedDataset);
      loadHistory(selectedDataset);
    } catch (err) {
      setError("Failed to start analysis");
    } finally {
      setAnalyzing(false);
    }
  };

  const handleAddFilter = (column: string, value: any, operator: string = '==') => {
      // Check if filter already exists to avoid duplicates if needed, 
      // but for now let's allow multiple filters on same col (e.g. range)
      const newFilter = { column, operator, value };
      const newFilters = [...filters, newFilter];
      setFilters(newFilters);
      runAnalysis(undefined, newFilters);
  };

  const handleRemoveFilter = (index: number) => {
      const newFilters = [...filters];
      newFilters.splice(index, 1);
      setFilters(newFilters);
      runAnalysis(undefined, newFilters);
  };

  const handleToggleExclude = (colName: string, exclude: boolean) => {
    setExcludedColsDraft((prev) => {
      if (exclude) {
        if (prev.includes(colName)) return prev;
        return [...prev, colName];
      }
      return prev.filter((c) => c !== colName);
    });
  };

    const handleApplyExcluded = () => {
    setExcludedColsApplied(excludedColsDraft);
    runAnalysis(excludedColsDraft);
    };

  // Sync target col and excluded cols from report if available
  useEffect(() => {
    if (report && report.profile_data) {
        if (report.profile_data.target_col) {
            setTargetCol(report.profile_data.target_col);
        }
      const serverExcluded = Array.isArray(report.profile_data.excluded_columns)
        ? report.profile_data.excluded_columns
        : [];
      setExcludedColsApplied(serverExcluded);
      setExcludedColsDraft(serverExcluded);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [report?.id]);

    const excludedDirty = (() => {
    if (excludedColsApplied.length !== excludedColsDraft.length) return true;
    const appliedSet = new Set(excludedColsApplied);
    for (const col of excludedColsDraft) {
      if (!appliedSet.has(col)) return true;
    }
    return false;
    })();

  // Helper to find existing report for current target
  const existingReport = targetCol ? history.find(h => h.target_col === targetCol && h.status === 'COMPLETED') : null;

  const renderContent = () => {
    if (loading && !report) {
      return <LoadingState message="Analyzing dataset..." />;
    }

    if (error) {
      return (
        <ErrorState
          error={error}
          onRetry={() => selectedDataset && loadReport(selectedDataset)}
        />
      );
    }

    if (!report) {
      return (
        <div className="flex flex-col items-center justify-center h-64 text-gray-500">
          <BarChart2 className="w-16 h-16 mb-4 opacity-20" />
          <p className="mb-4">No analysis found for this dataset.</p>
          
          <div className="flex flex-col items-center space-y-4">
            <div className="w-64 space-y-2">
                <input
                type="text"
                value={targetCol}
                onChange={(e) => setTargetCol(e.target.value)}
                placeholder="Target Column (Optional)"
                className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-blue-500 focus:border-blue-500 dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                />
                
                <div className="flex items-center space-x-2">
                    <select
                        value={taskType}
                        onChange={(e) => setTaskType(e.target.value)}
                        className="w-full px-3 py-2 border border-gray-300 rounded-md shadow-sm focus:outline-none focus:ring-blue-500 focus:border-blue-500 dark:bg-gray-700 dark:border-gray-600 dark:text-white"
                    >
                        <option value="">Auto-Detect Task</option>
                        <option value="Classification">Classification</option>
                        <option value="Regression">Regression</option>
                    </select>
                    <div className="group relative flex items-center">
                        <HelpCircle className="w-4 h-4 text-gray-400 cursor-help" />
                        <div className="absolute left-full ml-2 w-64 p-2 bg-gray-800 text-white text-xs rounded shadow-lg opacity-0 group-hover:opacity-100 transition-opacity z-50 pointer-events-none">
                            Force a specific task type. Useful for ID columns (force Classification) or numeric categories (force Regression).
                        </div>
                    </div>
                </div>
            </div>
            <div className="flex gap-2">
                {existingReport && (
                    <button
                        onClick={() => loadSpecificReport(existingReport.id)}
                        className="flex items-center px-4 py-2 bg-green-600 text-white rounded-md hover:bg-green-700"
                    >
                        <RefreshCw className="w-4 h-4 mr-2" />
                        Load Existing ({new Date(existingReport.created_at).toLocaleDateString()})
                    </button>
                )}
                <button
                    onClick={() => runAnalysis()}
                    disabled={analyzing}
                    className={`flex items-center px-4 py-2 ${existingReport ? 'bg-gray-600 hover:bg-gray-700' : 'bg-blue-600 hover:bg-blue-700'} text-white rounded-md disabled:opacity-50`}
                >
                    {analyzing ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Play className="w-4 h-4 mr-2" />}
                    {existingReport ? 'Run New Analysis' : 'Run Analysis'}
                </button>
            </div>
          </div>
        </div>
      );
    }

    if (report.status === 'PENDING') {
      return (
        <div className="flex flex-col items-center justify-center h-64 text-gray-500">
          <Loader2 className="w-16 h-16 mb-4 animate-spin text-blue-500" />
          <p>Analysis in progress...</p>
          <p className="text-sm text-gray-400">This may take a few moments.</p>
        </div>
      );
    }

    if (report.status === 'FAILED') {
      return (
        <div className="flex flex-col items-center justify-center h-64 text-red-500">
          <AlertCircle className="w-16 h-16 mb-4" />
          <p>Analysis Failed</p>
          <p className="text-sm text-gray-600 mt-2">{report.error_message}</p>
          <button
            onClick={() => runAnalysis()}
            className="mt-4 flex items-center px-4 py-2 bg-gray-100 text-gray-700 rounded-md hover:bg-gray-200"
          >
            <RefreshCw className="w-4 h-4 mr-2" />
            Retry
          </button>
        </div>
      );
    }

    const profile = profileForUi;
    if (!profile) return <div>No profile data</div>;

    const allColumns = report?.profile_data?.columns ? Object.keys(report.profile_data.columns) : [];

    return (
      <div className="flex h-full w-full overflow-hidden bg-white dark:bg-gray-900">
        <EDASidebar 
            activeTab={activeTab} 
            setActiveTab={setActiveTab} 
            profile={profile} 
            filters={filters}
          columns={allColumns}
            excludedCols={excludedColsDraft}
            excludedDirty={excludedDirty}
            analyzing={analyzing}
            onAddFilter={handleAddFilter}
            onRemoveFilter={handleRemoveFilter}
            onClearFilters={() => { setFilters([]); runAnalysis(undefined, []); }}
            onToggleExclude={handleToggleExclude}
            onApplyExcluded={handleApplyExcluded}
        />
        
        <div className="flex-1 overflow-y-auto p-6 pt-4 bg-gray-50 dark:bg-gray-900/50">
            {activeTab === 'dashboard' && (
                <DashboardTab 
                    profile={profile} 
                    onToggleExclude={handleToggleExclude}
                    excludedCols={excludedColsDraft}
                />
            )}

            {activeTab === 'insights' && (
                <InsightsTab profile={profile} />
            )}

            {activeTab === 'pca' && (
                <PCATab 
                    profile={profile} 
                    isPCA3D={isPCA3D} 
                    setIsPCA3D={setIsPCA3D} 
                    downloadChart={downloadChart} 
                />
            )}

            {activeTab === 'geospatial' && profile.geospatial && (
                <GeospatialTab profile={profile} />
            )}

            {activeTab === 'target' && profile.target_col && profile.target_correlations && (
                <TargetAnalysisTab 
                    profile={profile}
                    downloadChart={downloadChart}
                    history={history}
                    loading={loading}
                    loadSpecificReport={loadSpecificReport}
                    report={report}
                />
            )}

            {activeTab === 'timeseries' && profile.timeseries && (
                <TimeSeriesTab 
                    profile={profile}
                    downloadChart={downloadChart}
                />
            )}

            {activeTab === 'variables' && (
                <VariablesTab 
                    profile={profile}
                    handleToggleExclude={handleToggleExclude}
                    handleAddFilter={handleAddFilter}
                />
            )}

            {activeTab === 'bivariate' && (
                <BivariateTab 
                    profile={profile}
                    downloadChart={downloadChart}
                    scatterX={scatterX}
                    setScatterX={setScatterX}
                    scatterY={scatterY}
                    setScatterY={setScatterY}
                    scatterZ={scatterZ}
                    setScatterZ={setScatterZ}
                    scatterColor={scatterColor}
                    setScatterColor={setScatterColor}
                    is3D={is3D}
                    setIs3D={setIs3D}
                />
            )}

            {activeTab === 'outliers' && profile.outliers && (
                <OutliersTab profile={profile} />
            )}

            {activeTab === 'correlations' && (profile.correlations || profile.correlations_with_target) && (
                <CorrelationsTab 
                    profile={profile}
                />
            )}

            {activeTab === 'causal' && profile.causal_graph && (
                <CausalTab profile={profile} />
            )}

            {activeTab === 'rules' && profile.rule_tree && (
                <RuleDiscoveryTab profile={profile} />
            )}

            {activeTab === 'decomposition' && selectedDataset && (
                <DecompositionTab 
                    datasetId={selectedDataset}
                columns={allColumns}
                    initialFilters={filters}
                />
            )}

            {activeTab === 'sample' && profile.sample_data && (
                <SampleDataTab 
                    profile={profile}
                excludedCols={excludedColsDraft}
                    handleToggleExclude={handleToggleExclude}
                />
            )}
        </div>
      </div>
    );
  };

  return (
    <div className="flex flex-col h-full w-full overflow-hidden bg-white dark:bg-slate-950">
      {/* Top Navigation Bar */}
      <header className="flex-none h-16 bg-white dark:bg-slate-900 border-b border-gray-200 dark:border-gray-800 px-4 flex items-center justify-between gap-4 z-20 shadow-sm">
        
        {/* Left: Title & Dataset */}
        <div className="flex items-center gap-6">
            <div>
                <h1 className="text-lg font-bold text-gray-900 dark:text-white leading-tight">Exploratory Analysis</h1>
                {report && report.created_at && (
                    <p className="text-[10px] text-gray-500">
                        Last analyzed: {new Date(report.created_at).toLocaleString()}
                    </p>
                )}
            </div>

            <div className="h-8 w-px bg-gray-200 dark:bg-gray-700 mx-2"></div>
            
            <div className="flex flex-col">
                <label className="text-[10px] font-medium text-gray-400 uppercase tracking-wider">Dataset</label>
                <select
                    value={selectedDataset || ''}
                    onChange={(e) => setSelectedDataset(Number(e.target.value))}
                    className="block w-48 text-sm font-medium bg-transparent border-none p-0 focus:ring-0 text-gray-900 dark:text-white cursor-pointer hover:text-blue-600"
                >
                    <option value="" disabled>Select a dataset</option>
                    {datasets.map((ds) => (
                    <option key={ds.id} value={ds.id}>{ds.name}</option>
                    ))}
                </select>
            </div>
        </div>

        {/* Center: Controls */}
        <div className="flex items-center gap-4 bg-gray-50 dark:bg-gray-800/50 p-1.5 rounded-lg border border-gray-200 dark:border-gray-700">
            <div className="flex flex-col px-2">
                <label className="text-[10px] font-medium text-gray-400 uppercase tracking-wider">Target Column</label>
                <select
                    value={targetCol}
                    onChange={(e) => setTargetCol(e.target.value)}
                    disabled={!report || !report.profile_data}
                    className="block w-36 text-sm bg-transparent border-none p-0 focus:ring-0 text-gray-700 dark:text-gray-200 cursor-pointer disabled:opacity-50"
                >
                    <option value="">None</option>
                    {report && report.profile_data && Object.keys(report.profile_data.columns)
                        .filter((col) => !excludedColsDraft.includes(col))
                        .map(col => (
                            <option key={col} value={col}>{col}</option>
                    ))}
                </select>
            </div>

            <div className="w-px h-8 bg-gray-200 dark:bg-gray-700"></div>

            <div className="flex flex-col px-2">
                <div className="flex items-center gap-1">
                    <label className="text-[10px] font-medium text-gray-400 uppercase tracking-wider">Task Type</label>
                    <div className="group relative">
                        <HelpCircle className="w-3 h-3 text-gray-400 cursor-help" />
                        <div className="absolute bottom-full mb-2 w-56 p-2 bg-slate-800 text-white text-xs rounded shadow-lg opacity-0 group-hover:opacity-100 transition-opacity z-50 pointer-events-none left-1/2 -translate-x-1/2">
                            Force Classification or Regression.
                        </div>
                    </div>
                </div>
                <select
                    value={taskType}
                    onChange={(e) => setTaskType(e.target.value)}
                    disabled={!report || !report.profile_data}
                    className="block w-28 text-sm bg-transparent border-none p-0 focus:ring-0 text-gray-700 dark:text-gray-200 cursor-pointer disabled:opacity-50"
                >
                    <option value="">Auto</option>
                    <option value="Classification">Classification</option>
                    <option value="Regression">Regression</option>
                </select>
            </div>

            <button
                onClick={() => selectedDataset && runAnalysis()}
                disabled={!selectedDataset || analyzing}
                className={`ml-2 px-3 py-1.5 rounded text-sm font-medium transition-colors flex items-center shadow-sm ${
                    existingReport 
                        ? 'bg-white dark:bg-gray-700 text-gray-700 dark:text-gray-200 border border-gray-300 dark:border-gray-600 hover:bg-gray-50' 
                        : 'bg-blue-600 text-white hover:bg-blue-700 border border-transparent'
                }`}
            >
                {analyzing ? <Loader2 className="w-4 h-4 mr-2 animate-spin" /> : <Play className="w-4 h-4 mr-2" />}
                {existingReport ? 'Re-Run' : 'Analyze'}
            </button>
        </div>

        {/* Right: History & Actions */}
        <div className="flex items-center gap-3">
             {existingReport && report && report.id !== existingReport.id && (
                <button
                    onClick={() => loadSpecificReport(existingReport.id)}
                    className="flex items-center px-3 py-1.5 text-xs bg-green-50 text-green-700 border border-green-200 rounded-md hover:bg-green-100 transition-colors"
                    title={`Load existing from ${new Date(existingReport.created_at).toLocaleString()}`}
                >
                    <RefreshCw className="w-3 h-3 mr-1" />
                    Load Saved
                </button>
            )}
            
            <button 
                onClick={() => setShowHistoryModal(true)}
                className="flex items-center px-3 py-1.5 text-sm font-medium text-gray-600 bg-gray-50 dark:bg-gray-800 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg transition-colors"
            >
                <List className="w-4 h-4 mr-2" />
                History
            </button>
        </div>
      </header>

      {/* Recent Targets Bar */}
      {history.length > 0 && (
        <div className="flex-none bg-white dark:bg-slate-950 border-b border-gray-100 dark:border-gray-800 px-4 py-1.5 flex items-center gap-3 overflow-x-auto z-10 shadow-[0_2px_3px_-1px_rgba(0,0,0,0.02)]">
            <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider whitespace-nowrap">Recent Targets:</span>
            <div className="flex gap-2">
                {Array.from(new Set(history.filter(h => h.target_col && h.status === 'COMPLETED').map(h => h.target_col))).slice(0, 8).map(target => (
                    <button
                        key={target}
                        onClick={() => {
                            const match = history.find(h => h.target_col === target && h.status === 'COMPLETED');
                            if (match) loadSpecificReport(match.id);
                        }}
                        className={`px-2 py-0.5 text-xs rounded-full border transition-colors flex items-center ${
                            report?.profile_data?.target_col === target 
                            ? 'bg-blue-50 text-blue-600 border-blue-200 font-medium'
                            : 'bg-white text-gray-500 border-gray-200 hover:border-gray-300 hover:text-gray-700'
                        }`}
                    >
                        <Target className="w-3 h-3 mr-1" />
                        {target}
                    </button>
                ))}
            </div>
        </div>
      )}

      {/* Main Content Area */}
      <div className="flex-1 overflow-hidden relative">
        {renderContent()}
      </div>

      {/* Jobs History Modal */}
      <JobsHistoryModal 
        isOpen={showHistoryModal}
        onClose={() => setShowHistoryModal(false)}
        history={history}
        onRefresh={() => selectedDataset && loadHistory(selectedDataset)}
        onFetchReport={async (id) => {
            return await EDAService.getReport(id);
        }}
        onSelect={(selectedReport) => {
            setReport(selectedReport);
          const serverExcluded = Array.isArray(selectedReport.profile_data?.excluded_columns)
            ? selectedReport.profile_data.excluded_columns
            : [];
          setExcludedColsApplied(serverExcluded);
          setExcludedColsDraft(serverExcluded);
        }}
      />
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { 
  Activity, CheckCircle, XCircle, Clock, Search, 
  RefreshCw, Database, BarChart2, Cpu, Filter
} from 'lucide-react';
import { jobsApi, JobInfo } from '../core/api/jobs';
import { LoadingState, EmptyState } from '../components/shared';

type TabType = 'training' | 'tuning' | 'eda' | 'ingestion';

export const JobsPage: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('training');
  const [jobs, setJobs] = useState<JobInfo[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('all');
  const [showFilters, setShowFilters] = useState(false);
  const [skip, setSkip] = useState(0);
  const [hasMore, setHasMore] = useState(true);
  const LIMIT = 20;

  const [cache, setCache] = useState<Record<TabType, { data: JobInfo[], skip: number, hasMore: boolean }>>({
    training: { data: [], skip: 0, hasMore: true },
    tuning: { data: [], skip: 0, hasMore: true },
    eda: { data: [], skip: 0, hasMore: true },
    ingestion: { data: [], skip: 0, hasMore: true }
  });

  const fetchJobs = async (reset: boolean = false) => {
    if (reset) {
      setLoading(true);
      setJobs([]);
      setSkip(0);
      setHasMore(true);
    }

    try {
      const currentSkip = reset ? 0 : skip;
      let fetchedJobs: JobInfo[] = [];
      
      if (activeTab === 'training' || activeTab === 'tuning') {
        fetchedJobs = await jobsApi.getJobs(LIMIT, currentSkip, activeTab);
      } else if (activeTab === 'eda') {
        fetchedJobs = await jobsApi.getEDAJobs(LIMIT);
      } else if (activeTab === 'ingestion') {
        fetchedJobs = await jobsApi.getIngestionJobs(LIMIT, currentSkip);
      }
      
      // Sort by created_at desc
      fetchedJobs.sort((a, b) => new Date(b.created_at).getTime() - new Date(a.created_at).getTime());
      
      const isMore = fetchedJobs.length >= LIMIT;
      if (!isMore) {
        setHasMore(false);
      }

      if (reset) {
        setJobs(fetchedJobs);
        setCache(prev => ({
          ...prev,
          [activeTab]: { data: fetchedJobs, skip: currentSkip + LIMIT, hasMore: isMore }
        }));
      } else {
        setJobs(prev => {
          const updated = [...prev, ...fetchedJobs];
          setCache(prevCache => ({
            ...prevCache,
            [activeTab]: { data: updated, skip: currentSkip + LIMIT, hasMore: isMore }
          }));
          return updated;
        });
      }
      
      setSkip(currentSkip + LIMIT);
    } catch (error) {
      console.error('Failed to fetch jobs:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    const cached = cache[activeTab];
    if (cached.data.length > 0) {
      setJobs(cached.data);
      setSkip(cached.skip);
      setHasMore(cached.hasMore);
      setLoading(false);
    } else {
      void fetchJobs(true);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [activeTab]);

  const handleLoadMore = () => {
    void fetchJobs(false);
  };

  const filteredJobs = jobs.filter(job => {
    if (statusFilter !== 'all' && job.status.toLowerCase() !== statusFilter) return false;
    if (searchTerm) {
      const term = searchTerm.toLowerCase();
      return (
        job.job_id.toLowerCase().includes(term) ||
        (job.model_type && job.model_type.toLowerCase().includes(term)) ||
        (job.dataset_name && job.dataset_name.toLowerCase().includes(term))
      );
    }
    return true;
  });

  const activeFilterCount = (statusFilter !== 'all' ? 1 : 0);

  const getDuration = (start: string | null, end: string | null) => {
    if (!start || !end) return '-';
    const startTime = new Date(start).getTime();
    const endTime = new Date(end).getTime();
    const diff = endTime - startTime;
    
    if (diff < 1000) return '< 1s';
    
    const seconds = Math.floor(diff / 1000);
    if (seconds < 60) return `${seconds}s`;
    
    const minutes = Math.floor(seconds / 60);
    if (minutes < 60) return `${minutes}m ${seconds % 60}s`;
    
    const hours = Math.floor(minutes / 60);
    return `${hours}h ${minutes % 60}m`;
  };

  return (
    <div className="p-8 space-y-6 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold text-slate-900 dark:text-slate-100">Jobs</h1>
          <p className="text-slate-500 dark:text-slate-400 mt-1">Monitor and manage all your pipeline activities</p>
        </div>
        <button 
          onClick={() => fetchJobs()}
          className="flex items-center gap-2 px-4 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-md hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors text-slate-700 dark:text-slate-300"
        >
          <RefreshCw size={16} />
          Refresh
        </button>
      </div>

      {/* Tabs & Filters */}
      <div className="flex flex-col md:flex-row justify-between items-center gap-4 bg-white dark:bg-slate-800 p-4 rounded-lg border border-slate-200 dark:border-slate-700 shadow-sm">
        <div className="flex gap-2 overflow-x-auto w-full md:w-auto pb-2 md:pb-0">
          <TabButton active={activeTab === 'training'} onClick={() => setActiveTab('training')} icon={<Cpu size={16} />} label="Basic Training" />
          <TabButton active={activeTab === 'tuning'} onClick={() => setActiveTab('tuning')} icon={<Activity size={16} />} label="Advanced Training" />
          <TabButton active={activeTab === 'eda'} onClick={() => setActiveTab('eda')} icon={<BarChart2 size={16} />} label="EDA" />
          <TabButton active={activeTab === 'ingestion'} onClick={() => setActiveTab('ingestion')} icon={<Database size={16} />} label="Ingestion" />
        </div>
        
        <div className="flex items-center gap-2">
          <div className="relative w-full md:w-56">
            <Search className="absolute left-2.5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none z-10" size={16} />
            <input 
              type="text" 
              placeholder="Search jobs..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-8 pr-4 py-2 text-sm bg-slate-50 dark:bg-slate-900 border border-slate-200 dark:border-slate-700 rounded-md focus:outline-none focus:ring-2 focus:ring-indigo-500 dark:text-slate-100"
            />
          </div>
          <button
            onClick={() => setShowFilters(!showFilters)}
            className={`flex items-center gap-1.5 px-3 py-2 text-sm rounded-md border transition-colors ${
              showFilters || statusFilter !== 'all'
                ? 'bg-indigo-50 dark:bg-indigo-900/20 border-indigo-200 dark:border-indigo-800 text-indigo-700 dark:text-indigo-300'
                : 'bg-slate-50 dark:bg-slate-900 border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'
            }`}
          >
            <Filter size={14} />
            Filters
            {activeFilterCount > 0 && (
              <span className="ml-0.5 w-5 h-5 flex items-center justify-center rounded-full bg-indigo-600 text-white text-xs">{activeFilterCount}</span>
            )}
          </button>
          {(searchTerm || statusFilter !== 'all') && (
            <button
              onClick={() => { setSearchTerm(''); setStatusFilter('all'); }}
              className="text-xs text-indigo-600 dark:text-indigo-400 hover:underline whitespace-nowrap"
            >
              Clear all
            </button>
          )}
        </div>
      </div>

      {showFilters && (
        <div className="flex items-center gap-4 px-4 py-3 bg-white dark:bg-slate-800 rounded-lg border border-slate-200 dark:border-slate-700 shadow-sm">
          <label className="text-xs text-slate-500 dark:text-slate-400 font-medium">Status</label>
          <select
            value={statusFilter}
            onChange={(e) => setStatusFilter(e.target.value)}
            className="px-2.5 py-1.5 text-sm rounded-md border border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900 text-slate-700 dark:text-slate-200 focus:outline-none focus:ring-1 focus:ring-indigo-500"
          >
            <option value="all">All statuses</option>
            {[...new Set(jobs.map(j => j.status.toLowerCase()))].sort().map(s => (
              <option key={s} value={s}>{s.charAt(0).toUpperCase() + s.slice(1)}</option>
            ))}
          </select>
        </div>
      )}

      {/* Jobs Table */}
      <div className="bg-white dark:bg-slate-800 rounded-lg border border-slate-200 dark:border-slate-700 shadow-sm overflow-hidden">
        {loading ? (
          <LoadingState message="Loading jobs..." />
        ) : filteredJobs.length === 0 ? (
          <EmptyState title="No jobs found matching your criteria." />
        ) : (
          <div className="overflow-x-auto">
            <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
              <thead className="bg-slate-50 dark:bg-slate-900/50">
                <tr>
                  <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">Status</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">Job ID</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">Type</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">Details</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">Duration</th>
                  <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">Created At</th>
                </tr>
              </thead>
              <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-200 dark:divide-slate-700">
                {filteredJobs.map((job) => (
                  <tr key={job.job_id} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <StatusBadge status={job.status} />
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-slate-900 dark:text-slate-100">
                      <span className="font-mono text-xs bg-slate-100 dark:bg-slate-700 px-2 py-1 rounded">
                        {job.job_id.substring(0, 8)}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 dark:text-slate-400 capitalize">
                      {job.job_type}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 dark:text-slate-400">
                      {job.model_type || job.dataset_name || job.target_column || '-'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 dark:text-slate-400 font-mono">
                      {getDuration(job.start_time, job.end_time)}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 dark:text-slate-400">
                      {new Date(job.created_at).toLocaleDateString()} <span className="text-xs opacity-70">{new Date(job.created_at).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}</span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
        
        {/* Load More Button */}
        {!loading && hasMore && filteredJobs.length > 0 && (
          <div className="p-4 border-t border-slate-200 dark:border-slate-700 flex justify-center">
            <button
              onClick={handleLoadMore}
              className="text-sm text-indigo-600 hover:text-indigo-700 font-medium flex items-center gap-1 px-4 py-2 rounded-md hover:bg-indigo-50 dark:hover:bg-indigo-900/30 transition-colors"
            >
              Load More
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

const TabButton = ({ active, onClick, icon, label }: { active: boolean; onClick: () => void; icon: React.ReactNode; label: string }) => (
  <button
    onClick={onClick}
    className={`flex items-center gap-2 px-4 py-2 rounded-md text-sm font-medium transition-all whitespace-nowrap ${
      active 
        ? 'bg-indigo-600 text-white shadow-sm' 
        : 'text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-700'
    }`}
  >
    {icon}
    {label}
  </button>
);

const StatusBadge = ({ status }: { status: string }) => {
  const styles = {
    succeeded: 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400',
    completed: 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400',
    failed: 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400',
    running: 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-400',
    pending: 'bg-yellow-100 text-yellow-800 dark:bg-yellow-900/30 dark:text-yellow-400',
    queued: 'bg-slate-100 text-slate-800 dark:bg-slate-800 dark:text-slate-400',
  };
  
  const icons = {
    succeeded: <CheckCircle size={14} />,
    completed: <CheckCircle size={14} />,
    failed: <XCircle size={14} />,
    running: <Activity size={14} className="animate-pulse" />,
    pending: <Clock size={14} />,
    queued: <Clock size={14} />,
  };

  const key = status.toLowerCase() as keyof typeof styles;
  const style = styles[key] || 'bg-slate-100 text-slate-800 dark:bg-slate-800 dark:text-slate-400';
  const icon = icons[key] || <Clock size={14} />;

  return (
    <span className={`px-2.5 py-1 inline-flex items-center gap-1.5 text-xs font-medium rounded-full ${style}`}>
      {icon}
      {status.charAt(0).toUpperCase() + status.slice(1)}
    </span>
  );
};

import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Archive, Box, CheckCircle, ChevronRight, X, Play, Folder, FileText, Cloud, HardDrive } from 'lucide-react';
import { LoadingState, ErrorState, EmptyState } from '../components/shared';
import { useEscapeKey } from '../core/hooks/useEscapeKey';

interface ArtifactResponse {
  storage_type: string;
  base_uri: string;
  files: string[];
}

interface ModelVersion {
  job_id: string;
  pipeline_id: string;
  node_id: string;
  model_type: string;
  version: number | string;
  source: string;
  status: string;
  metrics: Record<string, unknown>;
  hyperparameters: Record<string, unknown>;
  created_at: string;
  artifact_uri: string;
  is_deployed: boolean;
  deployment_id?: number;
}

interface ModelRegistryEntry {
  model_type: string;
  dataset_id: string;
  dataset_name: string;
  dataset_type?: string;
  latest_version: ModelVersion | null;
  versions: ModelVersion[];
  deployment_count: number;
}

interface RegistryStats {
  total_models: number;
  total_versions: number;
  active_deployments: number;
}

export const ModelRegistry: React.FC = () => {
  const navigate = useNavigate();
  const [stats, setStats] = useState<RegistryStats | null>(null);
  const [models, setModels] = useState<ModelRegistryEntry[]>([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [selectedModel, setSelectedModel] = useState<ModelRegistryEntry | null>(null);
  const [deployingId, setDeployingId] = useState<string | null>(null);
  
  useEscapeKey(() => setSelectedModel(null), !!selectedModel);

  // Artifacts viewing
  const [viewingArtifacts, setViewingArtifacts] = useState<string | null>(null);
  const [artifacts, setArtifacts] = useState<ArtifactResponse | null>(null);
  const [loadingArtifacts, setLoadingArtifacts] = useState(false);
  
  // Pagination
  const [page, setPage] = useState(0);
  const [hasMore, setHasMore] = useState(true);
  const LIMIT = 10;
  
  // Filters
  const [datasetFilter, setDatasetFilter] = useState('');
  const [modelTypeFilter, setModelTypeFilter] = useState('');
  
  // Manual deployment tracking (Local Storage)
  const [manualDeployments, setManualDeployments] = useState<Record<string, boolean>>(() => {
    try {
      const saved = localStorage.getItem('skyulf_manual_deployments');
      return saved ? JSON.parse(saved) : {};
    } catch (e) {
      return {};
    }
  });

  const toggleManualDeployment = (key: string) => {
    setManualDeployments(prev => {
      const next = { ...prev, [key]: !prev[key] };
      localStorage.setItem('skyulf_manual_deployments', JSON.stringify(next));
      return next;
    });
  };

  const handleViewArtifacts = async (jobId: string) => {
    setViewingArtifacts(jobId);
    setLoadingArtifacts(true);
    setArtifacts(null);
    try {
      const res = await fetch(`/api/registry/artifacts/${jobId}`);
      if (res.ok) {
        const data: ArtifactResponse = await res.json();
        setArtifacts(data);
      } else {
        const err = await res.json();
        // Fallback for error display
        setArtifacts({ 
          storage_type: 'error', 
          base_uri: '', 
          files: [`Failed to load artifacts: ${err.detail || 'Unknown error'}`] 
        });
      }
    } catch (e) {
      setArtifacts({ 
        storage_type: 'error', 
        base_uri: '', 
        files: ['Error loading artifacts'] 
      });
    } finally {
      setLoadingArtifacts(false);
    }
  };

  const fetchStats = async () => {
    try {
      const statsRes = await fetch('/api/registry/stats');
      if (statsRes.ok) {
        const statsData = await statsRes.json();
        setStats(statsData);
      }
    } catch (e) {
      console.error("Failed to fetch stats", e);
    }
  };

  const fetchModels = async (pageNum: number, reset: boolean = false) => {
    if (loading) return;
    try {
      setLoading(true);
      const skip = pageNum * LIMIT;
      const params = new URLSearchParams({
        skip: skip.toString(),
        limit: LIMIT.toString()
      });
      const modelsRes = await fetch(`/api/registry/models?${params.toString()}`);
      if (!modelsRes.ok) throw new Error('Failed to fetch models');
      const modelsData = await modelsRes.json();
      
      if (modelsData.length < LIMIT) {
        setHasMore(false);
      } else {
        setHasMore(true);
      }

      setModels(prev => reset ? modelsData : [...prev, ...modelsData]);
      return modelsData;
    } catch (err: unknown) {
      setError((err as Error).message);
      return null;
    } finally {
      setLoading(false);
    }
  };

  // Initial load
  useEffect(() => {
    void fetchStats();
    void fetchModels(0, true);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Infinite scroll listener
  useEffect(() => {
    const handleScroll = (e: Event) => {
      const target = e.target as HTMLElement;
      if (
        target.scrollTop + target.clientHeight >= target.scrollHeight - 100 &&
        !loading &&
        hasMore
      ) {
        setPage(prev => prev + 1);
      }
    };

    const mainElement = document.querySelector('main');
    if (mainElement) {
      mainElement.addEventListener('scroll', handleScroll);
      return () => { mainElement.removeEventListener('scroll', handleScroll); };
    } else {
      // Fallback to window if main not found (though it should be there)
      window.addEventListener('scroll', handleScroll as unknown as EventListener);
      return () => { window.removeEventListener('scroll', handleScroll as unknown as EventListener); };
    }
  }, [loading, hasMore]);

  // Fetch on page change
  useEffect(() => {
    if (page > 0) {
      void fetchModels(page, false);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [page]);

  const handleDeploy = async (jobId: string) => {
    if (!confirm('Are you sure you want to deploy this model version? This will replace the currently active deployment.')) return;
    
    try {
      setDeployingId(jobId);
      const res = await fetch(`/api/deployment/deploy/${jobId}`, { method: 'POST' });
      if (!res.ok) {
        const err = await res.json();
        throw new Error(err.detail || 'Deployment failed');
      }
      
      // Refresh data to update UI (reset to page 0)
      setPage(0);
      const updatedModels = await fetchModels(0, true);
      
      // Also update selected model if open
      if (selectedModel && updatedModels) {
        const updatedModel = updatedModels.find((m: ModelRegistryEntry) => 
          m.model_type === selectedModel.model_type && m.dataset_id === selectedModel.dataset_id
        );
        if (updatedModel) setSelectedModel(updatedModel);
      }

      // Ask to go to inference page
      if (confirm('Model deployed successfully! Do you want to go to the inference page?')) {
        navigate('/deployments');
      }
    } catch (err: unknown) {
      alert(`Error deploying model: ${(err as Error).message}`);
    } finally {
      setDeployingId(null);
    }
  };

  const getStatusColor = (status: string) => {
    switch (status.toLowerCase()) {
      case 'completed': return 'bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-400';
      case 'failed': return 'bg-red-100 text-red-800 dark:bg-red-900/30 dark:text-red-400';
      case 'running': return 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-400';
      default: return 'bg-gray-100 text-gray-800 dark:bg-slate-700 dark:text-slate-300';
    }
  };

  const formatMetrics = (metrics: Record<string, unknown>) => {
    // metrics is typed as Record<string, unknown>, so it's always truthy if it exists on the type.
    // Assuming strict null checks, if metrics is not optional, this check is redundant.
    // However, if it can be null/undefined, the check is valid.
    // Based on the error "Unnecessary optional chain on a non-nullish value" elsewhere, maybe metrics is guaranteed.
    // But here it's "Unnecessary conditional, value is always falsy" which is weird if metrics is an object.
    // Wait, the error was:
    // frontend/ml-canvas/src/pages/ModelRegistry.tsx:194: if (!metrics) return '-';
    // Unnecessary conditional, value is always falsy.
    // This means metrics is NEVER falsy, i.e. it's always an object.
    
    // Try to find common metrics
    const score = metrics.score || metrics.accuracy || metrics.f1_score || metrics.rmse || metrics.mse;
    if (score !== undefined) {
      // Format to 4 decimal places if number
      return typeof score === 'number' ? score.toFixed(4) : String(score);
    }
    // Fallback: first key
    const keys = Object.keys(metrics);
    if (keys.length > 0) {
      const val = metrics[keys[0]];
      return `${keys[0]}: ${typeof val === 'number' ? val.toFixed(4) : val}`;
    }
    return '-';
  };

  const formatSource = (source: string) => {
    if (source.toLowerCase() === 'tuning') return 'Advanced Training';
    if (source.toLowerCase() === 'training') return 'Standard Training';
    return source.charAt(0).toUpperCase() + source.slice(1);
  };

  const filteredModels = models.filter(model => {
    const matchDataset = (model.dataset_name || '').toLowerCase().includes(datasetFilter.toLowerCase()) || 
                         (model.dataset_id || '').toLowerCase().includes(datasetFilter.toLowerCase());
    const matchModel = model.model_type.toLowerCase().includes(modelTypeFilter.toLowerCase());
    return matchDataset && matchModel;
  });

  if (loading && !stats && models.length === 0) return (
    <div className="p-8">
      <LoadingState message="Loading registry..." />
    </div>
  );
  
  if (error) return (
    <div className="p-8">
      <ErrorState error={error} />
    </div>
  );

  return (
    <div className="p-8 min-h-screen bg-slate-50 dark:bg-slate-900 text-slate-900 dark:text-slate-100 transition-colors duration-200">
      <div className="mb-8 flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold tracking-tight text-slate-900 dark:text-white">Model Registry</h1>
          <p className="text-slate-600 dark:text-slate-400 mt-1">Manage versions, track metrics, and deploy your best models.</p>
        </div>
        <button 
          onClick={() => { setPage(0); void fetchModels(0, true); fetchStats(); }} 
          className="px-4 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-md text-sm font-medium hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors shadow-sm"
        >
          Refresh
        </button>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-8">
        <StatsCard 
          title="Total Versions" 
          value={stats?.total_versions || 0} 
          icon={<Box className="text-blue-500" />} 
        />
        <StatsCard 
          title="Active Deployments" 
          value={stats?.active_deployments || 0} 
          icon={<RocketIcon className="text-green-500" />} 
          valueColor="text-green-600 dark:text-green-400"
        />
        <StatsCard 
          title="Model Types" 
          value={models.length} 
          icon={<Archive className="text-purple-500" />} 
          valueColor="text-purple-600 dark:text-purple-400"
        />
      </div>

      {/* Filters */}
      <div className="mb-6 flex flex-col sm:flex-row gap-4">
        <div className="flex-1">
          <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Filter by Model Type</label>
          <input 
            type="text" 
            placeholder="e.g. RandomForest" 
            value={modelTypeFilter}
            onChange={(e) => { setModelTypeFilter(e.target.value); }}
            className="w-full px-4 py-2 rounded-md border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        </div>
        <div className="flex-1">
          <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">Filter by Dataset</label>
          <input 
            type="text" 
            placeholder="e.g. Iris Dataset" 
            value={datasetFilter}
            onChange={(e) => { setDatasetFilter(e.target.value); }}
            className="w-full px-4 py-2 rounded-md border border-slate-300 dark:border-slate-600 bg-white dark:bg-slate-800 text-slate-900 dark:text-white focus:ring-2 focus:ring-blue-500 focus:border-transparent"
          />
        </div>
      </div>

      {/* Models List */}
      <div className="bg-white dark:bg-slate-800 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden">
        <div className="px-6 py-4 border-b border-slate-200 dark:border-slate-700 flex justify-between items-center bg-slate-50/50 dark:bg-slate-800/50">
          <h2 className="text-lg font-semibold flex items-center gap-2">
            <Archive size={20} className="text-slate-400" />
            Registered Models
          </h2>
          <span className="text-sm text-slate-500 dark:text-slate-400">
            Showing {filteredModels.length} of {models.length} models
          </span>
        </div>
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
            <thead className="bg-slate-50 dark:bg-slate-900/50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">Model Type</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">Dataset</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">Latest Version</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">Source</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">Created At</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">Status</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">Deployments</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white dark:bg-slate-800 divide-y divide-slate-200 dark:divide-slate-700">
              {filteredModels.length === 0 ? (
                <tr>
                  <td colSpan={8}>
                    <EmptyState
                      icon={<Box size={48} className="text-slate-300 dark:text-slate-600" />}
                      title="No models found matching your filters."
                    />
                  </td>
                </tr>
              ) : (
                filteredModels.map((model) => {
                  const latest = model.latest_version;
                  if (!latest) return null;
                  
                  const rowKey = `${model.model_type}-${model.dataset_id}`;
                  const isSystemDeployed = model.deployment_count > 0;
                  const isManuallyDeployed = manualDeployments[rowKey] || false;
                  const isDeployed = isSystemDeployed || isManuallyDeployed;

                  return (
                    <tr key={rowKey} className="hover:bg-slate-50 dark:hover:bg-slate-700/50 transition-colors">
                      <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-slate-900 dark:text-white">
                        {model.model_type}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 dark:text-slate-400">
                        <div className="flex flex-col">
                          <div className="flex items-center gap-2">
                            <span className="font-medium text-slate-700 dark:text-slate-300">{model.dataset_name}</span>
                            {model.dataset_type && (
                              <span className="px-1.5 py-0.5 rounded text-[10px] font-medium bg-slate-100 dark:bg-slate-700 text-slate-500 dark:text-slate-400 border border-slate-200 dark:border-slate-600 uppercase">
                                {model.dataset_type}
                              </span>
                            )}
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 dark:text-slate-400">
                        <span className="font-mono bg-slate-100 dark:bg-slate-700 px-2 py-1 rounded text-xs">v{latest.version}</span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 dark:text-slate-400">
                        {formatSource(latest.source)}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm text-slate-500 dark:text-slate-400">
                        {new Date(latest.created_at).toLocaleDateString()}
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap">
                        <span className={`px-2 py-1 inline-flex text-xs leading-5 font-semibold rounded-full ${getStatusColor(latest.status)}`}>
                          {latest.status}
                        </span>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-sm">
                        <div className="flex items-center gap-2" onClick={(e) => { e.stopPropagation(); }}>
                          <input 
                            type="checkbox" 
                            checked={isDeployed} 
                            onChange={() => { toggleManualDeployment(rowKey); }}
                            disabled={isSystemDeployed}
                            className={`w-4 h-4 rounded border-gray-300 focus:ring-green-500 ${isSystemDeployed ? 'text-green-600 opacity-50 cursor-not-allowed' : 'text-blue-600 cursor-pointer'}`} 
                          />
                          {isDeployed ? (
                            <span className="inline-flex items-center gap-1 text-green-600 dark:text-green-400 font-medium bg-green-50 dark:bg-green-900/20 px-2 py-1 rounded-full text-xs">
                              <CheckCircle size={12} /> {isSystemDeployed ? 'Active' : 'Manual'}
                            </span>
                          ) : (
                            <span className="text-slate-400 dark:text-slate-600 text-xs">None</span>
                          )}
                        </div>
                      </td>
                      <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                        <button 
                          onClick={() => { setSelectedModel(model); }}
                          className="text-blue-600 dark:text-blue-400 hover:text-blue-900 dark:hover:text-blue-300 flex items-center justify-end gap-1 ml-auto"
                        >
                          View Versions <ChevronRight size={16} />
                        </button>
                      </td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
      
      {loading && models.length > 0 && (
        <div className="py-4 flex justify-center text-slate-500 dark:text-slate-400">
          <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-blue-600 mr-2"></div>
          Loading more models...
        </div>
      )}

      {/* Versions Modal/Drawer */}
      {selectedModel && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm" onClick={() => { setSelectedModel(null); }}>
          <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl w-full max-w-4xl max-h-[90vh] flex flex-col overflow-hidden border border-slate-200 dark:border-slate-700" onClick={e => { e.stopPropagation(); }}>
            <div className="px-6 py-4 border-b border-slate-200 dark:border-slate-700 flex justify-between items-center bg-slate-50 dark:bg-slate-900/50">
              <div>
                <h3 className="text-xl font-bold text-slate-900 dark:text-white">{selectedModel.model_type}</h3>
                <p className="text-sm text-slate-500 dark:text-slate-400">Version History</p>
              </div>
              <button onClick={() => { setSelectedModel(null); }} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors">
                <X size={24} />
              </button>
            </div>
            
            <div className="flex-1 overflow-y-auto p-6">
              <table className="min-w-full divide-y divide-slate-200 dark:divide-slate-700">
                <thead>
                  <tr>
                    <th className="px-4 py-2 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase">Version</th>
                    <th className="px-4 py-2 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase">Date</th>
                    <th className="px-4 py-2 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase">Metrics</th>
                    <th className="px-4 py-2 text-left text-xs font-medium text-slate-500 dark:text-slate-400 uppercase">Status</th>
                    <th className="px-4 py-2 text-right text-xs font-medium text-slate-500 dark:text-slate-400 uppercase">Action</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-200 dark:divide-slate-700">
                  {selectedModel.versions.map((version) => (
                    <tr key={version.job_id} className={`hover:bg-slate-50 dark:hover:bg-slate-700/30 ${version.is_deployed ? 'bg-green-50/50 dark:bg-green-900/10' : ''}`}>
                      <td className="px-4 py-3 whitespace-nowrap text-sm font-medium text-slate-900 dark:text-white">
                        <div className="flex items-center gap-2">
                          <span className="font-mono">v{version.version}</span>
                          {version.is_deployed && (
                            <span className="text-xs bg-green-100 dark:bg-green-900 text-green-800 dark:text-green-200 px-1.5 py-0.5 rounded border border-green-200 dark:border-green-800">
                              Deployed
                            </span>
                          )}
                        </div>
                      </td>
                      <td className="px-4 py-3 whitespace-nowrap text-sm text-slate-500 dark:text-slate-400">
                        {new Date(version.created_at).toLocaleString()}
                      </td>
                      <td className="px-4 py-3 whitespace-nowrap text-sm text-slate-600 dark:text-slate-300 font-mono">
                        {formatMetrics(version.metrics)}
                      </td>
                      <td className="px-4 py-3 whitespace-nowrap">
                        <span className={`px-2 py-0.5 inline-flex text-xs leading-5 font-semibold rounded-full ${getStatusColor(version.status)}`}>
                          {version.status}
                        </span>
                      </td>
                      <td className="px-4 py-3 whitespace-nowrap text-right text-sm font-medium">
                        <div className="flex items-center justify-end gap-2">
                          <button
                            onClick={() => { void handleViewArtifacts(version.job_id); }}
                            className="text-slate-500 hover:text-slate-700 dark:text-slate-400 dark:hover:text-slate-200"
                            title="View Artifacts"
                          >
                            <Folder size={16} />
                          </button>
                          
                          {version.status === 'completed' && !version.is_deployed && (
                            <button 
                              onClick={() => { void handleDeploy(version.job_id); }}
                              disabled={deployingId === version.job_id}
                              className="text-blue-600 dark:text-blue-400 hover:text-blue-900 dark:hover:text-blue-300 disabled:opacity-50 flex items-center gap-1"
                            >
                              {deployingId === version.job_id ? (
                                <span className="animate-spin h-3 w-3 border-b-2 border-current rounded-full"></span>
                              ) : (
                                <Play size={14} />
                              )}
                              Deploy
                            </button>
                          )}
                          {version.is_deployed && (
                            <span className="text-green-600 dark:text-green-400 text-xs flex items-center gap-1">
                              <CheckCircle size={14} /> Active
                            </span>
                          )}
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
            
            <div className="px-6 py-4 border-t border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50 flex justify-end">
              <button 
                onClick={() => { setSelectedModel(null); }}
                className="px-4 py-2 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 rounded-md text-sm font-medium text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors"
              >
                Close
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Artifacts Modal */}
      {viewingArtifacts && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm" onClick={() => { setViewingArtifacts(null); }}>
          <div className="bg-white dark:bg-slate-800 rounded-xl shadow-2xl w-full max-w-2xl max-h-[80vh] flex flex-col overflow-hidden border border-slate-200 dark:border-slate-700" onClick={e => { e.stopPropagation(); }}>
            <div className="px-6 py-4 border-b border-slate-200 dark:border-slate-700 flex justify-between items-center bg-slate-50 dark:bg-slate-900/50">
              <h3 className="text-lg font-bold text-slate-900 dark:text-white flex items-center gap-2">
                <Folder size={20} className="text-blue-500" />
                Artifacts
              </h3>
              <button onClick={() => { setViewingArtifacts(null); }} className="text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors">
                <X size={24} />
              </button>
            </div>
            
            <div className="flex-1 overflow-y-auto p-6">
              {loadingArtifacts ? (
                <div className="flex justify-center py-8 text-slate-500 dark:text-slate-400">
                  <div className="animate-spin rounded-full h-6 w-6 border-b-2 border-blue-600 mr-2"></div>
                  Loading artifacts...
                </div>
              ) : !artifacts || artifacts.files.length === 0 ? (
                <div className="text-center py-8 text-slate-500 dark:text-slate-400">
                  No artifacts found.
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="flex items-center gap-2 p-3 bg-blue-50 dark:bg-blue-900/20 rounded-lg border border-blue-100 dark:border-blue-800">
                    {artifacts.storage_type === 's3' ? (
                      <Cloud size={20} className="text-blue-600 dark:text-blue-400 flex-shrink-0" />
                    ) : (
                      <HardDrive size={20} className="text-slate-600 dark:text-slate-400 flex-shrink-0" />
                    )}
                    <div className="flex flex-col min-w-0">
                      <span className="text-xs font-semibold uppercase tracking-wider text-blue-700 dark:text-blue-300">
                        {artifacts.storage_type === 's3' ? 'S3 Bucket Storage' : 'Local Storage'}
                      </span>
                      <span className="text-xs font-mono text-slate-600 dark:text-slate-400 truncate" title={artifacts.base_uri}>
                        {artifacts.base_uri}
                      </span>
                    </div>
                  </div>
                  
                  <ul className="space-y-2">
                    {artifacts.files.map((artifact, idx) => (
                      <li key={idx} className="flex items-center gap-3 p-3 rounded-lg bg-slate-50 dark:bg-slate-700/30 border border-slate-100 dark:border-slate-700">
                        <FileText size={18} className="text-slate-400" />
                        <span className="text-sm font-mono text-slate-700 dark:text-slate-300 break-all">
                          {artifact}
                        </span>
                      </li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
            
            <div className="px-6 py-4 border-t border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50 flex justify-end">
              <button 
                onClick={() => { setViewingArtifacts(null); }}
                className="px-4 py-2 bg-white dark:bg-slate-800 border border-slate-300 dark:border-slate-600 rounded-md text-sm font-medium text-slate-700 dark:text-slate-200 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors"
              >
                Close
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

const StatsCard = ({ title, value, icon, valueColor = "text-slate-900 dark:text-white" }: { title: string, value: number, icon: React.ReactNode, valueColor?: string }) => (
  <div className="bg-white dark:bg-slate-800 p-6 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 flex items-start justify-between">
    <div>
      <div className="text-sm font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">{title}</div>
      <div className={`mt-2 text-3xl font-bold ${valueColor}`}>{value}</div>
    </div>
    <div className="p-3 bg-slate-50 dark:bg-slate-700/50 rounded-lg">
      {icon}
    </div>
  </div>
);

const RocketIcon = ({ className }: { className?: string }) => (
  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" className={className}><path d="M4.5 16.5c-1.5 1.26-2 5-2 5s3.74-.5 5-2c.71-.84.7-2.13-.09-2.91a2.18 2.18 0 0 0-2.91-.09z"/><path d="m12 15-3-3a22 22 0 0 1 2-3.95A12.88 12.88 0 0 1 22 2c0 2.72-.78 7.5-6 11a22.35 22.35 0 0 1-4 2z"/><path d="M9 12H4s.55-3.03 2-4c1.62-1.08 5 0 5 0"/><path d="M12 15v5s3.03-.55 4-2c1.08-1.62 0-5 0-5"/></svg>
);
